--
-- Table structure for table `restaurants`
--

DROP TABLE IF EXISTS `restaurants`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `restaurants` (
  `restaurant_id` int(11) NOT NULL AUTO_INCREMENT,
  `restaurant_name` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `address` varchar(255) NOT NULL COMMENT '區與之前部分已去頭，例：保安街87號',
  `zipcode` char(3) NOT NULL,
  `latitude` decimal(10,7) NOT NULL,
  `longitude` decimal(10,7) NOT NULL,
  `price_level` tinyint(4) DEFAULT NULL COMMENT '1: ~200 / 2: 200~600 / 3: 600~1500 / 4: 1500+',
  `rating_avg` decimal(3,2) NOT NULL DEFAULT 0.00 COMMENT 'trigger 維護',
  `rating_count` int(11) NOT NULL DEFAULT 0 COMMENT 'trigger 維護',
  `google_place_id` varchar(100) DEFAULT NULL,
  `updated_at` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`restaurant_id`),
  UNIQUE KEY `uk_restaurants_google_place` (`google_place_id`),
  KEY `idx_restaurants_latlng` (`latitude`,`longitude`),
  KEY `idx_restaurants_rating_avg` (`rating_avg`),
  KEY `idx_restaurants_zipcode` (`zipcode`),
  CONSTRAINT `fk_restaurants_zipcode` FOREIGN KEY (`zipcode`) REFERENCES `districts` (`zipcode`) ON UPDATE CASCADE,
  CONSTRAINT `chk_restaurants_price_level` CHECK (`price_level` is null or `price_level` between 1 and 4),
  CONSTRAINT `chk_restaurants_rating_avg` CHECK (`rating_avg` between 0 and 5)
) ENGINE=InnoDB AUTO_INCREMENT=694 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `restaurants`
--

LOCK TABLES `restaurants` WRITE;
/*!40000 ALTER TABLE `restaurants` DISABLE KEYS */;
INSERT INTO `restaurants` VALUES (1,'蘇義興餐廳','現任老闆以前為民歌歌手，餐廳會在週六、日不定時提供民歌演唱的服務，招牌菜色有龍蝦炒菜脯、酥炸三層肉、羊肉火鍋、粉皮蝦捲、鮮肉芋頭酥...等。季節性菜色:過貓沙拉、山藥排骨','中華路77號','227',25.0383700,121.8657300,2,0.00,0,'ChIJTWTK76hbXTQRPRp5kA6dLMM','2026-05-30 23:01:55'),(2,'游記米粉湯','傳統臺灣道地小吃-米粉湯','同安街45號','241',25.0568400,121.4954900,1,0.00,0,'ChIJh0ZpV5KpQjQR8zuG0VqqHpc','2026-05-30 23:01:56'),(3,'大紅袍','除了各式火鍋，大紅袍引以為傲的就是他們的麻辣燙，麻辣燙所有的湯底都有加入鴨血和豆腐，口味有多種選擇，還有拉麵、冬粉等搭配海鮮、牛肉、嫩雞、羊肉、豬肉的餐點，可依照個人喜好選擇。這裡的湯頭的味道，超級香醇濃郁，而且不只是辣而已，還帶有麻的感覺，就像四川花椒的麻一樣，搭配吸飽湯汁的冬粉，讓喜歡嘗鮮的朋友躍躍欲試。推薦菜色:手打嫩牛鍋、手打嫩雞鍋、養生菇菌鍋、 手工川丸子、紅袍嫩牛嫩雞','中興路三段1-8號','231',24.9764100,121.5459400,NULL,0.00,0,'ChIJ5YLVQvABaDQRXvyen38YCMM','2026-05-30 23:01:57'),(4,'玉麵堂','以江浙菜聞名的玉麵堂，建築以傳統中式風格呈現，原木的大門以及內部使用沉木裝潢，加上古典雕花窗扇，還有水晶珠廉及設計感的吊燈，使整體呈現和諧的中西式混搭風格，讓店內的用餐氣氛很溫馨，這裡融合了江浙菜與台菜的料理，除了飯麵、冷盤、熱炒、砂鍋、還有海鮮，很適合團體聚會還有家庭聚餐，而店家首推的各式雞湯以及特色砂鍋還有黃魚，一定要你親自試過才能感受到箇中奧祕。推薦菜色:吊銅鐘土雞湯、砂鍋土雞煲湯、雪菜肉絲雞湯煨麵、砂鍋牛腩牛筋煲、老雪菜燒黃魚','中華路113號1樓','231',24.9692700,121.5386600,2,0.00,0,'ChIJR4QcN_UBaDQRLWjHKgEYsBg','2026-05-30 23:01:58'),(5,'大胖子豆腐冰淇淋','懷念的古早味枝仔冰，在深坑也吃得到，這間深坑豆腐冰淇淋店，有提供各式各樣的口味給民眾選擇，除了傳統的枝仔冰，這邊也有受到小朋友喜愛的雞蛋冰，焦糖以及芝麻還有黑豆腐製成的多種口味豆腐冰淇淋，在夏天除了消暑外，熱量又不會太高，適合想吃又怕胖的朋友一起來嚐鮮。','深坑街62號','222',25.0016200,121.6146600,NULL,0.00,0,'ChIJT30aAcWqQjQRhPr193yx1gc','2026-05-30 23:02:00'),(6,'翡翠谷飲食店','到店內用餐不但可以品嚐高貴不貴的風味餐點，如溪蝦、珠蔥、放山雞等，還可以吃到女主人的現做手工蛋捲，純手工製作的蛋捲，隨著口味有不同香氣，散發濃濃蛋香，相當可口誘人。','烏來街26-28號','223',24.8639000,121.5514000,NULL,0.00,0,'ChIJHZGSJokGaDQRL6nt0SRC0gQ','2026-05-30 23:11:16'),(7,'大團圓餐廳','大團圓，於民國79年創業，創辦人李先生為園藝出身，當初這片空地由窪地到打地基、建築等，都是李先生一手打造。透過農委會輔導轉型經營，大團圓成為當地歷史悠久的餐廳。大團圓相當注重飲食養生觀念，於是不但結合戶外花園座位、深坑特色豆腐料理、專業筵席、更結合了藥膳料理與創意料理，要讓大團圓的獨特性發揮淋漓盡致，無論是尾牙聚餐、包場筵席，都相當適合。目前由第二代接手經營，強調大團圓一切以「美」為出發點，店內的戶外座位充斥綠意、服務的團隊也以親切熱心為主，歡迎闔家到深坑遊玩、體驗大團圓的美食與美景。','阿柔里25-1號','222',24.9991200,121.6128500,2,0.00,0,'ChIJqeFY_JaqQjQRTwJ3Qa6QaUQ','2026-05-30 23:11:17'),(8,'美養莊園餐飲','健康飲食‧體貼身心-美養莊園一樓餐廳開放給所有愛好享用美食的您，店中招牌餐點主打健康養生鍋系列，以新鮮的自然食材搭配各式主廚精心熬煮的湯頭，不添加味精和人工香料，讓您吃的美味健康又安心，另有義大利麵和精緻排餐和下午茶餐點供您選擇。休閒氛圍‧獨家打造-莊園中的餐飲部門在規劃設計時就以融合大自然的氛圍為主軸，舒適寬敞的用餐空間，呈現清新又自在、無拘無束的休閒風，在大都會中更顯獨特珍貴，邀請您來享受慢食、樂活的新現代飲食。','二十張路11巷1-1號','231',24.9825700,121.5398700,NULL,0.00,0,'ChIJZZ0HQREBaDQRdB0U2_RDST0','2026-05-30 23:11:18'),(9,'Gino Pizza店','蘆洲湯姆咖啡廚房提供平價、專業歐式料理、義大利麵、排餐，還有專業窯烤披薩，講求高品質、健康的料理方式，份量大、走精緻的視覺效果，您可在充滿南法情懷的餐廳用餐。湯姆咖啡嚴選食材及優質調味品，以現點現做的方式，提供道地義大利風味料理，以及融合歐法日料理元素的創新菜色，從開胃菜、義大利式窯烤PIZZA、義大利麵、精緻套餐到甜點、義式咖啡、花茶應有盡有。義大利式窯烤PIZZA，擁有外厚內薄，麵皮口感香Q彈牙的特色，越嚼越香，且外型非常特別，外圈的點點烤痕，讓他有豹紋披薩的暱稱，邀您一嚐這獨到的異國美食。','長安街108巷27號','247',25.0825500,121.4621000,2,0.00,0,'ChIJyVgLC7qoQjQRQex5vfM7Eaw','2026-05-30 23:11:19'),(10,'廣泰香西點麵包店','曾被非凡大探索報導。廣泰香西點麵包店，是一家極傳統的家庭式麵包店，妳來到這裡建議嚐看看傳統菠蘿麵包，純菠羅不含其他香料，以頂端的糖酥與下部的麵糰共嚼之後，吃的到菠羅的甜腴與麵香，除了傳統菠蘿，現在口味增加至十多種，供民眾選擇。特色料理：菠羅麵包、奶酥菠蘿、奶油菠蘿等。曾被非凡大探索報導。廣泰香西點麵包店，是一家極傳統的家庭式麵包店，妳來到這裡建議嚐看看傳統菠蘿麵包，共有3種口味，純菠羅不含其他香料，以頂端的糖酥與下部的麵糰共嚼之後，吃的到菠羅的甜腴與麵香，除了傳統波羅，現在口味更新增至10多種，供大家選擇。特色料理：菠羅麵包、奶酥菠蘿、奶油菠蘿、蒜味麵包等。營業時間：07:00-22:30 (16:00-17:00麵包成品較多)假日(17:00~19:00)','淡金路三段347號','251',25.2066900,121.4487200,1,0.00,0,'ChIJ9ct0MnSwQjQRg1iP8ctIWJo','2026-05-30 23:11:21'),(11,'老楊煎包','想吃獨家口味的煎包嗎？絕對不能錯過超高人氣、外皮酥脆的老楊煎包，一到周末時段，常常遠遠就可以看到，摩托車及汽車並排的等候車潮，老顧客都知道，看到老闆的第一句話常常是：請問這一鍋還要等多久，堅持現做現煎的老楊煎包，早上是賣高麗菜口味，下午則是賣韭菜口味，煎包裡面還加了絞肉，這裡的水煎包物超所值，內餡都是真材實料，尤其是鍋邊的煎包，外皮煎的金黃酥脆，真的是非常香脆可口。推薦產品:黃金脆皮水煎包','中興路一段112號','231',24.9623100,121.5413000,1,0.00,0,'ChIJG6V-XYkBaDQRtgOK5dyLn84','2026-05-30 23:18:58'),(12,'清真雲南小吃','每當香味四溢的烤餅出爐，外酥內軟又充滿香氣與奶香的烤餅風味，加上茶香濃厚又甜度適中的奶茶，不禁讓人食指大動。推薦產品:印度烤餅、印度奶茶','華新街62號','235',24.9838100,121.5080100,1,0.00,0,'ChIJfx0-h24CaDQRSC12J5XO19g','2026-05-30 23:18:59'),(13,'萬香烤鴨','曾榮獲2008年烤鴨達人專業評審團評比第一名的實力可不是浪得虛名，烤至金黃色的鴨皮，散發誘人香氣，片下的鴨肉不管單吃或配上蔥段與鴨皮都讓人胃口大開，以大火快炒而成的炒鴨肉更讓人吮指回味！推薦菜色:萬香烤鴨三吃','忠孝路116號','220',25.0022400,121.4629000,2,0.00,0,'ChIJLVsA_6MCaDQREwnx7KhU6Q0','2026-05-30 23:19:00'),(14,'宜安路麵線','\"中和知名的30年以上歷史老店，從原本路邊小巷子內的攤位起家，到現在大馬路旁開了自己的店面，麵線攤子前大排長龍的景象依舊。用大骨和來自布袋鮮蚵熬湯3小時以上，製成麵線的湯底，再加上紅麵線及蚵仔、豬腸、肉羹等配料，不論大碗、小碗，淋上一點老闆特製的辣油入味，相得益彰十分過癮。推薦菜色:蚵仔麵線\"','宜安路117號','235',24.9978800,121.5102000,1,0.00,0,'ChIJPcVla9-pQjQRSMz87ObksXs','2026-05-30 23:19:01'),(15,'九份茶坊','洪先生於70年代在因緣際會下來到九份，深受此地得天獨厚的山海美景和山城繁華落盡的淒美風情所吸引，當時適逢翁山英故居要出售，於是決定暫時放下手邊的事業，於民國76年（1987年）買下這棟默默見證九份興衰、將近70年、老態龍鍾的殘破古厝。他以藝術家的敏銳觀察力與熱情，發掘出這棟古厝獨特的美，毅然保留結構與格局，唯一重大調整是為了自然採光而加開天井，無心插柳柳成蔭，使得風水師不看好的這棟古厝，又注入了全新充沛活力。整修完成後，古意盎然而且充滿人文懷舊氣息，洪先生決定經營藝文茶樓，於民國80年（1991年）開張，成為九份地區重啟繁榮的第一家茶坊。門口的古樸「茶陶畫」布簾，是茶坊的經營理念。四目所及，大面積的隔間與整齊疊放的商品或並排、或前後高低有秩疊放，呈現整體和諧美。天井下方的魚池與小花園、轉角的古董太師椅陪襯出特色茶具組、中堂的威嚴與兩旁拓印碑文的陪襯，至今仍是招待重要客人...','基山街142號','224',25.1081900,121.8435700,2,0.00,0,'ChIJrQbuXT1FXTQR0MWpgczEM7k','2026-05-30 23:19:03'),(16,'熱油麻糬','現在少見的熱油麻糬，不要以為很油膩，其實麻糬本身是不吸油的，老闆娘每天都換新鮮的油，這種處理方式，不僅能保持麻糬的Q度，更能長時間保溫保新鮮，再配上現磨現炒的花生粉，有甜跟不甜可選擇，大人小孩都愛吃！','民生街35巷2號','224',25.1069300,121.8058100,NULL,0.00,0,'ChIJ8326QPdPXTQRO7TCKA_IL5k','2026-05-30 23:19:04'),(17,'蔡家炒羊肉','蔡老板的炒羊肉攤在民國六十八年起就在三重國小邊擺攤，盛時附近羊肉攤多達十多攤，目前只剩三攤。蔡家炒羊肉以炒羊肉麵與炒羊肉起家，沙拉醬摻入新鮮的薄羊片與應菜，口味甘甜香濃道地，再一罐黃澄澄維大力汽水，可吃得很過癮，是一大美食享受；其他各式炒菜也都很受到歡迎，熱騰騰的炒箭筍、炒脆腸、炒蛤蜊、炒青菜等三十種家常菜美味，現點現煮，為寒冷的秋冬時節最佳的人間美味。','文化北路234號','241',25.0695500,121.4974000,NULL,0.00,0,'ChIJEQTCGySpQjQRbrq24fEMz9w','2026-05-30 23:19:05'),(18,'雙溪香甜小吃部','從雙溪火車站一出來，就能看到這間在地的小吃店，店內提供招牌的鐵路便當，有著雙溪的特產黑豬肉，加上特製的黑豬肉香腸，搭配滷豆乾醃黃瓜，簡單的家常味讓人食指大動，再點一份煙燻豬頭皮，口感Q嫩，黑豬肉不會有比較重的豬腥味，所以吃起來香氣十足，而老闆娘親切的態度，讓人感受到熱情的服務。','朝陽街3號','227',25.0386100,121.8661000,NULL,0.00,0,'ChIJx-Y5OahbXTQRA0QnmAwfwiA','2026-05-30 23:19:06'),(19,'富士海鮮','位於福隆海水浴場旁的富士海產，簡單家庭式的裝潢，牆面上提供給推薦朋友來簽名，另外還有提供戶外用餐場地，這裡的海鮮非常鮮甜，感覺就像是剛從海邊捕捉上來的，非常受到國外遊客的喜愛，有來自加拿大以及歐洲的觀光客也在牆上簽名留念，而富士海鮮也為2011年觀光護照之特約商店，來到福隆參加國際海洋音樂祭，歡迎你來這品嚐。','福隆里東興街8號','228',25.0200100,121.9504200,2,0.00,0,'ChIJ64yqK6tdXTQR9_oHG5c9WG8','2026-05-30 23:19:07'),(20,'怡如小吃店','藏身在街尾厝邊，來訪的旅客幾乎都是由在地人帶路，招牌的白斬雞香嫩多汁，清炒箭筍還有美味的炸溪蝦，都能讓你吃到在地的山產野味，在平溪的這間怡如小吃名號已漸漸傳開，都是由吃過的朋友推薦報路慕名而來，店內只有簡單的裝潢，卻讓人感到家庭式的溫暖。','嶺腳村中華街60號','226',25.0250000,121.7393400,NULL,0.00,0,'ChIJiSWEwK9WXTQRQtQc0tcM3S4','2026-05-30 23:19:09'),(21,'台灣煤礦博物館(礦工便當)','火車便當、鐵路便當、竹片便當、特製便當，這些便當已不稀奇，吃過礦工便當嗎？來到平溪的台灣煤礦博物館，購票入園體驗早期的礦工生活，以及參觀模擬煤礦隧道，園區的服務人員會先詢問是否需要特製的礦工便當，事先替入園客人準備，沒有大廚豪華的菜色，確有著心繫兒子的母親，所做出來屬於媽媽味道的菜餚。','新寮村頂寮子5號','226',25.0524800,121.7732500,NULL,0.00,0,'ChIJsYkJHvtQXTQR39h4dY1NC0s','2026-05-30 23:19:10'),(22,'美美飲食店','開店半世紀以上的美美飲食店，位於石碇區石碇東街上，是許多老饕推薦的店家，不起眼的店面卻是滿滿人潮，是石碇傳統鄉土美味的代表店之一，最有名的幾道鄉土菜：白斬閹雞、宮保皮蛋、炒蠅頭、滷桂竹筍、豆腐三吃(炸、羹、紅燒)，都是前往石碇的旅客所大力推薦，享受地方美食的必點好菜，店內點菜率超高的炒檳榔花，加入肉絲及木耳絲還有紅蘿蔔及蒜頭，就是一道令人讚賞的美味。','石碇東街71號','223',24.9909000,121.6605300,NULL,0.00,0,'ChIJnWTpURBVXTQRfqimODLANAc','2026-05-30 23:19:11'),(23,'二哥的店美食館','平民美食要吃的飽又要吃的健康，那就千萬不能錯過這間二哥的店，以各式精緻便當餐盒，多種菜色選擇，除了自助餐的經營方式，各式主菜也非常受到大眾的歡迎，雞腿飯、排骨飯，還有蒜泥白肉以及秋刀魚等多種選擇，價格非常的實在，深受在地居民以及學生們的喜愛。','大同北路41號','241',25.0629000,121.4953800,1,0.00,0,'ChIJl7RyaR-pQjQRr_tJiLqTmS4','2026-05-30 23:19:12'),(24,'魚之鄉','招牌上大大寫著「基隆生猛海鮮」，新莊第一市場裡的名攤「魚之鄉」為了給客人最新鮮的食材，周老闆不惜成本選用來自基隆漁港的現撈魚貨，食材新鮮、漂亮是最大的特色，對品質的堅持建立起良好的商譽，不少餐廳都指定選用魚之鄉的食材。','新莊路315號2樓','242',25.0340200,121.4534400,NULL,0.00,0,'ChIJGSjSp3OoQjQRaJNu-wqv7H4','2026-05-30 23:19:14'),(25,'酒莊美食餐廳','坐落在山林間不起眼的樸實小屋裡，有著對料理滿懷熱誠的老闆在此已經營近十年，希望讓每位蒞臨的客人能嚐到獨特又道地的料理，堅持不使用現成的簡便食材，新鮮純手工是特色之一，免費供應古早味豬油飯更是大人小孩的最愛，喜歡高歌幾曲的，也有卡拉ok免費歡唱，希望讓所有的客人都能吃的愉快，玩得盡興。','崁腳里內中福路4號','207',25.1653500,121.6676900,2,0.00,0,'ChIJyZ7JGQRNXTQRwtshF8f8b5U','2026-05-30 23:19:15'),(26,'高家冰溫泉蛋創始店','鄰近烏來老街「覽勝橋」頭的「高家冰溫泉蛋創始店」的一天從清晨的準備工作開始。熬煮店裡的「紫米八寶粥」、「小米八寶粥」、「紅豆八寶粥」，與準備木耳、紅棗、蕃薯、蓮子、薏仁、芋圓、湯圓、山粉圓、龍眼等配料，而最重要的溫泉蛋的準備工作自然不容怠忽。過去在老街經營滷味生意，希望能將自家產品與當地特色結合，便活用過去滷味經驗於溫泉蛋的生產製作中，於2001年以冰鎮溫泉蛋打出招牌，並廣受各平面電子媒體報導！除冰鎮溫泉蛋外，八寶粥料多實在，而全年販售的「山粉圓」與夏日限定的冰品更是遊客酷暑時的最愛！','烏來街135號','233',24.8627300,121.5515300,1,0.00,0,'ChIJF4ZFA4kGaDQRGz7oJXTmecY','2026-05-30 23:19:16'),(27,'客家小館','主廚推薦：燉雞、客家小炒、冰糖蹄膀、金莎蝦球','智光街22號','234',24.9992200,121.5180800,2,0.00,0,'ChIJUzP_O-GpQjQRx6eg6q6pzfA','2026-05-30 23:19:17'),(28,'聖保羅烘培花園','在寬敞明亮的廠房裡，作業員個個身著制服戴上口罩操作機器，不過這裡生產的不是科技產品，而是獲得全國十大伴手禮肯定，創立於1991年的聖保羅Q餅。精選屏東萬丹紅豆沙，內裹Ｑ彈麻薯 ，再加上使用北港紅土鴨蛋黃與阿里山黑毛豬肉脯為內餡，外層沿用歐洲餅皮工法，製作成外皮酥脆內餡醇厚濃郁鹹香味美的國民美食。另一項超人氣重芋泥蛋糕，以100％純正芋泥精製，減糖又無添加防腐劑，綿密細緻、腴滑紮實的口感，會讓您讚不絕口。南台灣的陽光雨水、鮮甜的果物、甘美有勁的盛情。承襲歐洲製餅工法的聖保羅，將它們仔細揉製烘焙。好的食物從選擇食材就已決定！來自南台灣的聖保羅就是這麼相信，最好的東西就是要留給我們的客人。','福和路327號','234',25.0071400,121.5157100,2,0.00,0,'ChIJd1sha-ipQjQRRg7Gg4aQVAM','2026-05-30 23:19:19'),(29,'蜜而可藝術蛋糕','若要大新莊地區民眾舉例自己熟知的蛋糕麵包烘焙坊，在地經營超過１５年的「蜜而可歐式烘焙坊」絕對榜上有名，甚至是大家首屈一指的第一品牌；能擁有廣大消費民眾的肯定與支持，應歸功於「蜜而可歐式烘焙坊」經營者周先生超過３０年始終堅持鑽研糕餅業的熱情，不斷創新研發口味以符合社會潮流，讓店內商品呈現多元且精緻化，無論是養生麵包、藝術蛋糕、傳統糕餅、造型西點等都擁有各自擁戴的忠實族群，值得一提的是，每天下午４點，剛出爐麵包散發熱騰騰的濃郁香氣，總是吸引大批民眾前來選購，「蜜而可歐式烘焙坊」受歡迎程度不言而喻！','建福路62號','242',25.0271100,121.4266500,2,0.00,0,'ChIJV90Mie2nQjQR0HhHBmn0vZ4','2026-05-30 23:19:20'),(30,'那年夏天咖啡館','美麗的北海岸，有藍天、碧海、白沙，總是讓人流連忘返，尤其是三芝淺水灣與咖啡街，有著如地中海般的浪漫。位於咖啡街上的那年夏天，是一風格獨具的咖啡館，女主人在十多年前曾經拜訪過英國南方的一個美麗小漁港，港口延伸的小路兩旁有二、三十間老房子，屋前種植各種花草，每個小店家都有一個角落，供遊客歇腳、喝咖啡，牆上展示著畫家們的畫作，被咖啡和藝術氣息所感動，於是提早退休，在這個蔚藍海邊做一個逐夢者。來到這裡，可以放鬆心情喝杯咖啡、享受美食，感受淺水灣的美。','後厝里北勢子45-13號','252',25.2503100,121.4674900,2,0.00,0,'ChIJ8Qe2G7iwQjQRdUVMC0Ug7W0','2026-05-30 23:19:21'),(31,'小竹屋日式小吃','小竹屋日式小吃，在永和已經有四十年以上的歷史，位於文化路及永和路口附近，在永和是個小有名氣的日式小吃店。１９７２年以路邊的一個小攤位起家，專賣沙拉、壽司、關東煮、烏龍麵等日式小吃。漸漸將名氣做起來，改變成為一個風格簡單大方的小店面，絕無分店。店裡提供的餐點做了多元的變化，因應不同時代潮流的顧客口味。小竹屋並以誠懇的態度服務顧客，一律採取現點、現烤、現炸的方式出餐，也會在菜單上告知顧客每道料理出餐的速度，由快到慢做一系列的排序，給客人更方便的選擇，實為貼心，是許多上班族的聚餐最愛地點。推薦菜色:烤雞腿、鮭魚、生魚片、炸蝦等各式定食、蓋飯、炸豬排、蛋包飯、咖哩飯、吻仔魚丼套餐。','文化路19號1F','234',25.0149300,121.5150300,2,0.00,0,'ChIJjU_pkOqpQjQR-x4eqVWQFs0','2026-05-30 23:19:22'),(32,'富貴陶園','延續藝廊豐厚的人文氣息，餐廳內從佈置到餐具，全都選用價值不斐的名工藝家作品。一組萬元以上的火鍋器皿，讓盛裝於內的啤酒雞更為醉人；飲品杯也不遑多讓，拿起質感厚實的咖啡杯輕啜一口香濃維也納，口感更為溫潤留香。戶外用餐區藏了老樹、水池和木棧台，每個座位彼此也刻意保持適當距離，讓用餐品質維持在可以靜靜欣賞周圍美景的理想狀況。','重慶街96~98號','239',24.9523000,121.3482900,2,0.00,0,'ChIJScuXgKweaDQRMDpsD_fdN8E','2026-05-30 23:19:23'),(33,'亞米ya複合式餐飲','亞米ya源自於好吃的意思，早餐店位於社區內，店內窗明几淨，進去用餐讓人有舒服的感覺。座位寬敞，可以容納 35~40 人，在一般的早餐店中算是寬敞。餐點多樣化，有輕食系列的早餐，有養生的早餐，還有可以讓你自己配的早餐，只要顧客有所要求，老闆都會幫妳做到滿意的早餐。價格方面，高貴不貴，歡迎各位想吃不一樣的早餐，可以來看看喔，一定讓你不虛此行。','成功路50巷27號','241',25.0500000,121.4884700,1,0.00,0,'ChIJzx3OlP2oQjQR2LE5smgBSvM','2026-05-30 23:19:25'),(34,'土城雲林鵝肉海鮮餐廳','土城的金鵝城在眾多的鵝肉店中，算是獨樹一格的風味，賣的是少數的港式燒鵝，新鮮的燒臘風味，是許多人愛吃的原因，本身就具有燒臘底子的老闆，更是獨自研發出能將燒鵝風味提昇，手續繁多的做法。還有自製的沾醬，讓濃郁的香味更佳，而且每天製作的鵝隻都有限，想要嚐嚐就要快。','金城路三段216號1樓','236',24.9899100,121.4722700,2,0.00,0,'ChIJbRlvnJYCaDQRBrR98NPd058','2026-05-30 23:19:26'),(35,'桔磨坊義式麵屋','在中和宜安路、中安街擁有兩家店面的桔磨坊，老闆張文川從自己愛吃美食的評論家，到最後跳下來自己開店，變成義大利麵屋老闆，好手藝常令許多行家跌破眼鏡。從事18年建築業轉行，桔磨坊用真材實料、新鮮美味，緊緊抓住每位消費者的心。從試吃、學習、調整、研發，不斷精進的技術，都彰顯在一盤盤Q度適中、彈牙有勁的義大麵裡。推薦菜色:茄汁雞肉義大利麵、青醬蛤蠣義大利麵','宜安路157號,中安街82號‎','235',24.9987800,121.5089400,1,0.00,0,'ChIJ-fHg2d2pQjQRM36iJ6Xr5xU','2026-05-30 23:19:27'),(36,'權仔鴨肉冬粉','湯頭清香好喝，冬粉也是精心挑選的，所以特別有嚼勁。喜愛吃辣的朋友亦可嘗試辣味泡菜，火紅的辣味保證叫人印象深刻。推薦菜色:鴨肉麵、冬粉、麵','永貞路349號','234',25.0074400,121.5092300,1,0.00,0,'ChIJ2QMnt9ypQjQR6jZh0Msf_p0','2026-05-30 23:19:29'),(37,'豐華小館','有政商饕客私房餐廳美稱的豐華小館，是板橋地區首屈一指的中式餐廳，來用餐如果沒訂位，通常要等很久。禪風的外觀，整體黑色系專業裝潢，和高級的用餐環境，為已滿分的美味再添風采。店內料理以手工江浙菜與港式小炒聞名，深具創意的菜色與十分舒適的空間營造，雅致又充滿現代感，具象與抽象的食之美，成為當地膾炙人口的代表作。','雙十路二段209號','220',25.0288800,121.4731000,3,0.00,0,'ChIJ8d5aJkGoQjQRYOKYZRwGfho','2026-05-30 23:19:30'),(38,'霸味薑母鴨','總是滿滿的人潮，即是其好吃的証明，曾被食尚玩家及非凡大探索等多家媒體所推薦過！位於三重重新路及重陽路交叉口附近，只要過秋，總是滿滿的人潮，從原本的一家店面到連續的三到四戶連在一起的店面，加上騎樓人行道下甚至是旁邊的工地，皆是人山人海，可知其生意之興隆，每到天氣稍涼的時候，就想邀些好友，一起來此熱絡熱絡一下。','重陽路一段98.100號','241',25.0593900,121.4864200,2,0.00,0,'ChIJRa9hPeGoQjQR8ROkgt0Qg5Y','2026-05-30 23:19:31'),(39,'阿川麻辣臭豆腐','麻辣臭豆腐的湯頭使用了蝦米、香菇、酸菜與肉燥，再加上數十種中藥細火慢熬，香氣足夠，且不像一般麻辣湯底的油膩、嗆辣，讓整碗麻辣臭豆腐吃起來更豐富而口味更多層次化，鴨血鮮嫩而入味，豆腐中的小空隙飽含著湯汁，一口咬下在嘴中流出，非常過癮。','永平路164號','234',25.0089100,121.5109100,NULL,0.00,0,'ChIJmywGbHGpQjQRYAmdcMR7ooQ','2026-05-30 23:19:32'),(40,'楊家雞捲','菁桐火車站，是全臺灣尚存四座保存良好的全木造車站之一；礦業興盛時，曾有多達12位的站務人員在此工作，而今，全站只剩一人打理。菁桐車站的興衰故事，位於車站斜對面、家族三代世居於此的楊家雞捲，大概最清楚不過；楊家早自煤礦全盛時期就在此經營麵店，生意最好時，曾經每天24小時營業不休息，隨著礦業沒落，生意也跟著不如以往，只好在1968年左右改為雜貨店兼賣雞捲，未料後來觀光業興盛，楊家雞捲反倒從此聞名。雞捲其實沒有雞店內放著一塊有趣的木牌，清楚告知來訪的顧客──「肉羹沒ㄍㄥ，雞捲沒有雞肉」！原來，所謂的雞捲，裡面其實沒有雞肉，而是以豆腐皮包裹紅蘿蔔、芋頭、洋蔥、絞肉等內餡，切塊之後、再下鍋油炸，吃起來酥脆爽口，且富芋頭香氣。','菁桐里菁桐街127號','226',25.0237600,121.7239700,1,0.00,0,'ChIJcVnRIqlWXTQRzdIOORwC7dk','2026-05-30 23:19:34'),(41,'高記生炒魷魚','滿滿一碗生炒魷魚中只有高麗菜與魷魚兩種簡單食材，但高麗菜炒得清脆香甜，魷魚也處理的又脆又Q ，融合酸甜鹹辣等四種調味，讓這一碗看似簡單的魷魚變得很不簡單。推薦菜色:生炒魷魚、蘿蔔糕推薦名人:黃俊哲議員推薦','宮口街28號','220',25.0102600,121.4574000,1,0.00,0,'ChIJ108UywKoQjQRnWs6rKFWWTU','2026-05-30 23:19:35'),(42,'黑肉圓','藏身在板橋區光仁中學巷口。之所以名叫「黑」肉圓，指的可不是黑色的肉圓，而是內餡採用黑豬肉而來，配上筍絲與Q勁十足的外皮，口感讓人回味。','中山路二段255巷5號','220',25.0178800,121.4770900,1,0.00,0,'ChIJuzDaVDqoQjQR3q8g_RvMDO0','2026-05-30 23:19:36'),(43,'檸檬草香茅火鍋專賣店(館東店)','「檸檬草美食連鎖」多年來秉持著：水煮最健康、創新食材、提升多層次的口感為原則，並以「清新、健康、熱情、活力」為經營理念；堅持著「食材的新鮮度、現泡的花茶系列、以客為尊的服務品質、提供健康而不油膩的優質用餐環境」。','館前東路26號','220',25.0071300,121.4603200,2,0.00,0,'ChIJe5HWCqcCaDQRmwhB4c8CaSM','2026-05-30 23:19:37'),(44,'中和廟口麻油雞','麻油的香味混著雞肉的鮮甜，酒的香氣濃郁，沾一口特製的沾醬與麵線一同享用，熱氣混合著麻油的香氣，只有美味兩個字足以形容。推薦菜色:麻油雞專賣','中和路92號','235',25.0003400,121.5011600,2,0.00,0,'ChIJ8_lbvtepQjQRs_B6LdAJx4k','2026-05-30 23:19:38'),(45,'石碇一粒粽','石碇老街超人氣名產「石碇一粒粽」創始於1978年，是一家三十幾年老字號的懷舊古早味肉粽店，取名為「一粒粽」是因為店家有自信，讓客人吃完一粒粽子就感受到粽子的健康、美味，不僅一粒就上癮並感覺到老闆的用心。每每例假日，慕名而來或路過遊客總是擠滿小小店面，限量的粽子也經常銷售一空。走進店內懸掛於牆面的黑白照片上，一首『三十餘年好手藝、因緣際會來湊合、用心做出一粒粽、呈現在地好味道』正是一粒粽的緣起。主要商品種類有粽子、奶酪、飲料、調味醬等。粽子主打不油膩、吃了不脹氣，且選用最優質的材料、並通過了國家品質保證頂級金牌獎；其中又以桂花粽最為特別，桂花粽乃全台獨創，經過數年研發後以整朵桂花加入粽子做調味，品嘗粽子的同時也能嚐到桂花香。[照片及文字介紹內容由店家提供]','石碇東街109號-1','223',24.9910700,121.6602000,2,0.00,0,'ChIJ_____-__ZzQRuIvU1WQmaqg','2026-05-30 23:19:40'),(46,'艾莉斯餐酒館','以家庭溫馨式風格佈置的異國料理小餐館，在淡水已經營業十多年，以高格調裝潢、五星級的料理、平易近人的價格，料好味美又實在，深獲淡水在地人以及學生的喜愛，除了現場的鋼琴演奏，還有來自歐洲的精緻典雅餐具，加上主廚提供的義式及法式養生料理，選用低脂鮭魚肉烹調的檸檬香烤鮭魚，沒有多餘油脂，爽口零負擔，法式羊排先將油脂烤出，熱量減半，讓客人吃起來安心、健康。推薦菜色:歐式異國料理','大忠街117號','251',25.1770800,121.4471900,2,0.00,0,'ChIJoXP2C1alQjQRQo6z84ED1KQ','2026-05-30 23:19:41'),(47,'紅麵線','在地人一致推薦已開店15年的「紅麵線」，以響亮的招牌打出名號\"住樹林沒吃稀奇，來樹林不吃可惜\"，這一家的麵線稠而不膩，老闆說這種寬麵線久煮不易爛，處理過後的滷大腸也香Q軟嫩，不會有豬內臟的腥味，另外，也有深受好評的獨門醬料甜不辣，非常受到歡迎，是樹林當地眾多出名的小吃之一。','保安街一段22之5號','238',24.9934500,121.4273500,1,0.00,0,'ChIJw2ypOD8daDQRAC4MJfFXNaI','2026-05-30 23:19:42'),(48,'德利休息站(東木河茶莊)','喜歡騎單車的朋友，常會利用假日休息，到坪林這邊挑戰自己的極限，許多車友都喜歡來到這間德利休息站，除了稍作休息外，到了用餐時間，店內提供各式中西式輕食，而老闆推薦的風味菜香滷蹄花，受到許多朋友的喜愛，滷豬蹄香甜滑嫩，令人難忘，在這養足精力，吃飽了又可以再次上路，飽覽坪林絕佳的美景。滷蹄花料理許多喜愛騎單車或走步道的旅客常探訪坪林，在從事完這些容易消耗體力的運動後，最需要的就是來碗能吃飽食的美味好料。那千萬別錯過當地的滷蹄花料理，肥瘦恰好的蹄花除毛清洗後，放進由大蒜、薑、醬油、米酒及中藥材所製成的滷汁裡悶燉。出鍋後的蹄花香氣十足，筋皮帶勁卻不過硬，吸入飽滿湯汁的肉質十分夠味，搭配一碗飯品嚐剛剛好。','北宜路八段206號','232',24.9349600,121.7089400,2,0.00,0,'ChIJO-Kmb-b_ZzQRq8DlUaNlRZM','2026-05-30 23:19:43'),(49,'北港龍門生炒鴨肉羹','三重龍門路上這家鴨肉羹，以道地南部口味，將鴨肉先炒再做成羹湯的香濃口感，每嚐一口總能稍解許多出外工作朋友們的鄉愁，每天一開店做生意，店裡的客人就從沒停過，尤其一到用餐時間，還要多點耐心排隊等位置，到了晚上六點多賣完老闆就收攤了，下班動作慢就吃不到，鴨肉羹的薄肉片炒的恰到好處，也沒有一般鴨肉烹煮過頭的硬度，加上老闆提供的辣椒粉，味道更棒。','龍門路134號','241',25.0731000,121.4981900,1,0.00,0,'ChIJDfBUjyWpQjQRjvgkVCjH9i4','2026-05-30 23:19:45'),(50,'梁師傅牛肉麵餃子館','招牌牛肉麵的湯頭是以長時間熬煮出的紅燒牛肉湯，搭配入味的滷牛肉腱及自製手工麵條，有嚼勁、有麵香。','中山路二段572號','249',25.1461700,121.3969900,2,0.00,0,'ChIJLbdRmrmlQjQRBZXWZTN6T4o','2026-05-30 23:19:46'),(51,'陳記養生甜點','店家製作豆腐味商品， 堅持高品質、低糖低熱量、健康無負擔的豆腐類甜點為主要商品，使用石碇老街上百年王氏豆腐為原料，口感清新爽口，不甜不膩，是受到現代人歡迎的美味。推薦產品:豆腐冰淇淋、豆腐蛋糕、豆腐奶酪、豆腐布丁','石碇東街77號','223',24.9909400,121.6603100,NULL,0.00,0,'ChIJL8QfUhBVXTQRGv2jgUv57ug','2026-05-30 23:19:47'),(52,'泰祐食堂','中和區異國美食店林立，特別是南勢角一帶，滇緬美食一支獨秀，加上大潤發大樓一帶美食小吃店也不少，在這兒開一家韓式料理顯得十分特別。年輕老闆阿泰因為自己熱愛韓式料理美食，但資金不足，因此找上新北市政府幫忙，在幸福創業貸款的幫助下，讓阿泰圓了創業夢想。歷經考驗，泰祐食堂用道地的韓國料理擄獲了無數饕客、上班族的胃，每到中午用餐時間，附近大樓上班的消費者，還有遠自臺北市慕名而來的行家，就把店裡塞得滿滿的，大家都是為了店裡美味又道地的石鍋拌飯、海鮮煎餅、銅盤烤肉、炒年糕，還有老闆整間店內滿滿的海賊王公仔而來。','景平路240巷2弄9號','235',24.9930900,121.5161300,NULL,0.00,0,'ChIJJZZB-woCaDQRC4fTfZL_EFU','2026-05-30 23:19:48'),(53,'北鴨鴨肉羹','離碧潭風景區不遠的北鴨鴨肉羹，是饕家們品嚐美食的好去處。北鴨鴨肉羹隱身在光明街裡，不起眼的外觀，有著十分乾淨的用餐環境，店內為了方便客人，在北新路、光明街兩邊都開了門，還真是有趣。北鴨鴨肉羹的羹湯勾芡得恰到好處，味道和嘉義新港的鴨肉羹十分接近，有淡淡的蒜香和甜洋蔥味，特色的鴨肉飯更是來此必點。鴨肉飯的處理其實和豬肉的滷肉飯類似，更少了油膩感，而且鴨肉本身的纖維較多，口感和滷汁搭配起來剛剛好，十分入味下飯。老闆鴨肉飯的鴨肉選用鴨胸部位，先用大火以醬料快炒，再淋上特製的高湯汁，飄香千里的鴨肉飯光聞味道就令人食指大動。。','光明街169號','231',24.9626600,121.5396400,1,0.00,0,'ChIJ4VD4gokBaDQRxF6JPiIOa5w','2026-05-30 23:19:49'),(54,'石牆仔內','在淡水大屯山下有一處古厝、美食、醇香咖啡，與詩人聚會的美食勝地，那就是祖傳三代知名詩人李魁賢的三合院老家─「石牆仔內」，當年先祖李山石於1871年開墾淡水、三芝建造三合院時，因考量治安所修築防禦土匪、與保護住家及人畜安全的一些建築特色，迄今仍保留下來，歷經翻修而成現存的瓦房華屋，當地人都稱李家為石牆仔內。歷經一百多年歷史，廣達四千多坪的空間，高達23棵百年老樹，在此休閒、嚐美食、喝咖啡，真是一件令人心曠神怡的快樂事。石牆仔內鄉土名菜在老饕心中，是深具古味的佳餚而佳評如潮，一般鄉土菜裡的白斬土雞，李家的料理的很簡單，吃出雞肉的天然甜味，清炒高麗菜、清炒蘆筍蝦仁，健康養生五味調和，讓身體處在大自然中，飲食也貼近大自然，感受著慢食的快活。而古早味的炒米粉和荷葉豆腐來此必嚐，吃得出阿嬤老手藝的米粉，清香濃郁的口感，味蕾完全服貼。','忠寮里大埤頭3號','251',25.1955700,121.4891500,2,0.00,0,'ChIJ-xFRA0uwQjQRPfKqLev7QZ8','2026-05-30 23:19:51'),(55,'小楊脆腸','位於三和夜市裏有一家小楊脆腸，是三和夜市最有名的滷味為招牌的滷味，常常都是人滿為患。小楊脆腸特別的地方就是冰冰涼涼的吃~再配上的酸菜跟調配有點辣的醬料，搭配起來真的很讚! 每個吃過的人都會上癮。如果來到三和夜市一定要記得來一份脆腸!','重新路一段87之12號','241',25.0638900,121.5011600,1,0.00,0,'ChIJ8zTh6iKpQjQRMOS4ip6tkVY','2026-05-30 23:19:52'),(56,'藥膳養生主題餐廳','羨慕中宗能享用大長今的特調宮廷御膳嗎？在新北市三重區就能有這麼高規格的服務！藥膳養身主題餐廳的黃福雄老闆 本 身 就 具 備 專 業 的 中 藥 背景，秉持神農嘗百草的精神，為客人開發出多種養身食譜，也能因應客人的不同體質以及健康需求，提供專屬的養身配方與中藥諮詢。每天早上8點起老闆就在準備不同客人的合適藥材，經過6小時的熬煮而成的個人化藥膳，如果沒有提前預約，也可以享用藥膳烏龍麵，也是同樣好吃又滋補。店內採用的中藥以及各種食材都經過嚴格篩選，不僅新鮮又有經過認證，整體口感香純原味，比市面上一般的食補口味更加可口。羨慕中宗能享用大長今的特調宮廷御膳嗎？在新北市三重區就能有這麼高規格的服務！藥膳養身主題餐廳的黃福雄老闆本身就具備專業的中藥背景，秉持神農嘗百草的精神，為客人開發出多種養身食譜，也能因應客人的不同體質以及健康需求，提供專屬的養身配方與中藥諮詢。','萬全街72號1樓','241',25.0700900,121.5013500,2,0.00,0,'ChIJTRAP3iSpQjQRk09CTkxA1YE','2026-05-30 23:19:53'),(57,'宋記食品','位於渡船頭路口。這裡的鹹鴨蛋是來自宜蘭鄉下的新鮮鴨蛋，以特選的紅土、米糠包裹約一個月後，再洗淨蒸熟而成，不僅鹹度適中，且蛋黃透出油亮光澤，常吸引許多饕客到此購買。油心蛋是八里的名產之一，其實就是指做得蛋黃又大又香的鴨蛋。這家宋記油心蛋原本是養鴨人家，家中女兒因為從小耳濡目染，對鴨蛋的好壞一眼就能辨出，再加上之後向前輩學習醃製鹹鴨蛋與皮蛋的技術，秉持著衛生、新鮮的原則，用自家健康養殖的鴨產出的鴨蛋，經過繁複的過程，做出光看就令人食指大動的鹹鴨蛋。皮蛋也是用鴨蛋做成，同樣的原則，讓他們做出來的皮蛋一樣香氣濃郁，而且選用的鴨蛋保證健康又新鮮。不少客人會特地買一大袋回家存放，方便入菜，直接吃也相當美味，蛋白軟滑且不死鹹，而黃澄澄的蛋黃，還閃閃發亮，吃下一口，濃厚香醇的口感，讓人印象難忘啊，當成伴手禮也很棒！','龍米路二段172號','249',25.1583100,121.4345600,1,0.00,0,'ChIJyzwfJmOlQjQR34EGcIspwaw','2026-05-30 23:19:54'),(58,'悅來亭餐廳','提供各式台菜料理、海鮮佳餚像是鮮嫩排骨酥、咖哩芋丸都是店家招牌，廣受好評，在三芝相當知名。','中山路一段56號~58號','252',25.2568100,121.5017800,NULL,0.00,0,'ChIJVcuVbtK2QjQRFFC1o1IkIb0','2026-05-30 23:19:56'),(59,'板橋石頭肉圓','以豬油浸炸的肉圓，皮Q餡香（餡料有醃漬肉塊、鴿子蛋、脆筍絲）；散發胡椒香氣、加了酸菜與韭菜的豬血腸湯，湯頭鮮美，豬腸軟而富嚼勁，豬血嫩而脆。','文化路二段410巷11號','220',25.0310200,121.4744400,1,0.00,0,'ChIJf4zTrUaoQjQRqd75FEsgHWo','2026-05-30 23:19:57'),(60,'船家海鮮世界餐廳','船家海鮮世界，證書編號：03-00155，聯絡電話：02-2492-5885','野柳村港東路153號','207',25.2049800,121.6893800,2,0.00,0,'ChIJ3aYexRRNXTQRYi9tJqeaka0','2026-05-30 23:19:58'),(61,'馥蘭朵烏來渡假酒店','由港籍西餐名廚Abu布秋榮，在五星級的烏來馥蘭朵渡假酒店主持的創意餐廳，巧妙結合世界各地一流食材，打造出五感滿足的法義風格創意饗宴！','新烏路五段176號','233',24.8694100,121.5476800,NULL,0.00,0,'ChIJY95n9o8GaDQRSItAncZDiS0','2026-05-30 23:19:59'),(62,'小義大利咖啡','在美食小吃攤林立的永和樂華夜市中段，遊客在不經意間，可能會眼睛一亮，目光掃到這間頗具人文風味的小小咖啡館，在人聲嘈雜的地段兀自屹立，用迷人的咖啡香帶給行家們驚喜。老闆從生豆、烘焙，到沖、煮，皆不假他人之手，讓每一種咖啡豆彰顯其獨特的性格；老闆拉花的技巧也是一絕，小歇一會，伴隨著浪漫的爵士樂，入口的咖啡不僅令人醇醉，更是不少人文雅士的精神食糧。','永平路145-1號','234',25.0084400,121.5112400,NULL,0.00,0,'ChIJMxDqH8OpQjQRHD_tuq4YPxg','2026-05-30 23:20:01'),(63,'三緣居蔬食餐坊','三緣居蔬食餐坊依照現代飲食文化著重健康取向的趨勢，精心嚐試研發許多不同的蔬食餐點，以期能滿足素食者的需求與葷食者所能接受的口味，讓人們了解素食並非只是吃齋唸佛的人所專屬，其實也可以比葷食來的美味營養。在食材的清洗上，使用金字塔能量水濾水器所流出的能量水洗滌，能夠將農藥徹底洗去，讓顧客能安心食用。','中正路501-2號','231',24.9837400,121.5335200,1,0.00,0,'ChIJPeh3rwMCaDQRV_LPPV7Q5Es','2026-05-30 23:20:02'),(64,'詹記麻辣火鍋','詹記麻辣火鍋創立於1994年，是二十幾年的名氣老店，甚至有「新莊之光」的稱號。以辣聞名，詹記的辣度分成為辣、小辣、中辣以及大辣四種供選擇，麻辣湯頭使用獨門配方，以特製的辛香料以及十幾種中藥材進行十個小時以上的慢火熬煮，味香口麻的風味無可匹敵，可說是極具代表性的台灣味，鍋底搭配豆腐及鴨血，麻辣鴨血可謂鎮店之寶，二十幾年以來人氣依舊，特殊的熬煮過程讓鴨血集結了所有辛香料的精華，同時保留滑嫩的口感。','新泰路187號','242',25.0377900,121.4472200,2,0.00,0,'ChIJN_ix3nWoQjQRrQWzhauGcUE','2026-05-30 23:20:03'),(65,'唐莊自助粥舖/艇王生猛海鮮','餐飲/外燴(阿美族)','八德街69號','238',24.9821900,121.4196200,NULL,0.00,0,'ChIJ087lIBkdaDQRJXX7VkRGG0s','2026-05-30 23:20:04'),(66,'源味本鋪現烤蛋糕店','源味本鋪現烤蛋糕店成立於西元2010年 從淡水老街的第一家傳統古早味蛋糕店，遵循古法製程融合現代人講求的養生概念,製作出令人好吃到難以忘懷又兼具養生的傳統手工古早味蛋糕 每逢假日 淡水老街最醒目的人氣美食排隊人潮就是本店的招牌 各國觀光客來到淡水必買來當伴手禮 CP值非常高。市面上最近出現大量古早味蛋糕店 讓消費者傻傻分不清楚哪家才是真正老店 請認明旗子標幟的 *源味本鋪*才是品質有保證的正宗創始店喔! 更多資訊可上官網查詢 http://www.originalcake.com.tw','中正路230-1號','251',25.1707900,121.4390300,1,0.00,0,'ChIJv7-NpFmlQjQRfdPTf81p-lY','2026-05-30 23:20:06'),(67,'Bern brunch 伯恩咖啡','一個簡單的信念不簡單的堅持從原物料到技術、具備傳統與創新，誠心對待每個環節，投注以深深的熱情與堅持，一份小心翼翼的信念，請您到Bern Brunch親身體驗！','佳園路一段26號','238',24.9712300,121.3927900,NULL,0.00,0,'ChIJx5HbANinQjQRgjWgdNLaafY','2026-05-30 23:20:07'),(68,'阿妃健康廚房(生食)','冷凍餃子已成為現代忙碌人的方便美食，2009年新北市餃子節拿下最佳人氣獎，以及最佳創意口味獎的冷凍水餃的阿妃健康廚房，早在參加比賽前，就已經是許多媒體關注的寵兒，阿妃強調水餃能兼具口感與高纖維，每顆水餃的餡料都經過了嚴格標準化的程序，包括在肉餡、調味料的比例、水餃皮的手感與功夫，層層步驟都關鍵影響著水餃的口感，重點是堅持不使用含防腐劑的食材，並使用豐富的蔬菜，讓水餃的營養價值更高，也因為這股熱情與堅持，成就了阿妃健康廚房在地經營或比賽中都能擁有亮眼的成績，讓阿妃的水餃成為每個人心中夢幻冷凍水餃。推薦菜色:鮮蝦軟絲芹菜水餃、一抹黛綠部落格：http://tw.myblog.yahoo.com/afei-afeibolg','中正路470號','234',25.0033100,121.5174800,NULL,0.00,0,'ChIJ-U8g_KqpQjQRsOlsnhPNp8A','2026-05-30 23:20:08'),(69,'Roliya(羅莉亞)','在新北市也能吃到五星級的義式、歐法料理！位於新店區的Roliya﹝羅莉亞﹞時尚美食特聘晶華飯店義大利廳的聞伯春師傅掌廚，設計多款精緻且美味的異國美食，早期在中和廟口一帶經營便奠定廣大好口碑，如今遷移到新店區，價位更平實、菜色更豐富，帶給附近一帶的居民耳目一新的感受。Roliya希望打破一般餐廳主題的侷限，希望呈現多變化、無國界的精緻料理；特別邀請了五星級飯店義大利廳的師傅駐店服務，就是希望讓顧客知道，想品嚐的異國料理美食，不用大老遠跑到臺北市，新北市也可以擁有這樣的五星級水準。','民權路42巷59弄12號','231',24.9835300,121.5378500,NULL,0.00,0,'ChIJd1zUqdkBaDQRkP1DioJts4A','2026-05-30 23:20:09'),(70,'銘鄉鐵板燒','位於新北市新莊中平路上的銘鄉鐵板燒，開業以來始終堅持使用高品質的食材，以及實在的調味與服務，奠定了新莊一帶的好口碑。銘鄉鐵板燒提供各式中式的料理，鐵板燒師傅個個炒功一流，在傳統中結合新穎的配方與炒法，讓鐵板燒料理的味道更加獨絕，希望給顧客有別於一般傳統鐵板燒的感受。店面裝潢給予顧客溫馨中帶點現代感的感受，並貼心為顧客設計單人或雙人套餐，讓您一次可以享有多重食材的口感，銘鄉鐵板燒以平實且美味的料理吸引顧客的味覺與視覺，帶您一同感受平價鐵板燒的好滋味！友善服務□.行動裝置充電 (提供電源插座、USB等供行動裝置、手提電腦等設備充電)。  □.友善廁所(提供借用廁所服務)。','中平路34號','242',25.0435200,121.4448900,2,0.00,0,'ChIJ861aA9inQjQR369cLrsozA8','2026-05-30 23:20:11'),(71,'山中傳奇','什麼是山中傳奇？山中傳奇以「美食、美景、咖啡」三大特色，位於深坑的大自然山林間，來到山中傳奇的朋友們，可以品嚐來自白宮御用、美國最老品牌的夏威夷獅王咖啡，在山林間品嚐咖啡香，感受愜意的午後；更可以呼朋引伴來到山中傳奇，品嚐由名廚親自配菜，無論是經典排餐、又或者是戶外的歡唱派對、聚餐BBQ、Buffet等，師傅的無國界菜單，讓您一次享用到各國美食的特色與美味，也讓來到山中傳奇變成一種視覺、味覺上的極致享受，與家人朋友相聚在山中傳奇，感受與溫馨、美食、咖啡歡聚的時刻，就是一種幸福。','風格街51號','222',25.0169800,121.6272500,NULL,0.00,0,'ChIJJwc2zM6qQjQRQRtv6tw_YQU','2026-05-30 23:20:12'),(72,'靴子義大利麵餐坊','總店位於新莊輔大的「靴子義大利餐館」，於熱鬧的板橋文化路段也開設分店，新莊總店成立以來，由於口味實在與平價美味，在輔仁學區一帶相當受到學生族群的喜愛與支持。由於義大利在地圖上的形狀近似「靴子」，於是以此命名，推出精緻、完美的義大利麵套餐、焗麵套餐、焗飯套餐、燉飯套餐，給顧客更全面的餐點享受。用心推出排餐、義大利麵，搭配豐富的前菜、沙拉、湯品與甜點飲品，不但講究製作的過程，謹慎選用食材，給顧客高品質的料理、平價的消費，目的在於希望讓人品嚐到物超所值的美食。','中正路593號','242',25.0319200,121.4329600,1,0.00,0,'ChIJT9gnvuinQjQRQEYgbE--X5c','2026-05-30 23:20:13'),(73,'唯力香食品有限公司','「唯力香食品有限公司」專門生產肉干、肉鬆等產品，經營者擁有近３０年經驗，堅持研發、製作到包裝的生產流程採統一管理，力求產品的品質優良。近年來，「唯力香食品有限公司」因應健康飲食的養生風潮，特別與專門生產素豆乾、素肉鬆的工廠合作，素食系列產品同時提供使用基因改造與非基因改造的產品，多元選擇將滿足更多族群的飲食喜好。「唯力香食品有限公司」商品除推出桶裝、袋裝之外，也特別推出美觀大方的禮盒包裝，適合公家機關、公司行號當作年節伴手禮餽贈員工、親友，另外，旅遊景點業者當做特色名產販售，也是不錯選擇喔！','嘉添里181-32號','237',24.9108200,121.3703200,NULL,0.00,0,'ChIJb4CdQM8baDQRXyVQ2POmv_Y','2026-05-30 23:20:15'),(74,'名根烤肉食材宅配外送','電話一通，烤肉輕鬆免煩惱-當要出外旅遊烤肉時，您不必為了採買、準備烤肉食材和用具而煩惱囉！只要一通電話就讓已有十多年經驗，全臺有多處據點的「名根烤肉」來替您一手包辦所有烤肉的相關事宜。名根烤肉套餐組合的價目表，以每人多少錢為單位，請自行乘以人數就是烤肉的預算了，既簡單又明瞭，您也不必為了該收多少活動經費而大傷腦筋。名根烤肉食材來源均符合CAS國家優良食品，並通過ISO9001與食品HACCP雙認證烤肉廠商，並為消費者投保二千萬產品責任險，品質有保障，讓您安心食用。','柴埕路60巷2號','231',24.9649300,121.5087000,NULL,0.00,0,'ChIJb_7iokgCaDQRa3DC8Prohgg','2026-05-30 23:20:16'),(75,'老店淡水魚丸','民國45年創立，店內販售精選素材製作的淡水知名特產，都是您不可錯過的淡水美味喔！香Ｑ鮮美的魚丸湯、配上店內特製的鮮味肉包，常常是許多遊客到淡水必吃的美味組合。還有店內的阿給以及餛飩湯也不要錯過喔。','中正路135-2號','251',25.1703200,121.4391400,1,0.00,0,'ChIJOUYwLlqlQjQRgcGwANfF9Qc','2026-05-30 23:20:17'),(76,'E61咖啡場所','E61咖啡位於永和區四號公園旁，老闆詹啟宏已經在這裡開店八逾年，這家咖啡店在永和區十分有名，賴雅妍也是這裡的常客，和老闆關係不錯，每天拍完戲後，一定會到這裡喝一杯，最多時喝3杯。「因為我本身就很愛喝咖啡，喝了這裡的咖啡之後，別地方的咖啡就不想喝了。」E61咖啡店面小，但客人多，有時要排隊要排很久，簡單的店面，裡頭賣著不簡單咖啡，因外觀不顯眼，有時路過一不留意就會錯身而過。E61咖啡沒有座位，客人拿了咖啡不是站在店裡喝，就是到外頭喝。一到晚上，路邊和公園裡滿是端著一杯咖啡品味的內行人，賴雅妍：「方圓100公尺就可以聞到咖啡香味。」她說，有一次很糗，喝完咖啡，車了一開就走了，開到一半想到好像有什麼事沒做，突然想起咖啡錢沒付，趕快打電話給老闆說對不起，忘了付錢。老闆也可愛回答，沒關係，常有客人忘了付，下次來再給就好了。','安樂路200號','234',25.0017100,121.5151500,1,0.00,0,'ChIJh5g4ROepQjQRjXc6X9oPaqA','2026-05-30 23:20:18'),(77,'阿媽的酸梅湯','雖然開店資格並不老，但所供應的酸梅湯有著古早樸實的酸甜滋味，懷舊的好味道，已成為觀光客旅遊淡水必嚐的小吃之一。老闆承繼母親煮酸梅湯的古法，以梅子加上洛神花、菊花、參鬚、百子、薄荷等中藥，一起熬煮成濃郁甘甜的酸梅湯，尤其炎炎夏日、口渴難耐，喝在嘴裡倍覺清涼爽快，比一般過甜的飲料或汽水還來得解暑，難怪一推出很快便成為遊客人手一杯的飲品。推薦產品:酸梅湯','中正路135-1號','251',25.1704100,121.4391400,NULL,0.00,0,'ChIJFdwtLlqlQjQRpcCJYzSofdc','2026-05-30 23:20:19'),(78,'正傳統小吃店','外觀古色古香的正傳統擔仔麵，標榜著「臺灣味、人情味、古早味」，不管是臺灣小吃、海鮮、山產野味、食療藥膳、擔仔麵，或是日式冷食，本店都可品嘗的到。源源不絕的顧客在店中漫談著，加上個性開朗的老闆和老闆娘熱情的招呼聲和笑容，輕易地就勾起臺灣人與人之間最珍貴的感覺呢！本店的擔仔麵是十分有特色！老闆用心地用魚骨、雞骨熬製高湯，加上柴魚片和蔬菜，絲毫不會有腥味，肉燥口味偏鹹，和臺南偏甜的口味不同。','建國路209號1樓','231',24.9803000,121.5376200,2,0.00,0,'ChIJOayzGvgBaDQR5r1WsaBnuK0','2026-05-30 23:20:21'),(79,'金山跳石沒有名字的咖啡店','位於金山跳石海岸旁的跳石Cafe，老闆是一位陶藝家綽號叫恐龍，當初因為來金山沙珠灣衝浪想要有一個休息的地方，並且也想有個陶藝工作室，所以就選擇了在這裡落腳，店中以他喜歡的沖浪和陶藝工作室為主題，牆上以衝浪板作裝飾最為醒目，還有古早捕魚用的浮球以及潛水夫帽，造型很像外星人。老闆很隨性喔！記得要來之前要先打個電話，因為老闆如果不在店裡就是跑去衝浪了！','永興里跳石4號','208',25.2572200,121.6332300,2,0.00,0,'ChIJ9Y1eOSxLXTQRHaau9FGW4Dw','2026-05-30 23:20:22'),(80,'觀音山土雞園','鮮蒸南瓜(220元)，特選臺灣老種、外型似木瓜的南瓜，瓜肉甜度高。蒸熟的南瓜放上與蜜汁拌過的絞肉，略帶鹹味的豬肉與南瓜的細膩甜味，彼此互相映襯；三杯杏鮑菇(400元)，健康養生的杏鮑菇，三杯做法讓它香氣四溢、更加下飯。以烏醋加上米酒、麻油、糖等烹調，有別於一般醬油膏的重鹹口味；手工饅頭(100元/8個)，純手工製作的黑糖饅頭不加化學原料，每天現做現蒸；剝皮辣椒雞湯，放山雞的香Ｑ肉質，湯頭入喉溫潤甘甜，是秋冬季店家的熱銷品(時報周刊 08年10月17日推薦)','凌雲路三段104號','248',25.1227700,121.4266000,2,0.00,0,'ChIJ6-EfzJSlQjQRbpKsVhgygA0','2026-05-30 23:20:23'),(81,'品鼎殿日式壽喜燒','無湯火鍋(壽喜燒)搭配美味且無限量供應的紐西蘭沙朗牛肉與梅花豬肉，配合蛋液一齊享用，豐富的各式火鍋配料與甜點則可提供味道上的變化與滿足，再配上去油解膩的麥茶，給人滿足的享受。推薦菜色:紐西蘭沙朗牛肉、梅花豬肉吃到飽','中山路一段24號2樓','220',25.0081900,121.4602500,2,0.00,0,'ChIJ01yafqcCaDQRHpasfxTd2XU','2026-05-30 23:20:24'),(82,'淡水紅樓咖啡館Red3Cafe','紅樓於西元1899年，歷經四年半的工期完工，隨著時代的變遷，歷經數任屋主， 80年代，曾面臨拆除蓋大樓的危機，在屋主阿媽排除眾議之下，才得以力保紅樓超過十年的荒廢閒置。 捷運通車後，淡水小鎮恢復活絡，屋主家族在許多朋友及文化工作者幫忙之下，於西元1999年開始修復，並於西元2000年元月開幕，當時的精神是『古蹟活化』。 推薦菜色:義大利麵,排餐,下午茶','三民街2巷6號3樓','251',25.1715800,121.4395300,2,0.00,0,'ChIJaQNWT1elQjQR-hqh7MHIZ2U','2026-05-30 23:20:26'),(83,'驊珍食品有限公司','現在的年代，追求養生休閒的人愈來愈多，店家也為了滿足消費者的需求，研發了\"\"養生桂圓糕\"\"。桂圓糕，咬一口，口感綿密，濃濃桂圓味充滿於你的口中，久久不散。','重新一段99號','241',25.0634500,121.5007500,2,0.00,0,'ChIJP_m5NR-pQjQRAAPcSjmhy4s','2026-05-30 23:20:27'),(84,'賴家上海鮮肉包','獨特的四季豆包，採用精心挑選的四季豆，配上獨家秘方吃上一口，回味無窮，肉包使用最上等的豬絞肉，加入提味的青蔥，同樣讓人愛不釋手。推薦菜色:四季豆包子','竹林路225巷48號','234',25.0086200,121.5226100,1,0.00,0,'ChIJlY48iu6pQjQR_BFlrOQwJDI','2026-05-30 23:20:28'),(85,'石門農會肉粽','石農肉粽是由石門區農會所輔導生產的肉粽專賣店，在肉粽的選料上，選用貼有CAS標誌的電宰豬肉、台東池上圓糯米，以及菇身厚、香氣足的台灣鈕釦菇。而在粽葉的處理上一點都不馬虎，打開水籠頭，在活水流動之下，一葉一葉仔細刷洗，另外，提味用的紅蔥頭，更是去頭掐尾撕去外膜，再一瓣一瓣清洗乾淨才下鍋爆香。就連包在粽葉裡的鹹蛋黃，都是下了功夫，先灑些米酒後，送進烤箱烤過後再入餡，就是為了讓蛋黃吃在嘴裡，更添一份香味。這幾年石農肉粽不斷研發新口味，加了干貝、鮑魚的滿意粽、更有時尚感的冰粽、結合養生想法的高纖素粽，以及紅麴養生粽；最新研發的「芋香櫻花蝦粽」給民眾更多的選擇。','中央路2號','253',25.2911200,121.5652700,NULL,0.00,0,'ChIJIeXKVbe1QjQRytvLjeIBCic','2026-05-30 23:20:29'),(86,'朱家卜肉店','走入金山老街內，在這條充斥新舊商店的老街上，除了琳瑯滿目的地瓜產品，順著老街，有一家門口掛著大紅燈籠的老店，這就是超過七十年的朱家老店，店門口的大爐灶，每天一開店就不停的炸出美味的卜肉，這可是歷經朱家三代，精心研發改良調製出來的好口味。而店門口的大紅燈籠，已經成為朱家的新地標，來到金山老街，只要看到大紅燈籠亮起，就代表熱騰騰的卜肉正式開賣囉。傳承總舖師的辦桌手藝在日據時代，朱家就已經在金山地區從事小吃業，據現任老闆朱慈洲的回憶，祖母的手藝在金山地區可是響叮噹，加上金山老街是附近地區的商業重地，舉凡週遭鄉里的熱鬧、婚喪喜慶都會在金山老街舉辦辦桌活動，而這辦桌一定會是由祖母負責烹調，這道聞名金山的卜肉更是辦桌必備的料理。','和平里金包里街49 號','208',25.2213200,121.6390200,2,0.00,0,'ChIJD5X071dLXTQRx1gdEkmLUnw','2026-05-30 23:20:31'),(87,'北門田不辣','已營業18年以上的北門田不辣，料多實在，米血、蘿蔔、甜不辣，滿滿的各式配料充滿整個碗中，淋上店家的特製醬汁，配合烹調已久的高湯，清爽美味就在其中。推薦菜色:甜不辣','北門街8號1樓','220',25.0105300,121.4577600,1,0.00,0,'ChIJtWpjNx2oQjQRYvoxu-unFuA','2026-05-30 23:20:32'),(88,'湘園雲泰緬小吃','湘園雲泰緬小吃的老闆娘，大家都尊稱陳媽媽，在華新街湘園以拿手的滇緬料理，讓許多美食行家、部落客撰文推薦，而且美食節目也常邀她上電視。陳媽媽最拿手的是汽鍋雞、月亮蝦餅、椒麻雞等知名的滇緬料理，菜單上數十種料理都能吃出道地的家鄉味。許多內行人都喜歡這種「媽媽的味道」，不僅用料實在、調醬非常有異國風味，而且價格實惠。因此湘園從原來的一家店面，後來又擴充為兩家店面，大家都是為了嚐嚐陳媽媽手藝而來。湘園的白飯用的是低脂肪的泰國白米，搭配酸、辣口感的滇緬菜十分的下飯。陳媽媽笑說，雖然這裡賣的是雲泰緬料理，但傳承了父親湖南菜好手藝，和媽媽的雲南菜技藝，加上老公又是廣東菜師傅，而自己專長是緬甸菜，來此吃頓飯，就好像辦了一桌聯合國佳餚。推薦菜色：木瓜雞','華新街83號','235',24.9834700,121.5085400,2,0.00,0,'ChIJj0sfKmwCaDQRZRHXPhZPIAM','2026-05-30 23:20:33'),(89,'晶豪樓經典婚宴會館','晶豪樓佔地一千多坪、坐擁五星級飯店裝潢場地，美食融合滬、粵、台、日四大菜系精華，主廚超水準手藝令老饕們讚不絕口。擁有各式大小宴會廳、包廂、會議室，宴會廳還有體貼的獨立新娘套房、新人禮車專用車位及賓客專用停車場。晶豪樓是結合休閒、運動、保齡球及餐飲的休閒大樓，也是雙和地區知名的結婚、文定、工商聚餐、會議好場所。','錦和路388號3樓','235',24.9906800,121.4905800,2,0.00,0,'ChIJ75Gu4ocCaDQRomiJiroziHM','2026-05-30 23:20:34'),(90,'阿春小吃店','位在烏來老街上的阿春小吃店，以提供多元化的特色美食深受國內外遊客的喜愛，店內可以吃到各式山菜野菜的美味，而招牌竹筒飯以及用紅糟山豬肉所特製的山豬肉粽，更是店內人氣居高不下的特產。打開包覆肉粽的竹葉除了可以聞到竹葉的清香外，濃郁的山豬肉更俱有獨特的咬勁和口味，呈現出食材的特色，是極具山野滋味的美食佳餚。店內的放山土雞，是老板自家飼養的玉米雞，口感紮實美味，配上滷桂竹筍和山珠蔥，最後再來一份馬告雞湯，不論是家庭出遊或是三五好友相聚，都能充份品嚐烏來的在地美食。推薦產品:山豬肉粽','烏來里烏來街109號','233',24.8635200,121.5514600,2,0.00,0,'ChIJcYyEEWQGaDQR6p3w3Aqd8DE','2026-05-30 23:20:36'),(91,'孟鴻養生坊','那念念不忘的好味道，只有嚐過招牌仙草雞的客人才知道，熬到軟爛的烏骨雞入口即化，喝一口仙草雞湯，濃郁中帶著自然散發出來的仙草香，清爽不油膩，這裡的白斬雞皮帶些油脂，咬起來有種脆感，而炒山菜及炸溪蝦都能讓你一嚐原始的山中美味，樸實的老闆親切的招待每一位遠道而來的客人，讓位在新店烏來小徑深巷裡的好店，連大老闆們都遠道而來，這邊平常白天吃飯的客人滿多，如果是晚上來看星賞月，搭配美食別有一番風味。推薦菜色:仙草雞湯、老菜脯雞湯、炸地瓜、炒過貓、白斬雞、鮮脆泡菜','廣興里平廣路一段202巷5弄2號','231',24.8908900,121.5146000,2,0.00,0,'ChIJ8WuTmloEaDQR3oMh002ckgg','2026-05-30 23:20:37'),(92,'三重香Q饅頭','好吃划算的手工饅頭，撕開內部一層一層，頗為紮實，燕麥、芋頭、五穀雜糧等口味，都吃得到果實；高山素包的滋味佳，筍包也有很多人愛。','大同北路89號','241',25.0637400,121.4946900,1,0.00,0,'ChIJY1R2gGapQjQRlsKB22cFQeA','2026-05-30 23:20:38'),(93,'晴光肉羹','晴光肉羹在林口老街可是響叮噹的老店，最受大家懷念的美饌，當然就是那肉羹大塊份量足的羹湯，再搭配一碗滷肉飯，總能吃出濃濃的古早情懷。晴光的肉羹，赤肉塊裹粉後下鍋先煮熟，等客人點用時再入鍋加羹湯，肉塊軟嫩又多汁有嚼勁，湯頭鮮美和一點地瓜粉勾芡，味道鮮美極了。除了滷肉飯、肉羹，大部份的來客都還會點上一份油豆腐，因放在滷湯中滷製入味，淡淡的鹹甜味更好吃。不大的店面一到用餐時刻，還得耐心等一下，除了赤肉羹，晴光的生魷魚羹也是很多饕客們心中的最愛。','中正路155號','244',25.0772100,121.3927100,1,0.00,0,'ChIJHxg4dfqmQjQRQ3_0Q-0lUgI','2026-05-30 23:20:39'),(94,'麗華餅店','傳統的中式餅店，除了接受預訂製作的訂婚禮餅外，店內的麵包及蛋糕也是非常的可口，而受到很多人喜愛的三明治，除了有招牌還有起士香鬆口味，吐司去邊再簡單的夾入蛋及火腿片，加上香醇的美乃滋，讓人懷念起傳統的媽媽味道，簡單的幸福從咬下綿密的三明治那一刻就開始，希望你能一同品嚐。','鎮前街77-2號','238',24.9906200,121.4251500,1,0.00,0,'ChIJ4e-Uej4daDQRHRC4Ie-76QI','2026-05-30 23:20:40'),(95,'添丁切仔麵','老闆廖添丁經營的添丁切仔麵，位於蘆洲廟口商圈，已有三十年以上的歷史，在此地是非常有名的店家，有一個很高很大的紅色招牌，大老遠就可以看到它。他們的麵條不會軟爛，清爽的湯頭也很鮮甜。小菜首推五花肉，是店內招牌菜。推薦菜色:切仔麵、五花肉、肝連、魷魚','得勝街22號','247',25.0839100,121.4738900,1,0.00,0,'ChIJLxORYcmoQjQRcg2KFcfHcKI','2026-05-30 23:20:42'),(96,'花神咖啡館','簡老闆為一圓創業夢想，和主廚好友一起在淡水河畔開了這家花神咖啡館，不同於附近的餐廳以西式料理為主，花神咖啡反而以中式創意料理，搭配濃郁的咖啡，在美食行家間贏得好評。美食的頂尖技術，難在於將平凡的菜色做得出神入化！花神的菜色就深具變化性，以合菜的用餐方式，幾個好朋友或家人同行一人點一道菜，就能分享到更多廚師創意料理手藝。簡老闆說，花神的海鮮食材都來自基隆坎仔頂等魚貨批發市場當天採購，就是要給消費者最新鮮的海港直送鮮味。其中，最受饕客歡迎推薦的太湖蟹府，用新鮮蟹肉、花枝、蚵仔、豆腐料理成羹湯，鮮美的好滋味真是一吃難忘。此外，簡老闆推薦的照燒牛肉、乾煸四季豆也是店內的名菜，還有店內的招牌「玫瑰鱸魚」，網路上深獲好評。簡老闆以鱸魚肉嫩無刺少腥味的特性，和玫瑰花瓣結合入菜，淡雅的玫瑰清香和鱸魚肉質的鮮甜調和成一種腴美極味，擺盤的視覺美感也為美食加分。','觀海大道59號','249',25.1616400,121.4279700,2,0.00,0,'ChIJCywH0mulQjQR-ceo_Jv3Cec','2026-05-30 23:20:43'),(97,'金都餐廳','在這間提供家常菜的金都餐廳，每到用餐時間店內人聲鼎沸，三五好友家庭聚會，這裡有各式合菜套餐，或是品嘗多樣招牌菜梅干扣肉、紹興醉雞等，梅干菜以及豬肉都是入口即化，帶點淡淡酒香的紹興醉雞，還有調配枸杞一同醃製，來到這就像是團圓過節，滿桌都是媽媽煮的家常菜，是讓許多遊客都懷念的好味道。','後厝村41-3號','252',25.2533800,121.4725600,2,0.00,0,'ChIJEfJeHkixQjQR66w8_MHt3Fw','2026-05-30 23:20:44'),(98,'王氏豆腐','石碇老街上的王氏豆腐，是商圈裡人氣最夯的美食名店，已經傳承5代經營上百年的豆腐店，純手工無添加任何防腐化學物，也是最單純的豆腐作法，不僅深受消費者喜愛，還有豆腐餐廳業者每天開車來批貨，店內最有名的除了豆腐，還有豆花和豆漿最受客人喜愛。','石碇東街85號','223',24.9910300,121.6602000,NULL,0.00,0,'ChIJ1epnURBVXTQRMEdVewrL4tw','2026-05-30 23:20:45'),(99,'吉市牛排','逛著三重三和夜市，遠遠的你就聞的到牛排的香味，越往飄來的香味接近，你就會發現排隊的人潮，大家都是衝著這邊物超所值的美味各式排餐而來，不同於其他傳統夜市牛排店，老闆的堅持選用大塊且厚實的肉排，絕對讓你吃的滿足吃的滿意，除了牛排、雞腿排、豬排外，魚排也是非常受到饕客的歡迎。','中央北路72號','241',25.0663100,121.5002400,1,0.00,0,'ChIJdY-sDiOpQjQRhnG3dLEjlx8','2026-05-30 23:20:46'),(100,'商義尤記鐵路月台便當','福隆的鐵路月台便當，早期其實只有一種口味，就是里肌肉加三層肉，再搭配8樣小菜，就是北迴鐵路上最令人難忘的滋味。不過因尤記的地理位置較偏僻，不在火車站前的動線上，加上臺2線旁便當店林立，這家老店現在只做假日生意，但是一週兩天還是人潮滿滿，便當依然是古早美味，老饕們一口接一口，有的還連吃三、四個。','福隆街2巷19號','228',25.0154600,121.9452400,1,0.00,0,'ChIJjx_VmFRcXTQRnoVzyGMRpnE','2026-05-30 23:20:48'),(101,'白河阿婆碗粿、米苔目【仁愛店】','從前在台南縣白河鎮，有一個85歲的阿婆，阿婆推著車子在市場賣米苔目、碗粿已經50多年了。沒有華麗的包裝，也沒有電視的報導，‧但只要吃上一口，就會被她的味道深深吸引住，彷彿回到古早年代，孩提嘻笑怒罵時的懷舊記憶一一浮現腦海。阿婆十分講求食物的品質，絕不偷工減料或添加任何化學物品，「遵循古法、堅持手工」是阿婆的理念，在阿婆身上，讓人看到了老一輩台灣人對吃的尊嚴與執著。雖然隨著年齡漸長，阿婆不得不放棄這項傳統的手藝，幸好，阿婆將這傳統又美味的做法傳授下來，讓實在的好味道繼續流傳。','仁愛街316號','241',25.0798700,121.4918800,1,0.00,0,'ChIJgZmm5SmpQjQR515T0UiocH4','2026-05-30 23:20:49'),(102,'貝里義大利薄餅披薩','貝里義大利薄餅披薩原本是位於三峽溪東路上的一家溫馨PIZZA店，後來搬到三峽北大特區，結果老客人也跟著過去，許多遊客暢遊三峽後，也喜歡選這裡做為旅遊最後的美食Ending，還有臺北大學的學生和附近工廠上班族也經常叫外送，讓這家以真材實料、道地口味的義式美食小店，成為北大特區的美食指標名店。貝里義大利薄餅披薩原本是位於三峽溪東路上的一家溫馨PIZZA店，後來搬到三峽北大特區，結果老客人也跟著過去，許多遊客暢遊三峽後，也喜歡選這裡做為旅遊最後的美食Ending，還有臺北大學的學生和附近工廠上班族也經常叫外送，讓這家以真材實料、道地口味的義式美食小店，成為北大特區的美食指標名店。貝里的老闆王德瑞原本就是美食家，陸陸續續學習比薩的作法，最後還曾跟隨一位義大利朋友學做道地的義式比薩，在大家的一致肯定下，在三峽開了「貝里義大利薄餅披薩，結果廣受好評，連樹林、中永和、臺北市和桃園的客...','佳園路三段612號','238',24.9437500,121.3796700,2,0.00,0,'ChIJh2a_pWQbaDQRwkZc_KieXds','2026-05-30 23:20:50'),(103,'原味麻油雞','如果要來個三重小吃點名，位於中央北路中段裡的原味麻油雞是一定不會被漏掉的前幾名。原味麻油雞的料理都是每天下午當場準備，新鮮度不在話下，價格更是比一般麻油雞來得實惠，因此牢牢綁住大票忠實饕客的胃。原味麻油雞的湯頭是比較清淡宜人的風味，酒味和麻油味都不會過重，吃完之後不會有很上火的感覺，真的是溫潤滋補的好味道！','中央北路56之3號','241',25.0653800,121.5004800,NULL,0.00,0,'ChIJMZ1gGtupQjQRO6d4DF2p684','2026-05-30 23:20:52'),(104,'山頂店鹽酥豬腳','取自石碇黑毛豬前蹄，肉質細膩有彈性富膠質，先滷過再蒸，保持肉質鮮嫩香甜的原汁，接著再油炸，表皮酥脆不油膩。','番子坑25號','223',25.0024600,121.6755000,2,0.00,0,'ChIJddt13BBVXTQRA7Iew1E_7O0','2026-05-30 23:20:52'),(105,'嘉邑海鮮小館','位於貢寮區澳底海鮮街地標「仁和宮」對面的嘉邑海鮮小館，雖然店面不大，裡面的美味卻令人驚艷，其中東北角盛產的九孔，在嘉邑老師傅的手藝烹調下，沾上一點特調的蒜蓉醬，就將九孔的終極理想之味，變得爐火純青，想品嚐這鮮Q的海之味，來這裡就對了。','仁和路2號','228',25.0485700,121.9234900,2,0.00,0,'ChIJkwzkEr9cXTQR8dUA6m2KveI','2026-05-30 23:20:54'),(106,'唯豐魯肉飯','在三重區名氣十分響亮的唯豐魯肉飯，不僅是當地三重區親們簡單解決一餐的熱門美食，還有許多運將朋友一到用餐時間，把車子往這兒開，找個位置、用幾個銅板，就開始享受起這人間難得的好滋味。唯豐魯肉飯是當地超過卅幾年歷史的老攤子，一鍋滷汁香濃黏郁的滷肉，淋在Q軟的白飯上頭，再加上一些酸菜，整碗飯甜鹹怡人、肥而不膩，還有一種難以言喻的滑順香氣，禁不住一碗接一碗，飽嚐這聞名世界的庶民極味。','三民街131號','241',25.0639700,121.4849500,1,0.00,0,'ChIJN01cL-eoQjQRgPL1fUpPoss','2026-05-30 23:20:55'),(107,'陽明山天籟溫泉會館','來陽明山天籟溫泉會館除了泡湯享受之外，這裡的美食也不容錯過哦！「義式PIZZA屋」裡有專研義式料理多年的主廚，由主廚們親手料理義式鄉村風味美食，Pizza屋採現作吃到飽(平日無隨點)、假日則有百匯自助餐，從冷盤、熱前菜、義式麵點、pizza、甜點、冷熱飲...等無限供應，使用進口專業Mozzarella、Padano Cheese與金山鴨肉、養生菇類等當地食材，美味跨越國界也結合家鄉味，新鮮現作，讓老饕們享受大啖美食、風呂之外，還能坐擁山泉環抱群山之美。另外，「總裁級牛肉麵」香Q帶勁麵條、軟嫩適中的肉塊與濃郁的湯頭大受歡迎，更榮獲台北國際牛肉麵節主辦單位邀請，2011首度參賽便拿到「無限創意組-佳作」佳績，泡好湯、吃好麵一定要來嚐嚐！','重合里名流路1-7號','208',25.2019100,121.5950900,NULL,0.00,0,'ChIJAQAAAAD_ZzQR1yoaRyW1f3w','2026-05-30 23:20:56'),(108,'兩支北方麵食館  (土城店)','兩支北方麵食館成立於土城海山捷運商圈，經營團隊的組合來自於一群志工同好，誠懇、樸實、熱心、充滿人情味是我們創立經營服務理念。     兩支對北方麵食有種堅持道地美味的執著，從醒麵、桿皮、包餡到成品，每一個環節都是對客戶的尊重與責任，期待您的肯定與支持~    專營北方麵食點心:牛肉麵、酸辣麵、豬肉炸醬麵、榨菜肉絲麵、各式炒麵、豬肉捲餅、牛肉捲餅、餡餅、抓餅、宜蘭蔥餅、蔥油餅、韭菜盒、招牌湯包、蟹黃湯包、各式蒸餃、小米粥、各式炒飯、燴飯、酸菜白肉火鍋、泡菜小火鍋、各式風味熱炒。','裕民路129號','236',24.9866000,121.4514300,2,0.00,0,'ChIJD9MigMkCaDQRfu7rVCukr84','2026-05-30 23:20:57'),(109,'深坑廟口王水成老店','本店創立於民國四十五年，早年因為經國先生來深坑必吃王水成料理的豆腐，並經由媒體爭相報導而聞名，後來因為老街改建關係搬離了原址，目前已由第二代經營，並將王水成辦桌手藝改良成精緻小吃吃法，進而更衍生可以做為火鍋湯底新吃法，目前新址裝潢明亮乾淨且帶有人文與創新，許多外國觀光客也都循網路介紹來訪，歡迎大家有空來深坑遊玩時順便品嚐正宗老店料理。','北深路二段204號','222',25.0015200,121.6151700,2,0.00,0,'ChIJ9yPdVsSqQjQR3MTL3_CepYs','2026-05-30 23:20:59'),(110,'香帥蛋糕','伴手禮老店「香帥蛋糕」取名靈感來自港劇「楚留香」，店中的人氣商品「芋泥蛋糕卷」，必嚐的美食，食材採用大甲溪畔的芋頭，口感紮實綿密，軟綿的蛋糕夾著飽滿的芋泥餡，飄著淡淡的香氣，讓人一口接著一口。店內還有其它種類的蛋糕美食，都是值得帶回去給家人朋友一起品嚐的必買伴手禮。','汐萬路一段238號１樓','221',25.0731400,121.6517000,2,0.00,0,'ChIJpeM3jBVTXTQRRZLmSyLmMMU','2026-05-30 23:21:00'),(111,'聚味軒 China Spice','時尚簡約的中國風華色調，讓您彷彿身臨上海十里洋場氛圍，設計理念取自「西方人眼中的東方風華」，「聚味軒」以新鮮食材手工精巧,經燒、蒸、煨、煮、燜、扣、燴多樣烹調手法，細膩呈現上海菜形色意境之美、文化內涵之博。雋逸雅緻的用餐氛圍，無論小吃、大宴，都讓您愜意品嚐當紅江南美饌。','文化三路一段一號二樓','244',25.0660900,121.3608800,NULL,0.00,0,'ChIJFf3au9ynQjQRXe7OXOXkcWk','2026-05-30 23:21:01'),(113,'布蕾派對','網路上的法式烘培熱門商品-布蕾派對play party，以無店鋪訂購宅配的方式經營，開幕四個月即受到廣大迴響，清爽無負擔的法式點心，悄悄的擄獲了消費者的心。布蕾派對堅持純手工製作，不含酥油、不添加防腐劑。像是招牌法式布蕾派即採用純鮮奶熬煮，只加牛奶、雞蛋不加水的原味布蕾派，有紐西蘭鮮奶的香醇。而底層的美式派皮不含酥油，口感清爽不油膩。另一項熱賣商品派卡客，有別於一般的中乳酪蛋糕，夾心有多種口味可作選擇，受到許多客人的青睞！布蕾派採用低溫宅配、每日現做，給你最新鮮味美的可口甜點。。','新北大道七段15巷1號','243',25.0319500,121.4205200,NULL,0.00,0,'ChIJ6cfOO9qnQjQRHVxkWDc-DLw','2026-05-30 23:21:03'),(114,'海豚Cafe','位在三芝佛朗明哥天橋旁的「海豚Café」不但提供寬敞的觀景空間和精緻美食，更是貼心自製專屬的單車架讓騎單車的朋友可以放心地停放自己的愛車；騎重車的朋友也可直接將車停在前庭，不必擔心日曬雨淋。店內空間均可感受海豚悠游海中的自在悠閒，而挑高寬敞的沙發空間更是讓遊客能夠輕鬆享受渡假的氣氛，店內也規劃有飛鏢機且不定時舉辦比賽，增加不少用餐外的趣味。','北勢子42-11號二樓','252',25.2519600,121.4716700,2,0.00,0,'ChIJicOdAeWwQjQRef0UFSdaol8','2026-05-30 23:21:03'),(115,'榕堤水灣餐廳','「榕堤水灣於2007年由水灣集團接手經營，結合了大淡水地區的美景，遠眺觀音山，近攬淡水夕照，特殊的紅磚、茅草、木瓦，將榕堤水灣幻化成更具國際視野的villa風情。 店名的由來係因店址位於河堤及老榕旁，所以便取名為「榕堤」，內有一座日據時代警察局哨所，是以前日本水上警察所駐守的崗哨所，用來監視淡水河上船隻來往情況，現在則規劃為室內用餐的一部份，裡面有一個黑色暖爐器，在寒冷的冬天會啟動使用，造形相當復古！在悠閒的午後，來一杯沁心的飲料，感受店家貼心的服務，而入夜後涼風搖曳的氛圍，更能享受異國風情的浪漫，體會優雅閒適的步調。」','中正路229-9號','251',25.1718100,121.4366400,2,0.00,0,'ChIJz4Wk9FqlQjQRtw_-JYBpxZU','2026-05-30 23:21:05'),(116,'青青餐廳','曾被非凡大探索報過。青青餐廳為提供消費者舒適與便利的空間，是聚餐筵席的最佳選擇。在菜色的挑選上更是以最新鮮的上等食材　，菜色變化多樣，可依顧客需求變化烹調，讓您輕鬆享用老饕級的美食饗宴。特色料理：千絲蝦餅、蕃茄排骨湯、蜜汁香魚等。推薦菜色:翡翠白玉絲、千絲蝦餅、蒜蓉小卷、佛跳牆、蕃茄排骨鍋','中央路三段6號','236',24.9698100,121.4390800,2,0.00,0,'ChIJZS5EENYcaDQRkiFCpA-kvng','2026-05-30 23:21:06'),(117,'王師父餅舖','王師父餅舖招牌商品－金月娘，細緻的橙黃色外皮，搭配甜而不膩的蛋黃與綠豆沙內餡，入口的瞬間美味即化於口中，僅留下令人回味無窮的韻味與奶香。金月娘主要成分是豆沙、蛋，入口即化，溢滿馨香滋味，生命中最滿足的時刻，源於品嘗美食的剎那。生活中最幸福的滋味，全都藏在私房極品－金月娘。推薦產品:金月娘、軟玉酥、玉黃酥、南棗火山果','中山路一段283號','234',25.0069600,121.5069700,3,0.00,0,'ChIJwbtuP9upQjQRxj7g4xRg_EY','2026-05-30 23:21:07'),(118,'來得福川菜客家菜餐廳','來得福始於1982年，曾被非凡大探索(2007/01/20糖醋黃魚、五更腸旺、宮堡蝦仁、客家小炒及天麻養生雞)、壹蘋果美食王(2007/4/27推薦客家風味-薑絲大腸／2007/6/29推薦季節瓜料理-苦瓜鹹蛋)、TVBS周刊~食尚玩家(2007/08/02鍋粑蝦仁)、東森綜合臺~食全食美(2007/11/07無錫子排)、東森財經生活臺~嚐鮮Let\'s go(2008/02/23大蒜魚頭、水煮牛肉、醉雞、京都排骨及乾燒蝦仁)等媒體所報導過','中正路294號','220',25.0204400,121.4550400,2,0.00,0,'ChIJ1SfuiA-oQjQRXMtjmDhkzkc','2026-05-30 23:21:08'),(119,'八德素食園','板橋的在地老餐廳，在素食還沒開始普及的六十年代開始經營，從一般的素食自助餐，到素食吃到飽、素食便當、點菜合菜、聚餐圍爐、素食喜宴、素食手工點心等等，多樣的素食料理令人目不暇給，難以相信素可以有那麼多變化。除了推薦給喜愛素食的朋友外，也歡迎不常吃素的人來體驗一下，原來素食可以吃得健康又兼具美味與絶佳口感。','實踐路32巷2號','220',25.0071500,121.4630800,2,0.00,0,'ChIJL8FRrqACaDQRsGN6qufcQZg','2026-05-30 23:21:10'),(120,'高雄黑輪','高雄黑輪是一台擺滿了數十種美味的攤車，高麗菜捲、黑輪、甜不辣與各式各樣的蔬菜在高湯中浮沈，挑動著每位顧客的食慾。以柴魚片與大量的白蘿蔔精心熬煮的高湯喝起來特別鮮甜，黑輪使用的沾醬則是由老闆的父親親手調製，數十年如一日的美味，難怪緊緊抓住顧客的胃。推薦菜色:黃金魚蛋、牛蒡甜不辣、菜卷','中興街16號','234',25.0117400,121.5159700,NULL,0.00,0,'ChIJqXhcI-qpQjQRYLbVAhAI_J0','2026-05-30 23:21:11'),(121,'韓國街肉圓王','小小的攤子，專賣當天現做現賣的新鮮肉圓，清蒸的作法讓肉圓吃來爽口不膩，百吃不厭。','中興街119號','234',25.0118800,121.5175200,1,0.00,0,'ChIJndw8vuupQjQR-W55Ph7iH-I','2026-05-30 23:21:12'),(122,'佶軒料理店','專賣港式美食的「佶軒料理店」，每到用餐時刻總是座無虛席，乾淨舒適的環境讓人用餐時更加的安心，透明櫥窗裡，各種烤得油亮誘人的燒臘讓人垂涎三尺。第一次造訪建議點人氣王「五福飯」，一次可以吃到五種主菜，划算又滿足。','漢生東路305號','220',25.0082400,121.4717400,1,0.00,0,'ChIJvejB_SCoQjQR2mJg94txqdU','2026-05-30 23:21:13'),(123,'天山鄉土雞城','觀音山盛產的綠竹筍，香甜可口，無論是做沙拉涼拌或是切成筍條清炒，都能品嘗到綠竹筍最新鮮的滋味，來到這再點一鍋以土雞還有綠竹筍一起熬製烹煮的筍仔雞湯，除了滿足口腹之欲，也能飽覽滿山翠綠的風景，吃飽了還可以到附近的凌雲禪寺走走，釋放生活中的壓力。','凌雲路三段79號','248',25.1261000,121.4234900,2,0.00,0,'ChIJcbxneJWlQjQRIq99LSW_lAQ','2026-05-30 23:21:15'),(124,'五股鹹粥小吃','一般人想到鹹粥，通常是宵夜點心為主，再搭配其他小菜來品嘗，但是，位於新北市五股區成泰路上的五股鹹粥店，只提供早上及中午用餐時段，鹹粥料多味美且物超所值，吃的到肉塊還有香菇以及多種的蔬菜，受到當地居民喜愛的酥炸蚵仔還有豆腐，搭配小黃瓜吃起來新鮮爽口。','成泰路三段433號','248',25.0977500,121.4498700,1,0.00,0,'ChIJp2JtvBumQjQRhfszzsi6Wm0','2026-05-30 23:21:16'),(125,'五燈獎豬腳飯','五燈獎豬腳飯主角是豬腳飯和滷肉飯，比較特別的是，豬腳飯是豬腳歸豬腳，白飯歸白飯，豬腳不會黏了一堆飯粒，滷肉飯則是用滷汁淋上，油亮的豬皮與嫩又爛的肉燥，蓋在飯上形狀完整，但又入口即化，口感超誘人，豬腳可挑前段、中段、後段或是腿庫肉，隨心所欲，淋上滷汁，香氣逼人。','自強路一段119號','241',25.0665300,121.4954600,2,0.00,0,'ChIJ2TFgoCGpQjQRJ0sJLt0tkEI','2026-05-30 23:21:17'),(126,'古早味油飯','在市場口賣了逾20年的古早味油飯，其實賣的不只有油飯，攤子上的大腸麵線有時還比油飯更早銷售一空，老客人都說，不論是油飯還是麵線，加一碗豬血湯，一百元有找的平價，吃得又飽又開心。顧攤的徐老闆已是第二代，他說油飯傳承自媽媽的手藝，不但客人會到攤子上來吃，有些林口的鄉親彌月油飯，或者是拜觀音寺的觀音菩薩，還會特地來訂作，通通都能滿足不同的需求。油飯好吃的訣竅在於使用來自中部的高級長糯米，先洗、泡讓米粒吸飽水分後，蒸煮起來更加軟Q，然後再拌炒調味料、香菇、肉絲和蝦米，一碗令人懷念的古早油飯就開始在市場內飄香了起來。此外，大腸麵線則是用大骨湯頭做基底，加上紅麵線熬煮，氣味芬芳和腸娛胃，而且大腸是經老闆娘特別滷製的，軟爛至鮮真令味蕾全活跳起來。','林口路17號','244',25.0786900,121.3907300,NULL,0.00,0,'ChIJeYJTwjKnQjQRTvPHQ7Cos20','2026-05-30 23:21:18'),(127,'俊客思','本店於2004年5月9日創立於新北市永和區永和國中校門旁,目前在中永和地區有四家分店,提供學生族群喜愛的手搖飲料及酷奇雞脆皮雞排,平實的價格及親切的服務是其經營宗旨。','民生路45號','234',24.9979300,121.5227800,NULL,0.00,0,'ChIJhS2TdeOpQjQRVZw5jT6L6Ug','2026-05-30 23:21:19'),(128,'梅春公路飯店','梅春公路飯店','水柳腳路191號,北宜路八段22號','232',24.9361200,121.7031600,1,0.00,0,'ChIJQYNtxkf_ZzQRulX9gbnBcDo','2026-05-30 23:21:21'),(129,'菁桐老街紅寶礦工食堂','「紅寶礦工食堂」位於新北市平溪區菁桐老街上，前身為石底礦坑的礦工福利社。「紅寶礦工食堂」主人為重現民國初年的礦採風貌，食堂特別掛上早期礦工採礦實况的超大紀錄照片、菸酒公賣招牌及老電影海報，營造濃濃的復古風情，此外，也推出礦工套餐、鐵路便當、麵茶等古早味經典美食，勾起許多人的回憶！由於，「紅寶礦工食堂」緊鄰菁桐車站，在食堂內用餐，只要往外望，還可看見民國初年沿用至今的老鐵道，若心血來潮，您也可以踏上鐵道，拾階通往石底煤礦遺跡尋古懷舊一番。戀戀菁桐鐵道‧石底礦村‧平溪山城，就從「紅寶礦工食堂」開始。','菁桐老街58號','226',25.0235200,121.7229200,NULL,0.00,0,'ChIJBy_iAKlWXTQR-rf73BZCWqI','2026-05-30 23:21:22'),(130,'海堤竹筍餐廳','新北市八里區以淡水河沿岸明媚風光聞名！當你騎乘單車暢遊八里左岸時，別忘了一併享受由海堤竹筍餐廳（原左岸竹筍餐廳）提供的八里特色風味餐。海堤竹筍餐廳位於左岸會館旁，經營者林大哥為土生土長的八里孩子，林大哥堅持新鮮就是美味的料理精神來推廣家鄉美食，與八里區農會合作，以當地農特產－黃金綠竹筍為主題推出四季不斷貨的鮮滋味，此外，來自臺北港的活魚、活蝦、魩仔魚、孔雀蛤等海鮮也都是桌上佳餚，值得一提的是，料好味美的餐點，價格卻很平易近人，無論親子家庭、旅行團體都能吃得盡興！','觀海大道28號','249',25.1598800,121.4298800,2,0.00,0,'ChIJM9DrtWulQjQRjrJKxqjb5g4','2026-05-30 23:21:23'),(131,'康喜軒牛角麵包總公司','三峽好伴手‧康喜軒金牛角-臺灣素有美食王國之稱，全臺各鄉鎮市都有地方指名的伴手好禮！說起新北市三峽區，金牛角可說是當地美食代表，想要品嚐外酥內Ｑ的金牛角又想了解三峽金牛角文化的民眾，康喜軒金牛角是你不可錯過的寶地！金牛角冰淇淋‧臺灣之光-康喜軒金牛角是三峽在地的麵包烘焙老店，人稱貓王的創始者為了傳承且創新家鄉的金牛角文化，積極投入研發金牛角風味的無限可能，其中金牛角冰淇淋是全臺首創的驕傲產品！ 近年來，康喜軒金牛角將觸角延伸至海外，要讓全球品嚐臺灣之光！','鶯桃路53號','239',24.9520900,121.3414800,NULL,0.00,0,'ChIJbz11H-4baDQRtF3ij3IMx2I','2026-05-30 23:21:24'),(132,'帕爾堤麵包蛋糕','位於蘆洲的帕爾堤烘焙坊，就如同同音「party」字面上的涵義，帕爾堤希望讓顧客都能像置身在派對中一樣輕鬆、無壓力，擁有一個愉快的購物環境。經營者本身從事烘焙工作，熱愛製作麵包及蛋糕，擁有自家烘焙工廠，強調產品品質及用料實在，希望將「麵包、蛋糕」這些平凡卻又不可或缺的食物更融入日常生活，讓顧客吃到「幸福」的味道。結合各式現泡、現煮的飲品，並設有座位，顛覆一般麵包坊的傳統印象，帶給消費者耳目一新、多元化的感受，也相當受到蘆洲這個新興社區許多家庭、親子的喜愛與支持。','長榮路211巷5號','247',25.0847700,121.4604200,2,0.00,0,'ChIJ0drSWLeoQjQRBZbdIGUuvl0','2026-05-30 23:21:26'),(133,'八里亭麵館','八里亭麵館顛覆一般傳統中式麵館的口味，結合異國主餐風味，並搭配得獎的牛肉麵，讓中永和附近居民與上班族感受與眾不同的餐飲享受，用餐時段總是絡繹不絕的人潮，受歡迎程度由此可見。八里亭老闆之一吳先生是柬埔寨華僑，曾經營泰國料理餐廳，親自烹調研發的料理道地且美味，結合中式簡餐的優點，將異國風味主餐結合在中式簡餐中，味道不但特別價位更實在，「用便宜的價錢吃到大菜！」多人同行便能一次享受到各種異國風味主餐的好味道，適合闔家用餐或團體聚餐。推薦菜色:清燉牛肉麵、椒麻雞飯、極品海鮮麵','中山路一段293號1樓','234',25.0068400,121.5068100,1,0.00,0,'ChIJdy7KP9upQjQRJsHGm0KhmY8','2026-05-30 23:21:27'),(134,'黃金海岸活蝦之家','在永和福和路上、靠近竹林路口的路旁，有一間小小店面「黃金海岸」，是申請黃金海岸為商標的第一家。黃金海岸在永和經營了十逾年，店內的海鮮料理相當受到雙和地區民眾的喜愛。當初張老闆在高雄吃到這些海鮮料理，覺得很美味，於是回到臺北後自己摸索烹調的過程、邊作邊試吃，慢慢研發出屬於自己的口味，開了這間黃金海岸。海鮮食材跟南部屏東產地的廠商固定配合，活蝦都採現撈現煮，相當新鮮。還沒嚐過「黃金海岸」海鮮的朋友，老字號的「黃金海岸」，就在永和福和路上，邀請喜愛海鮮的老饕一同來賞味。','福和路182號','234',25.0079400,121.5204900,2,0.00,0,'ChIJX3_B0O6pQjQRC-z74MjsxfI','2026-05-30 23:21:28'),(135,'建香四姐妹(建香海鮮料理店)','建香（四姊妹）海產店，位在野柳風景區內的，在當地已經成立了二十年的時間，能在競爭激烈的風景區裡長期佔有一席之地，所憑藉的，就是新鮮的食材、可口的料理、親切的服務，以及物超所值的消費。餐廳目前已接手給第二代經營，由四位姊妹負責，正式定名為「建香四姊妹海產店」。女性所烹調出來的料理，口感一點都不輸給其他廚師，還更加細緻、用心。新鮮、平價，以及親切的服務態度，是在風景區內站穩腳步的不二法門，建香四姊妹海產店的好口碑，邀請您一同分享。','野柳里港東路160號','207',25.2048500,121.6899000,2,0.00,0,'ChIJo1G0v3ZMXTQRBCCPuo53Sf8','2026-05-30 23:21:29'),(136,'萬吉豆腐老店','位於深坑老街「集順廟」對面的「萬吉豆腐美食」是由在老街土生土長的深坑老在地所經營。出身深坑，也在當地老街經營餐飲業，當然三句話不離豆腐！深坑人將單純的豆腐加入創意、製成各類美食的功夫早已名聞遐邇！「萬吉」的客源可分為平日與假日兩種，平日以北二高與信義支線、來自新店、士林、臺北東區的老主顧為主，假日自然是以觀光客為主要客源。「萬吉」店中由三位自開幕便共事的老師傅一同主管廚房，強調服務是經營之本！在商譽之外，能多注重衛生與食材及服務品質的自我要求！','深坑街122號','222',25.0013700,121.6134800,NULL,0.00,0,'ChIJAQAAAMWqQjQRBlkkXdf6C74','2026-05-30 23:21:31'),(137,'阿城鵝肉','位於清水路上的傳統鵝肉店「阿城鵝肉」，自民國79年成立至今，於土城一帶已有20多年的好口碑，創始者蔡芳成先生與妻子，當年在因緣際會之下，開創了第一間店面。倆夫妻白手起家創業，兩人秉持著「一定要成功」的信念，好口碑也打下了往後20年的成功基礎。二代經營者蔡宗佑先生傳承了父親對於阿城的熱情與使命，身為六年級生的他以設計系的專業與天份，將店內的空間菜單做了一番用心的設計，有別於大型餐廳的規模，阿城希望可以成為土城人心中的「家庭餐廳」，也讓外地的遊客經過土城時，可以「玩在土城、吃在阿城」。推薦菜色:鵝肉、麻辣鵝血、蝶花脆飩','清水路78號','236',24.9817300,121.4567000,2,0.00,0,'ChIJESlZWc8CaDQRQSC76inZox0','2026-05-30 23:21:32'),(138,'八八八海鮮','位在三芝市區的「八八八臺式海鮮」主廚陳羿箖先生用自己的創意研發出一道龍蝦三明治，不但兼具色香味，連外觀也是讓用餐的朋友大感驚喜。人稱阿國師的陳羿箖先生從18歲開始就學習中菜，到目前為止已有近30逾年的料理經驗。阿國師的另一個強項是泰式料理，搭配新鮮海味和創意更是呈現不同的風味。','中興街2段30號之1','252',25.2558000,121.4990300,2,0.00,0,'ChIJxfsJGtO2QjQR2sZ1kDG9QHo','2026-05-30 23:21:33'),(139,'女皇餐廳(女皇海鮮餐廳)','來到北海岸嚐海鮮，萬里區的野柳、龜吼是饕客們最愛嚐美味的熱門地點，位於野柳的女皇海鮮餐廳，已是第三代經營，也是當地著名的海鮮餐館。以野柳漁港的新鮮海獲為食材，配合大廚的特殊料理創意，不論是店內的招牌菜清蒸三點蟹，還是外面較少吃到的軟絲生魚片，或者清淡的炒海菜、炒鯊魚，都有店家很用心的滋味。特別是炒海菜的食材，是野柳本港沿海潛水摘採的，超新鮮、絕對美味，也只有萬里海岸一帶才有，且因季節不同品種也有所不同，是到北海岸泡湯、吃美味不可錯過的鮮滋味。北海岸的野生三點蟹秋季正肥美，肉質鮮甜且價格平實，和野生軟絲生吃法齊名，用探照燈半夜捕撈的軟絲，是野柳海鮮美味一絕。','野柳里港東路163號','207',25.2048800,121.6899100,2,0.00,0,'ChIJg72Dl3ZMXTQRga88ZtnzK-E','2026-05-30 23:21:34'),(140,'舜德農莊休閒餐廳','位於深坑外環道下、文山路一段的舜德農莊，是一間擁有傳統美味料理、山產的山莊餐廳。擁有上千隻自家養殖的放山雞，以天然穀物、玉米餵食，讓山雞肉質堅實富彈性、甘甜可口，是深坑難得一見的自家放山雞料理。舜德擁有寬敞的戶外座位，燈光極富設計感、給人眼睛一亮的舒適感受，一年四季還可以聞到自然的花鄉由四處飄來；室內座位更有包廂，讓顧客歡唱KTV，無論筵席或一般家庭聚餐桌菜皆適合。一到假日便人潮絡繹不絕，供應的料理有深坑傳統的豆腐料理、山產、時蔬、合菜等，歡迎您蒞臨品嚐。','文山路一段62巷35號','222',25.0007200,121.6219300,2,0.00,0,'ChIJX9tfgitVXTQRGqRf4ZF2-no','2026-05-30 23:21:35'),(141,'鹿鶴園蔬食養生館','隱身在南天母風景區的山林間、專門供人賞景、喝茶、嚐茶點的茶館「鹿鶴園」，結合了土城的自然山色景觀，並專門提供健康素食簡餐、品茗、茶點，是一間風格相當素雅的品茗茶館。「鹿」象徵福祿壽的「祿」；「鶴」則象徵了和平的「和」字，「鹿鶴」兩字，也同臺語發音的「越來越好」之意，連命名都相當用心。「我們發願希望所有的人一進門，心靈就可以馬上沉澱下來。」園主強調店內主張寧靜的感覺，由於依山傍水，不但讓人暫時忘掉山下的煩惱，當起了霧、飄點小雨的時分，景色更呈現霧濛濛的浪漫詩意，令人陶醉其中。','承天路92-5號','236',24.9544900,121.4459600,2,0.00,0,'ChIJV9TUSzMDaDQRk0RsXyilhLc','2026-05-30 23:21:37'),(142,'劉安平古早味什錦麵','劉安平古早味，雖然在中和安平路上沒有顯著的招牌或看板，但令人無法轉移目光的是絡繹不絕的用餐人潮，無論是內用或外帶，不難見到顧客將店門口塞到滿滿的景象。這是因為劉安平古早味每份料理皆堅持現點現做，就連麵品也不例外，所以想吃的顧客就必須耐心等候。什錦麵也許大家都不陌生，但什麼樣的什錦麵好味道，竟可以流傳40年以上歷久不衰？這碗什錦麵的湯頭大有來頭，店家精心熬煮的大骨柴魚高湯，再添加自家秘方調味，呈現獨到的鮮美，與海鮮食材相得益彰，麵條吸附高湯後，每一口都嚐到鮮甜，是在小吃中難得一見的好味道。推薦菜色:什錦麵、大滷麵、各式炒飯','安平路128號','235',24.9977600,121.5120200,NULL,0.00,0,'ChIJ7Toto9-pQjQRR2DK7pzw-Yc','2026-05-30 23:21:38'),(143,'義麵寶寶義大利麵','義麵寶寶主廚劉師傅，早期從外場員工學習到內場廚房，歷經多年習得一手好廚藝，並學習如何開店、創業，將一間店從無到有打拼起來，由於還是喜愛餐飲，劉師傅決定在中和自家附近開一間義大利麵館，結合地區性的平價消費，並將自己所長運用發揮，加上喜獲麟兒，將店名取為義麵寶寶。劉師傅表示，每份義大利麵都使用自行熬煮的蛤蠣高湯來拌炒，並堅持用料要實在、並且使用大量的蔬菜，認為堅持品質，客人覺得好吃才會再回流。店裡採半開放式的廚房，顧客可以看到師傅現作每一份餐點，非使用調理包，現炒的風味更佳、更值得品嚐比較。推薦菜色:青醬義大利麵、奶油義大利麵、辣味海鮮義大利麵','圓通路198巷2號1樓','235',24.9944600,121.4960700,1,0.00,0,'ChIJPUyXEHwCaDQR2iNpTXcmXwU','2026-05-30 23:21:39'),(144,'好茶饌(原順益茶館)','坪林文山包種茶享譽全臺，其係清光緒年間由福建泉州引進之品種，烘焙後之茶葉呈條索狀，沖泡後之茶湯金黃，茶香幽雅，落喉甘潤。「順益茶館」本身便是經營茶園的店家，老闆將茶葉和餐飲結合推出茶餐饗宴，其招牌菜色包括老茶山豬肉、茶油松板肉、茶油土雞、茶油麵線、茶葉香腸等，最大特色便是料理內蘊茶香，滋味清爽不膩，風味獨絕，教人一試成主顧。','北宜路八段216號','232',24.9345500,121.7067800,2,0.00,0,'ChIJ13GXjU7_ZzQRTpcN5MHQsL0','2026-05-30 23:21:41'),(145,'深坑麗芬肉粽','說到麗芬肉粽就不得不提到這家店的歷史，原本是由廖麗芬阿嬤所創立的肉粽店，從一開始並沒有店面招牌，傳承手藝到第三代的廖麗芬接手後，才以自己的名字登記註冊商標，並將店家改為肉粽專賣店，肉粽內餡是由胛心滷肉，以及炸得香酥的芋頭，再加上整朵香菇，風味絕佳，如果事先預定，還可以依照客人的需求，加入蛋黃、干貝及栗子等配料，口感扎實，深獲客人青睞。另外，店家還有提供養生的紫米肉粽及紅麴肉粽，夏天消暑的紅豆鹼粽及原味鹼粽。','深坑街80號','222',25.0015200,121.6142700,NULL,0.00,0,'ChIJOcuzHQCrQjQR52PJx-ZmEg4','2026-05-30 23:21:42'),(146,'嘉義閣小吃店','開啟深坑老街美食濫觴的王嘉義、王水成兩兄弟，早年在廟口開麵攤，後來弟弟的深坑廟口豆腐王水成老店遠近馳名，而手藝超群的哥哥王嘉義「嘉義閣」也不遑多讓，在老街也以豆腐美食打響名號，由於深坑豆腐燒煮方式不去黃豆豆頭，熬煮時沉底後略帶焦味，料理成紅燒豆腐、豆腐羹有一種特別的香味，軟嫩滑順的味道，也很令美食行家推薦。','深坑街58號','222',25.0017800,121.6147100,NULL,0.00,0,'ChIJcaakBcWqQjQR1qM6vxu8WX4','2026-05-30 23:21:43'),(147,'不一樣燒臘店','座落於淡水老街街口的「梁記燒臘店」，是真正具有香港血統的廣式燒臘名店，每逢用餐時間，店裡總擠滿人潮，不僅淡水人愛吃，不少外地來的內行饕客也經常來此大快朵頤。廣式燒臘的特色，在於肉香濃重、皮薄色鮮，油潤脂滑的口感，讓饕家們總是讚不絕口，店裡的招牌料理很多，部分如鼓油皇炒麵、燒鵝腿、干炒牛河等等，火候獨到，是一般燒臘店少見的特別菜色。推薦菜色:臘味飯','北新路182巷27號','251',25.1774900,121.4487500,NULL,0.00,0,'ChIJWZT60rWvQjQRcYRUMt28H5M','2026-05-30 23:21:44'),(148,'烏來小吃店','位於烏來老街上，主要提供原石燒烤的山豬肉及泰雅風味料理，這裡有道女士們趨之若鶩的名菜，那就是對女性朋友很有幫助的「青木瓜大奶煲」，這道菜取用山上尚未成熟變黃的青木瓜，由於此時青木瓜富含木瓜酵素，以其和中藥的紅棗、枸杞、小排骨、白木耳等一起熬燉，據中醫師表示，女性吃青木瓜可以形補形，對發育頗有幫助，懷孕婦女吃也會增進乳汁分泌，山村小店居然有這種滋補名菜，果真是不同凡響。','烏來街91號','233',24.8639300,121.5515800,NULL,0.00,0,'ChIJTRYCJIkGaDQRJxEnd3DSIDc','2026-05-30 23:21:46'),(149,'合歡茶宴風味餐廳','合歡茶宴風味餐廳位於坪林街上，所推出的茶餐風味獨絕，為當地最老牌的茶宴餐廳之一，合歡餐廳的經營者在北勢溪上游漁光、虎寮潭一帶亦經營合歡營地，溪谷腹地寬廣，向來是坪林露營勝地，當地並有多處營區，提供完備的野營場地、設施。','水德里水聳淒坑28號','232',24.9339800,121.7116200,2,0.00,0,'ChIJR7gplU7_ZzQR_UgNxZ2-Nd4','2026-05-30 23:21:47'),(150,'阿婆壽司','來到鶯歌遊玩的民眾，除了陶瓷博物館、陶瓷老街、鶯歌石登山步道外，最重要的美食據點，應該就非「阿婆壽司」莫屬。阿婆壽司早期是由李陳英老太太在鶯歌的中正一路旁賣壽司，由於口味獨特又好吃，深獲大家的喜愛，於是「路邊賣壽司的阿婆」名聲不脛而走，最後開店面就將店名註冊為「阿婆壽司」。透天厝的用餐環境，讓吃份壽司都感覺很享受，店內共有多達十幾種口味的壽司供消費者點用，壽司十分平價，真是大碗又滿意。第二代老闆娘陳愛娜說，阿婆壽司的原則就是讓客人吃到便宜又好吃的壽司，這也是阿婆當年做壽司的堅持。','中正一路63號','239',24.9543100,121.3522200,1,0.00,0,'ChIJ6QF1wQQfaDQRkCYkQ6p07fY','2026-05-30 23:21:48'),(151,'雪豹冰城','金山廟口綜合冰城就是金包里老街上的雪豹綿綿冰，為當地老字號冰品店，自第一代在金山賣冰及甘蔗汁算起，至今已超過30年。秉持真材實料、現做現賣的原則，這裡的冰品在金山眾多小吃中異軍突起、一枝獨秀，採用低糖、低脂的上等原料，口感不甜膩有健康概念，都是廟口綜合冰城多年盛名不墜的原因。其產品包括各式口味綿綿冰、雪花冰等，尤其以金山57號蕃薯所製的甘藷冰淇淋，綿密細緻，最是別出新裁。','金包里街94號','208',25.2218200,121.6385200,1,0.00,0,'ChIJne5v6VdLXTQRe7HSHDOLJUg','2026-05-30 23:21:49'),(152,'泰雅媳婦麻糬','為烏來老街上製作小米麻糬的專家，口味眾多，有紅豆、芋頭、山藥、綠茶、地瓜、花生、芝麻等多元口味，小米麻糬的特色為小小圓圓，剛好一口大小，香Q有彈性，非常可愛又好吃。除了麻糬，店家亦賣有其它在地特產，其中胖胖的黃金地瓜乾，微甜不膩，非常爽口，遊客還能品嚐添加黑糖熬煮的地瓜乾，濃濃的黑糖香非常吸引人。','烏來里烏來街18號','233',24.8640000,121.5514600,NULL,0.00,0,'ChIJewXXJokGaDQR7gAPJyzWCic','2026-05-30 23:21:51'),(153,'三角湧金牛角','近來當紅的牛角麵包，起源就是三峽的這家三角湧金牛角。純手製作，外皮酥香，內餡紮實柔軟，一口咬下滿嘴奶香，其油亮金黃的色澤，更引人垂涎。','大同路79號','237',24.9271900,121.3752200,1,0.00,0,'ChIJo3rTY-sbaDQRzj_4b99IDaQ','2026-05-30 23:21:52'),(154,'兄弟食堂','兄弟食堂位在金山媽姐廟隔壁分局正對面，因為地處山村與海港交界地，因此這裡的料理不論海鮮臺菜或山產畜產都很有名； 提起「兄弟食堂」，不僅金山在地人如雷貫耳，就連外國來的觀光客都知道要來這裡嚐嚐道地的美味。「兄弟食堂」經營十多年，由於口碑甚佳，除了目前位在媽祖 廟旁的本館，還增建了一處可容納180桌酒席的新餐廳，不過僅供團客使用，一些散客則可到廟旁的本館用餐。','大同里金包里街2號','208',25.2205700,121.6406000,2,0.00,0,'ChIJ5aCV71dLXTQRBf5FyHySdmI','2026-05-30 23:21:53'),(155,'VILLA SUGAR','有著南洋島國風情的VILLA SUGAR簡單的色彩，純潔無瑕的白融入自然的木頭原色，對照於海天一色的沙灘，正是使人百去不厭的主因。店內推薦的招牌海鮮酸辣義大利麵，炒乾的麵條吸附檸檬汁的酸度與辣椒粉的微辣，風味絕佳。','土地公坑54-16號','252',25.2497100,121.4660300,2,0.00,0,'ChIJH1IzrrmwQjQRHPE6wJ41c54','2026-05-30 23:21:54'),(156,'巴莎諾瓦','在室內可以感受地中海式的放鬆，在露天區則享受海風的親吻。巴莎諾瓦融合了義式、美式以及南洋風味，天氣熱時不妨來個海尼根冰沙，沁涼冰透的消暑口感。','後厝里土地公坑54-6號','252',25.2500000,121.4669100,2,0.00,0,'ChIJuUDLPbiwQjQRBftt_9xQ7s0','2026-05-30 23:21:56'),(157,'家一牛肉麵','半肚半肉麵，混合牛肚的半肚半肉麵，脆口的牛肚與鮮嫩的牛肉，口味超搭配','新北大道1段21號','241',25.0713400,121.4937300,1,0.00,0,'ChIJTcBOgVKpQjQRlGP4yJgqHXk','2026-05-30 23:21:57'),(158,'李園清真小吃','華新街上的印度烤餅，就屬這間李園人氣最旺。 店內瀰漫撲鼻的奶油香，只見老闆熟練的將餅皮一塊塊的甩上烤爐，烤得微膨的餅皮，豪邁的塗上奶油，就成了店內的人氣招牌，奶油印度烤餅。豌豆口味的印度烤餅，酥薄的印度餅搭配熬成泥狀的豌豆醬，是嘗試異國風味的入門菜。（時報周刊曾經推薦報導。）','華新街9號','235',24.9853400,121.5076900,1,0.00,0,'ChIJNQOObm4CaDQRFB4tFpUYqCc','2026-05-30 23:21:58'),(159,'走味的咖啡','溫暖氣息在一進門就立刻瀰漫在週遭的簡單咖啡廳，這裡不只販售好咖啡，還多了一股人情味，從臺北返鄉經營的女主人，室內設計由兒子操刀，結合在地天燈元素和造型牆面，讓投印在空間處的天燈倒影宛若在店內升空，十分有創意。','十分里十分街110號','226',25.0430400,121.7769800,NULL,0.00,0,'ChIJqZtXmuhQXTQR_-ZD3suMyfc','2026-05-30 23:21:59'),(160,'皇宮茶坊','皇宮茶坊有濃濃的日式建築風格，是平溪一棟日據黑瓦建築。在此用餐、品茗、喝咖啡，是您遠離塵囂、享受寧靜、洗滌心靈的最佳好去處。*請先去電預約','白石里白石腳5號','226',25.0216100,121.7218100,2,0.00,0,'ChIJd1hLCx1UXTQR4MEfh6mOJBE','2026-05-30 23:22:00'),(161,'麒麟閣沙茶火鍋','濃郁的魚鮮湯頭，搭配鮮美的牛肉涮煮，濃厚的沙茶香與火鍋堪稱美味的絕搭。人氣名點炸雞翅與炸旗魚更是來店必點的招牌。金黃酥脆的外皮包住鮮嫩美味的肉質，搭配美味的湯頭、極品的美味沙茶醬與口感細膩的牛肉，絕妙滋味令人難忘。推薦菜色:炸旗魚、炸翅膀','永和路二段57號2樓','234',25.0110900,121.5146000,2,0.00,0,'ChIJV_xv_OmpQjQR8FFY6X66-j8','2026-05-30 23:22:02'),(162,'哥弟筒仔米糕','筒仔米糕，古法手工製作，將飯及油蔥放進木桶攪拌，搭配芹菜、肉鬆，獨門甜辣醬，不吃不可','保安路29號1樓','234',25.0162400,121.5098700,1,0.00,0,'ChIJF00KwsCpQjQR-c_5bU-vm7c','2026-05-30 23:22:03'),(163,'留香園江浙菜','牛筋牛肉煲，牛筋入口即化，咬下鬆軟的牛肉，香味自口中化開，餘味猶存。推薦菜色:蘿蔔牛筋牛肉煲、香蔥烤子排','永生路283號','234',25.0051100,121.5113500,2,0.00,0,'ChIJkcRHY8WpQjQRSGb-IXg79BE','2026-05-30 23:22:04'),(164,'三分俗氣','能讓香港的美食專家蔡瀾來臺必嚐美味的「三分俗氣」，是隱身在國光路永和區公所後方的人氣江浙小餐館，簡單裝潢的用餐環境，每一道料理卻都不簡單，不僅蔡瀾，國內不少美食家也被曹老闆精緻的江浙料理手藝所吸引，讓店裡的人氣菜色，成為美食書和節目介紹的指標。曹老闆以私房料理起家，江浙美味精緻料理令老饕們難以忘情，來吃過的，紛紛成為這兒的老主顧。老闆在牆面掛上蘇軾的《 寒 食 帖 》，風雅氛圍卻取名「三分俗氣」，十分有趣。店裡深獲行家們推薦的，都是老闆的功夫菜，最具人氣的砂鍋獅子頭是來店必點的人間美味，軟綿卻不鬆散的豬肉餡，肉剁得十分細緻整齊，光這道菜就不難發現曹老闆的刀工了得，也是母親節招待媽媽的水準佳作。','國光路49巷8號','234',25.0079400,121.5189900,3,0.00,0,'ChIJh8qL3-ipQjQRuBb6pSx2gZI','2026-05-30 23:22:05'),(165,'林員大粒肉圓','已交由第二代接棒的林員大粒肉圓，是到板橋媽祖廟「慈惠宮」拜拜的香客，和懂門路的老饕們不會錯過的美食名店。不大的店面經常座無虛席，客人都為了那特別大顆又好吃的肉圓而來。林員是第一代老闆娘的名字，為了體貼客人一粒就能吃到飽，將肉圓做得特別大顆，內餡則選用了溫體豬肉後腿肉，醃製後和鳥蛋、香菇、筍絲包入肉圓漿皮裡。畫龍點睛的肉圓外皮，則是用在來米漿和蕃薯粉糰揉後捏製塑型而成。每天上午先將肉圓進蒸籠蒸熟，待客人點用時在下鍋油泡，淋上提升口感的蒜味醬汁更是美味。除了肉圓，這兒還有一味傳統虱目魚丸湯，南部口味的湯頭和魚丸，和肉圓搭配得剛剛好。林員的大粒肉圓使用在來米和蕃薯粉調製而成，先蒸煮、後油炸，餡料多口感扎實，許多臺北市饕客還專程搭捷運來吃。','府中路104號','220',25.0096100,121.4558900,1,0.00,0,'ChIJIQ8hoQKoQjQRUmS6_NMVoeI','2026-05-30 23:22:07'),(166,'大山無價','有多久沒有坐下來好好吃ㄧ頓飯？已經忘了食物的原始味道是什麼嗎？沒有多餘的人工添加物調味，老闆及師傅的用心堅持，保留每樣食材的新鮮及口感，讓蒞臨過的客人都覺得跟這家店的店名一樣－無價，採預約制的點餐方式，並以日式極簡風格搭配落地窗，讓人能完全放鬆，優雅的享受精緻的美食，從餐具還有擺盤以及預熱盤的服務，讓人倍感窩心。推薦菜色:蔬浮糕渣、香菇炒飯、蓮花雞湯、套餐菜色14道','北宜路三段62號','231',24.9512000,121.5748600,3,0.00,0,'ChIJBcjcubEBaDQR0MLW55MxJ8c','2026-05-30 23:22:08'),(167,'可口豬腳大王','已在新店大坪林美食界屹立逾20多年的可口豬腳，萬老闆以其滷製豬腳的獨門秘技，緊緊抓住老饕們的味蕾，光看著門口那幾個老滷鍋，每鍋豬腳分批設定火候，排放整齊的悅目色澤，還有誘人的香氣，加上嚴格品管讓美味達到相同水準的口感，令人難以抗拒這美食的吸引力。招牌豬腳的滷功是萬老闆幾十年的老練經驗結晶，每天市場嚴選溫體豬腳的中段和腳蹄兩部位，料理前先汆燙去腥，然後撈起冰鎮，讓肉質緊實。接著，前一天備料時再煮熟、除毛、加蔥蒜等配料大火滷製七、八個小時後，再轉小火燜透。萬老闆說，等端到店裡要上菜前，還要在鍋內再開大火滷製、再燜，如此反覆多次後，豬腳才能達到入口即化、軟嫩又香濃、肥而不膩的境界。來這兒用餐的客人，除了美味豬腳，主食滷肉飯往往不小心就讓人多吃了幾碗。','北新路三段129號','231',24.9826200,121.5412400,1,0.00,0,'ChIJY6B9AfYBaDQRDjTWbRQ7aAU','2026-05-30 23:22:09'),(168,'光明街油飯','吃過各式肉粽、米糕、油飯的朋友，一定要來嚐嚐古早味的光明街油飯，這裡的油飯是道地的北部口味－香菇油飯，你可以看到這裡的油飯色、香、味俱全，米飯油亮，搭配另人垂延三呎的肉燥醬汁，聞起來就會讓人回想起阿嬤做的油飯，吃起來真的很香很Q，再搭配附上的黃蘿蔔，清爽解膩，這裡還有提供帶點沙茶口味的五香肉羹，你一定不能錯過。','光明街125號','231',24.9617900,121.5392700,1,0.00,0,'ChIJ2ehWCYgBaDQRSeP-Yq5SsAc','2026-05-30 23:22:10'),(169,'光頭佬','知名美食節目也抵擋不了的台灣道地小吃，臭豆腐酥脆的外皮，一口咬下卻仍是滿滿湯汁，蚵仔麵線採用手工麵線，入口即化，依口味再加上蒜頭末與辣椒，讓人讚不絕口。推薦菜色:蚵仔麵線/臭豆腐','中和街210號','242',25.0506900,121.4479700,1,0.00,0,'ChIJ9RQ2BH-oQjQRmD05k6GBMOA','2026-05-30 23:22:11'),(170,'大使館','店內滿滿飄散異國的風味及舒適的氣息，供應多元的菜色、家常的口味，尤其店家研發的新式餐食，，另外寬敞的用餐空間，也適合親子同遊，因此也更深受消費者的肯定。推薦菜色:鹽烤鱒魚定食、照燒雞腿定食','民安路188巷4號','242',25.0235100,121.4251200,2,0.00,0,'ChIJly29DfOnQjQRLPcpN8gf96A','2026-05-30 23:22:13'),(171,'瑞三福利餐廳','採煤時代的礦工餐廳「瑞三福利餐廳」，老闆做的海鮮便宜又好吃，龍蝦、螃蟹、蟹肉獅子頭，唯一非海鮮類的是「芝麻雞」，放山雞用胡椒、鹽醃漬後蒸熟，裹上滿滿的白芝麻和少許麵粉後整隻雞油炸，酥脆的皮咀嚼起來滿口芝麻香，配上鮮嫩多汁的雞肉更是夠味。推薦菜色：芝麻雞、佛跳牆營業時間：11:30 ~ 14:00 16:30 ~ 19:00 (欲於晚上用餐者，請事先電話預約)','侯硐路45號','224',25.0888700,121.8298800,2,0.00,0,'ChIJbaQM5rRaXTQRMrqmRVpht-0','2026-05-30 23:22:14'),(172,'水心月茶坊(原名天空之城)','天空之城以日式洋樓的復古風情，矗立於輕便路上，棲身於山崖邊，是一座清水紅磚建的紅樓，磚石還有著斑駁的痕跡，清水紅磚與洗石子所營造的30年代懷舊感，與外牆上鑲嵌著的陶製星象圖像，更是讓人有股想一頭栽入舊時回憶與想像的衝動。有機會到九份一遊的您，請盡情的享受這一切吧！天空之城的再出發，就是為了與您分享這美好的人生。','九份輕便路308號','224',25.1088200,121.8428600,3,0.00,0,'ChIJYeX3NT5FXTQRfkwkvclR2m0','2026-05-30 23:22:15'),(173,'淡水滬尾豆花店','位於淡水英專路巷內的淡水滬尾豆花，豆花美味不僅淡水人都知道，連香港遊客都拿著旅遊指南慕名而來。滬尾豆花能夠在淡水有著不可動搖的地位，主要是豆花的製成從研磨黃豆到凝固成形，都是由老闆親自手工完成，並經過衛生署抽驗合格不含防腐劑，老闆就是要讓客人吃得健康與安心。豆花的4種特製口味更是別出心裁，原味豆花綿密口感，入口細膩而柔順；布丁豆花滑嫩的滋味與淡淡的清香極為誘人；可可豆花帶著濃郁的巧克力香氣但不甜膩；杏仁豆花濃濃的杏仁味使人食指大動。而配料花生則是採用宜蘭沙地栽種本土花生，綠豆則選用品質好的毛綠豆慢火燉煮，粉圓的Q彈與大紅豆的綿密口感更是老一輩的特愛，除豆花外，夏日期間消暑解渴的綠豆湯更是頻頻賣到缺貨。顧客從學生、遊客、甚至國外遊客都特地來此品嚐美味的豆花。','英專路21巷9號','251',25.1696800,121.4452000,1,0.00,0,'ChIJMUpFc1ilQjQRZ3tWBr0OXJs','2026-05-30 23:22:16'),(174,'獅子林當歸鴨','金山獅子林當歸鴨位於金山市區中心(全家便利商店正對面)，店家老闆親切熱情，外地的觀光客來這裡用餐就對了!每每假日總是客滿，由此可證明老闆的手藝是受到大家喜愛的，當歸鴨料多實在，歡迎大家前來品嚐唷~!','民生路222號','208',25.2213700,121.6380200,1,0.00,0,'ChIJzURrXFZLXTQRUNfEwjfRYCo','2026-05-30 23:22:17'),(175,'三重橋小館','主要以自家飼養的放山雞、活魚為主要烹飪招牌菜，古色古香的設計空間，彷彿讓人置身龍門客棧，加上老闆親切熱情的招待，帶給您一個絕佳的用餐體驗。','三重橋5鄰1號','208',25.1968100,121.5949800,2,0.00,0,'ChIJ-wIfaKuzQjQRJsa4r_o8xcA','2026-05-30 23:22:19'),(176,'小天使麵飯館','小天使麵飯館，主要以各式小菜、海鮮粥、麵、飯為主要經營項目。','中山路172號','208',25.2212200,121.6382900,1,0.00,0,'ChIJIQS14FdLXTQR3vBY31hL4dk','2026-05-30 23:22:20'),(177,'淡水領事館咖啡店','領事館餐廳座落在紅毛城對面，喜愛旅遊的老闆娘總會利用出遊之際，蒐集各國五花八門的紀念品、民俗工藝飾品，帶回店內放置，將用餐休憩空間點綴的琳瑯滿目、趣味橫生，2樓區域用來裝飾桌子的各式義大利麵，就是與家人周遊列國的戰利品。館內設有露天咖啡座，可感受小鎮海岸的懷舊風情，遠眺觀音山，並沈醉於淡水落日的美景，在清風吹拂的夏天下午，一邊品茗香醇的咖啡，一邊享用店家自製甜點，很有閒情的雅致。如果你到過淡水，那你對紅毛城一定不陌生，英國曾經在清末時期於此地設置領事館，這也是領事館餐廳名字的由來。坐落在紅毛城對面，緊鄰著淡水出海口，在這裡喝咖啡，除了可以看到淡水歷史的滄桑與繁華外，還可以遠眺出海口那連接一片汪洋的地平線，門里門外，就這麼幾步距離，彷彿就可以瞬間脫離城市喧囂，享受一下午的悠閒。特別推薦這裡的領事館咖啡、維也納咖啡及巴黎香榭紅茶。推薦餐點：冰拿鐵、水果茶','中正路257號','251',25.1743300,121.4332700,2,0.00,0,'ChIJX9ECY1qlQjQRcF96HDC6iW8','2026-05-30 23:22:21'),(178,'陳記米苔目','距離三峽老街不遠的陳記米苔目，入口彈Q的米苔目有湯、乾兩種口味，曾被非凡大探索列為美味米苔目店家之一。帶湯的米苔目以油蔥、蔥段、蝦米、胡椒粉為作料，湯頭夾雜些許碎肉，帶著甘甜的鮮味猶如餘音繞樑，在口中久久不散；可與上頭澆些琥珀色的特調醬料、乾癟外觀卻蘊涵極不相稱軟綿口感的油豆腐搭配吃，汁多味美的滋味，是常見的在地人餐點組合。','和平街54號','237',24.9377300,121.3703800,1,0.00,0,'ChIJQePSafEbaDQRsIXKQjjPwDc','2026-05-30 23:22:22'),(179,'可魯果子工房','藏身巷弄的可魯果子工房，出爐的糕餅很不一樣，因為全出自一位聽不見的年輕師傅，全心全意的投入烘培世界中，糕點除精緻之外，提供顧客滿滿的幸福美味。推薦產品：布朗尼蛋糕、手工餅乾、紅豆蛋糕、年輪蛋糕、雜糧吐司','化成路178巷3號','242',25.0457600,121.4658700,NULL,0.00,0,'ChIJ0_wV4WCoQjQRlooIchcnhoQ','2026-05-30 23:22:23'),(180,'香港成記粥麵專家','\"距離永和頂溪捷運站不遠的香港成記粥麵專家，在香港師傅坐鎮下，煮出道道地地的港式料理，曾被非凡大探索列為好吃粥品的店家之一。上頭僅灑些蔥花、薑絲，米粒熬到不成形、看似清淡的皮蛋牛肉粥，配料靜靜地沉在白粥底下，只要稍加攪拌，蘊藏在口感滑嫩牛肉的鮮味，立即融入粥中，越吃愈有味道；至於一般粥品商家常附的油條段，店家則是以炸地金黃的碎餛飩皮取代，在粥湯的浸潤下，滋味不遜於油條。推薦菜色:鮑魚牛片粥、狀元及第粥、鮮魚片粥\"','竹林路46號','234',25.0142400,121.5175900,1,0.00,0,'ChIJd9jLD-upQjQRmAplnG5KDqo','2026-05-30 23:22:25'),(181,'儷宴美食','\"良好的服務品質，精緻與多變化的菜色組合，加上寬闊的用餐空間，最適合家庭聚會或喜慶宴會宴席。推薦菜色：蒜香五穀牛\"','民權路53號2樓','234',24.9968600,121.5200100,NULL,0.00,0,'ChIJxf0MvPqpQjQRu-nuRGptfpc','2026-05-30 23:22:26'),(182,'山東餃子館','「山東餃子館」的佳餚五花八門，「乾烹雞」是用調過的醬料醃過後，再炸乾，加上辣椒、大蒜、糖、葱，吃起來酸酸甜甜的。「涼拌杏鮑菇」是把杏鮑菇切絲後，用水燙熟，灑上些許調味，就是一道脆甜的涼拌菜了。「香茅豬排沙拉」是把豬排放一點香茅、醬油、鹽醃過，豬排炸過後，再沾點和風醬，清爽、不油膩。「避風塘草蝦」是先把黃豆和大蒜炒酥，再把草蝦炸熟拌在一起就成了，黃豆的香和草蝦的甜，會讓饕客一隻一隻吃不停。餃子和酸菜白肉鍋是「鎮店之寶」，餃子有四種，素蒸餃、四季豆餃、蝦餃和鮮魚餃，所有餃子都是老闆自己親手做的，皮薄餡多，湯汁鮮甜。「酸菜白肉鍋」更是有名的美味，據很多饕客推薦，一點兒都不輸台北知名的「台電」和「長白」的「酸菜白肉鍋」呢。','中央路133巷19號1樓','231',24.9734300,121.5314300,2,0.00,0,'ChIJDbeb1B4CaDQR09_3NBlR3UA','2026-05-30 23:22:27'),(183,'布佬廚房','布佬這個名字是以老闆的洋名字「布魯斯」而來，餐廳主食以提供西式蔬食料理為主，餐廳平日有Live演唱，將慢活的味道全都彰顯出來。披薩、蔬食是這裡的招牌，不過青醬麵、烤飯類也賣得極好。主廚說，來到這兒瑪格麗特比薩、油醋香菇和匈牙利乾燒洋芋是必點名菜。其中，匈牙利乾燒洋芋是將洋芋切塊後，先水煮至六分熟，再用小火油炸形成外酥內軟的口感，然後再以洋蔥、蒜末、月桂夜爆香後，加入黑胡茭及匈牙利辣粉，繁複的手工，卻有令人驚艷的滋味。而另一道招牌油醋香菇，以高級香菇和蒜爆香後，加入陳年好醋調味，既美味又養生，是許多行家來此必嚐的養生蔬食。供餐時間 : 午餐 11:00~14:30 / 下午茶 14:30~17:00 / 晚餐 17:00~22:00(最後點餐至20:30)','車子路137號','231',24.9478900,121.5052000,2,0.00,0,'ChIJ3RN6r7EDaDQR2t_VNnOKqvw','2026-05-30 23:22:28'),(184,'魚丸伯仔','魚丸伯仔魚丸從民國35年就開始經營，目前是由第二代掌舵，目前店供應四種菜色：乾冬粉、魚丸湯、魚丸冬粉、豆干包。魚丸伯仔魚丸店的招牌是乾冬粉配魚丸湯，而這也是大多數的顧客來店裡會吃的東西。這裡的魚丸冬粉也是頗受遊客歡迎，冬粉的滑順及紮實Q彈的魚丸，配上甘甜的湯頭，如果再灑上一點胡椒，更會提升湯頭的鮮味。魚丸伯仔魚丸店位於基山老街的前段，由於距離基山老街的入口(舊道口)不遠，周邊有楊建成商號、茹緣、老友號芋園等九份地區知名的商店與小吃，這一個熱門地段常常吸引很多遊客前來逛街，而從店中飄散出來的烹煮食物香味也吸引著路過遊客的胃口。魚丸伯仔魚丸店在用餐時間總是擠滿了客人，特別到了周末時間一定會擠爆，建議可以與中午熱門用餐時間錯開來，才能真正享受到店內的真正古早味環境與小吃。推薦菜色:乾冬粉、魚丸冬粉、豆干包','九份基山街17號','224',25.1094200,121.8453700,1,0.00,0,'ChIJ1bV5IhhFXTQRQFJ34-buFrE','2026-05-30 23:22:29'),(185,'金山鴨肉','金山老街，沿著山城的民居巷弄而形成，是舊時熱鬧市集的集散地、是今日熱門的老街觀光景點之一。說起金山金包里老街，就不能不提到遠近馳名的「金山鴨肉」；這家自1958年開始營業，叱吒金包里五十餘年的老店，至今已傳承至第二代，由李光雄、游美夫婦經營。小麵攤轉型賣鴨肉剛開始，這裡只是一家賣麵的小攤，經營兩、三年後才開始轉賣鴨肉；起初一天只能賣出一隻，後來食客漸多，但最多也只能賣出十幾隻。直到十多年前，政府開發北海岸風景區，促進金山當地的觀光產業興起，金山鴨肉的生意才開始真正水漲船高。後來，生意好到縱使請來多達四十餘位的親朋好友幫忙，依然應接不暇；遠道而來垂涎鴨肉的饕客們，於是開始自己動手端盤碗、拿鴨肉，久而久之，便形成了人手一盤鴨肉在老街上穿梭尋找「地盤」的奇景，號稱一年就能吸引將近五十萬的饕客。','金包里街104號','208',25.2219400,121.6383500,1,0.00,0,'ChIJ_xrGQ12zQjQRYqbPfL1i8_Y','2026-05-30 23:22:31'),(186,'福昌餐廳','平溪老街上，樸實簡單的「福昌餐廳」，早自1957年就開始營業，以道地純樸的鄉土小吃聞名，亦是當地聚會、喜慶、宴會的最愛聚餐場所。道地臺灣宴席料理舊名「永閣樓」的褔昌餐廳，曾是礦業黃金年代的宴會辦桌專門店，總舖師能端出一手道地臺灣味，店內提供的菜色更像辦桌般豐富；尤其是平常很難在一般餐廳看到的「芋屯三鮮」，一入口就能感到一股令人懷念的濃郁古早味，相當值得一啖。此外，平溪素以盛產「箭筍」著稱，倘若是在秋末冬初、約莫11月的時節造訪，道地又新鮮的「平溪箭筍」，挑選軟嫩的箭筍，加上白豆豉和辣豆瓣醬後，快炒而成，清脆爽口又下飯，絕對不能錯過！而宴席上最常見的「佛跳牆」，亦是頗受饕客推薦的招牌菜之一；以雞湯為底，加入先醃再炸的排骨燉煮，以及筍片、炸鳥蛋、仿魚翅等多樣食材，調製出豐富的口味與甘醇的湯頭，是一端出就香氣四溢、令人垂涎的一道料理。','平溪街6號','226',25.0249200,121.7388000,NULL,0.00,0,'ChIJnWjd_rRWXTQR85SpQLNJidM','2026-05-30 23:22:32'),(187,'福寶飲食店','位於「石碇之心」廣場正前方，外貌並不起眼、但已在當地開業超過五十年，且相當受到本地人歡迎的福寶飲食店，每逢周末例假日必定客滿，是一家在簡單菜色中、深藏著高超廚藝的馳名老店。必點好菜 招牌豆腐三吃頗具盛名的「福寶豆腐三吃」─ 炸豆腐、豆腐羹，與紅燒豆腐，是饕客們到此必嚐的招牌好菜；尤其是「紅燒豆腐」這一道菜，作法不同於一般餐廳常見的先油炸、再紅燒，而是只加入金蘭醬油、以文火慢慢熬煎而成。不僅外皮軟嫩，且甘甜入味，連豆腐中心都風味十足，由此可見掌廚師傅深厚的烹調功力。「石碇豆腐」的名號雖然不如「深坑豆腐」來得響亮，但據稱深坑豆腐其實多數是由石碇所供應，所以同樣都帶著一股特殊的焦香味。不過，這種說法的真實性如何？則是見仁見智；有興趣一探究竟的朋友，不妨親自前往品嚐驗證。','石碇東街75號','223',24.9908900,121.6604300,2,0.00,0,'ChIJQXnlTRBVXTQR_gCH4HwNTVU','2026-05-30 23:22:33'),(188,'新建成餅店','1951年，第一代老闆林清鐓創辦了新建成餅店，開店至今已有近一甲子的時間，新建成餅店研發出不少產品。除了最暢銷的芝麻蛋黃餅外，還有和生餅、米香、沙其馬，以及傳統婚禮需要的禮餅，目前店中顧客以準備訂婚的新人和家屬居多，零售的比率較低。最暢銷的芝麻蛋黃餅，外皮佈滿著芝麻，在吃下之後，滿口的芝麻香殘留於口齒之間，內餡的冬瓜和蛋黃融合ㄧ體；不能吃蛋黃的朋友，店家也貼心設計不加蛋黃的產品。製作芝麻蛋黃餅需要將近13種原料，才能創造出香酥的餅皮和適中的甜味，為了創造出如此美妙口感，餅裡頭所添加的食材，曾更改過不下百次。另外，常吸引觀光客購買的商品，則叫做「和生餅」。上頭印有中國傳統餅模圖案，裡頭包含著不同的材料，有鳳梨、紅豆和咖哩口味，任由顧客依自己的口味挑選。','公明街42號','251',25.1689300,121.4430400,2,0.00,0,'ChIJPReL_1ilQjQRMCXcMlGbKuc','2026-05-30 23:22:34'),(189,'德裕魚丸','1953年，一對年輕夫婦洪炳堅、洪許俸，在褔佑宮 (媽袓廟) 左側開了第一家店，每天清晨五點，小小店面就擠滿採購人潮，自淡水魚港現撈的鮮魚，在老師傅的技巧下，去除多餘鰓片魚鱗，每一種鮮魚製品都搭配不同的獨家配方，如菠菜魚丸、添加DHA及鈣質的營養魚酥，德裕的魚漿製品很受歡迎，更是淡水阿給老店指定使用的原料。接手紅樓 保存淡水老記憶1963年，德裕洪家入主淡水著名地標「紅樓」，在財團大肆開發的腳步下，洪家決定保存「紅樓」的歷史價值，並於1999年以恢復原始面貌為原則，讓興建於19世紀末、橫跨三個世紀的「紅樓」繼續屹立在渡船頭半山上，成為淡水發展的世紀見證。來到德裕，除了買魚丸、魚酥，別忘了沿著店旁巷內樓梯往上走，欣賞紅磚建築的美景，體會根生淡水的老店執著。','中正路228號','251',25.1705300,121.4393300,NULL,0.00,0,'ChIJKdJjJVqlQjQRbXjZ8I7OmG4','2026-05-30 23:22:36'),(190,'阿妹茶樓','位於九份老街豎崎路上的阿妹茶樓，是九份茶館中的指標名店，許多九份的宣傳照、海報及各式照片，只要帶到豎崎路的畫面，阿妹茶樓四個大字，往往都會出現在畫面裡。這家九份老茶館，充滿著古色古香與九份的歷史氛圍，來這兒泡茶賞景，或三五好友嚐點心、聊天消磨一整個下午，都是人間最快樂的時光。','九份崇文里市下巷20號','224',25.1089500,121.8436100,2,0.00,0,'ChIJsSYt4BdFXTQRquCsN8eG7BE','2026-05-30 23:22:37'),(191,'九份食謎店','這家隨時可以聽到歌星伍佰的嘹亮樂曲、一面享受著熱騰騰的臭豆腐時，您可能會突然問：「老闆！你的店名為什麼叫『食謎店』？」九份食謎店是九份第一家臭豆腐店。店內牆壁貼上數十個台灣諺語，讓客人瞭解台灣人的智慧，牆上木質對聯「食盡天下美味 謎歇臺灣智慧」正是老闆的動機，故取名「食謎店」。老闆會想在店內貼這些諺語，是因為從小就對謎歇語有興趣，常常不時就蹦出一句俗諺，還買書學查諺語辭典，後來乾脆把自己的店布置成「謎歇語教室」。除了諺語，老闆的故事也說得很好，常常忘情地與客人聊起各種故事典故，對於九份地區的特殊俗諺也瞭若指掌。老闆表示現代人生活於科技、商業社會中，根本沒有機會接觸到台灣的文化與智慧－台灣諺語，所以要讓大家知道先人遺留至今的名言並體會其意涵。另一個用意就是讓用餐的客人可以猜測或互相討論其意涵造成話題，並且回憶起當年阿公阿嬤順口成章的台灣諺語。','基山街106號','224',25.1085400,121.8440500,NULL,0.00,0,'ChIJL74POaBFXTQRUjtwEgWdxkg','2026-05-30 23:22:38'),(192,'全香豆花','位在板橋慈惠宮旁全香豆花，以香濃鮮嫩、帶有淡淡雞蛋香的布丁豆花，廿幾年來成為府中商圈知名的甜品攤之一。全香的豆花製法比較繁複，使用無基改黃豆研磨後，煮成香噴噴的豆花，綿密、清香、淡雅的口感，每吃一口回味綿長。除了豆花好吃，這裡的配料全是老闆自己一鍋鍋慢慢熬煮的美味配角。傳統的粉圓、QQ圓、小紅豆、花豆、仙草、愛玉、燕麥、芋頭、芋圓、湯圓、蕃薯等，加在豆花裡淋上特調不甜膩的糖水，炎夏時節一碗在手，有令人停不住口的吸引力。冬天全香還有紅豆湯、花生湯和薏仁湯，也很受消費者推薦。綿密、清香、淡雅的全香豆花，是許多板橋人飯後來碗點心的美好回憶。','府中路105號','220',25.0094400,121.4567700,NULL,0.00,0,'ChIJ2zPAqwKoQjQRMR_8yWBwoQk','2026-05-30 23:22:39'),(193,'布娜飛比利時啤酒餐廳','板橋車站周邊美食多，車站本身也有不少美食你可知道？位於板橋車站二樓的布娜飛比利時啤酒餐廳就是其一，無論平假日人潮都不少，尤其假日店內經常爆滿呢！店內提供多達200種的比利時精釀啤酒，可依個人偏好的口味去選擇，有好喝的酒當然也有噴香的美食，有多種義大利麵、手工窯烤披薩、早午餐、排餐等可享用，不管是想來用正餐、小酌一番都合適呢。','縣民大道二段22號B1','220',25.0137300,121.4646500,2,0.00,0,'ChIJUWXuQBmoQjQREB1H5QfTvr0','2026-05-30 23:22:40'),(194,'長興餅舖','位於板橋府中商圈有婚紗街之稱的南門街上，這家已有上百年歷史的老店，自日治時期就是板橋地區婚嫁喜餅的第一選擇，歷經歲月洗禮老而彌堅黃長興號，依然以知名的板橋名產「長興豆沙餅」，吸引老饕和內行人上門。豆沙餅薄如紙的餅皮層層疊疊口感鬆軟香滑，細密的白豆沙餡料使用白鳳豆製成，從齒頰間散發出使人讚譽的馥郁，質感恆久遠的手藝，仍是板橋漢餅界第一把交椅。除了甜而不膩的白豆沙餅，魯肉酥、綠豆凸和咖哩肉餅，也都是店內超人氣點心，搭配古典的包裝盒，老店面、新感受，無疑是來板橋必買的最佳伴手禮。','南門街58號','220',25.0080200,121.4568000,2,0.00,0,'ChIJO0-qC6gCaDQRxvuAKi32DIo','2026-05-30 23:22:42'),(195,'香之味烤鴨','位於新莊區中正路和思源路口大漢橋下旁邊的香之味，是許多新莊和三重區親的美食深層記憶，原因無它，美味的烤鴨外脆內軟嫩，鴨肉肉汁經過高溫烘烤卻完全鎖住，每一口和麵餅、大蔥段、甜麵醬搭配入口，無法忘懷的好吃，難怪吸引客人大排長龍耐心等待。香之味片鴨的刀工也很受客人推崇，尤其捷運通車後慕名而來的客人更多，等待的時間不妨邊欣賞老闆切鴨肉的刀法，也是一種美啊。香之味的脆皮烤鴨，在新莊極具知名度，幾乎和「盛宴」畫上等號，也是招待親友、家裡加菜的美味。香之味片鴨後的鴨骨大火快炒，湯汁很下飯，尤其每到逢年過節，大家都來買幾隻大快朵頤，店裡的烤爐完全沒停過，空前盛況連路過的客人也忍不住聞香下馬嚐嚐。推薦菜色:脆皮烤鴨(全隻)','新莊路2號','242',25.0379900,121.4592800,2,0.00,0,'ChIJ-eyfrW-oQjQRJ1IP3OVwZ2c','2026-05-30 23:22:43'),(196,'鼎太香菇肉羹','藏身在巷弄的美食，肉羹湯滿滿的肉羹，配上筍絲清脆的口感與南部一貫的微甜羹湯，清甜美味。推薦菜色:香菇肉羹湯、米糕、乾麵、魯肉飯','豐年街55-3號','242',25.0311800,121.4466100,1,0.00,0,'ChIJL5G1lgqoQjQRuYDCl8TadMU','2026-05-30 23:22:44'),(197,'日月香烘培坊','提供試吃乃日月香的一大特色，且試吃份量大方，甚至有網友開玩笑表示光是試吃就飽了；在地議員大力推薦紅豆麵包，紅豆餡多且不甜膩，值得一試！推薦產品:紅豆麵包、法國牛奶棒(提供多種且量多的麵包試吃)推薦名人:黃林玲玲議員推薦','新泰路82號','242',25.0352000,121.4490900,1,0.00,0,'ChIJrZowV3SoQjQRZxopJYGHRoI','2026-05-30 23:22:45'),(198,'咖哩王子','店內的招牌除了各式各樣的咖哩料理可供選擇外，亦提供多種的熱炒合菜可供選擇，但價格便宜實惠，是夜市裡的人氣名店。推薦菜色:咖哩藍帶豬排飯、咖哩炸蝦飯','永平路153號','234',25.0094200,121.5100300,2,0.00,0,'ChIJGfr5DsOpQjQRqorkQnAQmS4','2026-05-30 23:22:47'),(199,'樂華夜市佳佳香鍋貼','「佳佳香鍋貼」只賣鍋貼和酸辣湯，靠著這兩樣東西，老闆娘蔡玉珍就可以一做24逾年，想必有她獨到之處，「佳佳香鍋貼」剛開始只是路邊攤，現在不但開起了店，還有13家加盟店。賴雅妍說：「我也是從騎腳車開始吃，吃到騎機車，現在開車了還在吃，我已經是十多年的老主顧，是永和的鄰居帶我來的。」。對「佳佳香鍋貼」賣的鍋貼，賴雅妍讚不絕口，她說：「這是我吃過史上最大顆的鍋貼，一定要沾醬吃會更棒，我常嘴巴塞得滿滿的沒辦法講話，直到吃完為止，才能開口說話，那種好吃和迫不及待的樣子，應該不難想像。」賴雅妍說，「佳佳香鍋貼」都是現包、現做、現煎，麵皮煎到金黃色，下脆、上Ｑ，咬起來「卡嗞」的感覺，真的很棒，餡料也是鮮嫩無比，她說，人少的時候，就在店裡吃，人多時就帶回家吃，最後配上一碗酸辣湯做ending，心滿意足地解決了一餐。','永和路一段114號','234',25.0074600,121.5137100,1,0.00,0,'ChIJn1KLo8KpQjQRb7Z76mVvnP0','2026-05-30 23:22:48'),(200,'楊家麵食水餃館','老闆以蝦仁、魚肉、豬肉三者相互搭配製成的特製「三鮮水餃」以及「超大鍋貼」，每天專注認真地做出台灣式的傳統道地風味美食，讓許多到此用過餐的朋友們一吃就上癮。推薦菜色:大鍋貼、水餃','中和路324巷5號','234',25.0007900,121.5101700,1,0.00,0,'ChIJNSOSlN6pQjQRSY7d8iyatD0','2026-05-30 23:22:49'),(201,'永美雪花冰','永和人從小吃到大的老牌雪花冰，與一般雪花冰不同，不攪拌，更好吃！花生雪花冰使用含有花生粒的花生醬，濃到化不開，牽絲出濃稠好滋味，與甜蜜清爽的芒果煉乳冰，都是老饕的最愛。推薦產品:花生雪花冰、新鮮芒果煉乳','永平路67號','234',25.0083800,121.5121900,NULL,0.00,0,'ChIJVVVVVcKpQjQRGFgv_mFas7I','2026-05-30 23:22:50'),(202,'永和金八式豬排專賣店','店面並不起眼，但是只要是到吃飯時間就是抱歉，請等待！金八式，這家網上口耳相傳的好店，便當選擇有7~8種，每種口味豬排還會裹不同的粉下去炸，便當有一主菜三配菜再加一顆蛋，名副其實的俗又大碗！推薦菜色:脆皮豬排飯','民生路6-1號','234',24.9978200,121.5225900,1,0.00,0,'ChIJb1aTn-OpQjQRHISkywTT_Xs','2026-05-30 23:22:52'),(203,'叉子義大利麵','這家店走平價風，但老闆一點也不馬虎，真材實料份量大，從店內環境，到料理食材，都可以感受到老闆經營的用心，是相當值得推薦的餐廳。推薦菜色:蕃茄海鮮義大利麵','永平路247號','234',25.0128500,121.5065700,1,0.00,0,'ChIJYfC7JMSpQjQR1QFxCcpthko','2026-05-30 23:22:53'),(204,'老葉牛肉麵','輔仁大學正門對面建國一路上的老葉牛肉麵，只要是輔大學生應該都知道的美食，能在校園附近屹立不搖，其美味程度可見一斑，店裡另一讓人津津樂道的是，小菜要自己動手切，原因來自早期老板實在太忙，只好請客人自己動手，無心插柳，倒也成為一種樂趣。','建國一路14號','242',25.0318900,121.4337000,1,0.00,0,'ChIJ7S6lPGqnQjQRXqw7KtovirQ','2026-05-30 23:22:54'),(205,'蔗雞王','在傳統市場的好味道，進入網購世代後，仍必須要堅持的就是新鮮！店家自製的產品，不論是雞肉或是內臟等滷味，都帶有獨特的香氣，擁有吮指回味的魔力！推薦菜色:蔗香雞、蔗鹽雞','福樂街71巷31號','242',25.0470600,121.4569200,NULL,0.00,0,'ChIJgd7cFHqoQjQRN1wFnDQGKEA','2026-05-30 23:22:55'),(206,'雙喜饅頭','店家的製作老麵製作方式，從發酵到完成每顆饅頭必須耗時10小時以上，加上純手工， 堅持不加防腐劑、人工甘味劑、漂白劑，口感札實味美，每日限量供應。推薦產品:芋頭地瓜饅頭、牛奶起司饅頭、紅豆牛奶起司、抹茶紅豆饅頭','後港1路76巷14弄4號1F','242',25.0255300,121.4272100,1,0.00,0,'ChIJexEOFfKnQjQR9a0GCDVp0bs','2026-05-30 23:22:57'),(207,'醄醴敬妻泡菜','老闆娘遠赴韓國學藝，為保持正統韓國味，堅持手工製作，維持傳統做法，並強調無添加，特以蘋果、水梨、蘿蔔熬製的高湯加上獨家醬料製成的醃醬來釀造的泡菜，讓顧客吃的安心又健康。','五權一路5號7F之7','242',25.0664200,121.4578500,NULL,0.00,0,'ChIJWeI_u5CoQjQR032qNMM1L5Y','2026-05-30 23:22:58'),(208,'斯味漢堡','打破傳統早餐店的視覺與味覺，斯味漢堡在餐點設計上更傾向多國口味，將各國早餐的精髓濃縮結合在簡單大方的套餐組合中，能感受到斯味漢堡的獨特性以及用心','重慶路245巷26號','220',25.0006700,121.4645000,1,0.00,0,'ChIJW152SqICaDQRxYuC9GHjoPc','2026-05-30 23:22:59'),(209,'大小品鍋貼水餃專賣店','煎得金黃酥脆的外皮，精選黑豬後腿肉與多種中藥配方所調配而成的內餡，無論鍋貼或水餃的口味均是一絕，配合店內的特製沾醬，風味更是絕佳。推薦菜色：鍋貼、水餃、酸辣湯、玉米湯','興南路二段15號','235',24.9844900,121.5079400,NULL,0.00,0,'ChIJq6qqqm8CaDQRG0_8rxufH1k','2026-05-30 23:23:00'),(210,'打狗舖-肉包子專賣店','黑豬三層肉與梅花肉混合而成的內餡，以鬆軟的包子皮包上，鮮美多汁的鮮肉包是店裡的人氣招牌。酸菜與肉餡混搭的酸菜包亦充滿人氣，略帶辣味的口感更能引起食慾。推薦菜色：肉包、酸菜包','自立路56巷2號','235',24.9918800,121.5232300,1,0.00,0,'ChIJWfNLTwgCaDQRo3-4f8KetlE','2026-05-30 23:23:01'),(211,'呷七碗油飯','Q軟且帶有絕佳口感的油飯上鋪上滿滿的的香菇、肉絲、魷魚、蝦米等豐富的餡料，再配上一隻完整的烤雞腿及兩顆水煮蛋，味道不但豐富扎實且份量滿點，是滿月送禮的熱門禮盒選擇。推薦菜色：滿月油飯、肉粽、年菜優惠資訊:30週年油飯全面85折','中正路907號','235',25.0061300,121.4837700,NULL,0.00,0,'ChIJIbsRDimoQjQRBKHHzt1GVlo','2026-05-30 23:23:03'),(212,'小胖手工蛋捲','原味、咖啡、芝麻、抹茶四種風味各異的蛋捲，滋味濃厚的香氣與扎實的口感，每咬一口幸福的滋味便充滿口中。推薦口味：原味、咖啡、芝麻、抹茶','中和路 241 號','235',24.9997700,121.5048500,NULL,0.00,0,'ChIJnz0vRdipQjQRklAydiOGa00','2026-05-30 23:23:04'),(213,'滇城雲南美食','中和華新街各南洋美食美食中，滇城雲南美食是唯一提供道地雲南菜、麵食、小點聞名的老店，來自緬甸臘戌的華僑老闆娘黃桂英，燒得一手好菜，包括基本的粑粑絲、米線、豌豆粉、稀豆粉，或是經常受到美食作家推薦的巴巴絲，老闆娘親自料理，加入大薄片，呈顯出一種過人的妙滋味。因此不僅一些家庭聚餐喜歡來這裡，學生們參加烘爐地登山活動後，也喜歡來此嚐嚐可口的滋味。老闆娘將炸豌豆粉料理得極好，不油膩的特殊風格，沾上她特調，用芝麻、花生、花椒、醋等香料調製而成，入口香酥而帶著微酸，和豌豆粉的軟嫩達到了香酥脆嫩的美食境界。推薦菜色：涼拌豌豆粉','華新街78號1樓','235',24.9834900,121.5082600,1,0.00,0,'ChIJv3rTg24CaDQRracePYQV9Fs','2026-05-30 23:23:05'),(214,'阿榮本家','\"米粉湯、肉粥簡單外表，湯頭卻不簡單。小菜搭配主食，舌上的頂尖美味，反而成為美食主角。這裡最紅的是菜色為炸豆腐，使用高溫將豆腐炸得外酥內嫩，皮餡分離的技術十分高竿。此外用紅麴醃製過炸紅燒肉，也是店裡人氣炸物。推薦菜色:香菇肉粥、米粉湯\"','安平路184號','235',24.9989300,121.5131000,1,0.00,0,'ChIJ1yUBu9-pQjQROuA2-c80dJs','2026-05-30 23:23:06'),(215,'RED紅餐廳','福朋喜來登飯店二樓的知名中式餐廳RED「紅餐廳」，以現點現做吃到飽的方式服務，提供絢麗千味的中式美饌，每道菜新鮮現做，極具視覺、味覺、嗅覺的美感和張力，不但深得電視節目、報紙美食專欄的稱讚，更有許多名人雅士指名來此聚餐，品嚐大廚們的即時手藝。','中正路631號2樓','235',24.9948900,121.4852100,2,0.00,0,'ChIJ_4bpKIQCaDQR0bO9czsC8Yw','2026-05-30 23:23:08'),(216,'李家麵館','走出410巷，往左手邊轉去不到50公尺就可以看到李家麵館，功夫刀削麵是這裡的最大特色，忙碌的備餐區可以看見師傅們分工仔細地備料、削麵與炒麵，每一道麵點都是在控制在美味的黃金時間裡上菜，熱騰騰的香濃滋味撲鼻，搭配微Q有嚼勁的口感，份量更是絲毫不吝嗇給了滿滿一大盤，讓所有吃過的人都直呼過癮。推薦菜色:刀削木須炒麵','景新街404號','235',24.9894200,121.5126500,1,0.00,0,'ChIJJ09CFXMCaDQRd20fjpDcqPA','2026-05-30 23:23:09'),(217,'九金店','據說在九份黃金山城，有一間糕餅店專門賣「小蜜蜂的家」。什麼是小蜜蜂的家呢？原來是九份有名的黑糖麻糬蜂巢糕，是九金店裡最夯的商品之一。九金店專賣的蜂巢糕之所以特別，是因為它濃濃的蜂蜜香，然後切開來裡頭有一格格的空隙，空隙間又有QQ軟軟的黑糖麻糬，不論是視覺上、味覺和口感上都很獨特。九金店蜂巢糕採用龍眼花蜜加上牛奶、雞蛋等新鮮食材，還有蘇打粉和天然酵母，經由烤箱低溫長時間的烘烤製成，由於製作過程環環相扣，有一定的比例和烘烤溫度，需要用很多的愛心耐心及細心的慢火烘焙，所以顧客有時要等比較久的時間，但也因為對品質的堅持，才有這樣好吃的蜂巢糕。不論是伴手禮、結婚喜餅、過節蛋糕、禮餅都可以在這裡訂購，並可以使用宅配，宅配消費滿一千五百元可免運費，讓更多的人可以吃到如此特別又美味的蜂巢糕。九份老街的九金店，有古早味的回憶，也有加入創意的研發產品，讓傳統的老街加入一股新的潮流，到九份旅...','九份基山街14號','224',25.1093900,121.8452500,NULL,0.00,0,'ChIJowSyGBhFXTQRyEeyBBEg8R8','2026-05-30 23:23:10'),(218,'豐味肉羹','在瑞芳已有三十年以上歷史的豐味肉羹，純手工製作的肉羹，選用優選豬肉和現打魚漿，加入多種中藥密方混合，湯頭使用大骨熬製加上竹筍，佐料沙茶醬加上油蔥酥，味道獨特且經濟又實惠。','民生街35巷2號','224',25.1068300,121.8056300,1,0.00,0,'ChIJXaj3RvdPXTQR4P0GqyBTh78','2026-05-30 23:23:11'),(219,'忘情小築茶坊','本茶坊是九份地區唯一木屋外觀的茶坊，門口顯眼的「忘情小築」木匾，極容易辨認，門牌地址恰好是「168一路發」，是許多前來此地拍攝婚紗照的必要取景地點之一。訪客進門前需更換室內拖鞋，進門後可看到整片的淺色系實木裝潢，簡單、清潔、明亮、厚實。室內有大型原木桌椅與其他一些木製品、玩石等，渾然天成、未經雕琢、造型多變的天然原木與原石，襯托出主人的品味。本茶坊提供茗茶、個人壺單點茶類、咖啡、冷飲、精緻套餐等服務。茗茶包括烏龍、金萱、鐵觀音等道地台灣茶與普洱茶。個人壺單點茶類包括各式花茶、水果茶與奶茶，冷熱皆宜。其水果茶是以新鮮水果如蘋果、鳳梨、柳丁、番茄、檸檬等水果與各種高級茶包組合而成。咖啡包括藍山、曼特寧、綜合咖啡，還貼心附送餅乾。冷飲包括冰咖啡、夏威夷蘇打、新鮮柳橙汁或檸檬汁；果汁類飲品，老闆堅持新鮮水果現搾，絕不使用濃縮原料回沖。套餐方面，提供多種中式料理，素食者可享用鮑魚...','基山街168號','224',25.1078800,121.8432100,NULL,0.00,0,'ChIJm1DEbj1FXTQRxHjiUDYk9c8','2026-05-30 23:23:12'),(220,'山海觀茶坊(山海全觀茶坊)','山海觀茶坊位在基山街後方的一棟貼有黃色磁磚的三層樓建築，此處恰巧是老街的大轉角處與後觀景台，所以視線沒有障礙，風景比一般的店家美麗。本店內部以木製裝潢及桌椅為主，大量陳列詩詞字畫，相當溫馨與雅緻。一樓有全玻璃式的室內觀景座位，與風景既親近又不怕雨淋。三樓有頂樓露天座位。各樓層之間的座位與包廂配置非常有彈性，從雙人情人雅座、和室座位一直到10人以上大包廂，不管三五好友或家族聚會，不論多少人，都能夠找到適當的座位，溫馨且熱鬧。本店為了讓遊客可以充份享受在九份的美好時光，所以服務的時間也特別延長到晚上，是喜歡享受九份夜晚風情的遊客最喜歡的茶坊之一。','基山街150號','224',25.1081800,121.8433400,2,0.00,0,'ChIJwcBWZj1FXTQRGs1iQnjDyh0','2026-05-30 23:23:14'),(221,'北京城餡餅粥','麵條是手工刀削麵，一條一條『削』出來的，很有咬勁，另外也還有拉麵可以選擇，端上桌來，碗裡最搶眼的非一塊塊超厚的牛肉塊莫屬啦，有網友戲稱這根本就是牛排麵了。給料大方，就是讓客人吃的痛快又開心的不二法門啦。推薦菜色:牛肉麵、蔥油餅、餡餅、韭菜盒','永元路34號1樓','234',25.0007200,121.5224500,2,0.00,0,'ChIJGVp1XOSpQjQRBn0q5fmvii0','2026-05-30 23:23:15'),(222,'德記鍋貼','清爽的煎餃與餡料滋味，煎得金黃焦香的餅皮，香氣隨著內餡一齊散發出來。煎得恰到好處的外皮去除掉多餘的油膩，僅留下純粹的好滋味隨著餡料一同下肚。','北新路34號','251',25.1778000,121.4454000,1,0.00,0,'ChIJ_7M2i1WlQjQR9Wrl_WfKo_0','2026-05-30 23:23:16'),(223,'大胖活海鮮','觀景桌位欣賞淡水落日餘暉，還有美味的瀨尿蝦佐餐，享受生活的平靜在這裡輕鬆就能滿足，鮮甜美味又平價的海鮮料理。推薦菜色:瀨尿蝦、胡椒鳳螺、鯊魚羹','觀海路37-1號','251',25.1818600,121.4131300,2,0.00,0,'ChIJt42ixTalQjQRONw31pFQIws','2026-05-30 23:23:17'),(224,'老孫涼麵','天氣炎熱吃不下，沒有胃口嗎？那你一定要來位於新店中正路上的老孫涼麵，店內主打的涼麵分成四種：麻醬涼麵、素食涼麵、酢醬涼麵還有綜合涼麵，有分大碗跟小碗，如果天氣涼了，想吃熱食這邊也有提供湯麵，另外店內招牌小菜也不少，有豬腳、豬肉凍、雪菜、豆干和豬耳朵等，這裡也有超值的味噌熱湯，絕對可以滿足你的胃口。推薦菜色:麻醬、炸醬涼麵、味噌湯','中正路294號','231',24.9744900,121.5377600,1,0.00,0,'ChIJlWGQCPYBaDQRvTo1SNS7sxc','2026-05-30 23:23:19'),(225,'勇伯米粉湯','吃過的客人一致推薦的米粉湯，這家位於光明街的勇伯米粉湯，價格非常的平民化，米粉湯的湯頭用了許多的材料下去熬成，一碗米粉湯的份量還滿多的，這裡的滷味滷得非常透徹，還有油豆腐、肝連、菜頭等小菜完美搭配，讓吃過的朋友都成為了這家店的忠實顧客。','光明街57號','231',24.9602900,121.5386900,1,0.00,0,'ChIJbXTgSIgBaDQRjFzEtZgxGbk','2026-05-30 23:23:20'),(226,'錦龍土雞城','錦龍土雞城有著寬敞的用餐空間，可以容納大型團體或是公司行號辦理聚餐宴會，店家的招牌菜－白斬雞，採用閹雞製成，新鮮味美；另推薦外皮炸的金黃酥脆的豆腐，淋上店家特調醬汁，嚐一口，雞蛋豆腐的軟嫩，讓你有入口即化的感覺；此外，極品花雕雞、陳年菜脯雞，可品嚐到雞肉的各種質地與變化；另外還有多種新鮮健康的山蔬野菜。','廣興里平廣路一段30號','231',24.9034400,121.5350900,2,0.00,0,'ChIJUeL3TAAEaDQRObNJC0F6wQA','2026-05-30 23:23:21'),(227,'阿琴鹹水雞、鵝(介壽廣場老店)','新鮮、有很多美味的雞凍，是阿琴鹹水雞的特色。選用四個月左右肥瘦適中的半土雞，慢火炊蒸後冷凍，嚐起來軟嫩腴潤、雞汁鮮甜，燻雞也是一絕，金黃的雞皮彈性Q脆鹹香得很入味。鴨、鵝初一、十五拜拜時才有。推薦：老闆推薦鹹水雞、燻雞更下飯。','大智街156號','241',25.0687900,121.4918700,2,0.00,0,'ChIJ8WP-oiCpQjQR_waZ68UNROE','2026-05-30 23:23:22'),(228,'豪季水餃專賣店','韭黃的豬肉餡兒，蝦仁餃的蝦肉鮮脆、緊實，吃在嘴裡肉汁四溢，彷彿蝦子在嘴裡彈跳。煎餃很出色，吃過的人都認為香過八方四海；炸醬拉麵份量超多，蔥油、豆乾和碎肉的澆頭，簡單中帶著媽媽的味道。（三民路進來右轉第一條巷子）推薦：蝦仁水餃、炸醬麵，蝦仁煎餃。（酌沾阿嬤特調的醬，滋味更好）','重陽路二段18巷7號','241',25.0625100,121.4863500,1,0.00,0,'ChIJd6OEOuGoQjQRBkRYhp7tHlA','2026-05-30 23:23:23'),(229,'烘大師鮮焙咖啡','中和區一家專業烘焙咖啡豆的店，提供①顧客現烘咖啡豆（客人訂購後才烘焙咖啡，以確保咖啡絕對新鮮)②現做新鮮濾泡掛耳包③咖啡相關產品、禮品販售','保健路91號','235',24.9966200,121.5112400,NULL,0.00,0,'ChIJt5H1tZ4CaDQROW1qABvR-a0','2026-05-30 23:23:25'),(230,'阿娥排骨麵','排骨酥與高湯的巧妙組合，搭配煮得熟度適中的麵條，夾起麵條的同時佐著蔬菜與排骨酥一齊享用，簡單卻純粹的美味，在吃下嘴裡的瞬間在口中迅速地擴散開來，令人懷念的好滋味不禁讓人回味無窮。推薦菜色：海鮮麵、鮮魚麵','淡金路一段150-1號','251',25.1766200,121.4566300,1,0.00,0,'ChIJ5_lSKf2vQjQRyoHI97tz2Ys','2026-05-30 23:23:26'),(231,'龍抄手','還記得學校合作社裡賣的涼麵味道嗎？清爽的涼麵口感搭配古早味的花生醬，加上切絲的小黃瓜還有紅蘿蔔，每一口都是完美的搭配，這家涼麵攤在地方上已獲得不少老主顧的青睞，來到這也不能錯過的招牌紅油抄手，不會太油，辣油的味道剛好跟抄手中和，讓人忍不住一口接一口。','中正路153號','244',25.0772100,121.3928600,1,0.00,0,'ChIJ1wre-eamQjQRdF3RR6OSlAg','2026-05-30 23:23:27'),(232,'芳鄰包子饅頭','手工製作的包子饅頭，不論是早餐或是點心宵夜，都非常受到婆婆媽媽們的喜愛，店內的特製火腿起司包，融合了西式內餡，搭配傳統中式包子外皮，口感十分特殊；芋頭包子吃得到紮實的芋頭泥，看得出店家的用心。','竹林路157巷5號','244',25.0799800,121.3882500,1,0.00,0,'ChIJa2wD2O-mQjQRF_Qr1As_gBs','2026-05-30 23:23:28'),(233,'碧瑤山莊庭園餐廳','位於新北市五股區的碧瑤山莊，以筍子料理以及鄉土料理深受老饕們的喜愛，除了現場歌曲演唱，還提供給小朋友們陀螺等童玩用具，除了全家同樂，兩人情侶還可以到這邊欣賞夜景及品嚐雙人套餐，涼拌竹筍還有竹筍排骨湯在炎熱的季節，讓您消暑降火氣喔。','凌雲路三段112號','248',25.1249400,121.4258900,2,0.00,0,'ChIJKdd5ApWlQjQRvPSsxVfEXAg','2026-05-30 23:23:30'),(234,'平林農場','位於雙溪的平林農場，提供住宿、餐飲、烤肉還有教學DIY等多項體驗活動，而雙溪為野薑花的生產地，所以可以品嘗到各式野薑花風味料理，這裡提供野薑花粽、野薑花餅乾、野薑花煎蛋，淡雅清香的野薑花，在你的嘴裡漸漸散發開來，招牌的山藥細麵，口感滑順，健康養生。','平林里外平林35號','227',25.0364400,121.8535300,NULL,0.00,0,'ChIJPcbxl1NaXTQRkz2cQNcO7nw','2026-05-30 23:23:31'),(235,'陳家豆腐','以黑豆腐以及白玉豆腐腦為名的陳家豆腐，黑豆腐是以黑豆來製成的，而白玉豆腐腦則是由花生及在來米研磨成粉製成，店內除了提供多樣化精緻的豆腐料理，在炎炎夏日裡，來杯祖傳酸梅湯，完全手工自製純天然又健康，另外，店內還有販售自行研發的豆腐蛋糕，除了甜點口味，也有鹹式口味，口感更綿密更鬆軟，喜歡嘗鮮的朋友，一定要來試試看。','深坑街91號','222',25.0015000,121.6143200,2,0.00,0,'ChIJNajmAMWqQjQRtfdYp47P0jw','2026-05-30 23:23:32'),(236,'故鄉的口味','同樣都是位在深坑老街，每一間豆腐料理店都有各自拿手的料理，而在這間故鄉的口味，你也可以品嘗到麻辣臭豆腐、炸臭豆腐、三杯臭豆腐以及清蒸臭豆腐，除了豆腐料理外，各式山產野味也是值得推薦品嚐看看，滷桂竹筍還有各式野菜都非常受到歡迎，店內的招牌菜-鼔椒炒臭豆腐，是一道重口味的菜，非常下飯，是一道不錯的選擇。','深坑街146號','222',25.0012000,121.6125000,1,0.00,0,'ChIJafMIXcSqQjQRQSRnjQ1QKJI','2026-05-30 23:23:33'),(237,'阿芳石花凍','石花凍是近海沿岸所特有的植物，而位在福隆火車站左手邊的阿芳石花凍，老闆堅持手工製作，不添加其他成分，保留最天然最原始的味道，石花凍也有養顏美容功效，來這邊老闆還會教你如何分辨石花凍的好壞品質，品嚐石花凍，除了消暑解渴，又能獲得豐富的知識。','福隆里福隆街15號','228',25.0163600,121.9447900,NULL,0.00,0,'ChIJ358ciVRcXTQR8bcIcb3XuSw','2026-05-30 23:23:34'),(238,'福隆發記月台便當','月台便當選擇眾多，每個人口味不同，但要吃的健康美味又安心，就要來品嚐獲得金字招牌獎的發記福隆月台便當，招牌便當料多味美實在，豬肉沒有多餘的肥肉，菜圃及酸菜開胃，讓你扒著便當一口接一口，位在省道旁，福隆海水浴場正對面，開車經過的朋友，肚子餓時也可以直接外帶很方便的。','福隆村興隆街17號','228',25.0165100,121.9441000,1,0.00,0,'ChIJt6wUiVRcXTQRmgHmR8kkv7g','2026-05-30 23:23:36'),(239,'新港海鮮','想吃海鮮就一定要到貢寮區澳底，沿著海灣的貢寮區所捕獲的海產都是最新鮮的，在地知名的新港海鮮海產店，在地經營50多年，經常是宴客親友以及團體旅遊的指定餐廳，店門口都是當天現補現撈的活海鮮，喜歡吃什麼還有烹調方式，都可以直接跟老闆說，價格也是經濟實惠，招牌的紅燒鰻以及胡蔴海鮮沙拉都是不錯的選擇。','真理里新港街69號','228',25.0561100,121.9268200,NULL,0.00,0,'ChIJp-zjxsdcXTQR2stOWWIoDjk','2026-05-30 23:23:37'),(240,'蘆洲大廟口切仔麵','到大廟口用餐，一定不能錯過老闆特調的醬料，口味微辣，淋在小菜上讓人齒頰留香；切仔麵的乳白色的湯底可看出老闆的好手藝，選用較粗且較有嚼勁的麵條，吸飽湯汁之後，麵條的Ｑ度適中，且沒有過多的調味，僅淋上油蔥酥提味，入口瞬間，鮮美的滋味讓人難忘。推薦菜色:切仔麵','得勝街6號','247',25.0841800,121.4745500,1,0.00,0,'ChIJ77AarM6oQjQRzWFByzVQvQI','2026-05-30 23:23:38'),(241,'林鴻鈞滷味專賣店','林鴻鈞的滷味帶是在攤車上販賣，賣的是冷滷味，夏天嘴饞時的好選擇，有點中藥的香料味，吃起來很香，再淋上老闆特製的辣醬，美味無法擋。','建國路113號','239',24.9540700,121.3528600,1,0.00,0,'ChIJt5_t9KkeaDQRM1M3cz8yR0Y','2026-05-30 23:23:39'),(242,'勇伯垃圾麵','鶯歌有種很特別的平價美食，那就是當地人都知道的垃圾麵。這種麵的怪名字來自於它這碗顏色渾濁的湯頭，因為湯頭是用豬骨熬製而不去渣，另外又加上特製辣油，使整碗麵看起來賣相不佳而得此名。但加了紅糟肉和燒肉的垃圾麵，湯頭層次可說十分豐富，麵條是一般的家常麵條，但又辣又香的湯頭配上煮得恰到好處的麵條，搭配一片紅糟肉入口，滋味完全有別於麵名，味道可說十分頂級呢！','中正一路157號','239',24.9563900,121.3525400,NULL,0.00,0,'ChIJVQb_tKkeaDQRAtx6l8oy768','2026-05-30 23:23:40'),(243,'山泉水手工豆花','來到三峽熱鬧的民生街，逛累了感到口乾舌燥，這個時候一定要來上一碗用天然山泉水製作的手工豆花。手工製作的豆花質地綿密，微微豆香吃一口就能聞到，進入嘴中舌頭更能清楚感受到豆花的香氣。另外推薦加薑汁一起品嚐，特別是在寒冷的冬春交替之際，來碗溫熱的手工薑汁豆花，讓人全身都暖和起來呢！','民生街149號','237',24.9348600,121.3729300,1,0.00,0,'ChIJL40qQfIbaDQRWkIi2jO6scI','2026-05-30 23:23:42'),(244,'福長商號','坪林以產茶業為主，用茶葉調理製作出許多種風味餐，來到坪林推薦您品嘗茶油麵線，茶香搭配清爽的白麵線，讓您忍不住一口接一口，這裡的風味餐除了茶油麵線，還有茶葉貢丸湯、茶葉紅豆麻糬、茶凍，讓你來到茶葉的故鄉，一次就能品嘗到各式茶風味料理，另外眾多茶葉禮盒也是不錯的伴手禮。茶葉貢丸湯另一個坪林特色茶美食就是茶香貢丸，製作過程得先將挑選過的茶末攪碎，再加入電宰上等豬肉泥精製而成，堪稱完美組合。完成後的茶香貢丸具有獨特口感，比起一般傳統貢丸清爽不油膩，口感爽脆有彈性。放入口中咬開後的貢丸，茶香四溢，搭配芹菜末與店家特別熬製的湯頭，喝起來口齒留香，大呼過癮！','坪林街18號','232',24.9363500,121.7120600,NULL,0.00,0,'ChIJ0UqtXE7_ZzQRf2jrQXwgoQ0','2026-05-30 23:23:43'),(245,'老地方小籠湯包','老地方的小籠包內餡材料選用三芝當地的黑豬肉，加蔥、韮黃和獨家配料攪拌成餡，蝦仁湯包則是多加草蝦仁，皮薄餡滿，蒸熟上桌後用筷子輕輕夾起，沾點醬油及薑絲入口，鮮肉湯汁在口裡爆開竄流，一種幸福感動油然而生，口感完全可以和五星級的餐廳匹敵。','淡金路二段21號','252',25.2596000,121.5028100,1,0.00,0,'ChIJi9jBH862QjQRxEFmDNsbM2s','2026-05-30 23:23:44'),(246,'溫泉商店 雞捲攤','別看路邊一攤不起眼的雞捲店，很多好吃的小吃都是起源於這些地方，位於菁桐車站老街轉彎處的雞捲攤，沒有特製的招牌，只有用心製作的手工雞捲，嚐起來的味道就是不一樣，還有花枝肉丸提供選擇，假日一到，就會看到許多遊客在這邊排隊，就是為了要購買轉角的美食。','菁桐里菁桐街165號','226',25.0235800,121.7230700,NULL,0.00,0,'ChIJmRQ1f65WXTQRD293eePMKGI','2026-05-30 23:23:45'),(247,'廟口的油飯','這間店一開始只是廟前的小攤販，至今已在廟旁有了自己的小店面，一般人對於油飯的印象就是很油，但是這家廟口油飯，米飯粒粒分明，清新爽口，讓人忍不住一碗接著一碗吃，老闆會先淋上魯汁，再照個人喜好加入店家特調醬料，加上醬料後更加突顯油飯的香味。','大仁街64號','241',25.0650900,121.4923100,1,0.00,0,'ChIJZV04GiCpQjQRQaK1rG-Bzvo','2026-05-30 23:23:46'),(248,'新興號貢圓','老闆做貢丸已經長達40年以上，每天早上老闆就會去市場買溫體豬肉，將豬肉打成肉漿後，製作成貢丸拿到市場販賣，老闆說，現在的貢圓大多是用機器製作，但他們家的貢圓堅持傳統做法，都是用手工捏製，而且不含防腐劑，大家想吃老闆做的貢丸，可以在三重區中央北路26號的「新興號摃圓」購買，不過這裡賣的是冷凍貢圓，大家要買回家後記得要煮5~7分鐘才可以吃喔，老闆透露如果加入少許芹菜及香油會更好。','中央北路26號','241',25.0643400,121.5005900,NULL,0.00,0,'ChIJrTDe8SKpQjQR43kZgRcLaCg','2026-05-30 23:23:48'),(249,'冰芝林','在炎熱夏日的來碗涼的消消暑，是人生一大享受。店家販賣的冰品口味眾多，其中「焦糖地瓜口味」，甜甜的焦糖，配上每一口都可以吃到地瓜纖維，讓人一口接一口，每一口都驚奇！推薦產品：焦糖地瓜、仙人掌綿綿冰','金包里街59號','208',25.2215800,121.6386900,NULL,0.00,0,'ChIJTf5J71dLXTQRJSAX5WBbq6c','2026-05-30 23:23:48'),(250,'阿嬤ㄟ等路','店家賣的是傳統口味的零食，超人氣的是地瓜片，因為地瓜本身的甜度就高，香氣十足，吃起來甜甜的但感覺不會很甜膩，口感紮實爽脆，甜甜脆脆會讓人一片接一片！推薦產品:養生黃金冰烤地瓜','金包里街74號','208',25.2215800,121.6388800,NULL,0.00,0,'ChIJSZLfAFhLXTQRXete8JCfOQc','2026-05-30 23:23:50'),(251,'真傳牛肉店','精選各部位的牛肉，以清燉的方式烹煮更顯得出手藝的好壞。Q中帶勁的牛肉與口味適中的湯頭組合，與麵條一起入口更突顯了牛肉的鮮美。多種牛肉的特色菜肴與湯點亦是店內的招牌之一，每道均可享用不同的牛肉風味。','北新路56號','251',25.1781400,121.4460100,2,0.00,0,'ChIJDSSbZP-vQjQRY09xJ1tAlqk','2026-05-30 23:23:51'),(252,'台G店養生藥膳(淡水總店)','麻油的馨香，精選的雞肉透過加熱傳達出特有的鮮美，濃郁的麻油滋味更增添了口味上的變化。一口咬下雞肉流出的肉汁與麻油香，整個身體頓時暖和了起來。推薦菜色：招牌麻油雞','英專路31號','251',25.1699900,121.4454900,2,0.00,0,'ChIJCx2ieVilQjQREScRQ4QqvD0','2026-05-30 23:23:52'),(253,'大樹堡','在最早之前大樹堡早餐店就是開在深坑老街上，因應客人要求以及老街重建，現已遷至北深路老街大樹對面，店內的總匯三明治物超所值，別的地方吃不到的排骨堡，肉質香甜鮮美，再搭配鮮奶調製的鮮奶茶，健康加分，這裡還有提供自製手工豆漿，常常不到9點就賣完了，想要體驗的朋友要記得早起喔。','北深路2段220號','222',25.0014000,121.6125900,NULL,0.00,0,'ChIJOQA5Z8SqQjQRW7xUoMUIrFg','2026-05-30 23:23:53'),(254,'美之品滷味','隱身在不起眼的小巷弄中，若不是當地人報路，還真的找不太到這間位於信義西街的美之品滷味，親切的老闆娘忙得不可開交，一邊川燙著客人的滷味，還要記每個人點的東西，攤子上的每樣食材都滷的非常入味，當拿到所點的滷味，咬下的那一口就知道不是浪得虛名，所以排隊半小時是值得的，歡迎你來嚐嚐。','信義西街13號','241',25.0646900,121.4978000,1,0.00,0,'ChIJAYCBKpipQjQR9lA_5lVgdTo','2026-05-30 23:23:54'),(255,'4號公園良古早味黑糖剉冰','安樂路上的良記冰店，招牌為其獨特的黑糖冰磚。看著老闆取出一大塊急速冷凍製成的冰磚，放在剉冰機上，轉眼間，一盤淋著焦香黑糖的剉冰便送到眼前。剉冰的口感不同於平常吃到的冰粒，顆粒不那麼粗，沒有需要咬碎，介於綿綿冰的細緻與剉冰的爽脆之間，由於黑糖製成的冰磚刨片後，顏色當然也不那麼純白，吃進嘴裡有淡淡的黑糖香與綿細的冰粒。','安樂路232號','234',25.0025300,121.5149600,NULL,0.00,0,'ChIJI15Eb-epQjQRK9Sh4g45TXw','2026-05-30 23:23:56'),(256,'大庭牛肉麵','大庭老闆葉賢露說，牛肉麵店在板橋已經營數十幾年了，每天從市場採買新鮮牛肉後，牛花腱肉刀切2公分厚，先汆燙再煮熟，後爆炒大蒜、辣椒、豆瓣醬等佐料，用紅燒的手法加入牛大骨滷湯中一起滷製，多重的繁複手工，湯頭清爽而不油膩，是不少在地饕客的推薦首選。','國光路39號','220',25.0177900,121.4574500,2,0.00,0,'ChIJR5A_zhqoQjQRZ8use6ah4GU','2026-05-30 23:23:57'),(257,'臺電桂山電廠桂山冰棒','臺糖、臺鹽賣冰棒一點都不稀奇，電廠賣冰棒才真的「Cool」。桂山電廠之所以會賣「桂山冰棒」， 是因早期這裡的建設工程中，混凝土攪拌時需要加入冰塊，讓熱能冷卻更平均以免水泥牆面產生龜裂， 而當年的製冰機存留至今，電廠原本只是想賣冰給員工解饞，未料一傳十、十傳百，最後就成了許多美食家的私房地。*每年只營業三月至十月','桂山路34號','231',24.9034200,121.5577600,1,0.00,0,'ChIJvaKemDUBaDQR4zSsMfeUjLc','2026-05-30 23:23:58'),(258,'金包里市場豆漿店','舊市場內的老豆漿店，是金山地區無人不知的美味早餐店，傳承了半世紀的手工製豆漿古法美技，使用進口無基改高級黃豆，磨豆後不過濾豆渣，煮熟後帶點淡淡的焦味兒，讓每一位來喝過的客人，都忍不住還想再來嚐嚐。第一代老闆娘陳林寶絨，現在每天都還在店裡幫忙包飯糰，糯米飯糰裡面的肉鬆、菜脯加上受熱軟嫩的油條，雖然外觀和一般豆漿店的飯糰沒兩樣，但吃起來口感可是高竿許多。難怪很多住金山的上班族，搭車前都會拐進來市場買幾個飯糰隨身帶。還有古早味蛋餅，有一種慢工出細活的香郁口感，別的地方吃不到喔。資料來源:新北市美食吃透透8月號','中山路190巷2號','208',25.2217000,121.6380100,NULL,0.00,0,'ChIJlbZEw1dLXTQRi5NYhDA3jVg','2026-05-30 23:23:59'),(259,'周烏豬切仔麵','店家位在湧蓮寺旁，人來人往相當熱鬧，切仔麵口感ＱＱ的，湯頭清爽不油膩，加入一些油蔥增加香氣還有豆芽菜，口感簡單卻有味道。開店已30逾年的「周烏豬切仔麵」，老闆娘葉秀卿表示，蘆洲切仔麵的湯頭相當特別，是採用大骨、三層肉長時間燉熬，完全不加味精，許多老主顧幾乎天天來吃，有民眾也說，只要來到蘆洲就會來品嚐切仔麵的滋味!「切仔麵」的由來，相傳是烹調時，師傅習慣將韮菜或豆芽菜放入煮麵的竹勺子，和七分熟的麵條在麵鍋中「切切」抖動幾下，這「沏刷」的聲音，讓這種麵成為現在的「切仔麵」。傳聞家住蘆洲的周烏豬，早在台灣光復前，在湧蓮寺大廟口擺攤叫賣切仔麵，收有門徒楊萬寶，師徒倆小本生意慘淡經營，光復後，楊萬寶靠著這項一技之長，在大廟口自立門戶，吸引北上謀生民眾爭相仿效，切仔麵店如雨後春筍到處林立。推薦菜色:切仔麵、豬血糕、透抽、三層肉','得勝街106號','247',25.0829900,121.4712100,1,0.00,0,'ChIJU3cGU8ioQjQRayQ0Mg0FgYg','2026-05-30 23:24:01'),(260,'保安堂','傳承三代的百年老藥行，不斷推陳出新，開發符合現代人愛好養身、美容需求的茶飲。事先預約還能參觀藥舖內滿室古物。元氣茶也是店裡的人氣商品，喝起來也是甘甘的，可增加免疫力。據說，證嚴法師的弟子都買這個來奉請上人，訪問那天，剛好有人來買中藥要回去泡酒，十全加上千年龍骨等15種中藥，老闆說，這個比XO還好。「保安堂」傳到現在，已是第三代，老闆陳信雄準備再傳給第四代的媳婦陳施慧梅，因為歷史悠久，店裡所有道具都有來頭，杯子和盤子是50年前省主席周至柔在用的，還有老闆最得意的是黃花梨秤和竹子秤，他說，這比黃金還貴呢。推薦產品：酸梅湯、洛神花茶、青草茶、六神梅','中正路89號','251',25.1697100,121.4404900,NULL,0.00,0,'ChIJx4zuglmlQjQRz5rYZn6wyz4','2026-05-30 23:24:02'),(261,'廖木成百年老店入口酥','到廖木成百年老店走走，嚐嚐店內名氣響叮噹的「酥餃」，是遊逛九份必走行程，廖家酥餃傳承四代的好味道，繁複的手工擀麵，將美味揉於麵中，加入各式餡料，烘烤出上等的酥爽、齒頰留香之感，行家均為之激賞。因酥餃入口酥香，餅皮與內餡各種滋味的交融映掩，妙不可言，所以後來就以「入口酥」為名。廖木成百年老店是草創自廖克愛之手，因第二代的廖木成老闆曾在日本人的俱樂部當廚師，將酥餅打響名號，於是店名就以「廖木成」沿用至今。歷經多年演進，廖木成的產品從原來的酥餃，又多了老饕推薦的糖蔥、滷肉包、草仔粿和芋粿巧等。最精彩的還是多重口味的酥餃，芋頭、紅豆、綠豆、白豆、綠茶都是甜口味，蘿蔔絲為鹹口味。真材實料輕咬內餡軟嫩香酥，百年手藝名不虛傳。','基山街129號','224',25.1084900,121.8441100,NULL,0.00,0,'ChIJWfq-4hdFXTQRuxlmYTQVRYk','2026-05-30 23:24:03'),(262,'德佳香食品行','已有四十幾年歷史的宜家香，是永和著名的肉脯老店，店裡的肉紙、肉乾、肉鬆、肉脯和肉絲五大主角，是年節的伴手好禮，也是附近上班族、公司行號送禮的好選擇。最有名的宜家香肉鬆，是劉新元老闆經典代表作之一。每天市場嚴選溫體豬後腿肉，先細分、去油脂、去薄膜之後，下鍋清燙3小時至豬肉熟爛，接著用手工槌打、加入獨門的調味料醃製後，再下鍋小火翻炒至完全熟透入味，中間的過程毫不馬虎。這種純古早味作法，深受饕家們的欣賞，連臺北市的客人都深為這人間美味折服，專程搭車來採購。','永和路一段18巷11弄21號','234',25.0046800,121.5136500,NULL,0.00,0,'ChIJGRFSZN2pQjQROI_jKDBcJAw','2026-05-30 23:24:04'),(263,'草地人蚵仔麵線','草地人蚵仔麵線已經開了17逾年，總共搬了4次家，搬家的原因都是因為生意太好，房東眼紅一直漲租金。做蚵仔麵線之前，老闆張文連是賣檳榔的，後來檳榔西施沒落了，不得已只好轉行，他花了二個月的時間去學做蚵仔麵線，涼麵和甜不辣。張文連選擇這三樣下手，是因為學這個比較簡單，只要知道配方和煮的技巧就可以了。說來容易，技巧不同，煮出來的味道也不同，經過慢慢研究改善，現已成為板橋人最愛的台灣小吃。每天蚵仔麵和甜不辣至少都可以各賣三、四百碗以上，生意好，是因為蚵仔很大很新鮮，每天從彰化王功直送。老闆很高興轉行轉對了。草地人麵線的口味，有花枝麵線和蚵仔麵線。涼麵的口味有麻醬，泰式和酢醬3種口味，都是令人懷念的老滋味。','文化路二段182巷5弄1號','220',25.0271800,121.4716400,NULL,0.00,0,'ChIJ5ZFogUCoQjQRndh3DRD3zdg','2026-05-30 23:24:05'),(264,'舊金山總督溫泉會館','舊金山總督溫泉是金山區著名的大型溫泉會館，「總督」的名稱是因日治時期台灣總督府曾於昭和13年5月撥款3萬日元興建此溫泉，所以後來就命名為「舊金山總督溫泉」。溫泉館主建築由舊有的新館溫泉招待所加以修建而成，外觀像極了古典洋樓別墅。二樓為享受美食的餐飲空間，並以清爽的海洋風格作裝潢。溫泉會館內的美食主要以現撈海鮮套餐為主，美味的精致金山海味就呈現眼前。最著名的「金多蟹跳跳鍋」是會館內超人氣的美食，各式各樣的鮮美火鍋料，加上主角「花蟹」或季節性螃蟹，和會館特調的美味湯頭，在泡湯之樂的同時，淺嚐一口新鮮在地食材，真是幸福感滿分。另外總督套餐、翡翠套餐，多變化的海鮮及金山特產「地瓜」料理，錯過可惜。溫泉館的頂樓分為左右兩邊，為男、女露天大眾浴池，其中一面為台灣本島唯一可泡湯看海的地點；另一面，則遠眺陽明山國家公園的群巒和山嵐，讓人浸泡其中感到無比的清爽舒暢。','民生路196號','208',25.2218600,121.6459000,NULL,0.00,0,'ChIJy5Mo1F5LXTQR8f3ynfGKV_c','2026-05-30 23:24:06'),(265,'王記蝦仁羹','真正厲害的美食名家，菜色不必多，一、兩樣極致美食就能擄獲老饕們心。位於三重三和路上的王蝦仁羹就是這樣的一家老店，專賣單一項美食「蝦仁羹」，其他什麼都沒有，進到店內也不必看牆上的菜單，只要跟老闆說要幾碗就行了。感覺和一些知名的蚵仔麵線店一樣，孤行獨市一品定天下，其實真正令人激賞的美味，就是這樣，也充滿老闆對自家美食的信心。王蝦仁羹在三重經營已經有卅幾年了，最早期第一代王老闆在大同南路開店，因房東收回店面，於是搬到介壽市場外現址，後來交由第二代的王家兄弟一起經營。由於王家的蝦仁羹光看尺寸大到要滿出湯匙的蝦仁，就令人大呼過癮，加上特調的羹湯，讓每個上門的客人都讚賞有加。王老闆一碗蝦仁羹裡，處處表現了主人對客人的用心，1碗50元的銅板價羹湯，用較深、較廣口的碗來裝，份量十足又實在，一碗下肚就讓人半飽了。','三和路三段86號','241',25.0717700,121.4945000,NULL,0.00,0,'ChIJt3Uz58ypQjQRQ23_rXgYbVI','2026-05-30 23:24:08'),(266,'蔥油餅的故鄉','可別以為「蔥油餅的故鄉」裡頭就只有賣蔥油餅，手藝了得的老闆朱耀輝，料理北方麵餅的技藝高超，從內含滿滿三星蔥花的蔥油厚餅，到鮮甜清爽的絲瓜湯包，嚐進嘴裡、滿嘴幸福。這裡的工夫菜也相當不得了，如軟嫩到位、入口即化的東坡悶肉，酸得夠味又有層次口感的酸菜白肉，以及椒鹽排骨、三絲拉皮等，大宴小酌都十分過癮。','萬板路59號','220',25.0219600,121.4713400,2,0.00,0,'ChIJKwGhgD6oQjQRdcv3JyGzNjo','2026-05-30 23:24:09'),(267,'蓮霧魯肉飯','民國64年開店至今，是三重地區頗富盛名的老字號小吃。有趣的店名來自於老闆綽號，原來老闆小時候抓周，抓到一顆蓮霧，從此有了「蓮霧」小名，長大後他賣魯肉飯，便乾脆引為店名。這裡的魯肉丁有瘦有肥軟爛且入口即化，店家並供應白菜滷、滷豆腐等入味的各式小菜，除了居民常來捧場，也是許多運將心中最愛的口袋名單。已傳承兩代的蓮霧魯肉飯，鄰近三重區公所，由於主要客層是以中年、從事較耗體力工作的勞工朋友為主，所以長久下來上門的顧客對店家料理的既定印象，就是\"呷粗飽\"，這點可以從代表小吃魯肉飯看得出來：米飯上頭的肉燥，以肥肉居多，香氣是不如其他著名老店，但是肥肉卻能提供勞動者所需的熱量，滿足\"粗飽\"的需求，曾被非凡大探索的運將美食報導過。','重陽路2段24巷13號','241',25.0627800,121.4862900,1,0.00,0,'ChIJE-vXReGoQjQRKfdtI0ir5Xo','2026-05-30 23:24:10'),(268,'輔大霜淇淋','來到輔大，當然不能不品嘗學生口耳相傳的知名平民美食。輔大食品科學系學生實習工廠熱銷廿幾年的霜淇淋，口感濃郁香甜，有巧克力、香草、綜合口味。','中正路510號','242',25.0346600,121.4344300,1,0.00,0,'ChIJO-jLdeinQjQRDemqu-me7BA','2026-05-30 23:24:11'),(269,'陶花園餐廳','走過輔大校門旁邊的中正路514巷，也是輔大學生經常光顧的地方，巷弄間非常的熱鬧，位於514巷的「陶花園」餐廳為一間老店，店內兼賣鮮花，講口味也要分量足，讓學生吃得飽，是男生尤其體育系學生的最愛。','中正路514巷7號','242',25.0327500,121.4330100,1,0.00,0,'ChIJW_GTjeinQjQRlDJT3cYbfJo','2026-05-30 23:24:12'),(270,'楊媽媽古早味','先嗇宮旁邊的「楊媽媽古早味」小吃店是婦人楊吳芙蓉與女婿合開，楊媽媽最早在先嗇宮旁插3支雨傘，擺攤賣滷肉飯、臭豆腐和大腸蚵仔麵線，因口味道地，因此吸引不少忠實的客戶，後來在先嗇宮旁買下店面，擴大營業。楊媽媽精心熬製的滷肉醬有股古早味，行家來此多會點碗滷肉飯，因為香嫩不膩口的滷肉與醬汁配上熱騰騰的白飯，讓人覺得很有飽足感，因此常常供不應求，後因應網路購物趨勢，女婿也把特製的滷肉醬做成真空包網拍，滿足無法親自一訪的饕客。','五谷王北街42巷14號','241',25.0491900,121.4753000,1,0.00,0,'ChIJzaPFaPaoQjQRJFSedGnWluE','2026-05-30 23:24:14'),(271,'阿爸的客家菜','最初在餐廳當學徒，學成之後，偶然之下回到家鄉吃到老一輩的客家菜餚，主要是家常小吃口味，心想為何客家菜無法被當成是餐廳料理。苦思很久之後，因此開始試圖結合經驗並改良傳統客家菜很油、味道偏重的缺點，配合現代養生食材的開發，務必讓客人吃得創新吃得健康。這一路走來，由高雄北上，選擇好山好水的三峽作為餐廳的據點，並以創新客家口味作為挑戰自我料理的極限，這樣的心路歷程，除了試圖保留客家傳統的味道，更希望將傳統客家料理創新研發。並將創新的客家料理推進新的領域。主要商品、規格說明：客家創意料理、客家料理、美濃粄條等','中山路118號','237',24.9358500,121.3658900,2,0.00,0,'ChIJ6xviC_AbaDQRKYlkjGLZyF0','2026-05-30 23:24:15'),(272,'白河阿婆碗粿、米苔目【復興店】','阿婆米苔目、碗粿的由來在以前台南縣白河鎮，有一個80歲以上的阿婆，推著車子在市場賣米苔目、碗粿已經50多年。沒有華麗的包裝，也沒有電視的報導，但只要吃上一口，就會被她的味道深深吸引住。彷彿回到古早年代，孩提嘻笑怒罵時的懷舊記憶一一浮現腦海。阿婆十分講求食物品質，絕不偷工減料或添加任何化學物品。「遵循古法、堅持手工」是阿婆的理念，在阿婆身上，讓人看到了老一輩臺灣人對吃的尊嚴與執著。但阿婆現在已經沒有在賣了，身體的老化，迫使她不得不放棄這項傳統的手藝。於是阿婆的碗粿、米苔目，也好久讓人吃不到。可惜的是，獨特的味道竟也隨著老人的凋零而消失。幸好，阿婆將做法傳授了下來，讓她不致遺憾，也讓這種味道得以重新在世上流傳，接續阿婆創下的米苔目、碗粿傳奇。主要商品、規格說明：米苔目、碗粿、肉粽','復興路51號','247',25.0870800,121.4757300,1,0.00,0,'ChIJfapu9cyoQjQRYWkvAs3Lo9Q','2026-05-30 23:24:16'),(273,'桐花鄉咖啡館','位桐花步道第二停車場旁的桐花鄉咖啡館，是登山客和賞花遊客力薦的半途休憩小站，咖啡館主人鍾媽媽，四年多前用自己的土地蓋了這間咖啡館，露天平台的咖啡座，5月時分，桐花隨風飄落肩上的悠閒，愜意、詩意滿分。在餐廳裡每一角度都能欣賞桐花染白山頭，享受視覺美學帶來的震撼，鍾媽媽美食手藝也是嚇嚇叫。其中拿手招牌菜「醬燒燉豬膝套餐」，用洋蔥、豬腱肉以慢火燉1小時，軟嫩的口感、香氣撲鼻入口即化的滋味，是店內第一人氣美食。此外「照燒豬排」燒得入味三分，清香微甜令人難忘。桐花鄉的菜色屬中西合併，滇緬知名菜色「椒麻雞」，鍾媽媽也料理得極讚，和月亮蝦餅搭配，有桐花步道上濃濃的異國美食風情。除了美食，咖啡和鬆餅也是出了名，鬆餅有蔓越莓、巧克力和楓糖等多種口味，午后時分搭一杯拿鐵、藍山、卡布奇諾，或者泡壺老人茶，坐在樹下享受徐徐涼風，沉浸桐花飄雪的氣氛，真是幸福滿滿。','承天路153號之2','236',24.9451400,121.4501600,2,0.00,0,'ChIJ-3jnzNMcaDQRYc-Cr6gp2fo','2026-05-30 23:24:17'),(274,'南川麵館','位在永和區公所旁的南川麵館，在永和是老字號的川味麵館，在新店、臺北市和平東路也有分店，創立迄今已近40年。南川麵館和一般現代重視裝潢的麵館不太一樣，一走進店內一種民國六十年代的老氛圍就讓客人感受到一種即將嚐到古早味的期待。南川麵館的麵條口感比一般的麵更帶點Q感嚼勁，搭在各種湯頭裡，不論是牛肉麵、蹄花麵、榨菜肉絲麵等，都能呈顯出一種相融的完美。','竹林路208號','234',25.0084000,121.5206700,2,0.00,0,'ChIJHZK6xe6pQjQRk6bIug7qhts','2026-05-30 23:24:19'),(275,'雪花軒涼麵','在新店與老孫涼麵齊名的雪花軒，也是當地美食行家力薦的涼麵名店，兩家店賣的涼麵和產品大同小異，卻各有死忠的美食粉絲。雪花軒最受歡迎的美食除了涼麵之外，熱湯和炒麵、炒米粉古早味的口感，也很受老饕的喜愛。雪花軒涼麵口感綿軟富彈性、味香而不膩，老闆將麵條抓入盤子裡，再淋上香濃的麻醬，與小黃瓜絲搭配，一起拌勻後讓麵條與麻醬相融，麵條微Q彈、有嚼勁，芝麻醬和各種味道交相掩映，真是妙不可言。','中正路96號','231',24.9705400,121.5434500,1,0.00,0,'ChIJX7GRg_MBaDQRpl4OZWLey4A','2026-05-30 23:24:20'),(276,'彼得公雞地中海料理','位於土城巷弄內的彼得公雞，因老闆英文名字叫Peter，店內擺放許多他多年來收集的公雞造型藝品，客人邊享用美食，還同時欣賞手工藝品帶來的驚喜感。由於這裡內部有著浪漫的情調，享譽北臺灣的極品鹽烤牛排也深受老饕推崇，特殊假日和情人節，沒先預訂位子，就只能排隊了。店內的開胃菜沙拉，吃來令人心曠神怡，特調的地中海油醋醬和法式芥末醬兩種，異國風情任客人自選。法式焗烤田螺已經去殼，包在香濃的起司裡一起烤，表皮金黃酥脆，裏面的田螺鮮美和起司的香濃，好吃到不行，田螺的Q彈嚼勁很讚，搭配切片的法式麵包一起吃，更是爽口不膩。湯品有法式蔬菜湯和奶油蘑菇濃湯等選擇，田園風味的法式蔬菜湯，吃得到蔬菜的原味新鮮口感；奶油蘑菇湯適合口味較重的美食客，蘑菇鮮美滑嫩值得一嚐。','裕民路92巷16弄2號','236',24.9865900,121.4499000,2,0.00,0,'ChIJ-xfWycsCaDQRiQPA6N9VmCY','2026-05-30 23:24:21'),(277,'三重彭園','有「湘菜之神」稱號的彭園老闆彭長貴，善用食材、廚藝精湛，呈現湘菜的豐厚細緻的面貌，內蘊百年的美食傳承下，對料理更是十分講究，「食不厭精，膾不厭細」的料理宗旨，更達食之藝的境界。湘園的年菜和一般坊間冷凍年菜不同，道道菜色新鮮現做、熱菜上桌，以單點自由配方式，讓美食行家們有多種選擇。','龍門路6號3、4樓','241',25.0713400,121.4947500,2,0.00,0,'ChIJcTrd-iapQjQRO64QlPueKV0','2026-05-30 23:24:22'),(278,'永和周家年糕','永和區早年因大陸來臺軍公教人員多，眷村菜、年糕等各式外省料理十分出名，提起年糕，位於大陳眷村的周家年糕更是新北市年節必嚐美味。歷史悠久的年糕老店內，一年到頭，蒸籠幾乎從未停過，熟客一個接一個地上門，除為這難忘的大陳年糕，還有因應大批韓僑客人製作的韓國年糕。周家的大陳年糕口感Q滑，通常會與其他美食一塊兒拌炒，製作過程十分費工；將蓬萊米浸泡後，經磨漿、壓乾、碾碎，最後進入特殊的蒸籠蒸熟、拌勻，接著再塑形、陰乾。除了買美食，光站在店門前看著蒸製年糕的過程，也是非常有趣的體驗。','文化路173號','234',25.0167600,121.5098400,1,0.00,0,'ChIJucTav8CpQjQRtsYBYRzTrzw','2026-05-30 23:24:23'),(279,'新莊燒肉店','新莊區場內超人氣的熟食名攤「新莊燒肉店」，位置就在阿寶燒雞對面，其實這兩家店是一家人，老闆葉光裕是李寶貴的兒子，都在市場賣熟食，一攤賣燒雞、一攤賣燒肉、雞捲、雞翅和排骨酥，兩攤成了市場裡的美食指標。逾30年的老經驗，傳承自「東寶食堂」阿公的手藝，紅燒肉非常美味，每天一開店做生意，一旁的油鍋就滋滋地炸個不停，好應付不斷上門的熟客。','新莊路315號1樓','242',25.0340100,121.4534400,2,0.00,0,'ChIJV9xXikGpQjQRbIPnh_6J1ak','2026-05-30 23:24:25'),(280,'巨佳食品','在新莊區場經營超過35年的山海肉鬆，在消費者口中是山珍海味都有的地方，也是市場裡老字號的肉鬆、肉脯、肉乾名店，許多新莊上了年紀的鄉親，對山海的產品讚不絕口，直誇這古味依舊，連移民國外的老主顧，回國都不忘來找回熟悉的美食記憶。','新莊路315號1樓','242',25.0340200,121.4534400,NULL,0.00,0,'ChIJGSjSp3OoQjQRiQIhH0tSno4','2026-05-30 23:24:26'),(281,'龍鳳肉攤','攤舖前人潮絡繹不絕，老闆忙的不可開交，周老闆經營攤舖逾30年，上門的都是認識十年的老主顧，特別選用新鮮無腥味的母豬肉，每天至少賣出四頭以上，「新鮮、信用、童叟無欺」是周老闆自豪的經營之道。','新莊路315號','242',25.0340200,121.4534400,NULL,0.00,0,'ChIJhU8vewCpQjQRsGvFHrFIE2s','2026-05-30 23:24:27'),(282,'新味香肉鬆攤','魚鬆、肉乾、花生...新味香肉鬆攤上各式商品琳瑯滿目，為了讓客人吃到最好的肉鬆，陳老闆用料紮實，堅持親手炒製，用心的美味讓客人一吃就是數十年。陳老闆相信只要東西好吃，價格實在，客人就會不斷回籠。','新莊路315號','242',25.0340100,121.4534300,NULL,0.00,0,'ChIJ1VT5IcKpQjQR_ralTrzxQ5c','2026-05-30 23:24:27'),(283,'全味香肉鬆','全味香肉鬆是民享市場裡的老字號名攤，以肉鬆、肉條、肉干和肉脯等全系列商品最受消費者歡迎，其中肉鬆的美味更受到早餐店主的喜愛，專程來此採購。細膩的口感、溫綿細軟的滋味，連小孩子都愛吃，四溢飄散的香味，讓整個市場都充滿香氣，一走過攤子前，都不禁想停下腳步買來嚐嚐。','民享街37號民享市場88號攤','235',25.0035500,121.4741200,NULL,0.00,0,'ChIJ-bbsdZ4CaDQRHMu8aD_Koww','2026-05-30 23:24:28'),(284,'泰山李記胡椒餅','不到兩坪大小的店內，放著兩個烘烤胡椒餅的大缸甕，是老闆親手用火山土捏塑而製造而成，胡椒餅口感香酥不膩，皮薄酥脆，肉多味美，內餡是精選新鮮的豬後腿肉加青蔥、胡椒和獨門辛香料配方，讓人一口接一口。','泰林路二段216號','243',25.0618000,121.4328000,1,0.00,0,'ChIJaRKsIjKmQjQR0iWgteymT5s','2026-05-30 23:24:30'),(285,'茶鄉園','茶點種類繁多，也是坪林最大的茶點製造廠，像是茶蛋捲、茶糕、茶方塊酥、茶餅、茶糖等等不同口味茶點。茶葉蛋捲「以茶入菜」可說是坪林在地美食的特色，遊客來到坪林都能大快朵頤一番，近來當地商家還研發出茶葉蛋捲，廣受消費者歡迎。融合茶香的蛋捲，吃起來仍舊蛋香十足，其間還不時滲出清爽的茶香味，讓蛋捲吃起來更加爽口。當地一推出茶葉蛋捲，立刻引起遊客趨之若鶩，可說是繼包種茶葉之後最受歡迎的伴手禮！','北宜路八段223號','232',24.9350500,121.7088900,NULL,0.00,0,'ChIJRf_gxPn_ZzQRovBu5Wvo3yA','2026-05-30 23:24:31'),(286,'十方茶食料理','老闆將日本懷石的禪風意境，運用在店內的茶食式伴隨著季節，而有百多種口味，任食客選擇。','北宜路八段219號','232',24.9350000,121.7087700,2,0.00,0,'ChIJO5yfXE__ZzQRdniI88vMsA4','2026-05-30 23:24:32'),(287,'鶯歌香香水餃館','老闆現場手工製作，大顆厚實飽滿的韭菜水餃，以新鮮韭菜與豬肉為內餡，味道鮮甜。','南雅路37號','239',24.9541900,121.3488600,1,0.00,0,'ChIJd1c5-qseaDQRfFwWyTiCpNE','2026-05-30 23:24:33'),(288,'托洛閣阿嬤','經營以烤香腸、炸溪蝦、小香魚為主的小吃店，竹筒飯是她親手拌炒配料蒸煮，地瓜餅也是手工料理。每天早上10點半左右，兩三位已是「托洛閣阿嬤」級的姊妹淘會聚在這裡，向看完舞蹈演出的觀光客，兜售檀香扇、泰雅編織手機吊飾。經營以烤香腸、炸溪蝦、小香魚為主的小吃店，竹筒飯是她親手拌炒配料蒸煮，地瓜餅也是手工料理。每天早上10點半左右，兩三位已是「托洛閣阿嬤」級的姊妹淘會聚在這裡，向看完舞蹈演出的觀光客，兜售檀香扇、泰雅編織手機吊飾。','瀑布路1-5號','233',24.8478400,121.5513400,NULL,0.00,0,'ChIJzTd7fW8GaDQRJ5TAAudsejs','2026-05-30 23:24:35'),(289,'佳宜肉粽-鵪鶉芋香粽','已經由第三代接手的佳宜肉粽，是樹林區老字號的肉粽店，陳家以令人懷念的北部粽口味，讓美食行家們每到節日，總會再回來嚐嚐各式肉粽美妙滋味。佳宜的招牌粽之一「鵪鶉芋香粽」是內行人才知道的佳品，有別於市面上的內餡，幾十年古早手路的傳承，將鵪鶉蛋、芋頭、五花肉、菜脯、香菇、土豆、栗子、櫻花蝦一起入味，和來自彰化頂級糯米拌炒後再蒸，淳和的食之極味，老饕無不說「讚」！另外，佳宜肉粽的肝腸香筍粽，精選糯米、臘腸、肝腸、土豆、香菇、筍干、金鉤蝦為內餡，也是人氣美味之一。如果喜歡客家口味，客家魷魚粽以魷魚絲、金鉤蝦、香菇、豆干、筍干入餡，一定要嚐嚐。香酥魚干粽和臘肉香筍粽也是市面少見的美味，老饕們可先預訂，端午節前就會宅配到府。已經由第三代接手的佳宜肉粽，是樹林區老字號的肉粽店，陳家以令人懷念的北部粽口味，讓美食行家們每到節日，總會再回來嚐嚐各式肉粽美妙滋味。','佳園路三段101巷62弄10號','238',24.9378000,121.3777500,NULL,0.00,0,'ChIJOa-rsWQcaDQRXnsNsJlkNBI','2026-05-30 23:24:36'),(290,'福美軒金牛角','牛角麵包可說是三峽地區最具代表性的伴手禮，三峽區場裡的福美軒，以手桿麵皮烘烤出外層酥脆、內裡柔軟的口感，入口還帶著濃郁的奶香，相當受到歡迎！','信義街25號','237',24.9354300,121.3710100,1,0.00,0,'ChIJOw06ifEbaDQRnmM31oCYKB0','2026-05-30 23:24:37'),(291,'樂山莊','位於新店烏來風景區，店內推薦特色美食為大閘蟹、鱒魚、苦花與鱘龍魚等，另外也有供應土雞、山上的山產及野菜還有許多美味的料理。','福山里屯鹿71號','233',24.7918600,121.4924800,2,0.00,0,'ChIJT_ul4I8OaDQRBZv6j30nZos','2026-05-30 23:24:38'),(292,'漁村活海鮮','魚村海鮮餐廳，證書編號：03-00144，聯絡電話：02-2492-1046','野柳里港東路74之6號','207',25.2052000,121.6892300,2,0.00,0,'ChIJocywKHdMXTQRswFtt0Cvu_o','2026-05-30 23:24:40'),(293,'碧利咖啡','進到寬敞的「碧利咖啡」，想喝一杯極品咖啡？那就一定要先認識黃氏父子。黃重慶先生在咖啡界有三十幾年的經驗，是臺灣數一數二的大咖啡商，從大量的批發到限量的精品咖啡，都可以在他的「碧利咖啡」找得到。而且物美價格合宜。','中山路二段315巷2號7樓','235',25.0017300,121.4940200,NULL,0.00,0,'ChIJAbAlddWpQjQRVJ9zljJgwSE','2026-05-30 23:24:41'),(294,'海洋城活海鮮','在澳底海鮮街上赫赫有名的海洋城活海鮮餐廳，宛如東海龍宮般鮮紅色的兩層樓建築，讓路過的老饕們過目不忘。這家已有廿幾年歷史的老牌海鮮餐廳，以新鮮活跳海鮮料理聞名，外面一整排的玻璃養殖箱，客人還沒進門就感受到豐盛海之宴的期待。海洋城以東北角的龍蝦、活海鮮及蔥燒海鰻聞名，其中龍蝦以清蒸後沾醋汁入味風味最佳，也是行家們宴客的必點頂級食材。而另一道招牌蔥燒海鰻，則是將海鰻魚先下油鍋酥炸後，再快炒主廚特調的蔥燒醬，形成一種特殊風味，吃起來濃郁酥香、鹹鹹甜甜，嫩細軟酥的口感老饕們一致推薦，還有很多內行人直誇，每次來每次點都不嫌膩。','仁和路164號','228',25.0520500,121.9234100,2,0.00,0,'ChIJTbU9Sb9cXTQR-G_8HuWP7_E','2026-05-30 23:24:42'),(295,'筒簫魯麻糬','位於樹林夜市博愛街裡的筒簫冰城，是許多樹林、板橋溪崑居民半世紀的美食記憶，第二代老闆陳昆宏接手後從年輕賣到現在，用料實在、新鮮，烹煮功夫到家，不論是冬天才賣的「魯麻糬」，還是夏天超夯的紅豆牛奶冰、芋頭牛奶冰，緊緊抓住老饕們的味覺，加上仙草在季節上做成燒仙草和仙草冰，一旦嚐到這變化無窮的滋味，就永生難忘。','博愛街168號','238',24.9908000,121.4259000,NULL,0.00,0,'ChIJYz2PKtsdaDQRoy3w3E785wU','2026-05-30 23:24:43'),(296,'八廚小籠湯包脆皮鍋貼','「八廚」是在地人及橋對岸世新大學學生心目中地美食饗宴名店，這裡的上海點心道地又夠味，老闆苦心專研的烹調技法，不僅彰顯了江浙美味的殊勝，也讓許多愛挑嘴的饕客們，找到了一個解嘴饞的好地方。八廚最著名的招牌美味正是名聞遐邇的爆漿湯包，之所以取名「爆漿」就不難得知這湯濃味美的鮮滋味是多麼誘人，每次一上桌老闆娘還不厭其煩地提醒客人小心燙嘴。嚴選黑豬胛心肉製成的湯包，受、肥達到七比三的完美比例，無筋、肉質彈又滑嫩，還無任何腥味，這人間好味果然吸引了臺北市的老饕們也過橋來嚐。','順安街79號','231',24.9870400,121.5407000,1,0.00,0,'ChIJ19-xWf4BaDQRFsgmFIV9gGg','2026-05-30 23:24:44'),(297,'準休閒農場','這處大臺北地區唯一坐落於都會區內的合法休閒農場，就在高速公路五股交流道旁，由萬海航運董事長陳朝亨為紀念母親李準女士所創辦。這裡的美食走南洋泰國菜風格，其中最受歡迎的熱門美食，就是泰菜招牌「椒麻雞」，用鮮嫩的雞肉高溫油炸讓外皮呈現酥脆感後，再淋上主廚特調的醬料，花椒的香氣飄散引人食慾。而另一道人氣美食，是主廚親自調配的紅咖哩鮮蝦麵，味道濃郁、香味誘人的經典美食，紅咖哩跳脫一般日式的料理法，採泰式風格製作，將麵條和鮮蝦放入紅咖哩中，味道令人懷念再三。還有一到歐風的拿坡里海鮮麵，是主廚將泰國盛產的鮮濃椰汁，與海鮮一起調和，包括透抽、蝦的甜味，還有香茅的清香，很適合闔家來品味的好料理。','新五路二段70號','248',25.0738800,121.4383800,NULL,0.00,0,'ChIJY6zDoSOmQjQRKP45yh55QA0','2026-05-30 23:24:46'),(298,'異嗑堂','kooks 是由一對熱愛旅行並熱衷於人文藝術的夫妻所開的異國料理美式餐廳。這裡的每一種醬料、每一道菜及每一張掛在牆上的畫，皆是百分之百手工的，這也是他們引以為傲之處。kooks的餐點種類豐富，首先在漢堡類：麵包是由一位德國師傅手工製作，口感外酥內軟十分帶有嚼勁，塗上進口奶油，置於石板上烤至均勻，再配上加拿大主廚以北美口味調製成厚度3公分的牛肉堡，加上鮮蔬最後搭配雙倍脆薯，十分過癮！在捲餅方面：約30公分長的薄餅捲，上一層kooks特調香料飯、一層沙拉、一層kooks特調天堂醬料、一層無敵美味的主食、兩層濃厚的澳洲進口馬茲瑞拉，美味無人可擋！歡迎您前來體驗kooks道地且多樣化的異國美食!','仁愛街18巷12號1樓','251',25.1702600,121.4469900,2,0.00,0,'ChIJFyMs8vevQjQRQh96l36Zua0','2026-05-30 23:24:47'),(299,'鴻興土雞城','擁有三十餘年歷史的鴻興土雞城，座落在觀音山凌雲禪寺石階入口處，保有最傳統的在地特色，熱情好客李老闆烹調著遠近馳名的山雞料理，招呼假日遠道而來的客人們，而其中最為人稱道的便是筍仔雞。使用觀音山每年5月到10月出產的綠竹筍，以及硬漢嶺純淨的山泉水熬煮，使鴻興自家飼養的土雞多了一絲甘甜與清香。','凌雲路三段100號','248',25.1228600,121.4268800,2,0.00,0,'ChIJ3dj3BY2lQjQRbvwLzdpTuHE','2026-05-30 23:24:48'),(300,'海倫咖啡烏來館','海倫咖啡烏來館依山畔水,坐擁山水橋邊,是烏來唯一露天咖啡店,座上客清風微薰,相伴醇香咖啡,浪漫爵士音樂,不論是享片刻歇息,或作半日悠閒,都是人生絕佳快樂！','溫泉街86巷1號及3號','233',24.8613200,121.5502400,2,0.00,0,'ChIJz41IR4gGaDQR0Y8FtD956nw','2026-05-30 23:24:49'),(301,'蔡家排骨飯','位於板橋福德街的蔡家排骨飯從民國67年營業至今已有三十幾年的歷史，蔡老闆說','福德街30號','220',25.0084500,121.4559600,NULL,0.00,0,'ChIJK_m0FqgCaDQRk92O3cCMZyQ','2026-05-30 23:24:51'),(302,'錦興園休閒餐廳','位於平廣溪旁的錦興園休閒餐廳，主打自製雞料理以及甲魚料理，這家美食名店從裡到外、從美食烹調到外場服務都是老闆一家人。有山、有溪的大自然美景為錦興園吸引更多遊客，夏日可以玩水、餐廳周邊還有小溪，大朋友可以帶著小朋友在溪邊嬉戲，抓小魚小蝦。','平廣路一段182號之一','231',24.8888900,121.5161400,2,0.00,0,'ChIJIYfulBUEaDQRy0hUwXSidQM','2026-05-30 23:24:52'),(303,'大胖烏醋乾麵','已經在三重屹立快廿年的大胖烏醋乾麵，向來是運將大哥們中午停歇、嚐一頓銅板美食的好所在，主要是老闆、老闆娘親切的招呼，和那一碗令人回味的烏醋乾麵，簡單中又帶有很深的美食技藝，只要花個幾十元就能嚐到這三重埔難得的庶民美食。','光復路一段138號','241',25.0528800,121.4719900,1,0.00,0,'ChIJ28OKevSoQjQRrkf2VqUVq7A','2026-05-30 23:24:53'),(304,'周家祖傳烏醋乾麵','這家位於土城區明德路、仁愛路口的周家祖傳烏醋乾麵，雖然開業僅一逾年，但因為老闆周連春十幾年製作小籠包排隊美食的好功力，對各家美食也有獨到的鑽研，因此在乾脆在土城自己開店，除了原本就拿手的小籠包，再加上用老醋調和出令人感動的烏醋意麵，不僅是當地居民最愛品嚐的小吃，連許多美食行家也聞風而至。','明德路一段164號','236',24.9784200,121.4628500,1,0.00,0,'ChIJ9V0qgMQCaDQR0Rpdt2XE_Fo','2026-05-30 23:24:54'),(305,'松柏園餃子館(林松柏園餐廳)','\"林松柏園餐廳，是在地30年以上的老店，當選過新北市特色餐廳。老闆娘從10坪小店，開到如今還要開發票的200坪水餃特色餐廳。招牌韭菜水餃採用三峽黑毛豬，產地直送新鮮韭菜，加上數10種獨特秘方而成。靠近明德中學附近，擁有2個超大停車場，是你工商聚會，大宴小酌的最佳選擇。\"','中正路二段414號','237',24.9083500,121.3649600,2,0.00,0,'ChIJuQbrENIbaDQRVcj0clKkb94','2026-05-30 23:24:56'),(306,'阿拉拍奇早餐店(新北瑞芳店)','「阿拉拍奇」的這四個字，是從台灣原住民語言裡的字音所翻譯過來的，在原住民語言裡他的意思是指「錢來吧」招財的意思，使用阿拉拍奇作為店名，是希望錢來吧!賺錢喔，發大財!另外將原住民語言的音寫成國字「阿拉拍奇」四個字，是因為這四個是的筆劃都為八劃，數字的「8」，將之橫的來看則會變成符號裡的「∞」(無限大)，也代表的希望營業長長久久，生意興榮喔!','明燈路一段171號1樓','224',25.1074800,121.8192500,NULL,0.00,0,'ChIJUbB3CltFXTQRckvWNNC_lHk','2026-05-30 23:24:57'),(307,'豬二哥現烤芝麻杏仁豬肉干','我們主要產品有芝麻杏仁豬肉脆片.及蜜汁厚片..脆片有:原味.黑胡椒.辣味三種....蜜汁厚片:原味.黑胡椒.及泰式檸檬..      雖然我們剛做這行業不久..但是.我們極為重視產品的品質.其實.芝麻杏仁豬肉脆片有些傳統肉鬆店也有兼著在賣.或許並非是主打商品.所以在口感品管方面也就沒那麼重視!      因為芝麻杏仁脆片.較易受潮..因此在製作及包裝上要特別注意.爲了維持其脆片口感及應有特色..豬二哥在包裝材料上..使用食品安全等級專用的包裝盒..及防潮系數高達95%的自家專用包裝袋..以維持脆片最佳的鮮度及口感!      我們家的產品已通過SGS檢驗合格(八大檢驗合格)..及投保1000萬產品責任險!請各位喜愛豬肉脆片的朋友.安心食用!','新莊路14-2號','242',25.0376800,121.4590100,NULL,0.00,0,'ChIJswrFfJ2pQjQRY-F7O0tGfxc','2026-05-30 23:24:58'),(308,'龍鳳堂餅舖','由李壽夫所創的傳統糕餅鋪，總店位於中正路，分店在中山二路，創立至今逾五十年歷史，除製作有臺灣古早味訂婚喜餅及婚喪喜慶所用之紅龜粿等傳統糕餅，店內也提供有關傳統訂、結婚禮俗諮詢服務並與淡水知名三協成糕餅鋪同為祖傳行業。','中正路49號','247',25.0825500,121.4709300,2,0.00,0,'ChIJSedddsioQjQRuc_tRL6HWtg','2026-05-30 23:24:59'),(309,'吾穀茶糧 SIIDCHA','客家諺語句話：「每天三碗擂茶、保您活到九十八」。為傳承客家擂茶文化，吾榖茶糧創辦人走訪全台客家庄，發揮實驗室不屈不撓的研究精神，將茶葉磨成超微茶粉的喫茶「食茶」方式，為客家人招待貴賓茶點「擂茶」注入與時俱進的嶄新元素，並以廿多種穀物創造多樣化口味，希望以天然、養生為出發點，傳遞出大地穀物的純淨滋味。本店座落於基山街底，一棟面海簡約俐落的人文時尚建築，素雅內斂的風格，讓遊客賞景看海之餘可以沉澱思緒；在這裡可以享受到各式各樣天然養生的擂茶、抹茶蒸菁綠茶、五穀飲品及伴手禮。到老街一定要來吾穀茶糧(九份食茶館)，品嚐最屬於大地樸實的原味。','基山街166號','224',25.1079000,121.8431900,2,0.00,0,'ChIJgehLZj1FXTQRzhzY5WjKKsU','2026-05-30 23:25:00'),(310,'麒香豆干店','麒香食品位於新北市瑞芳區的九份山城老街入口處，已在此為九份遊客服務多年，秉持一貫理念，不斷研究創新，為大家推出傳統手工素豆干，口味獨特、種類繁多，相信是您旅遊的最佳伴手禮。麒香食品：麒香豆干菩提素、梅子系列、薑母茶、海燕窩、為團購首選的台灣特產。不論您是要現吃或買回去吃、送禮，都是您最佳的選擇；菩提素傳統純手工精製，全素食，配製獨特的原料，以精進的技術製成獨特的口感，口味與眾不同，香Q適中，老少咸宜，都是當零食或下酒菜的最佳良伴。','基山街7號','224',25.1096200,121.8453600,NULL,0.00,0,'ChIJedHWVNpFXTQRX-xVt88OAgM','2026-05-30 23:25:01'),(311,'極北藍點','位於台二線23.5K白沙灣旁，原為海巡廢棄營舍。「極北藍點」左擁麟山鼻右抱富貴角，面臨大海，景觀條件極佳，邀請在地藝術家舉辦藝文展覽，於每週日舉辦文創小農市集，透過一系列的活動協助在地文創品牌發展，打造北海岸在地人文新據點，增進北海岸文創藝術的能見度。原為北海岸更是重要軍事要塞，交通部觀光局北海岸及觀音山國家風景區管理，而在2016年10月中旬完工。因座擁台灣最北邊，將此景點命名為「極北藍點」。2017年9月，由米詩堤甜點王承接經營','頭圍段八甲小段1-101號','253',25.2856400,121.5234600,2,0.00,0,'ChIJN2f378i1QjQRyFHop9oQW04','2026-05-30 23:25:02'),(312,'柴米夫妻中式麵館','品牌宗旨：源自於最高品質理念製作，重新定義傳統料理新食代。柴米夫妻創始於2013年，以網路冷凍調理食品為主，被多家媒體報導採訪過，就在今年2019年，終於達成線上線下整合的目標，首家實體店正式登場。從原本網路購物到實體超市，從國內市場拓展到海外（上海/香港/澳門/美國/澳洲），今年更聘請榮獲多項殊榮的主廚於淡水老街開設第一間中式麵館，裝潢走輕工業風，主打台灣特色料理：牛肉麵/山東燒雞/蔥油餅/珍珠奶茶…等，歡迎各位來淡水旅遊的朋友，可以來店體驗。','中正路326號','251',25.1730200,121.4362000,2,0.00,0,'ChIJW6ntQwqlQjQRHhws_KRo4rE','2026-05-30 23:25:03'),(313,'九嬸婆古早味豆花','位於淡江大學旁的這家「九嬸婆古早味豆花」開業於民國97年，專營30年代挫冰、古早味傳統豆花，風味樸實卻相當受當地人及學生們歡迎。店內吃得到少見的月見冰、四果冰、雪花冰，也有手工愛玉、米苔目等，網友們笑說這裡的冰吃著吃著感覺彷彿回到了童年。夏天來上一碗清涼解暑的冰超級暢快，冬天則強烈推薦店家的黑糖燒麻糬，在糖水裡熬得甜蜜蜜軟呼呼，裹上香濃的花生粉就是暖心暖胃的下午茶，或者來碗紅豆湯、薑汁地瓜也都超美味喔！','北新路182巷21弄20號','251',25.1771800,121.4485700,1,0.00,0,'ChIJq57K5f6vQjQRxFLGOIL4FzM','2026-05-30 23:25:04'),(314,'Dave & Jess 大衛潔希市集餐廳','大衛潔希位於新北市淡水區，臨近淡海輕軌竿蓁林站，結合在地小農的複合式餐廳經營，餐點提供沙拉、手工漢堡、豐富的早午餐、創意義大利麵/燉飯、咖啡以及手作甜點，餐點現點現做，不做過多的調味、不添加味精。因為新鮮，所以美味，更能兼顧營養、健康、環境友善的理念！','坪頂路40號2樓','251',25.1622000,121.4575000,2,0.00,0,'ChIJi8IvZsKvQjQRklJOEc2pvKM','2026-05-30 23:25:05'),(315,'BUTTERFLY 1 夏威夷豆塔/黑熊堅果塔','BUTTERFLY 1       是糕餅與台灣伴手禮的品牌以甜點食茶傳達美好的日常生活美學與糕餅的款款相待更是人文、風土、山林的文化媒介。2022 英國世界柑橘果醬大賽       玫瑰花香柑橘-銀獎','文昌街5號1樓','220',25.0101200,121.4559600,NULL,0.00,0,'ChIJhfGg4AepQjQRF7RK-y5smNE','2026-05-30 23:25:07'),(316,'特香齋西餐廳','已有近40年歷史的特香齋原本是板橋知名的糕餅店，後來延伸發展至西餐，在新北市西餐界是美食指標名店之一，在當年也是「新北市」第一家高級西餐廳。知名紅星剪綵和名人雅仕的推薦，逐漸擦亮餐廳的金字招牌。優雅氣氛的用餐環境、獨步全臺的百萬音響，加上主廚用心推陳出新的美味菜色、新鮮食材與口感的堅持，各式排餐光看圖片都令人垂涎。最特別的是特香齋的牛排作法，引進美國Moneatue專業牛肉烤爐，以環繞烤箱華氏1800度的高溫燒烤，肉汁完全鎖住不外流，形成一種特殊軟嫩口感。不論前菜、排餐、點心，店家的用心還曾經獲得臺灣省優良宴席餐廳獎、全國第一屆餐飲評鑑會總金牌獎等獎項。特香齋的德國豬腳皮脆肉嫩，搭配主廚特調的醬料，更能吃出豬腳的美味。 資料來源:新北市美食吃透透九月號','中山路一段26號2樓','220',25.0083800,121.4603900,3,0.00,0,'ChIJ2Qlwhx2oQjQRJ5_cYW7kQ5k','2026-05-30 23:25:08'),(317,'紫藤花藝村','山間餐坊‧溫馨聚餐座落於新北市八里區觀音山區的紫藤花藝村，由原木、花草、涼傘等元素所營造出的山間小屋形象，給人猶如童話故事一般的溫馨氣氛！紫藤花藝村經營團隊嚮往恬靜的山林田野生活，供作餐廳食材的文旦柚、黃金筍與地瓜葉等均為自家種植，吃得到健康美味！大廚坐鎮、老饕推薦遠離喧囂城市的紫藤花藝村，餐點品質可是有都會等級的高水準！紫藤花藝村主廚曾於知名餐廳任職，擁有十多年專業廚藝的他，精通中菜、海鮮、粵菜等料理，甫開幕，精湛手藝，已受到許多老饕的肯定，值得親嚐！入園資訊：免門票。','荖阡坑路6鄰69-1號','249',25.1253300,121.4066300,2,0.00,0,'ChIJocEh5MmlQjQR18DzOGpMApc','2026-05-30 23:25:09'),(318,'厚道飲食店','科技進步、資訊爆炸的時代，四、五０年代，臺灣經濟起飛時期的光景，有著濃厚人情味與樂天知命生活的氛圍，讓走過那時代的人們是格外懷念！為了替三、四年級生等同父執輩的民眾，尋回那一段漸被遺忘的時光，七年級的孫先生特別開設厚道飲食店，將自己鍾愛的老東西運用超過１０年的設計功力打造一間民初復古主題餐館，店外，一部三輪車、店內，一隻臺灣黃牛標本，搭配排骨飯、雞腿飯、醬筍肉片湯、地骨露等傳統美味，從空間到餐飲都致力讓顧客彷彿進入時光隧道，重溫兒時回憶！與孫先生一樣醉心懷舊臺灣的民眾，厚道飲食店值得你參訪！','尖山埔路79號','239',24.9509400,121.3477900,1,0.00,0,'ChIJG6UhkKweaDQRktWh7YCPZBI','2026-05-30 23:25:10'),(319,'東道飲食亭','東道是三峽仁愛老街上知名的復古餐廳，老闆雖然很年輕，但老舊的四、五十年家居擺設，老電視、老電影海報、老汽水瓶、轉盤式老電話，一種濃濃的懷舊風油然而生，也勾起許多人的幸福回憶。店外頭有輛非常古味的三輪車，已成為三峽遊客拍照的重要場景。店內最有名的就是香傳千里的排骨飯和焢肉飯，尤其坐在老黑白電視機前吃排骨飯，那種早年和家人一起吃飯的鄉愁又再度被挑起。東道的排骨飯肉大塊、處理得又極細緻，嚴選三峽在地黑豬肉，搭配店內的精緻小菜，吃巧又吃飽，很令人回味。除了排骨飯，人氣香酥雞腿也是東道亭的招牌之一。排骨飯、雞腿飯、焢肉飯等美食外，也有各式麵點，來逛老街絕不能錯過。','仁愛街7號','237',24.9340400,121.3685100,1,0.00,0,'ChIJK6QlK-4baDQRLEMNGd26des','2026-05-30 23:25:11'),(320,'豆花工房','位於新店光明街上的「豆花工房」，於2007三月份正式開幕，由一對夫妻白手起家、共同創業。店面充滿中國風的設計感，加上燈光與掛飾搭配，讓簡單的豆花店，看起來更具都會時尚感。兩夫妻當初在摸索創業的過程中，不但吃遍北部的豆花店，回家後一一研究並尋找好的食材，花了不少功夫與時間，堅持要給顧客最好的口感。加上自己的創意，兩夫妻研發出獨一無二的「黑豆花」及「抹茶豆花」，成為開店後的人氣暢銷單品。無論是夏天或冬天，豆花工房也推出雪綿冰、燒仙草等不同的季節商品，兩夫妻的用心經營，值得您的品嚐與肯定。','光明街272號','231',24.9641900,121.5404400,1,0.00,0,'ChIJD-j3yIsBaDQRCEdRh91KMa0','2026-05-30 23:25:13'),(321,'亞米小鎮','蘆洲長榮路這個新興餐廳興盛的地段，有一間具西班牙鄉村風格的西餐廳「亞米小鎮」，西餐廳在蘆洲相當少見，亞米小鎮便成為上班族品嚐下午茶、親子聚餐的新選擇。經過老闆娘具有巧思與創意的DIY，亞米小鎮呈現典型的西班牙式鄉村風格，讓顧客一走進便能感受到與眾不同的氣氛，邀請知名五星級飯店主廚掌廚，推出一系列美味價格又實在的西式餐點。來到亞米小鎮，不光只有裝潢氣氛讓您喜歡，一系列的美味餐點、服務人員的親切，亞米邀請您前往品嚐用心。推薦菜色:厚切牛排、香料烤半雞','觀海大道29號','247',25.1604800,121.4293500,2,0.00,0,'ChIJqd8cxBSlQjQRUiPH76uh5wg','2026-05-30 23:25:14'),(322,'郭全福餅店','淡水郭全福囍餅從西元1968年創立至今，已經有逾四十年歷史，招牌是又酥又香的蛋黃芝麻餅，每到訂婚月份總是搶購一空，現老闆更推出多種口味酥餅，像是干貝、海鮮、巧克力、咖啡等，創新不失傳統，堅持以高品質安佳奶油烘焙，給你滿滿的祝福。國小就開始學做糕餅的郭老闆說，四十年來他們一直堅持每天生產，決不用防腐劑，讓客人吃得健康，尤其像招牌芝麻蛋黃，更挑選漂亮雪白的芝麻，蛋黃烤熟後，還會浸泡去腥增添風味，耗工費時、真材實料，也讓許多客人呷好逗相報，未來還會在第二代三個兒子的交棒下更加努力，創造老店的新歷史。推薦產品:蛋黃芝麻餅','中山北路一段61號','251',25.1757400,121.4417600,2,0.00,0,'ChIJaQRf7FalQjQRQdbhGspBtBY','2026-05-30 23:25:15'),(323,'美觀園海鮮餐廳(美觀園飯店)','一趟旅途，除了玩得開心，更要吃得盡興。位於野柳風景區內的美觀園海鮮餐廳，以提供新鮮生猛、經濟實惠的海鮮料理聞名。餐廳成立已有45年的時間，傳承三代，在當地擁有絕佳的口碑。餐廳所供應的海鮮料理極為豐富，清蒸、熱炒、紅燒、碳烤，應有盡有，滿足每一位老饕挑剔的胃。負責人闕嘉鴻為第三代傳人，秉持一貫新鮮的食材、實惠的價格，以及親切的服務，承先啟後，將美觀園打造成野柳當地最具規模的海鮮餐廳之一。餐廳就位於野柳地質公園旁，隨時歡迎您的惠顧。','野柳里港東路156號','207',25.2049400,121.6897500,NULL,0.00,0,'ChIJV_ylvHZMXTQREqRaXJKTJds','2026-05-30 23:25:16'),(324,'福州兩相好','於民國73年就在八里左岸開業的福州兩相好，當時店招牌兩相好(又名雙胞胎)也成為紅遍八里的著名小吃，來到八里，不吃上幾粒兩相好，可說是這趟旅途的最大憾事！不只兩相好，包括麻花捲及其他餡餅的口味之所以如此吸引人，秘密就在於「福州兩相好」至今仍遵循古法的手工製作方式，每一產品都是經過繁複手續揉製而成，過程保證不添加任何人工色素、香料以及防腐劑。「福州兩相好」致力傳承家鄉美味的用心，才讓多年前就令人驚艷的好滋味，歷經了雙十年頭都沒有改變。入口，一樣讓人深深感動！','米倉里渡船頭街30號','249',25.1586200,121.4350800,1,0.00,0,'ChIJB0smF2alQjQR2kskRuK_u5E','2026-05-30 23:25:17'),(325,'阿水獅豬腳大王','永和「阿水獅豬腳大王」位於永和中正路上靠近永和國小附近，迥異於古色古香的風情，永和阿水獅以現代化的裝潢、明亮感，吸引路人的目光。與臺中阿水獅同時開店，至今也有二十餘年之歷史，永和阿水獅的轉型，除了以老字號口味奠定年長的消費群，也成功帶來年輕的消費族群。豬腳在早期傳統社會裡，是過生日、過節時才會有的高級食材，如今豬腳漸漸成為生活化的一部分，也是普遍受歡迎的小吃料理。若您還沒嚐過阿水獅的豬腳料理，歡迎您來一趟永和店，這樣的傳統美味，會讓您回味無窮。推薦菜色:豬腳','永貞路186號','234',25.0043400,121.5161200,NULL,0.00,0,'ChIJSXaw2-apQjQRYIAP35FpcIU','2026-05-30 23:25:19'),(326,'么妹農產品','「么妹農產品行」提供了來自阿里山道地的各種名特產品，讓遊客來到九份都不會空手而歸。么妹農產品行負責人劉峻維大哥表示，店內提供有手工牛軋糖、阿里山高山烏龍茶、山葵、蜜餞等系列產品，每一種都是用心製作的精緻產品，且堅持以健康和美味為主要訴求，消費者不但可以吃得開心，更是可以吃得放心。','九份基山街169號','224',25.1079400,121.8433000,NULL,0.00,0,'ChIJ68jWZz1FXTQRnW0JPeHnxtw','2026-05-30 23:25:20'),(327,'匯‧鮨‧割烹','在永和永貞路，靠近保平路的路邊，有間店名「匯‧鮨‧割烹」，相當獨特的日本料理，很引人注目。大方沉穩的深褐色桌椅、明亮的吧臺與料理臺，氣氛優雅寧靜，讓客人可以悠閒自在的享受日本料理。店長沈先生從事日式餐飲業已經十餘年，「我們不侷限日本料理的形式，所以取名為匯，表示匯集的意思。」沈先生表示，「匯」提供的日本料理不侷限任何飲食的形式，雖然以日式手法、日式醬料為主，但「匯」常常研發不同的創意料理，也會因季節食材變化菜單，讓顧客不但可以吃到傳統的日本料理，也可以吃到新的日本料理創意，新奇又美味。推薦菜色:綜合握壽司、招牌干貝燒','永貞路303號','234',25.0057600,121.5106200,2,0.00,0,'ChIJc_WhEOCpQjQRagaMIvQ2GMA','2026-05-30 23:25:21'),(328,'客滿燒烤','為了給新北市的民眾高水準的精緻燒肉，客滿燒烤老闆尋覓各種好的食材及廠商配合，不單單在肉品上精挑細選，更每日提供澎湖空運來臺的牡蠣，全店以單點吃到飽的型態，搭配自家自製的小菜與魯味，讓更多人可以輕鬆品嚐平價又美味的燒肉美食。若是親子前往用餐，客滿燒烤更提供了飲品、冰淇淋、烤棉花糖、餅乾類等附餐通通吃到飽，也給了新北市的民眾一個吃燒烤的新選擇！推薦菜色:燒烤吃到飽、活生蠔、麻糬配冰淇淋等餐點組合。','景平路678號','235',25.0014700,121.4970300,2,0.00,0,'ChIJ9-A039WpQjQRVvAVgntbZKI','2026-05-30 23:25:22'),(329,'醍醐大師(淡江店)','一趟有特色的旅程，不但要玩得開心、更要吃得美味，並帶回具有紀念價值的伴手禮，才算盡興。「醍醐大師」位於淡水老街上，以販賣優質香鐵蛋、魚酥、蝦酥等 點心聞名。館方堅持不含防腐劑、不添加色素，並具有GMP、CAS認證標誌，務求讓消費者吃到原汁原味、香醇可口的淡水名點。優質的服務品質，連續榮獲中 華民國優良食品評鑑金牌獎等殊榮，5年內已累積10個獎項。醍醐大師鄰近淡水捷運站，交通位置醒目，是民眾選購香鐵蛋、魚酥、蝦酥等淡水名特產的最佳選擇。醍醐大師舢舨巧酥禮盒，透過特殊的舢舨船造型，以「船」與「傳遞、傳送、傳承」的諧音雙關，傳達淡水河岸文化的美麗與特殊，以及送禮人想要傳遞的真實情感。內容物的舢舨巧酥是改變傳統魚酥的油膩，以非油炸的方式，配合現代人口味，將新鮮魚漿以烘烤、無油方式製作，並特別添加奈米鈣，口感酥脆、香氣濃郁，大人小孩都很適合。','中正路11巷8號','251',25.1710800,121.4377900,NULL,0.00,0,'ChIJZVdI_1ilQjQR7TshpBmC2cI','2026-05-30 23:25:23'),(330,'星星牛排館(御品餐廳)','位於淡水老街上的星星牛排館，前身為淡水海珍餐廳，創業於民國６９年，後慢慢轉型為精緻單點牛排館，是淡水最老字號的牛排館。星星牛排最大特色在於六道西式精緻餐點，包含沙拉、濃湯、飲料、甜點、餐包，採現點現做方式供餐，加上店內裝潢精緻、充滿氣氛，適合家庭、情侶用餐，很受消費者歡迎。推薦頂級去骨牛小排，新鮮沒有醃漬，油花分布均勻，是饕客的最愛；而去油去筋的菲力牛排，香煎五分熟最能突顯鮮甜的肉汁，是您來到淡水輕鬆、舒適的用餐首選！','中正路11-4號','251',25.1695400,121.4431400,2,0.00,0,'ChIJXdRVUFilQjQR2_Y4_FIsp5o','2026-05-30 23:25:25'),(331,'麻吉奶奶鮮奶麻糬','來到淡水老街除了鐵蛋、蝦酥，不妨試試這全新口感的鮮奶麻糬，有著濃濃奶香，又Q又不黏牙，完全不添加糯米，是淡水老街的創意甜點。麻吉奶奶鮮奶麻糬老闆李先生，在習得日本製作鮮奶麻糬技術後，在淡水開設專賣店，推出臺灣難得一見的鮮奶麻糬，搭配可愛的麻吉奶奶意像，給人時尚又可愛的感覺，大受歡迎。因純手工製作，每天限量百份，可搭配不同材料，像是花生、紅豆等，還有客家擂茶等作出不同風味，每一種都值得一試，另外還有冰品「牛浣水」系列，口感更Q更細緻，喜歡嘗鮮的朋友來淡水老街一定要來此感受淡水特色甜品的魅力!推薦產品:花生水浣水麻糬','中正路220號','251',25.1706000,121.4394000,2,0.00,0,'ChIJ_2_GKFqlQjQRGAF9qRkQYRM','2026-05-30 23:25:26'),(332,'媽咪里啦手工餅乾','永和福和路上的「媽咪里拉」手工餅乾專賣店，顛覆手工餅乾昂貴的刻版印象，其親民、平價、美味的形象、精緻創意的包裝、濃醇的味道，獲得好口碑。原物料的調配完全出自自家的獨創研發，餅乾的厚度、密度也相當紮實，每個餅乾製作出來都可以保持相當平均的口感，由於自產自銷成本較低，媽咪里啦將優惠回饋在消費者身上。強調「天然、健康」，媽咪里啦使用燕麥、無糖奶油、天然的食材製作口味，也因此擁有著五星級飯店下午茶餅乾指定使用的品質保證，無庸置疑的打開年輕一代品嚐餅乾、伴手禮贈禮的市場，以及品牌的獨創性。推薦產品:燕麥、花茶系列餅乾','福和路229號-2','234',25.0073500,121.5187200,NULL,0.00,0,'ChIJ42qV3OipQjQR-SYaaPJAPSI','2026-05-30 23:25:27'),(333,'濠記食坊','位於中和宜安路上的濠記食坊，是一間成功以「路邊攤」型態轉型成為店面的成功案例！當年以甜不辣為主打，濠記由簡單的路邊攤起家，當初一天營業額僅2500至3000元左右，相當辛苦，但在老闆的用心經營之下，短短兩年後，成功打出市場與好口碑，之後更推出「紅油炒手」第二主打商品，更讓濠記的成績蒸蒸日上。在生意穩定之後，老闆以自己的名字命名，在宜安路上開了這間「濠記食坊」，如願擁有自己的店面，即便如此仍然堅持每天白天親自現作餡料，讓顧客可以吃到當日現捏的炒手好味道，也是濠記獲得好口碑的最大元素。推薦菜色:紅油抄手、甜不辣','宜安路55號','235',24.9969100,121.5115100,1,0.00,0,'ChIJJb6Zg9-pQjQRBxGbNxSs-GQ','2026-05-30 23:25:28'),(334,'鹿港甘仔店懷舊餐廳','想帶爸爸、媽媽、阿公、阿嬤一起來土城看桐花嗎？不妨順道一訪位於土城區廣興街上的鹿港甘仔店懷舊餐廳。老闆父子二代都是骨董收藏家，為了賦予這些懷舊文物展示意義與生命力，將整家店佈置得懷舊又復古，無論是早期戲院的電影海報、甘仔店的古早糖果罐、醬油鹽醋罐、公共電話筒、古早公佈欄等，都相當有系統地擺設布置，充分營造出四O、五O年代特色，讓人不但能一嚐道地古早味菜餚，還能體驗宛如時光倒流般的趣味。餐廳提供古早幸福宴，菜單以現場為主。','廣興街14號','236',24.9918400,121.4566200,1,0.00,0,'ChIJ25UkZ7cCaDQRfbjxDgrVWcc','2026-05-30 23:25:30'),(335,'雅米早午餐','用早餐店的價位，就能享用精緻早午餐，板橋新埔站附近的雅米早午餐，用優雅的藍色調，帶出地中海的悠閒風情，輕鬆坐著品嚐精心料理，三明治、貝果、法式土司、漢堡等多樣選擇，補滿元氣活力，充實精神開啟新的一天。超值人氣熱銷‧法式田園套餐-雅米早午餐的超人氣法式套餐，法式土司夾著蔬菜與特製醬料，煙燻火腿、法式嫩蛋、黑胡椒豬排、洋芋沙拉與飲品，超值豐盛高居點餐排行榜冠軍，給自己一個優閒的早晨，享用輕鬆溫馨的早餐。','陽明街28號','220',25.0218700,121.4662900,2,0.00,0,'ChIJbaJ8ihaoQjQRJh1VOe-qDBE','2026-05-30 23:25:31'),(336,'國光饅頭','\"位於中和連城路近新生街口的國光饅頭，成立逾15年，從前蕭老闆花了60萬，就只是為了學一顆饅頭怎麼做的好吃，饅頭不添加酵母，加入老麵糰，再讓它自然發酵，保留住饅頭原始的香味，光是一顆饅頭製作到完成就需要大約12小時的時間，過程中皆以手工去搓揉，讓饅頭口感較具有層次與Q勁。另外蕭老闆也研發多種包子的口味，像是素香菇筍包、鮮肉包、芝麻包、紅豆沙包等，為搶攻年輕人市場，研發了起司火腿捲，讓饅頭呈現另一種饅頭的好味道。\"','連城路330號','235',24.9962600,121.4832000,1,0.00,0,'ChIJGSf1WYQCaDQRptg5MbMaPiU','2026-05-30 23:25:32'),(337,'咖啡走廊','「咖啡走廊」是位在新店小碧潭捷運站附近一家相當有名氣的咖啡館，店主人林小姐本身為室內設計師，對於咖啡有一股情有獨鍾的熱情，開店至今已過了十多個年頭，不為了商業利益，目的是希望大家能夠像她一樣享受和品味生活。為了要帶給大家品味生活的感動，店中一律堅持選用高品質的咖啡豆和原物料來製作咖啡、特調飲品和手工糕點，並且有別於一般的咖啡店，這裡不提供插座和網路服務，希望來到這裡的客人放鬆心情不為工作，卻可透過這裡的咖啡、美食、景物來體驗生活的感動時刻。','中央五街5號','231',24.9741900,121.5301400,2,0.00,0,'ChIJrRm-mBkCaDQRBOvtjdnLr-c','2026-05-30 23:25:33'),(338,'山間倉房','位於往中和烘爐地的山間，有一間由舊型倉庫改建而成的精緻蔬食餐廳，老闆何先生曾赴日本專供設計，喜愛美食的他，認為未來養生蔬食、環保養生是一大飲食的潮流，甚至在國外蔚為風潮，充分發揮自己的設計專業與美感，打造了這間頗具時尚感的「山間倉房」。山間倉房全館採無菜單、提供創意蔬食料理套餐，鄰近中和烘爐地福德宮以及山上有名的算命街，結合中和烘爐地山間的自然綠意風景，主張蔬食的健康與養生觀念，常上山朝拜的民眾不妨前往坐坐，山間倉房的健康蔬食創意料理，結合日式作法，顛覆您對傳統素食的想法，給您全新飲食感受。','興南路二段399巷124號-1','235',24.9753100,121.5007600,3,0.00,0,'ChIJebmGHF0CaDQRWO0ixisIWgU','2026-05-30 23:25:34'),(339,'惠香嘉義火雞肉飯','遠從嘉義北上創業的兩夫妻，在十多年前來到土城這個美麗的都市，為了發揚自己故鄉的當地小吃美食，兩夫妻學習了餐飲的技術、更經過無數次的嘗試與研發，打造出屬於自家的口味，用心的經營也在土城當地受到相當好的口碑。日前於土城裕民路與中央路二段各有店面，惠香嘉義火雞肉飯與坊間的火雞肉飯不同，將一般絲狀的雞肉改變刀法，以切塊方式，更增加火雞肉的口感與韌度，搭配自家研發以黑豆醬油與高湯調配的醬汁，呈現自家獨家的口味，受到附近土城工業區上班族以及大老闆的喜愛，指名愛吃！也歡迎顧客過路土城時停下，品嚐其用心。店家所賣的火雞肉飯不但是以真正的火雞肉為食材，更與其他店家所賣的雞肉飯不同，將一般絲狀的雞肉改以塊狀方式呈現，增加了火雞肉的口感與韌度，再搭配自家研發的黑豆醬油與特製醬汁，滋味獨特。推薦菜色：滷白菜、滷豆腐、蘆筍汁','中央路二段264號','236',24.9744500,121.4415200,1,0.00,0,'ChIJM8-7LCodaDQRHeXWoXj0QwQ','2026-05-30 23:25:36'),(340,'小樂天餃子館','小樂天餃子館前身為同福齋飯館是由杜玉山先生在1953年於愛國東路、博愛路口所成立的北方飯館，後因遷址及環境改變杜老先生夫妻于1974年在武昌街（西門町電影街）成立小樂天餃子館。1979杜老太太在新店現址開設分店，爾後在老夫婦監督下由第二代子女重新裝潢開幕。第二代尊承老人家的經營理念，精選食材，不添加任何防腐劑及人工色素，以新鮮為前提，純手工製作水餃，受到許多在地人的喜愛及肯定。','民族路14號','231',24.9789700,121.5414100,1,0.00,0,'ChIJB3_C4PkBaDQR0d0L_kGfG6A','2026-05-30 23:25:37'),(341,'彰鶯肉圓','正統彰化風味的肉圓，原來在鶯歌也吃得到，紮實飽滿的內餡讓人一吃就上癮，再咬一口超Q彈的肉圓皮，吃了一碗也能有飽足感！好的肉圓搭配的醬汁很重要，在鶯歌吃到的肉圓醬汁是店家自行調製，加一小匙蒜泥會讓肉圓更有滋味！一碗肉圓，搭配四神湯一起品嚐，是在鶯歌就能大飽口福的庶民美食小吃！','行政路35號','239',24.9559800,121.3520500,1,0.00,0,'ChIJ66kVpakeaDQRbiLDHy00I5g','2026-05-30 23:25:38'),(342,'芋仔蕃薯(芋仔蕃薯茶坊)','九份昇平戲院前的豎崎路，是九份重要的人行步道，也是電影「悲情城市」的主場景之一，因此每逢假日總是摩肩擦踵、熱鬧不已。沿著階梯的兩側，自然而然也成為茶坊的聚集點，其中「芋仔蕃薯」是間非常特別的老茶館，其門口有如山洞隧道，館內為九份山城的舊式樓房，主人收集陳設許多老古董，洋溢著濃濃的懷舊氛圍，由於豎歧路是條層層而上的階梯道路，茶坊也沿坡逐次建立，因此身處館內可眺望美麗的山海景觀。老闆推出九份特產紫心蕃薯，其口感香濃鬆軟，另外店裡也提供麻婆豆腐、炒山豬肉等鄉土餐點，讓人備感親切。','崇文里市下巷18號','224',25.1089800,121.8436300,2,0.00,0,'ChIJIR7-nRdFXTQRE2dpysSbSqY','2026-05-30 23:25:39'),(343,'九份老麵店','九份老麵店從民國47年就開始經營，目前是由第二代的石老闆掌舵，也是由老闆在麵攤前掌廚煮麵。雖然九份老麵店並不是九份地區第一家成立的麵食店，但是如果說到牛肉麵的話，那就是第一家提供牛肉麵的店家，而且從以前到現在，牛肉麵一直是九份老麵店的招牌麵食。九份牛肉麵最早的客群是在金瓜石及九份的當地人及採礦工人，可能是因為採礦需要花費相當很多的體力，所以這裡的牛肉麵特受到當地人及採礦工人的歡迎。','基山街45號','224',25.1088300,121.8454200,NULL,0.00,0,'ChIJVbDhGhhFXTQR_mU55edyCXA','2026-05-30 23:25:41'),(344,'阿娟小吃','經營超過20餘年的「阿娟小吃」，是經常被報章雜誌報導的毛蟹專賣店，雙溪地區溪流清澈盛產毛蟹，由於蟹肉不多以前吃的人很少，對捉毛蟹很有一套的老闆便試著賣賣看，沒想到一賣就超過20年，而各地老饕也被毛蟹的香甜氣味吸引，每逢農曆7月中旬到過年前的產季，都會準時到店裡報到。除了毛蟹，老闆也推出炸溪哥、炒野薑花等在地山溪產，一樣大受食客歡迎。季節性商品(如毛蟹), 營業時間：約7月中~12月(其餘時間不營業)','中華路8號','227',25.0364900,121.8660600,1,0.00,0,'ChIJX8DvMqlbXTQRFkxEJ4QaDk4','2026-05-30 23:25:42'),(345,'88號水碼頭活海鮮餐廳','「88號水碼頭」是一間海鮮餐廳的名字，位於金山水尾漁港旁，不僅可以聽到海濤聲還可以望見整片的星空真是不勝浪漫。餐廳主人曾任職於各大飯店，以學得的臺、粵、日式等烹調手法，研發出取用時令海鮮為食材，擺盤精美講究的的無國界料理，因創意十足、色香味俱全，吸引許多老饕捧場，成為當地最富盛名的海味餐廳。招牌菜「西式生魚片」，以快刀薄片海鱺，搭配特調醬汁，風味獨具，口感極佳。其他美味名菜，還包括日式淋蔥鰻、深海香螺等。','豐漁里民生路88號','208',25.2238700,121.6483400,2,0.00,0,'ChIJIVt_KlxLXTQRXLOXm_Q75So','2026-05-30 23:25:43'),(346,'原住民泰雅婆婆美食店','以料理泰雅山地美食聞名的泰雅婆婆美食店，是烏來老街上著名的風味餐館，店內裝潢全部採用竹片拼貼，十足山地風味。門口攤架上滿滿陳列過貓、桂竹筍、山地芭蕉、檳榔花、山豬皮等原住民常用食材，經過泰雅婆婆的巧手料理，幻化成清香竹筒飯、月桃飯、竹筍包、山胡椒生木瓜雞湯、香酥蔗蜂、清蒸馬告鱒魚、當紅炸竹雞、涼拌山豬皮、炒過貓、山地醃肉等野味菜餚，令人食指大動。','烏來里烏來街14號','233',24.8640000,121.5514600,2,0.00,0,'ChIJJcceJokGaDQRurBwfUHZ_wI','2026-05-30 23:25:44'),(347,'姊妹雙胞胎','位於八里渡船碼頭旁的姊妹雙胞胎，人氣鼎盛，每逢假日店前便大排長龍，其標榜添加了鮮奶的雙胞胎，吃起來奶香濃郁，加上炸得又酥又香，難怪讓人意猶未盡。此外，甜香可口的甜甜圈，亦有好評。','渡船頭街25號','249',25.1588700,121.4350800,1,0.00,0,'ChIJE5jMF2alQjQReRiq_32pAUs','2026-05-30 23:25:45'),(348,'獅子林餅舖','金山獅子林餅舖是由糕餅界聞人黃樹旺所創立，原本在基隆起家，前身是獅子林西點麵包，後來因口碑日盛，於是在金山老街裡開店，發展至今共有三間店面，分別以麻荖、手工蛋捲、鳳梨酥聞名。傳統古早味的餅藝技術，和全新的創意，讓獅子林的糕餅成為觀光客和公司行號送禮的好伴手禮。店裡的麻荖歷史悠久，早期老街並沒有金山在地特色的小吃和伴手禮，後來老闆以金山的芋頭和蕃薯突發奇想，變成了風味絕佳的一口芋頭酥和一口番薯酥，不但為金山美食打響名號，一口蔴荖也成為遊客順手必買的好禮。','金包里街76號','208',25.2217000,121.6386000,NULL,0.00,0,'ChIJvXNB6VdLXTQRXFhG6_AMhVM','2026-05-30 23:25:47'),(349,'洋荳子咖啡屋','矗立在金山臺2線省道旁，與海天連成一線、藍白地中海基調希臘風情的美麗建築，正是名聞遐邇的洋荳子咖啡館。吳老闆原本也是游動四處的行動咖啡車經營者，後來因咖啡車常故障，又很難忘情金山迷人的海岸風光，加上觀光局北觀處力薦開店建築粉刷改藍白基調，於是他就決定在此構築他夢想中的希臘城堡。原本就經常客滿的咖啡館，因電視劇和網路再推波助瀾，每到假日來此品嚐咖啡吃鬆餅的客人絡繹不絕。洋荳子的主要魅力除了令人難忘的山海景，咖啡和鬆餅一樣讓人感動喔。行家們推薦的原味拿鐵、愛爾蘭拿鐵，果然名不虛傳，輕啜中齒頰留香難以忘情。而多種口味的鬆餅，有巧克力鮮奶油、蜂蜜、藍莓等等，坐在咖啡座上放鬆心情，盡情享受那份都市中所沒有的悠閒。','忠義路29-1號','208',25.2635200,121.6308600,2,0.00,0,'ChIJ729x9CpLXTQRlu-ihpE7nyI','2026-05-30 23:25:48'),(350,'蘇明興糕餅號','本店創立於1961年-專業製作傳統古早味訂婚喜餅(芝核蛋黃,咖哩魯肉,綠豆凸,綠豆魯肉,綠豆蛋黃)中秋月餅,蛋黃酥,鳳梨酥,鳳梨餅,拜拜各式壽龜,普渡用佛手,包仔,麵龜.壽桃等...麵包,蛋糕，店家對品質有高規格的要求，也不斷創新經營理念，品質信譽值得信賴。','林口路150號','244',25.0822400,121.3880300,NULL,0.00,0,'ChIJUxroIe6mQjQRrzwqNMQpckc','2026-05-30 23:25:49'),(351,'練家蜂蜜石花凍','練家鹹冰棒位於石門區\"劉家肉粽\"隔壁，店裡以販售鹹冰棒及石花凍為主。招牌的\"蜂蜜石花凍\"冰涼好喝!是夏季解渴的最佳冰品 。','中央路28號','253',25.2922000,121.5680300,NULL,0.00,0,'ChIJwfBWXLq1QjQRMMTQiUzHRGg','2026-05-30 23:25:50'),(352,'中角灣咖啡餐飲','中角灣咖啡餐飲位於中角派出所對面，就在中角灣沙灘旁邊，有室內與室外座位可供選擇。室內裝潢獨具特色，處處可見巧思，戶外視野開闊，賞海景或賞夜景都十分愜意，好景致曾吸引包括偶像劇《王子變青蛙》、歌手孫燕姿MV等到此拍攝取景。中角灣咖啡餐飲也提供多樣化的飲品及餐點，適合獨自或闔家在此度過愉快時光。','海興路188號','208',25.2405000,121.6336200,2,0.00,0,'ChIJiZAKzUtLXTQRi5sCu2h6hvY','2026-05-30 23:25:51'),(353,'九份張記傳統魚丸','位於九份基山老街的張記傳統魚丸，開店至今將近12年了，傳統魚丸是店內最大的特色，這一小顆又Q又有嚼勁，吃起來像貢丸的魚丸內，可是有大學問呢! 傳統魚丸是用魚漿和豬肉，再加上油蔥酥、胡蘿蔔、芹菜等下去攪拌打製而成，有些小朋友不喜歡吃胡蘿蔔之類的蔬菜，卻非常喜歡吃這邊的傳統魚丸，一小顆魚丸裡，有著非常豐富的營養。另外店內的福州丸也相當受歡迎，口咬下去，鮮美的湯汁隨即溢出，因為加了油蔥，增添不少風味。','基山街25號','224',25.1091500,121.8455300,NULL,0.00,0,'ChIJLbR5IhhFXTQRj2UzXC_E_lM','2026-05-30 23:25:52'),(354,'金山福華海鮮餐廳','位於金山老街附近的金山福華海鮮餐廳餐廳的主廚自國中畢業便專心投入餐飲工作，一路走來一直秉持著提供新鮮、美味、物超所值的海鮮料理為理念，十多逾年的磨鍊，無論再料理、蔬果雕、冰雕等各項技術皆堪稱一流。餐廳位在往救國團金山青年活動中心之中興路旁，停車方便，歡迎來嚐鮮。','豐漁里民生路51巷1之2號','208',25.2201200,121.6420600,2,0.00,0,'ChIJLdQBeVhLXTQRzCXk8rho52A','2026-05-30 23:25:54'),(355,'港式曹記燒腊小館','位於中山路上的「曹記燒腊」，以港式口味的燒臘為主，這裡每一樣食材都是老闆向港式正統的師傅學作而成，所以每一口吃得到老闆對於食材的用心及堅持，每到用餐時刻，大家幾乎都爭相排隊等待','中山路213號','208',25.2215300,121.6377900,1,0.00,0,'ChIJeeOo21dLXTQRWoaP_3VXa-c','2026-05-30 23:25:55'),(356,'可愛家','可愛家主要以飯、麵、河粉及各式小菜為主，結合臺、越口味的麵飯類菜色','中山路155號','208',25.2204000,121.6387100,1,0.00,0,'ChIJW3WSG6hMXTQRhFoowkTuckk','2026-05-30 23:25:56'),(357,'看山小望海大','這家店之所以命名為如此特殊的名子，原因就是因為這家店前有小山，後有大海，充滿臺式爽直的風格。店家透過各路藝術友人將這裡形塑成理想中的海邊度假好去處，這是間風格強烈的店，色彩鮮明的露天觀海座椅，將海岸妝點的燦爛繽紛，舉凡店內所有的彩繪、壁畫，都是出自老闆Janet的傑作，擁有藝術家身份的老闆，自身獨特的氣息濃烈，也給人強烈的印象。而連店裡所有的料理，也都是由老闆與友人一手包辦，獨特的風味與老闆豪爽的個性，都會令人留下深刻的印象。FaceBook專頁：http://zh-tw.facebook.com/Lamer.Taipei/info','北勢子45-10號','252',25.2502600,121.4675000,2,0.00,0,'ChIJq1xaGriwQjQRRMpyiTK48Go','2026-05-30 23:25:57'),(358,'邊界驛站FRANK\'S TEXAS BBQ','一位來自德州的美國人 - 老孫（Frank），聽一位台灣人說「台灣錢很好賺」，毅然買張單程機票到台灣，那時他口袋裡只有50塊美金。來台灣先教英語，曾教過當年紅牌歌星「張利敏」，在台居住二十年以上，比台灣人更愛台灣。國語講的字正腔圓，台語也呱呱叫。2000年曾從事木材貿易的他，短暫的住過上海，也曾有過大陸發財夢，比較兩岸，台灣始終是他的最愛。2002年為了尋找小時候夢想中的生活環境，遠離塵囂，一路從臺北、汐止、淡水，最後選擇了三芝。德州是美國南方最大的一州，也是全美第二大州，以牛肉生產聞名。到這裡「儉樸」、「粗獷」的享受美食，『燒烤』是其特色，讓德州老孫為您提供並品嚐道地的美式德州BBQ加厚沙朗牛排全餐，超值24盎斯的特厚牛排煎成五分熟，肉汁香醇，肉質也不會太硬，有道地的德州牛仔風味','古庄里四棧橋24-1號','252',25.2620300,121.4865900,2,0.00,0,'ChIJt8QklHG3QjQRyPMjUs8aM6g','2026-05-30 23:25:59'),(359,'桂竹園餐廳','老闆娘的好手藝加上最新鮮的食材，烹調出老菜脯雞湯、半天花、過貓等豐盛的山產野味、季節性菜色','承天路149號','236',24.9460800,121.4510500,2,0.00,0,'ChIJ-wy9QjQDaDQRWEy0OUGvoo0','2026-05-30 23:26:00'),(360,'自強刀削麵','牛肉刀削麵，以牛骨、番茄、中藥、蔬菜熬出的湯頭雖屬紅燒，口味卻較淡，健康清爽的口感很受歡迎','裕民路75號','236',24.9877000,121.4497900,NULL,0.00,0,'ChIJoYUHK8oCaDQRqlYSby2zsCw','2026-05-30 23:26:01'),(361,'臺北園外園','臺北園外園隱身於新北市郊的五股準休閒農場內，占地約三．五公頃，從進入大門一開 始，林蔭大道帶出如茵綠地、花草庭園，婚宴場地很具南歐風格。這裡同時也是對一般民眾售票開放的準休閒農場，是臺北都會區惟一合法的休閒農場，除了 保留萬坪綠地草坪，亦擁有上萬株花草樹木、兩百餘種藥用植物、豐富的爬蟲鳥類生態、瀑布 小山造景等，有國外超豪華庭園婚禮的氣勢。最特別處是，這裡是全臺惟一可以停放直升機的戶外婚宴場地。準新人從臺北松山機場，搭 乘直升機前往會場，在直升機上俯視臺北盆地風光，然後，在與會賓客的驚呼聲中，緩緩降落 在翠綠的草地上是婚禮高潮。','新五路二段70號','248',25.0723400,121.4376700,NULL,0.00,0,'ChIJoQTQrR6mQjQRTX8XyBE039s','2026-05-30 23:26:02'),(362,'木櫥滷味','滷味樣數不少，通通陳列在一座特製的木櫥中，濃郁的香氣不斷的散發，這就是滷味名稱的來源。和其它派滷味最大的不同在於它的鹹香美味口感，香油部份下得重，所以吃的時侯口中充滿了麻油的香氣，和一般偏甜口味的滷味，多了一股迷人的香氣，吸引來往的客人。推薦菜色:滷鴨翅、滷雞腳、豬血糕、甜不辣、青菜','永平路25號','234',25.0086800,121.5133100,NULL,0.00,0,'ChIJgceoj8KpQjQRNgnfQn9Vmwc','2026-05-30 23:26:03'),(363,'上介青快炒','各式新鮮食材大火快炒，從海鮮熱炒到常見的台式菜餚一應俱全，提供您一個與朋友把酒言歡的好去處。推薦菜色:椒麻雞、炒山蘇','永貞路307號','234',25.0059300,121.5106300,2,0.00,0,'ChIJO96swtypQjQRrUT5y62ao4U','2026-05-30 23:26:04'),(364,'安娜咖啡','堅持只用日本UCC的豆子，餐點則是提供現做與餐包兩種，比較推薦的是自製餐點，像是經典香烤鮭魚排，就很受到歡迎，或者喝一杯單品的咖啡，也是人生一大享受唷！','中央路1-17號','253',25.2912200,121.5612400,NULL,0.00,0,'ChIJK9tV67e1QjQRTRPuuo1flOA','2026-05-30 23:26:06'),(365,'三芝小豬輕食館','三芝小豬的開設，是一個追逐夢想的故事，老闆喜愛西點，還為此放棄原本高薪的機會，遠赴北京學習。美味鬆軟的吐司是這裡的高人氣，每逢假日都是要排隊才不一定買的到，還有許多其他蛋糕類，都是出自老闆的巧手，也都頗受人喜愛。','崁子腳58-8號','253',25.2867200,121.5307100,2,0.00,0,'ChIJOcONRmq0QjQRpzHROzTi-1c','2026-05-30 23:26:07'),(366,'海釣族真味園','腸尾鳥生魚片，來自深海的腸尾鳥，肉質肥美，可做成一魚五吃，生魚片捲成圓筒狀內包洋蔥，或是製成生魚片壽司，風味絕佳。推薦菜色:御用飽魚粥、螃蟹粉絲煲、生魚片名人推薦:黃俊哲議員推薦','文化路二段126號','220',25.0263300,121.4702300,2,0.00,0,'ChIJjzILX0CoQjQRZMzeZEQOatM','2026-05-30 23:26:08'),(367,'三豐芋冰城','板橋知名的冰果店，店裡產品種類超多，最受歡迎的首推冰磚和雪冰，小小一塊冰竱宛如縮小版的冰棒，容易入口，雪冰口感綿密，入口即化，兩樣都是夏日聖品，值得一試。推薦菜色:冰磚、雪冰','民族路15號','220',25.0097900,121.4617400,1,0.00,0,'ChIJByhLxB2oQjQRxDZoOuhMk3k','2026-05-30 23:26:09'),(368,'蕃茄主義','主廚特調沙拉醬，以橄欖油、白醋、巴西利、堅果、大蒜為原料，並採用大量的新鮮香草製成，翠綠色彩的外觀象徵著業者提倡的健康飲食理念；手工麵包，外型有點類似一般坊間的圓形餐包，也有人認為更像English Scone(英式比司吉)，直徑約6公分，每顆重量約30~35克左右，口感紮實，吃了2~3顆就有飽足感。麵包採冷凍包裝，若從冷凍庫拿出來食用時，建議先用微波爐加熱30秒解凍，然後在麵包上面噴一點水後下去烤，這樣麵包才不會太乾，可搭配業者的特調新鮮麵包醬或蒜味麵包抹醬食用預約用餐制，歡迎新客人舊客人來新店嚐鮮平日│週二至週五　晚餐 約18:00~21:30假日│週六至週日　中午/ 晚餐 約12:00~21:30平日預約用餐請兩天前預約完成假日預約用餐請ㄧ周前預約完成我們好準備最新鮮的食材','中央五街55號','231',24.9755400,121.5277800,3,0.00,0,'ChIJfRSGaRwCaDQRyBjRMOS34iA','2026-05-30 23:26:10'),(369,'呷霸牛肉麵','\"辣\"是呷霸的特色之一，店內牛肉麵分為多種等級的辣度，甚至舉辦比賽，贈送勇敢挑戰的民眾獎金，半筋半肉牛肉麵，麵條口感Q，半筋半肉的牛肉，滷到完全軟爛入味，用料大方，讓人大快朵頤！推薦菜色:半筋半肉麵','民安西路175號','242',25.0159300,121.4261800,1,0.00,0,'ChIJN5Q1e18daDQRACl4_la9MB8','2026-05-30 23:26:12'),(370,'新莊牛肉大王','靠近大觀路的「新莊牛肉大王」是逾40年老店，以客家全牛料理知名，有招牌牛腩鍋、養生牛鞭甕等，還有老闆娘純手工牛軋糖、古早味花生糖販售。牛腩火鍋，來店「必點」的牛腩火鍋，濃醇芳香的湯頭魅力十足，軟嫩滑順的牛腩用的是臺灣黃牛肉，加上凍豆腐與大量蔬菜，是老饕最愛。推薦菜色：牛腩火鍋、炒牛肉、薑絲毛肚友善服務□外語友善(能提供與他國顧客溝通之語言或媒介)。   □行動裝置充電 (提供電源插座、USB等供行動裝置、手提電腦等設備充電)。  □信用卡/悠遊卡/第三方支付服務(提供現金以外的交易方式)。□素食友善(提供全素食/蛋奶素餐點) (不含蔥、蒜、韭菜、薤(蕎)、興渠(洋蔥)、肉類)。 □友善廁所(提供借用廁所服務)。  □Free WiFi(提供顧客無線網路之服務)。','新莊路178號之1','242',25.0352000,121.4547400,2,0.00,0,'ChIJd6QpN3KoQjQRpxIDg7QclX0','2026-05-30 23:26:13'),(371,'九戶茶語','這是九份的景觀餐廳和複合式茶坊。店內裝潢古樸典雅、人員服務親切有效率，另外還貼心設置專人泡茶及解說茶道的服務。讓來到這的遊客可藉由餐飲及品茗之中瞭解臺灣文化。','輕便路300號','224',25.1088100,121.8434000,2,0.00,0,'ChIJW3FvzDRFXTQRUMhNZD5WxOI','2026-05-30 23:26:14'),(372,'知味鄉玉米','這家知味鄉玉米相當的有名氣，有路過臺二線金山萬里附近的人應該都有注意過，店家的玉米是糯米玉米，來自雲林濁水溪兩岸一帶，最大的特色是烤前還要先經兩小時的高溫黑石燜煮，據說這樣可以把甜味都封存在玉米中；計價是秤重計價，在秤重結帳後，就開始塗上特製醬料，由人工來碳烤玉米，他們的辣椒用的是朝天椒，據說中辣以上就蠻具「挑戰性」，喜歡吃辣的人可以試試看。由於老闆堅持玉米品質不優時不賣，所以能不能吃到，就各憑運氣了(行遍天下 NO.202)','大鵬里加投路14-3號','207',25.2090000,121.6548700,2,0.00,0,'ChIJyXLnjt9MXTQRXNGe7Bu-gzA','2026-05-30 23:26:15'),(373,'仙草龍','在金山及萬里交界處，有著最具代表性的小吃，就是仙草龍。仙草龍的老闆說煮仙草其實有功夫，最重要的火候及時間都要掌握的恰到好處，讓仙草喝起來有濃濃的香味，而又不會苦澀，從這的招牌仙草布丁就可以看出，細緻的布丁口感，有著仙草的香味，再搭配上鮮奶油，常常是讓來這的客人都是一箱一箱買回去享用。','萬里加投212號','207',25.2162000,121.6426300,1,0.00,0,'ChIJc43mbaFMXTQRlwP2SKpvhh8','2026-05-30 23:26:17'),(374,'三葉活海鮮','這裡提供最新鮮的海鮮食材，任君挑選，讓您品嘗到大海的美味。','野柳里港東路74-16號','207',25.2050300,121.6892000,2,0.00,0,'ChIJbR_cyHBMXTQRWR_sCc9KkME','2026-05-30 23:26:18'),(375,'大眾餐館','在地45年以上的老餐廳，由現任老闆娘接手之後才打響名聲，海鮮料理為其拿手的食材，招牌菜色有龍蝦炒菜脯、大眾招牌雞、紅蟳冬粉煲、香酥芋頭捲、米醬砂魚條、冬瓜豬蹄湯...等。','新基里中華路68號','227',25.0381100,121.8659400,2,0.00,0,'ChIJIf3gQ6hbXTQRYvujBj4Z2uc','2026-05-30 23:26:19'),(376,'金枝紅糟肉圓','金枝紅糟肉丸的名號所以響亮，是因為店裡對於任何製作過程、食材選用都不馬虎，以紅糟肉丸來說，從製作、發酵紅糟，到包肉丸，都親自手工製作。紅糟要特定選秋季之後才開始發酵，發酵完還要密封起來；而肉丸裡的肉是選擇上等的夾心肉，一塊塊下去浸紅糟使其入味，口感細嫩不會太老，而且也加入了好幾種香料，例如五香粉、八角粉、胡椒粉、肉桂粉等。裡頭的竹筍絲則是選擇來自竹山的新鮮竹筍製成；而外面裹的粉皮也不隨便，使用了三種粉調製而成，分別是太白粉、番薯粉、在來米粉，所以滑嫩彈Q。','九份基山街112號','224',25.1085500,121.8437900,NULL,0.00,0,'ChIJ71qL4RdFXTQRfD6kuibOUSY','2026-05-30 23:26:20'),(377,'九份海悅樓觀景茶坊','海悅樓是一棟矗立於豎崎路旁的四層樓高聳建築，座落於豎崎路昇平戲院正上方，位於九份景觀最佳位置之一，臨山面海，可就近由高而下欣賞到九份地區許多著名茶坊，如戲夢人生、黃金之鄉、阿妹茶樓、芋仔番薯茶坊、小上海茶樓、古窗、九戶茶語、水心月茶坊等，還可向下俯視昇平戲院，遠眺基隆山、海景、山景。整棟樓呈現鄉土意象的古樸鐵灰色，融入幽遠的四季山海風情，簡單樸實的直線與圓弧線條、大量採用洗石子工法，非常具有台灣風味。走進茶坊門口就可看到充滿中國風味的簾幕、裝滿水果的木桶、地上的酒甕。','九份豎崎路31號','224',25.1084200,121.8435700,2,0.00,0,'ChIJW3FvzDRFXTQRJOhl_uVAVJM','2026-05-30 23:26:22'),(378,'老友號芋圓','老友號芋圓創立於民國79年，第一代老闆林榮吉、夏阿美希望這間店成為大家的好朋友，故取名為「老友號」。老友號芋圓老闆娘夏阿美善於製作點心，舉凡餅乾、包子、蛋糕、芋圓、蘿蔔糕、草仔粿等，九份街坊鄰居吃了皆讚不絕口，經鄰居大力鼓勵，以及九份商圈的興起，於是在民國79年將原本的米店結束營業，創立芋圓店，剛開始除了賣芋圓、地瓜圓，也賣小籠包、雙胞胎等其他點心，後來芋圓生意越來越好，沒辦法製作其他點心，故後來就成為以芋圓、地瓜圓為主的芋圓專賣店。','基山街4-3號','224',25.1096100,121.8452000,1,0.00,0,'ChIJ8-dfIRhFXTQRG5q6BWwY5W8','2026-05-30 23:26:23'),(379,'淡水文化阿給','「阿給」這個名稱是由日文稱油豆腐為「阿布拉給」而來。在淡江中學旁真理街附近的「文化阿給」，其真材實料的魚漿、冬粉、油豆腐填充與調味醬的特別口感，經常吸引許多名人、藝人去吃，更帶動這家美食店的人氣。每天清晨三點多，老闆就要開始手工將油豆腐切開，填入用醬油、油蔥、香料拌炒過的冬粉，再用新鮮魚漿將切口填補起，然後放入鍋中蒸煮。彈性油豆腐和粉絲、魚漿交疊成一種十分絕佳的口感，一般吃法是將油豆腐裡的粉絲挖起，讓粉絲吸飽老闆特製的醬料吃起來口味很特別，再配上一碗魚丸湯，味道令人著迷。每到假日店門前總是大排長龍。','真理街6之4號','251',25.1738200,121.4374200,1,0.00,0,'ChIJ01IjiVClQjQRRCv_YkllVD8','2026-05-30 23:26:24'),(380,'百葉溫州大餛飩','連周杰倫也推薦的淡水人氣名店！除了烤雞腿與餛飩湯的人氣組合「周杰倫套餐」，桂花芝麻湯圓更是遊客每次光臨都必點的人氣美食。無論甜或鹹的口味都能讓人滿足。百葉溫州餛飩在淡水已有幾十年的歷史，店內有著名的餛飩料理、蔥油餅、桂花芝麻湯圓、烤雞腿及各式小菜，菜色非常的多，不只提供外帶，也提供了宅急便訂購服務，來淡水旅遊的旅客們，不坊品嘗看看。推薦菜色:桂花芝麻湯圓','中正路177號','251',25.1712400,121.4386200,2,0.00,0,'ChIJ1dkLQFqlQjQRJxPCeNU36PM','2026-05-30 23:26:25'),(381,'薰衣草餐廳','薰衣草餐廳主要以餐飲為主其中的\"砂鍋魚頭\"更是值得前去品嚐，\"砂鍋魚頭\"是使用較難買到的鱈魚頭食材來料理的，就因為難買到這樣的鱈魚頭所以比較少餐廳此用來做招牌餐，另外炸雞腿餐也是薰衣草餐廳頗受顧客喜愛的唷~!','中正路106號','208',25.2217500,121.6331800,2,0.00,0,'ChIJmdaBHFZLXTQRBX6bq6iph9s','2026-05-30 23:26:26'),(382,'瓊玉小館','各式南北口味麵食，經濟熱炒南北小吃，名師主廚外燴包辦','中山路203號','208',25.2213200,121.6379800,1,0.00,0,'ChIJA-I2WKZMXTQRM6fqShhpJrQ','2026-05-30 23:26:28'),(383,'淡水老街滬尾餅舖','以百年作餅技術打底的店家，桿製出多層次酥薄餅皮，層疊出奶黃色的端正日形花粉酥，為滬尾鎮店之寶，也是全臺灣省唯一以花粉入餡的店家。重現60年代前風華滬尾餅鋪，讓阿公、阿嬤的記憶再度甦醒。店家不僅把古早味重新詮釋並融入現代健康新概念，店內所生產的食品皆為蛋素或純素，絕不添加任何香料、防腐劑、色素...等化學添加物。推薦產品:花粉酥','中正路85號','251',25.1696900,121.4405000,NULL,0.00,0,'ChIJO5AinVmlQjQRzBAgCB5OyzM','2026-05-30 23:26:29'),(384,'AMANDA CAFE','位於淡水老街馬偕銅像旁，去渡船頭或紅毛城都很方便喔，為複合式咖啡館，店內佈置優雅適合來個簡餐或一杯飲料休息一下，這裡也有經營民宿就在店的附近，民宿頂樓可觀看淡水河岸景觀喔！推薦菜色:招牌雞腿','中正路264號','251',25.1714400,121.4384300,2,0.00,0,'ChIJCRxMPlqlQjQRNqhXjOqQ1oY','2026-05-30 23:26:30'),(385,'鮮果日誌 Fruit Days','現代人工作繁忙、生活步調緊湊，漸漸喪失生活品質，許多人因此時常感覺疲憊不堪。也因為發現這樣的現代通病，慢活概念逐漸興起，現今的人們不但關心身體的健康，更開始要求心靈的健康。  而「鮮果日誌Fruit Days」以紀錄人們與水果的每一天為出發點，發掘水果與食用者之間的聯繫，除了外在的健康之外，更希望能帶給大家心靈的滿足。  簡單自然的幸福滋味，就是我們的主軸。拋開調味料和豪華美食的加工負擔，期待能以原始且單純的心境去體驗、去回憶、去創造屬於自己的幸福感覺！','三民街157巷12號','241',25.0647900,121.4839100,NULL,0.00,0,'ChIJgxSsFueoQjQRgZ2KB05w0Ew','2026-05-30 23:26:31'),(386,'義品苑','每天平均可賣出300份的義麵族，身為淡水人的老闆，希望以單價低、口味又道地的義式料理，以最輕鬆的方式滿足學生的口腹之欲，雖然店內樸實簡單，但還是深受學生歡迎，以咖哩、奶油培根、肉醬口味最暢銷。推薦菜色:焗烤麵、奶油類','大義街31號','251',25.1782100,121.4424400,1,0.00,0,'ChIJeYwtNFSlQjQRZUBVkyxJroA','2026-05-30 23:26:32'),(387,'陳林港式臭豆腐','讓在地人忘不了的陳林港式臭豆腐，隱身在不起眼的巷弄中，入口非常酥脆，用的不是大塊剪過的豆腐，而是小塊的臭豆腐並將中間剪開，炸過之後佐以蒜泥，再搭配醃製入味的台式泡菜，爽口不油膩，咬下一口，臭豆腐的湯汁流出，又香又酥滋味迷人，即使外帶回去品嚐，冷了還是酥脆好吃。','大豐路67號','231',24.9795200,121.5394900,1,0.00,0,'ChIJy-7KLvgBaDQRsmNwRRjJNkY','2026-05-30 23:26:34'),(388,'老中央燒餅店','堅持現烤的老中央燒餅店，每次一出爐就會馬上聚集排隊的人潮，店內提供的四種精緻口味，芝麻糖、蔥肉、紅豆、芝麻醬，味道調得剛剛好，而蔥肉裡一層一層的夾肉也很好吃，每層燒餅都非常的酥脆且層次分明，而這間小店在同一個社區內遷徙過數次，但是燒餅太好吃了，所以忠實的老客戶總是跟著來，不離不棄，而現在的接班人是六年級的陳志宏，以燒餅店作為他個人事業的起點，維持好吃的燒餅口味不減，並多了點朝氣，歡迎大家繼續光臨老中央燒餅店，並給堅持美味傳承的年輕人一點鼓勵。推薦產品:蔥肉燒餅、芝麻醬燒餅、紅豆燒餅、芝麻糖燒餅','中央路133巷22號','231',24.9733300,121.5312500,1,0.00,0,'ChIJS5XYKhkCaDQRBVzWKMNyZa8','2026-05-30 23:26:35'),(389,'豆花朴','吃豆花還可以養生？堅持純手工且吃出健康的理念，以有機黃豆製造成的豆花跟豆漿，搭配蓮子、白木耳、芝麻糊等，再加上淡淡黑糖香氣的甜湯，讓你吃的健康又美味。這裡的豆花及配料，料多實在，豆花綿密鬆軟，自製的仙草蜜，更是在夏天令人消暑透心涼，冬季還有各式熱呼呼的甜湯，還有限定的桂花酒釀口味，千萬不能錯過。','建國路93號','231',24.9767600,121.5403700,1,0.00,0,'ChIJ57hQBPcBaDQR4pi91uELmNA','2026-05-30 23:26:36'),(390,'明宏蚵仁湯','位於三重三和夜市內、文化北路與自強路一段岔口，鹹圓商家隔壁的蚵仁湯，以粒粒碩大飽滿的牡蠣，煮出海味十足的鮮美甘甜湯頭，再配上一碗炒米粉，即是讓人稱道多年的美味餐點組合。商家的炒米粉在頗具Q度、口感不軟爛的米粉上頭，淋些帶著豐腴肉燥的滷汁，散發誘人的香氣；如果不喜歡滷汁裡的肥肉，亦可先告知商家不澆湯汁，可口程度一樣不打折。','文化北路87巷3號','241',25.0675400,121.4982700,1,0.00,0,'ChIJ67XzRKSpQjQRY8kNd25CGBE','2026-05-30 23:26:37'),(391,'祥鈺港式茶樓','位於緬甸街上，賣的卻是港式點心，祥鈺多年來以真正道地的港式美食，緊抓住無數老饕們的胃，除了最有名的蟹黃燒賣、叉燒包、叉燒酥、鳳爪、腸粉等，炒飯類也是必點美食。近捷運、食材佳、平價又實惠，是內行的在地人無不豎起大拇指推薦的熱門名店。','華新街65號','235',24.9841100,121.5081700,1,0.00,0,'ChIJ-6uVfm4CaDQRAlb_HRO87DA','2026-05-30 23:26:38'),(392,'雲南婆婆','靠近永和樂華夜市，位於錢櫃對面巷子裡的雲南婆婆，老闆娘是正港的滇緬華僑，靠著真材實料及好手藝，不少老饕慕名而來，一吃成主顧；價格平實、菜色多樣化、酸辣微甜引人開胃的清爽口感，是人氣不墜的祕密武器，曾受包括時尚玩家、非凡大探索等知名美食節目報導推薦，現於板橋及新店都開有分店。','大新街12號','234',25.0084500,121.5149500,1,0.00,0,'ChIJLZQKMeipQjQRKGa-RmzOin8','2026-05-30 23:26:40'),(393,'板橋壽司','平價的日式料理店，廣受附近的上班族及學生族群青睞，除供應各式壽司外，亦有提供蛋包飯，金黃略焦的蛋皮上，是紅豔濃稠的番茄醬，底下的飯粒十分入味。店內最大特色在於店門口的關東煮攤，可以挑選喜好的食材後，再一併至櫃檯結帳，沾上店家自製甜辣醬甚是對味，還能無限續湯。','重慶路17號','220',25.0080000,121.4609000,1,0.00,0,'ChIJf9ZaYqcCaDQRZpoTZhc9Y_U','2026-05-30 23:26:41'),(394,'深坑竹香肉粽','身為客家人的老板娘，保有傳統客家風味並獨特研發的客家粽，是使用菜脯、蝦米、肉絲及香菇絲的獨特口味，一直深受老饕們的喜愛。位於深坑老街附近的深坑竹香肉粽，除了有傳統的南部粽及北部粽，店內還有提供客家粽、素粽、紅豆粽等多種口味，南部粽還有北部粽的餡料有蛋黃、香菇、五花肉、花生、栗子等，差別在於米粒的製作方法，口感也不大相同，而特製的紅豆餡甜粽，更是不能錯的好滋味。','北深路2段210號','222',25.0015900,121.6130800,NULL,0.00,0,'ChIJvzxQXsSqQjQREMzqHYYq17s','2026-05-30 23:26:42'),(395,'可樂屋','平價美食可樂屋的人氣商品為穿上酥脆外衣加上醃製入味的豬排，以及滿滿馬鈴薯內餡，還吃得到馬鈴薯口感的可樂餅，價格經濟又實惠，讓外帶人潮永遠洶湧。推薦菜色:咖哩豬排飯、可樂餅','新豐街8-1號','242',25.0345700,121.4487500,1,0.00,0,'ChIJDSPJ_XSoQjQR94KA413-62A','2026-05-30 23:26:43'),(396,'鼻頭阿珠老店活海鮮','鼻頭阿珠老店海鮮餐廳在地經營26年，各式活海鮮料理應有盡有，開放式店面整潔清淨且營業時間很長，提供鼻頭饕客用餐場所。而店中除味道新鮮的海鮮料理，也有團體 用餐的經濟合菜，多樣菜色可供選擇，而XO飛魚卵炒飯、乾煎鮑魚、冬瓜蒸海魚、川燙藍尾蝦、涼拌蜈蚣菜以及函天石花凍等都是極具當地代表性的美食，最適合是三五好友或是團體聚餐。推薦菜色：XO飛魚卵炒飯、乾煎鮑魚、冬瓜蒸海魚、川燙藍尾蝦。','鼻頭路115號','224',25.1227000,121.9164000,3,0.00,0,'ChIJY7jTRfFPXTQRYlO7O_xLSIU','2026-05-30 23:26:44'),(397,'林記香菇赤肉羹','新莊老街因為古廟林立，所以又有「新莊廟街」之名；現在的新莊觀光夜市以新莊路為主軸貫穿，從利濟街到新泰路長達350公尺的路段，入夜後就改為行人徒步區，商家林立，十分熱鬧。林記香菇赤肉羹位於新莊路上，就在三級古蹟武聖廟旁邊，店面的坪數不大，外貌老舊，且店外沒有任何招牌，整體的作風相當低調；不過，店內三代相傳，飄香了將近六十年的好味道，在新莊地區老顧客們的口耳相傳之下，可是一點都無法低調。精選新鮮豬後腿肉有別於市面上常見的肉羹，傳承兩代、在新莊老街經營超過半世紀的「林記赤肉羹」，從早期販賣的冰品、貢丸，到今日的赤肉羹，始終堅持品質，因此名列新莊在地人最愛「呷好逗相報」的美食老店之一。推薦菜色:香菇肉羹湯推薦名人:黃林玲玲議員推薦','新莊路344號','242',25.0338000,121.4499700,1,0.00,0,'ChIJe5M7k3SoQjQRvcaRu_2h-EI','2026-05-30 23:26:46'),(398,'金成蘭餅店','碧潭是新北市著名的風景地，隨著捷運新店線的通車，部分的人都直接走上吊橋，忽略了旁邊這條新店路，早在清道光年間即已存在，雖然現在已經看不出舊時景象，但這條老街一直是新店區的行政中心，老街形成交易中心，雖然昔日繁華不再，但仍有一些老店，持續在老街默默耕耘。和民俗信仰緊密結合例如公有巿場旁，已有將近百年歷史的金成蘭餅店。再度為碧潭帶來人潮。原本和生活緊密結合的糕餅，隨著社會變遷，信仰習俗的轉變，年輕一代對傳統糕餅及背後的文化意涵愈來愈陌生，所以這幾年來，接手老店已十幾年的陳志信，開始配合學校、文化單位等團體參訪需求，在店內解說糕餅與歷史、文化、民俗的關係，延續糕餅的文化精神。這也是金成蘭堅持與傳統文化民俗結合的初衷，不走燈光美氣氛佳的觀光土產路線，希望自己提供的是可以一窺民俗傳統精神的文化土產。「龜」的專賣店在各種糕點中，各種以「龜」為造形的產品是金成蘭最大的特點。','新店路155號','231',24.9549800,121.5370500,NULL,0.00,0,'ChIJucC_2CkCaDQRVc4xzebmiG4','2026-05-30 23:26:47'),(399,'新巴黎食品坊','新巴黎原本是新店區第一家西點麵包店，在西點不普及的年代，在當時可是十分時髦流行的店舖。私房滷味，傳出好口碑從新潮西點轉賣傳統滷味，其實事出偶然。現任店主的父親李正朝，除了會做麵包，也很會做菜，常做滷味給孩子當零食，因緣巧合下，讓麵包店的熟客嚐到李正朝的私房滷味，大為驚艷，演變成「來麵包店卻指名買滷味」的新鮮事，新巴黎的好吃滷味就此傳出口碑，也就此從麵包店轉型賣滷味。香草麻辣助陣，滷味更有味第二代接手後，李家兄弟倆負責做麵包，滷味就由大嫂黃素莉負責，她跟著公公李正朝學了一年多，才正式掌廚。有感於傳統滷味添加太多八角等辛香料，當時正流行香草料理，黃素莉試著在滷味中加入檸檬草、馬鞭草，意外發現有回甘的作用，之後又加入泰國朝天椒，增加麻辣口味，一開始公公質疑辣滷味的接受度，但客人卻很捧場，香草麻辣滷味就成了新巴黎的招牌。','北宜路1段96號','231',24.9554500,121.5389400,NULL,0.00,0,'ChIJ00cT5ocBaDQRrq4e03UGBxQ','2026-05-30 23:26:48'),(400,'周萬珍餅店','在礦業發達的年代，位於十分街上的周萬珍餅店生意興降，當地人無論婚喪喜慶、祭祀或平常食用的糕餅，都來自周萬珍，在平均日薪只有70幾元的年代，周萬珍一天就能有上千元的營業額，除了本店的生意，也很多人批貨去賣。隨著西式糕點進入臺灣，傳統糕餅業受到極大的衝擊，而周萬珍餅店面臨的挑戰更大，因為礦業沒落，平溪區人口大量外移，極盛時期的人口是現在的四、五倍，所以，在1986年後，周萬珍餅店只好慢慢轉型為一般柑仔店。但店內仍有販售平溪餅(傳統月餅)、黃金酥餅(敬神點心)。隨著平溪支線旅遊業的發展，周萬珍餅店再度重生，年輕人去平溪放天燈，也不忘到周萬珍嘗嘗傳統糕餅的滋味。店內目前生產的古早餅有1/4改良款大餅、黃金酥餃、咖哩餅、綠豆椪、碰餅。剛出爐的現烤香氣，是最吸引人的時刻。','十分街120號','226',25.0430500,121.7770500,NULL,0.00,0,'ChIJyxOjkOhQXTQREMhFaJ378M8','2026-05-30 23:26:49'),(401,'味香魚丸店(許義魚酥)','淡水老街上有不少店家販售著魚酥，其中味香魚丸店是淡水魚酥的創始老店，所賣的魚酥包裝則以老闆許義為名。淡水魚酥聞名全臺，其由來卻相當有趣，據說以前魚酥的口感並不是那麼酥脆的，而是老闆許義有一次在炸好後，不小心又掉到油鍋中，沒想到卻大受顧客青睞，過 去當地居民是拿來配稀飯吃，現在的遊客則是用來下酒或當休閒零嘴。魚酥的作法是將黃魚或鯊魚的骨肉碾碎，和上蕃薯粉下鍋油炸至香脆，以塑膠袋封裝後，就是 淡水名產「魚酥」了。','中正路184號','251',25.1700200,121.4402500,1,0.00,0,'ChIJl_4AhFmlQjQRiFdSvjBBZ88','2026-05-30 23:26:50'),(402,'興隆酸梅','來到淡水，很多人都會來杯古早味酸梅湯。各家酸梅湯風味不同，其中以來自南投自家梅子為原料的興隆酸梅，還吸引日本雜誌「昭文社」跨海採訪，廣受日本客及國人的喜愛與光顧。南投手工梅 變成淡水在地味「興隆」原是淡水第一家文具行，原本什麼都賣的小店，隨大型商場進駐淡水，消費習慣改變，南投媳婦徐素蓮引進娘家手工製作的梅子，轉型成酸梅湯及梅製品專賣店。店內商品不添加糖精、防腐劑，天然健康，而且不會黏膩也不會太鹹，除了以紫蘇梅熬製的酸梅茶，低鹽話梅、紫蘇梅、化核梅也很受歡迎。去年春天，興隆酸梅重新改裝，由第三代徐素蓮就讀室內設計研究所的女兒親自操刀、兒子幫忙，量身打造展示櫃及門口的攤子，明亮的風格，一改老店晦暗凌亂的形象，店裡的生意也明顯提升，下一步希望幫產品換包裝，讓產品不只是貨真價實的好料，更有出色的賣相吸引遊客來品嚐這份最道地的好滋味。推薦產品：低鹽話梅、紫蘇梅','中正路143號','251',25.1705200,121.4391300,NULL,0.00,0,'ChIJw5sWMFqlQjQRizGnZhLBnl4','2026-05-30 23:26:52'),(403,'阿蘭草仔粿','產品的新鮮也是許老闆最在意的，因此當天製作當天銷售，絕不隔夜販賣，而且選用最好的食材，絕不偷工減料，才有今天用料實在，味道獨特的阿蘭草仔粿出現；另外許老闆考量到糯米容易引起脹氣等問題，特別研究出將艾草改以鼠麴草來替代。因為對產品用心，對顧客用心，就是阿蘭草仔粿能經營半世紀的撇步。近年來阿蘭草阿粿開始了宅配的服務，讓遠在中南部的顧客不用千里迢迢北上九份，就能品嚐到這份用心的滋味，許老闆說這也是對顧客最好的回饋。','基山街90號','224',25.1086900,121.8442200,1,0.00,0,'ChIJ3-ED_BdFXTQRSdQ_IIRdiKM','2026-05-30 23:26:53'),(404,'蘭香坊','1.紅心土芭樂 係台灣野生種，採有機套袋栽培，不用擔心農藥與蟲蝕，含豐富vit C、茄紅素、鐵質、膠質，對心臟、血管、皮膚都很好。2.紅心土芭樂汁(新鮮現打)3.紅心土芭樂乾(純手工日曬)4.金棗(桔)：是鹼性的水果，富含vit C、vit P、類黃酮，顧喉嚨顧氣管，對肺部很好。5.金棗(桔)醬6.金棗(桔)喉糖我們的芭樂為---台灣野生種紅心土芭樂 我們的紅心土芭樂參加農會所舉辦的紅心土芭樂評鑑 勇奪特等獎與頭等獎殊榮 接受GTV八大電視台 候昌明主持的大特寫採訪 希望喜愛此項農產品的朋友也可分享此份喜悅','基山街173號','224',25.1078400,121.8432200,NULL,0.00,0,'ChIJNwDzTABFXTQRjvR2f6Kedd0','2026-05-30 23:26:54'),(405,'春野新派川菜','春野新派川菜老闆郭主義，人稱「古錐師」，他13歲入行就立志要當大廚師，對川菜情有獨鍾，三天兩頭就到四川「取經」，為的就是能夠給客人新的味覺驚喜。川菜的最高境界是「舌麻唇不辣」，古錐師常用一句順口溜來形容川菜的滋味：「三香三椒三料，七滋八味九雜」，媒體都封他為「川味王」，曾榮獲上海食神蒸霸賽金牌獎。「古錐師」會做的川菜料理有100多種，像水煮魚、剁椒魚頭、孜然香辣肉、水煮牛肉、椒汁白肉、嗆鍋黃魚和賽螃蟹，都是店裡的招牌菜。賽螃蟹其實是用蛋白、鱈魚和兩、三隻蝦子，用小火慢炒，再用大火炒乾，三樣混合起來，就像棉花糖一樣細嫩，起鍋加上一顆蛋黃攪拌，就有濃濃的螃蟹味了；椒汁白肉吃起來舌尖香麻，嗆鍋黃魚則香而不辣，還有不容錯過的川菜代表水煮魚和水煮牛肉，除展現古錐師精湛的炒菜功夫，用料講究也是秘訣。','文化路一段188巷36號','220',25.0190900,121.4666400,2,0.00,0,'ChIJhfsZvBeoQjQRFPlSGHrLRV0','2026-05-30 23:26:55'),(406,'上牛鐵板燒','板橋知名的鐵板燒，不論是食材、氣氛、服務走的都是頂級餐路線，價位雖高，但絶讓客人感到物超所值。吃鐵板燒最過隠的，不外乎看主廚以精湛手藝現場料理，新鮮看的見之外，肉汁在眼前滋滋作響，端盤上桌時那恰到好處的鮮嫩口感，絶對叫人畢生難忘。鐵板燒的吃法，主要在視覺味覺的同步享受，上牛長年以來，大廚們的頂尖技術在鐵板燒美食界中獨樹一幟，深獲美食行家好評，板橋的名人雅士也愛來這聚餐唷！推薦菜色:海陸特餐、精緻海陸套餐','民生路一段33號1F-1','220',25.0122200,121.4757900,3,0.00,0,'ChIJKQS2QiSoQjQRes5LJDfPQwI','2026-05-30 23:26:56'),(407,'彭園湘菜館','北部有名的湘菜連鎖店，精緻菜餚與高品服務深獲行家推崇。在高級餐廳中享受酒香濃淳、味道厚實的醉雞，或皮酥肉嫩的酥烤鵪鶉等美食是人生一大享受，還有相當大的空間與席次，也吸引板橋人前來辦喜宴。推薦菜色:左宗棠雞、富貴雙方、彭家豆腐','雙十路二段239號4樓','220',25.0294000,121.4727200,2,0.00,0,'ChIJjUTyH0GoQjQRq_mLkY4WFQc','2026-05-30 23:26:57'),(408,'永久手工包子專買店','隱身在新埔市場內這家赫赫有名的手工包子店，可別瞧店家外觀不起眼，它可是網路上人氣頗旺的團購美食，個頭紮實的大包子，包進筍塊、鮮肉、高麗菜冬粉、芝麻餡、紅豆餡等各種好料，吃一個就能飽很久，是實惠又好味的經濟美食。','文化路一段435巷31弄4號','220',25.0232400,121.4668400,1,0.00,0,'ChIJ56xn3BWoQjQRoAzmAugOzI4','2026-05-30 23:26:59'),(409,'熊記燒餅油條專賣店','熊記是許多新莊人的回憶，必吃的油條口感與眾不同，外皮酥脆但咬下後口感紮實，沾著花生湯，能吸滿飽飽的湯汁，樸實的燒餅，夾上熱騰騰的油條，帶給您一整個早上的溫暖飽足。推薦產品:燒餅油條推薦名人:黃林玲玲議員推薦','新莊路206號','242',25.0347600,121.4536000,1,0.00,0,'ChIJnUemsXOoQjQRkutOYZx7Gy8','2026-05-30 23:27:00'),(410,'翁裕美商行','「有點黏，又不會太黏，金黃又透明的色澤、香又微甜」，這就是新莊的麥芽糖。翁裕美麥芽糖遵循古法表現出製作的堅持，清香甜軟的味道瀰漫在口鼻之間，入口即化，不會黏牙，相較於其他麥芽糖，翁裕美的麥芽糖有麥的香味多過於甜味。','新莊路128號','242',25.0358100,121.4557100,NULL,0.00,0,'ChIJqbibMgGpQjQRwEUmsnOdwtA','2026-05-30 23:27:01'),(411,'好吃當歸鴨麵線','經過熬煮的濃厚當歸湯頭搭配鮮嫩的鴨肉，麵線的樸實美味，加上鴨肉扎實的口感與新鮮滋味，能夠同時暖和並滿足您的味蕾，堪稱一大享受。推薦菜色:鴨肉麵線、鴨肉冬粉','永平路187號','234',25.0092800,121.5101400,1,0.00,0,'ChIJhbj1DcOpQjQRpqwwbNyjG5s','2026-05-30 23:27:02'),(412,'義聚東/劉家水餃','位於永和韓國街的的義聚東/劉家水餃，第一代是祖籍山東威海的劉崇嵫夫婦，1947年兩人才19歲，就從家鄉東渡韓國，再到台灣，憑著家鄉學到的手藝，加上鄉親切磋，於1955年開起「義聚東餅店」，後由與店同齡的第二代劉德綱夫妻接手，也賣起北方熱炒、麵食、水餃等，深受美食作家朱振藩好評，超人氣的山東燒雞、三鮮炸醬麵、飽滿水餃、炒碼麵等，不僅媒體愛報導，更是山東伯伯懷舊的老滋味。','中興街98號','234',25.0122400,121.5189800,2,0.00,0,'ChIJQ554keupQjQRtAqCCXPuyko','2026-05-30 23:27:04'),(413,'下港米糕排骨酥店','魯肉魯的軟爛好吃、先炸後醃的排骨酥、配合冬瓜片與高湯蒸煮後，不管是裡頭的排骨酥或冬瓜片，全都是入口即化的好滋味。推薦菜色:特製排骨便當','保平路14號','234',25.0075700,121.5126100,1,0.00,0,'ChIJUSVax8KpQjQROtkcMOSwUx0','2026-05-30 23:27:05'),(414,'文化養生豆漿豆花','碗豆花食感大躍進，香濃綿密的豆漿豆花，超有飽足感！市面的豆花多使用糖水當湯底，但湯底過甜的話，便會影響到豆花的口感，因此老闆改用不加糖豆漿、杏仁茶當作豆花的湯底，讓豆香更為濃郁。推薦產品:綜合豆漿豆花','永貞路267號','234',25.0068800,121.5208900,1,0.00,0,'ChIJLU-yBd2pQjQRloBPbC1k04I','2026-05-30 23:27:06'),(415,'永新豆漿店','\"巷子裡的美食，食材實在、服務周到、價格公道，最為特別是永新豆漿為永和地區學校提供的愛心早餐來源，老闆的愛心值得大家去鼓勵彭場！推薦產品:燒餅油條加豆漿\"','竹林路213巷2號','234',25.0087800,121.5210300,1,0.00,0,'ChIJo1lcv-6pQjQRBKPACDrDEDo','2026-05-30 23:27:07'),(416,'麵嫂麵攤','雖然位在夜市不太顯眼的地方，不過熱情可愛的老闆娘和好吃便宜的麵，在當地仍舊擁有許多老顧客，美味的古早口味，客人最愛首推餛飩麵，餛飩的內餡拌了油蔥，吃來香氣更濃，到了樂華夜市也別忘了試試這在地人喜愛的平民美食喔!','保福路一段33號','234',25.0089600,121.5127300,NULL,0.00,0,'ChIJ5SWEvMKpQjQRZwAmKsZkm80','2026-05-30 23:27:08'),(417,'蓮薌冰糖蓮子','店家已有10餘年歷史，以純冰糖精熬的甜湯，口感豐富，征服挑剔的味蕾，來此絕對不容錯過的就是蓮子湯，除了從產地挑選優良品種，更堅持用手工剔除蓮心，剪去蓮子的黑端，讓每一顆蓮子都淨白無瑕，飽滿可人，軟滑的蓮子入口時，口感綿實，炎炎夏日來上一碗，讓人暑氣全消。推薦產品:桂花酒釀湯圓','得和路180號','234',25.0001700,121.5198300,2,0.00,0,'ChIJexiEA-ypQjQRdWB7Biovm38','2026-05-30 23:27:09'),(418,'閹豬切仔麵','要品嚐要動作快的美食，位於新莊區中正路大漢橋頭「閹豬切仔麵」，到下午1點就打烊了，目前經營到第三代，美味不變，特別是每日在攤子上現切現賣的三層肉，淋上獨家配方沾醬、薑絲，吸引無數老顧客的味蕾。','中正路139號','242',25.0381600,121.4598100,NULL,0.00,0,'ChIJMRvcqW-oQjQRGJNqp4LANtg','2026-05-30 23:27:11'),(419,'正古早味(古早味鹹湯圓)','深夜十分還是依然人潮洶湧，位於新莊的24小時不打烊的美味，當你夜深時肚子餓時，店家料好實在美食，正是解飢的好選擇！推薦菜色:鹹湯圓、蝦仁扁食、燒肉麵 、虎皮蝦捲','新莊路317號1F','242',25.0342000,121.4528100,1,0.00,0,'ChIJURrOoXOoQjQRQtuQl_xyUGQ','2026-05-30 23:27:12'),(420,'北城脆皮烤鴨','肉質鮮甜的鴨肉，烤得恰到好處的外皮，用烙餅與蔥段一起包裹，搭配獨特的醬汁，滿嘴都是鴨肉的鮮美與蔥的辛香。大火快炒的鴨肉、蔥與蒜的組合，鹹辣適中的口味與鴨肉堪稱絕配。','中正路248號','235',24.9941100,121.4956400,2,0.00,0,'ChIJ1Yo7k3gCaDQR8Ag8vtmgCGw','2026-05-30 23:27:13'),(421,'方王媽媽堅果饅頭','柔中帶勁的麵糰，搭配精選的松子、腰果、核桃、杏仁等各種核果，自然清新的風味，讓這饅頭成為熱門的人氣美食。推薦產品:堅果饅頭','立德街98巷72號','235',25.0085500,121.4885000,NULL,0.00,0,'ChIJnQYY9SyoQjQRlhdAlCrHmK0','2026-05-30 23:27:14'),(422,'老兵牛肉麵','裝潢優雅整齊有致的店面烹調技術非常高超，肉質好完全入味，牛肉凍口感獨特，牛腸小菜特色鮮明，充分發掘牛味的烹調，強力推薦。本店榮獲「北縣我最牛－牛肉麵pk賽」民眾票選第3名。推薦菜色:牛小排麵、老兵霸王麵','員山路453號','235',25.0041800,121.4804600,2,0.00,0,'ChIJhcIFBSioQjQRtKG_kLcOxPM','2026-05-30 23:27:16'),(423,'老饕園','擁有二十年以上的歷史老店，老饕園是附近居民從小吃到大的美食記憶，也適合親朋好友齊聚一堂大啖佳肴。走一趟窗明几淨的老饕園，舒適寬敞的用餐環境深獲饕客們喜愛，若是在想要在熱門時段來打牙祭可得靠些運氣，老饕園打下的好口碑讓美味不脛而走，店內高朋滿座的景象更是屢見不鮮。老饕園以道地的家鄉味川菜為主，翻開菜單看著琳琅滿目的菜單真是不知從何下手，其實張老闆本身就熱愛美食，是個名副其實的老饕，深知北方麵食以及川菜的美味祕訣以及料理重點，製做過程從食材到烹飪方式都極其講究，因此熟客們都說在老饕園裡，每一道菜色都是是主打，三五好友一同光顧才能多點幾道佳餚，嚐遍各種好滋味。','興南路一段46號','235',24.9907300,121.5109900,2,0.00,0,'ChIJDep3hHMCaDQRBRWIkZtG1PE','2026-05-30 23:27:17'),(424,'日發巴拉打','日發巴拉打的印度烤餅，可說是華新街餅類美食的代表作之一，主人鄭尚仁為緬甸華僑，在因緣下和一位印度烤餅老師傅學到烤餅的功夫。鄭老闆每天上午賣餅，下午就在店裡揉麵糰，一層麵糰、一層酥油，幾次來回下來，麵糰與酥油完全融合，然後再放一晚，讓麵糰發酵。隔天一早等客人點用，再壓平後貼在烤爐裡，幾分鐘時間，好吃的烤餅就上桌了。巴拉打其實就是烤餅之意，除了令人讚不絕口的烤餅，下平底鍋小火煎的煎餅，也是人間一大美味。材料和烤餅一樣，只是烤、煎作法不同，依客人喜愛點用，加上砂糖、咖哩等不同食材，就成了不同口味的巴拉打。記得，吃烤餅、煎餅，一定要點上一杯真正來自印度的阿薩姆奶茶，餅和茶的絕配，更是道地的緬甸人豐盛早餐的代表。','忠孝街7號','235',24.9828000,121.5098800,1,0.00,0,'ChIJNX7Be24CaDQRqq8x8ZmUomc','2026-05-30 23:27:18'),(425,'雲林福記烤鴨','以特殊口感、皮脆肉嫩的鴨肉，以及沙茶炒大骨做成招牌烤鴨三吃，贏得臺灣烤鴨王爭霸賽第三名，也是新北市唯一入選得獎的烤鴨店，吳老闆一家族都在經營烤鴨生意，每天上午烤鴨一出爐就有內行老饕口碑相傳來排隊。用雲林土番鴨為材料，川燙後淋上麥芽汁，風乾後以木炭火烤，切片配上自製的甜麵醬、麵餅和蔥段，鮮嫩欲滴的鴨肉，和重口味的鴨骨一搭配，就是人間絕妙美食。推薦菜色:招牌烤鴨','圓通路208號1樓','235',24.9941000,121.4962500,2,0.00,0,'ChIJ64bbGnwCaDQR7SR9TF9IsyM','2026-05-30 23:27:19'),(426,'王家美味點心','老闆依照傳統作法，所有的餡料都是親手製作，到附近山坡採青苧麻，烘乾製粉加入糯米蒸熟，染成純天然的綠色草仔粿，使用舊米，讓口感更Q。捏一小口，光吃粿就很香，客人上門買，才現場包餡，到九份逛逛時別忘了試試看哦(總店位於汽車路21-2號)。推薦產品:草仔粿芋粿巧','九份汽車路21-2號','224',25.1082900,121.8439400,1,0.00,0,'ChIJuQ8A1BlFXTQRyOg1heZwfYo','2026-05-30 23:27:20'),(427,'華記龍鳳腿','內餡以豬絞肉、紅蘿蔔丁、洋蔥丁、魚漿等構成，再以豬網脂包覆在肉餡外，豬網脂在經過高溫的油炸後融入肉餡體中，一咬下口後，無比的滑順口感，即使再燙口，也別忘了一嚐這美味的在地小吃。','民生街23號','224',25.1074200,121.8059500,1,0.00,0,'ChIJbegZw7hPXTQRvm5MfkBFDbs','2026-05-30 23:27:22'),(428,'福州林記胡椒餅','內餡肉塊比例肥瘦大約一半一半，調味帶著有著淡淡的胡椒與甜味，再搭配一些蔥增添香氣；餅皮硬脆有層次，內餡鮮甜會噴汁。','民生街35巷2號','224',25.1068300,121.8056300,1,0.00,0,'ChIJy3gjWPdPXTQRbV--YBvTX5Q','2026-05-30 23:27:23'),(429,'福哥牛肉麵','瑞芳在地的知名牛肉麵店，以台式牛肉麵著稱，湯頭帶有淡淡的中藥味，牛肉部份使用牛腱子肉，肉質紮實，麵條Q彈有口感，且價格實惠，經過瑞芳時值得一試。','民生街21號','224',25.1075800,121.8059900,1,0.00,0,'ChIJeas9W_dPXTQRtrf2HCBt-mY','2026-05-30 23:27:24'),(430,'保雲芋圓','假日經常座無虛席，不少客人都是衝著香Q的大顆芋圓冰及香濃綿密的芋頭而來，由於料好實在，「吃得到芋頭角」，讓客人口耳相傳。推薦菜色:菜頭滷、芋圓、涼麵、肉圓、乾麵、扁食','瑞芳街8號','224',25.1099100,121.8067100,1,0.00,0,'ChIJI6hE5vZPXTQRhMvGTRMk9rE','2026-05-30 23:27:25'),(431,'礦工食堂','這裡沒有人聲雜沓的街道，也沒有水泥建構的都市叢林。只有寧靜悠閒的小鎮和最悅耳的蟲鳴鳥叫；美食與自然景觀的完美結合，帶您回到心中嚮往已久的桃花源。餐廳內販售人氣甜點-地瓜霜淇淋，嚴選產量稀少之台農18號番薯，經多道繁複程序而成；不只吃得到獨特的香甜滋味，更能感受到農民們對這塊土地的熱情；而聯繫一家人情感的礦工便當，簡單的菜色裡卻有著最真實的感動，更是您到黃金博物館不能錯過的重點美食。若是想品嚐道地義式料理，我們亦有有別於一般觀光區的精緻安排可供選擇；餐後來壺日月潭紅茶或香醇的咖啡；美景相伴，堪稱人生一大樂事！在這裡，你可以寫下屬於自己的故事、記錄人生中的重要時刻；誠如溫暖的陽光；我們只想給您熱情的微笑、美味的餐點。礦工食堂-黃金印象咖啡館誠摯歡迎您，與我們共譜歡樂的樂章。特色推薦:礦工便當、地瓜霜淇淋','金光路8-1號','224',25.1084200,121.8562000,2,0.00,0,'ChIJ9653Kh5FXTQRAm5i2jxL4M4','2026-05-30 23:27:27'),(432,'帝王食補紅面薑母鴨(創始老店)','帝王食補田正德創辦人因緣際會下得到舊識相贈帝王養生藥膳良方，懷著感恩分享之心，在1981年草創全台第一家帝王食補薑母鴨。鵝黃色燈籠與食補香氣，吸引顧客成群上門，營造了台灣人鬥陣圍爐吃好料的獨特飲食文化。30餘年來店鋪歷經多次轉型與蛻變，產品也由單一燒酒薑母鴨到順應四季多元化養身鍋品，而本著分享健康、傳遞溫暖的心情，致力提升服務與品質的初衷始終不變。『人情味』是台灣最珍貴的特產，也是帝王食補最珍貴的秘方! 2005年起帝王食補跨出台灣，在海外設立多家分店，就是希望將這道地的台灣味分享國際，成為全球矚目的台灣獨特好味道。','長江路三段132號','220',25.0344800,121.4756300,2,0.00,0,'ChIJt_zT8kSoQjQRCZUXpMK-bKo','2026-05-30 23:27:28'),(433,'燒肉粽大賣場','除了在端午佳節吃的到各式肉粽，平常想吃美味的古早味肉粽，那就不能錯過這間燒肉粽大賣場，成立於民國85年的燒肉粽大賣場，不但對於品質以及味道有所要求，更在產品的製造與品管上，投下相當大的心力，遵循古法製作，餡料以特殊配方調製，讓肉粽色香味俱全，並以直營店的方式，提供給消費者乾淨明亮的用餐環境，來享受精緻的傳統美味。店內的肉粽口味眾多，除了千禧干貝粽、三寶蛋黃粽、香菇肉粽、南部水煮粽、花生粽〈菜粽〉外，為了貼近大眾對各種口味的需求，更研發以油飯炒開的竹筒飯、筒仔米糕、碗粿等美食系列，以平民化的價位，提供五星級的口味。','漢生東路111-2號','220',25.0152200,121.4672500,1,0.00,0,'ChIJi_ZQZhioQjQRK-XPbX5N090','2026-05-30 23:27:29'),(434,'七張米粉湯','宵夜的好伙伴，肚子餓的時候來碗米粉湯，再加上傳統風味的各式小菜，菜頭、豆腐..等，馬上讓你感到絕對的飽足，七張米粉湯是在地老店，從以前的小攤子到現在的店面營業，吸引的客人總是絡繹不絕，營業到半夜，讓夜班的加班人員和計程車司機還有一個地方能補充體力，遠遠就可以看到門口外的排隊人潮，不管是內用或是外帶，老闆都盡全力的滿足每個客人的需求，且靠近捷運站，所以客人有越來越多的趨勢。推薦菜色:米粉湯、蚵仔煎、黑白切','北新路一段239號','231',24.9658600,121.5406200,1,0.00,0,'ChIJQxIxCIsBaDQRSB_uHbL9_iw','2026-05-30 23:27:30'),(435,'張家小館','傳統的北方小館，無論是各式麵食、餡餅、小米粥，都保留著原汁原味，家庭式的格局，讓人用餐時倍感溫馨，這邊的麵條是現做的刀削麵，而小米粥搭配砂糖的吃法也很不錯。而這裡跟一般的北方小館不同的地方，除了賣餅賣粥外，也可以點菜，份量適中，口味樸實；牛肉捲餅及蔥油餅也是必點品項，有著外皮輕薄、帶點微微的焦香，口感不油膩，吃過的客人常外帶回去給家人享用；現做的刀削木須炒麵口感一流，配料紮實富口感，麵條咬勁十足，吃過都會再推薦朋友過來。推薦菜色:牛肉餡餅、花素餡餅、小米粥、木須炒麵','中興路一段265號','231',24.9676400,121.5447400,1,0.00,0,'ChIJVQL3MfMBaDQR1kuozt7deNw','2026-05-30 23:27:32'),(436,'源平溪傳統豆花大王','小巧精緻的源平溪傳統豆花大王，採用日式風格的陶瓷碗來盛裝豆花，這裡提供傳統豆花還有各式古早味挫冰及甜湯，來到這裡，網友一致推薦招牌的紅豆煉乳挫冰，細緻的紅豆再淋上香濃的煉乳，嚐在嘴裡有種幸福的滋味，真材實料，價格也是非常的物超所值。推薦產品:豆花芋圓,紅豆薏仁湯、芋圓仙草凍','新店路205號','231',24.9566700,121.5371000,NULL,0.00,0,'ChIJGXuD_YcBaDQRiTO9wrRkV7M','2026-05-30 23:27:33'),(437,'甕仔壯壯雞','使用正宗放山雞，原木悶燒的甕仔壯壯雞，曾經創下單日狂賣六百隻的紀錄，以手工調製燒烤，加上獨家配方的中藥香料，烤出來的放山雞滑嫩多汁，完全不會有乾柴的口感，令人愛不釋手；這裡還有提供各式山產野菜，如竹筒飯、龍鬚菜及炒溪哥等，適合全家大小一同來回味古早時光，品嚐最原始的味道。推薦菜色:噴汁甕仔雞','新烏路二段9號','231',24.9293000,121.5446700,2,0.00,0,'ChIJf4LMiGYBaDQR-FVmlD1Qm_8','2026-05-30 23:27:34'),(438,'粉圓王','在三重區享有極高評價的粉圓王，雖然才開業已逾七年，但粉絲可是來自大臺北各地，一年四季不論何時，店裡來吃黑糖粉圓的行家們，總是習慣了這裡排隊的盛況。廿幾種美味甜品冰料，讓客人自由搭選，以黑糖粉圓為基底。各種配料可以做成美味的剉冰，也能帶走當成時下最流行的飲品，美味兩吃的變化，很受饕客們的喜愛。','自強路一段270號','241',25.0676000,121.4923100,NULL,0.00,0,'ChIJW8D0muaoQjQRF1vgKdnb0g8','2026-05-30 23:27:35'),(439,'旻樺素食','老板夫婦最早是在先嗇宮廣場前賣素食攤，現在的店面用餐環境素淨舒適，所賣的素食熱食種類多。拿手創新的紅燒麵、紅燒米粉、紅燒冬粉，口味很棒，色香味佳（湯頭較甜），很有風味，豐盛菜色令人垂涎欲滴。最受青睞的紅燒麵的白、紅菜頭、素羊肉、素肉塊新鮮味醇，口齒留香。素水餃內高麗菜手工切細，加上香菇、紅蘿蔔、香椿等餡料，清脆可口。本店亦自製特製辣椒醬風味佳，不吃可惜。推薦：紅燒麵、紅燒米粉、紅燒冬粉、特製水餃麵、當歸麵、咖哩麵。','五谷王北街50巷47號','241',25.0515100,121.4749600,1,0.00,0,'ChIJn_4jvfaoQjQR266EkYkGDXY','2026-05-30 23:27:36'),(440,'Ancre café 安克黑咖啡','來到淡水，想要悠閒得享受下午茶時光，位在淡水河岸邊二樓的安克黑咖啡，讓你搭配著咖啡及美食，靜靜的欣賞淡水的美景，店裡的佈置充滿手作風味，木造的大門，進入玄關後，就看到有著復古風味的相機，搭配著懷舊木架，而特製的優格醬加上薯條的絕妙搭配，烤的香酥吐司，還有香脆洋芋片，都讓人一口接一口，停不下來，店內還有販售各式手工雜貨，喜歡的朋友一定要親臨這一間可愛的小店。推薦產品:安克黑咖啡、熱歐雷','中正路233-3號2樓','251',25.1733800,121.4352400,2,0.00,0,'ChIJSX_XplqlQjQRVeIJyQLCaeA','2026-05-30 23:27:38'),(441,'新莊好望角牛角麵包','專賣黃金牛角麵包小舖，以的上等材料手工製作，其牛角麵包口感扎實，而且又酥又香。','中原路219號','242',25.0541900,121.4503300,NULL,0.00,0,'ChIJ12lZuYCoQjQRVvvvqtpDVaU','2026-05-30 23:27:39'),(442,'宜蘭土包仔','土包仔門口總是大排長龍的原因，除了包子好吃、餡料紮實，每咬一口內餡湯汁直流，最重要的是有老闆夫妻倆對客人的貼心，且料多又實在，光成本用電子計算機一按，還真是替老闆捏把冷汗，結果老闆還說，這波油電雙漲，他還是沒打算要漲價，真是「足感心ㄟ」。推薦產品:招牌肉包、黃金黑糖麻糬包、黑胡椒豬柳包、泡菜豬肉包','文化路128號','239',24.9514600,121.3518600,1,0.00,0,'ChIJM5nrdHmoQjQR-Mrb83pquf4','2026-05-30 23:27:40'),(443,'阿香冰店','乾淨又明亮的冰店，以白色及藍色為主要裝潢，店內的剉冰配料都是手工親自熬煮製成，傳統豆花爽口清涼，黑糖漿淋在刨冰上，搭配黑糖做的麻糬，以及各式喜愛的手工配料，消暑又解渴，另外，除了在夏天提供冰品，冬天也有提供各式熱食甜湯。','樹德街55號','238',24.9918100,121.4210100,NULL,0.00,0,'ChIJY36lxBUdaDQR-o8uX1ePOvU','2026-05-30 23:27:41'),(444,'古早味蚵仔麵線','廟口的麵線一直讓人回味無窮，位於樹林千歲廟旁的古早味蚵仔麵線，已開店35年，很多小朋友跟著爸爸媽媽從小吃到大，濃郁的麵線香味，搭配著新鮮的蚵仔以及豬腸，讓人回味無窮，加上些許的辣椒及香菜，完整重現古早味的絕佳口感。','千歲街14號','238',24.9957800,121.4252100,1,0.00,0,'ChIJsSlfRhYdaDQRoZ3VklXYcUY','2026-05-30 23:27:42'),(445,'角之館(黃金牛角專賣店)','如果說吃牛角麵包要到三峽，那要吃正宗研發出多種口味的牛角麵包，就一定要到樹林的角之館來品嘗，以獨特口味吸引眾多饕客品嚐，葡萄奶酥還有焦糖瓦片以及巧克力口味供不應求，另外蒜味以及肉鬆口味也非常受到歡迎，特製的牛角棒讓小朋友當點心，營養又健康，團體訂購的熱愛。','保安街一段287-6號','238',24.9974000,121.4185900,1,0.00,0,'ChIJ_fbYOWsdaDQRI3T43JGKHqE','2026-05-30 23:27:44'),(446,'枋腳堡大天皇毛蟹城','遠離塵囂，享用美食欣賞美景，位於前往桃源谷路上的枋腳堡大天皇毛蟹城，以山產為主，特別以土雞、鱘龍魚、貴妃魚為招牌菜。農家子弟出生的黃老闆，開業十數載，在中華國際美饌交流協會擔任常務董事，對天然有機農產養殖非常用心經營，擁有自己的土雞養殖場、有機蔬菜農地、原生種絨鰲蟹養殖場，並有養殖鱘龍魚、貴妃魚，所有食材絕不添加抗生素。把食物的原味直接送入口中，加上葉下紅的野菜，養身又健康。','吉林村枋腳街13號','228',25.0015700,121.8891100,2,0.00,0,'ChIJwzA4gO9bXTQRfPQT50VBrmQ','2026-05-30 23:27:45'),(447,'阿生便當','來到貢寮，大部分的遊客只知道福隆便當，其實，貢寮也有專屬的火車站月台便當：以簡單傳統的紙便當盒，盛裝屬於記憶中的家常菜，爽口的高麗菜、香酥的炸雞翅、滷蛋及醃黃瓜，一出貢寮車站斜對面步行不到三分鐘，沒有明顯招牌，卻可以品嘗到懷念的味道。','朝陽街76號','228',25.0220500,121.9094300,1,0.00,0,'ChIJU64whFRcXTQRMLXIs9pYyLI','2026-05-30 23:27:46'),(448,'中葉飯店','中葉飯店老板花先生不但曾獲得2008新北市優質特色餐廳的殊榮，自行研發的伴手禮也獲得新北市十大伴手禮的肯定，其產品的精緻和美味值得遊客親自來品 嚐。花先生所研發的三寶包括了干貝XO醬、頂級海鮮醬和好呷丁香魚，不論是拌飯拌麵都很適合，也可搭配蔬菜拌炒，是自己品嚐和送禮的最佳選擇。這些美味除 了可以在店內吃得到外，現在也提供有宅配的服務，讓消費者在家也可輕鬆料理和品嚐。','德茂里下員坑30號','253',25.2829200,121.5198600,2,0.00,0,'ChIJWVjg1422QjQRi_aLZdvVoEw','2026-05-30 23:27:47'),(449,'長發切仔麵','店家的切仔麵，湯頭香甜、清爽不膩，再搭配黑白切小菜，是經濟美味的平民美食。推薦菜色:切仔麵、嘴邊肉、豬心、三層肉','中央路93號','247',25.0841400,121.4725900,1,0.00,0,'ChIJDXXUOs2oQjQRK4A4g-H_KVM','2026-05-30 23:27:49'),(450,'阿郎切仔麵','阿郎切仔麵的湯頭清甜而且不油膩，店家自製的醬料獨特，若是配上小菜或豬血糕，真是美味享受。推薦菜色:切仔麵、豬心、內臟、虱目魚頭','復興路30號之1','247',25.0850600,121.4723800,1,0.00,0,'ChIJLxORYcmoQjQR9M4n4JTTbGg','2026-05-30 23:27:50'),(451,'阿六切仔麵','是許多媒體爭相介紹的知名店家，小菜「黑白切」更是受顧客歡迎，而招牌的切仔麵，湯頭清香甘甜，麵條Q彈有勁，是非常實在的好味道。推薦菜色:切仔麵、鵝肉、卜肉、雞卷','長榮路280號','247',25.0867300,121.4601800,2,0.00,0,'ChIJC5txS7OoQjQRmQ4Ia-vtxSo','2026-05-30 23:27:51'),(452,'鳥來伯擔仔麵','到烏來泡湯賞景、放鬆身心，在進入烏來老街之前的美食名店「鳥來伯」可是老饕們必來朝聖的重鎮。鳥來伯擔仔麵老闆李啟全可是大有來頭，除了在大飯店學藝，當兵後經歷多家餐廳，最後自己開店，甚至持有很難考的乙級廚師執照，是美食界響叮噹的師傅級人物。除了店內著名的快炒，各式各樣的口味也難不倒他，白斬土雞、烤竹雞、烤松阪肉、紅糟軟絲、山豬肉、炒野菜、炒珠蔥、腸旺臭豆腐等各式山產海產，每樣都是飯店級的美食水準。','新烏路158號','233',24.8705000,121.5471800,2,0.00,0,'ChIJdQbghY8GaDQRCoFfrAUXrew','2026-05-30 23:27:52'),(453,'鶯歌林滷味','「鶯歌林滷味」已經創立二十逾年了，算是老店，每天總是大排長龍，受到大家歡迎的原因只有一個，那就是「新鮮」，老闆非常講究「衛生」和「新鮮」，口味更是最高境界，再來是價格合理，因此牢牢抓住顧客的心。','建國路152號','239',24.9539500,121.3510900,1,0.00,0,'ChIJ0ck10KseaDQRNyirQDVY9ic','2026-05-30 23:27:53'),(454,'滋味嘉羊肉麵','標榜著無腥羶味，老闆十分講究美味，十多年來走遍了南北各地嚐鮮，為的就是尋找更特別的美食，之後更慢慢研究改良，對調味方面更加的專精。店內必點美食\"紅燒羊肉麵\"，不僅麵好、湯濃、肉大塊還少了羊騷味，讓不敢吃羊肉的人也都能接受。','尖山埔路237號','239',24.9500500,121.3445500,NULL,0.00,0,'ChIJAQAAAKseaDQRRCT5ZTy3jyw','2026-05-30 23:27:55'),(455,'穎村食光','順著三峽文化路217巷進去狹窄的巷弄裡，就可以發現這件隱密的餐廳，用餐空間像是包廂式的，讓來用餐的客人都可以在這裡享受輕鬆、自在的時光，店家會定期變換菜色，但食材卻是一點都不馬虎，當天窯烤的披薩、烤雞及麵包都令人垂涎三尺，尤其是麵皮鬆軟、料好實在、卻甜而不膩的紅豆麵包，連新北市長朱立倫市長都讚不絕口! 來到這裡每次都會發現不同的驚喜，道道都是讓人會回味無窮的料理。','文化路213巷16號','239',24.9533800,121.3549400,2,0.00,0,'ChIJT35BVAIcaDQRX411_zCUKY8','2026-05-30 23:27:56'),(456,'昭和園','鶯歌昭和園的食材多且新鮮，店家裝潢也非常的日式風格，在純樸的鶯歌小鎮，有這麼高水準的日式燒肉店，總是吸引許許多多人前來用餐，也是朋友聚會的好地方。','光明街85號','239',24.9558200,121.3449700,2,0.00,0,'ChIJlf4teK4eaDQRsppoBO6vEwU','2026-05-30 23:27:57'),(457,'香香肉粽','位在土城的香香肉粽沒有實體店面只提供網路宅配，店家堅持無論是炒料、炸油蔥、熬滷肉、拌油飯、包粽子到送貨，全都堅持純手工製作。一顆粽子從原料到完成 全都是手工製作，用料也都是頂級嚴選食材，選用彰化精選尖糯米，紅蔥頭、蝦米配上獨家配方的醬汁拌飯，特選CAS五花肉及精心調配的滷汁經由長時間悶燉，埔里頂級的香菇及鹹蛋黃和栗子，以及製作繁瑣的的傳統手工流程，讓您每一口都吃出道地古早風味及香Q帶勁料好實在的肉粽，再再都是香香肉粽的堅持。(網路訂購為主)','中央路四段52巷42弄4號','236',24.9606500,121.4189300,NULL,0.00,0,'ChIJRVbEhQgDaDQRViwJfP45dO4','2026-05-30 23:27:58'),(458,'雅聖烘培專賣店','雅聖烘培專賣店，提供顧客多樣化的蛋糕麵包，尤其是店家的鹹蛋糕更是受到歡迎，吃起來有濃郁的鹹香、搭配恰恰好的鹹度、蛋糕綿密，平易近人的價位，帶給顧客無限的滿足。','裕生路53號','236',24.9864100,121.4479200,1,0.00,0,'ChIJBQjhoskCaDQRfus5Lumx4mY','2026-05-30 23:28:00'),(459,'三角湧(徐媽媽)醬菜茶','店家就位於祖師廟斜對面，最大的特色就是販賣手工醃製的各式傳統醬菜，自製豆腐乳、菜圃、嫩薑等傳統媽媽古早味醬菜，標榜遵循古法製作，與一般工廠做的截然不同，尤其是豆腐乳產品系列，更是吃起來口感濃郁，是炒菜、配稀飯的良伴。','長福街12號','237',24.9335900,121.3700500,NULL,0.00,0,'ChIJtwsDH-4baDQRtGKyrAUWsS8','2026-05-30 23:28:01'),(460,'三峽九鬮老店','\"陳記在地經營35逾年，賣的是當日新鮮溫體黑毛豬肉，秉持誠信、用心、堅持的好品質，店家販賣的香腸與其他香腸攤不同，就是香腸裡填充的是肉丁，而且不添加防腐劑，以新鮮豬肉製成，是當是許多婆婆媽媽必買的菜單之一。推薦菜色：香腸，鹹豬肉\"','成福路273號1樓','237',24.9235000,121.4283900,NULL,0.00,0,'ChIJEQHfe1wbaDQR6GIhmDdrxsg','2026-05-30 23:28:02'),(461,'鄭記豬血糕','位於三峽老街上的豬血糕店，老闆所賣的豬血糕Q軟有嚼勁，口感吃得到米粒的彈性，搭配上香氣濃郁的花生粉以及香菜，美味與香氣合一，完整呈現道地台灣小吃的美味，牢牢吸引住顧客的味蕾。','民權街87號','237',24.9328100,121.3693900,1,0.00,0,'ChIJOdyy6fEbaDQReK9gNPL1s2o','2026-05-30 23:28:03'),(462,'(中埔)阿嬤的日本冰','阿嬤賣的日本冰，就位在中埔靜安路二段198號，小小的一間店卻也讓人重溫小時候的記憶，冰箱內擺滿各式各樣的日本冰，有花生、巧克力、草莓、情人果等多樣口味、咬下一口、濃濃的滋味融化在你口中、在炎炎夏日清涼又消暑，一口接一口盡情的品嘗，享受這甜蜜的味道。','靜安路二段198號','226',25.0217100,121.7235800,NULL,0.00,0,'ChIJ_UhZlKhWXTQRuV7CfWYGxqk','2026-05-30 23:28:04'),(463,'阿吉嬸芋圓店','平溪的芋圓口感跟其他地方賣的不一樣，這間芋圓已是屬於在地人從小到大的共同記憶，當天現做現煮的芋圓，軟嫩卻富有嚼勁，讓許多遊客一試就成主顧，每隔一段時間就要回來再光顧一次，除了好吃的芋圓，濃郁的地瓜圓也是店內的招牌美食，搭配挫冰就能成為夏天的排隊美食，加入熱熱呼的甜湯，讓每種食材溫暖你的胃。','平溪街23號','226',25.0252600,121.7387200,NULL,0.00,0,'ChIJXQlN97RWXTQR-n9mJdkqVd8','2026-05-30 23:28:06'),(464,'平溪山泉豆花','堅持用山泉水手工製作的豆花，吃起來有一種透心涼又帶點淡淡豆香的豆花，不添加人工甘味或是防腐劑，純粹的山泉豆花，以及自製的衛生碎冰塊，加入砂糖熬煮的糖漿，每一口細細品嚐，你就能發現到簡單也是一種幸福的滋味。','平溪街20號','226',25.0253100,121.7388600,NULL,0.00,0,'ChIJtbRm-rRWXTQRXkp-CH4oHRc','2026-05-30 23:28:07'),(465,'三重牛乳大王','新鮮、衛生、好味道的口碑，最受歡迎的飲料就是木瓜牛奶，香醇濃郁又好喝。老闆從嚴選木瓜，自產地開始，到種植方式、削皮、挖籽、整理，每一個步驟都很小心翼翼，這裡的木瓜牛奶喝的到新鮮，口感也很鮮美，像是奶昔加上冰沙的感覺，除了木瓜牛奶外，綠豆沙牛奶以及芋頭沙牛奶還有現炸香雞排，都是店內的招牌喔。','重新路二段73號','241',25.0619700,121.4964900,1,0.00,0,'ChIJn309dEWpQjQR4fBYsC0LczM','2026-05-30 23:28:08'),(466,'朱記米粉炒花枝羹','在三重正義北路上推薦一家老店，這裡只賣米粉炒和花枝羹，米粉用豬油拌過加上些許白色豆芽，不同粗細的米粉吃進嘴裡非常入味，爽口彈牙，不像一般炒米粉的口感，而這裡的花枝羹，以特製的漁漿製作，花枝肉質鮮脆，咬一口花枝，彈性十足口感超好，加上鮮美的湯頭，再淋點特製的黑醋，簡單的好滋味，就讓人覺得幸福。','正義北路51號','241',25.0641700,121.4975600,1,0.00,0,'ChIJDR0YiCGpQjQR5K_rwgoxorY','2026-05-30 23:28:09'),(467,'三才靈芝農場','三才靈芝農場曾為日據時代官方俱樂部，光復後改為文山煤礦的招待廳舍，周遭環山，風景優美。三才靈芝農場將靈芝入菜，以10餘種漢方食材、烏骨雞、生鮮蔬菜經過熬煮，搭配山產野味，令人食指大動。推薦菜色:三才靈芝御皇烏骨雞膳食、靈芝養生美人茶、高山脆野菜','中民里十八重溪52-1號','223',25.0133600,121.6750300,NULL,0.00,0,'ChIJN-IviFhUXTQRz2fAAsXLzvg','2026-05-30 23:28:10'),(468,'石碇馬告香腸','台北的後花園---石碇區，93年仲夏，石碇馬告香腸創辦人許世宏正焦頭爛耳埋首嘗試研發各式香腸的製作時，在茫然之際，不小心的一個恍神翻身，不慎隨手將放置一旁的馬告原料磨粉，翻倒到已經調味完畢，仍尚不慎滿意的香腸肉餡中。許老闆非常懊惱，但卻又不忍浪費食材下，抱著上下不安的心情，仍將它製成成品充當家人晚餐；此時意外發生了，一個錯誤的動作，卻誕生了一個口感特殊、氣味非凡的產品---馬告香腸，口感柔中帶勁，帶有著一股清新涼意，猶如夏天時吃到冰淇淋似的清涼奇妙滋味，馬告香腸真謂是一個美麗的錯誤啊！意外帶給了大家一個全新的香腸養生概念，『石碇馬告香腸』也就從此孕育而生。','碇坪路一段180號','223',24.9862500,121.6663400,1,0.00,0,'ChIJy8tJwev_ZzQREoQ2DE3QTN8','2026-05-30 23:28:12'),(469,'喜相逢米粉湯','香氣濃郁的米粉湯淋上些許的蔥花，雖然簡單卻蘊含著美味，一口小菜一口米粉湯，價格雖低卻給人大大的滿足。','長興街2號','251',25.1705100,121.4439000,1,0.00,0,'ChIJk-2PPFilQjQR0cc1lpvqJfE','2026-05-30 23:28:13'),(470,'海霸王','店家提供美味的中式料理，大宴小酌都很適合到此與親朋好友渡過，美味料理不但讓人吃的飽也吃的巧，尤其是店家所提供的紅鱘米糕，更是受到歡迎的佳餚，是宴客的首選菜色。','中央路一段22號','236',24.9912200,121.4482200,2,0.00,0,'ChIJ5a7BdLUCaDQR7niI144TpjI','2026-05-30 23:28:14'),(471,'加意蜂蜜茶鵝','鵝肉有許多吃法，各有各的風味，各有各的愛好者。來到泰山，還能吃到一種蜂蜜茶鵝，店家特別選用5至6斤左右的成鵝，煮熟後先塗上蜂蜜和自製醬料，讓味道先入鵝肉中。接著再將熟鵝送進烤爐中煙燻，二次將蜂蜜味薰入鵝肉中，如此反覆手續就是為了要讓鵝肉更具風味。來到泰山，絕對要買一份蜂蜜茶鵝帶回家，不僅肉質極富彈性，獨特的蜂蜜滋味更能吃出店家的用心與巧思！','全興路212號2樓123號攤','243',25.0561600,121.4336400,NULL,0.00,0,'ChIJcSYetYynQjQRlhmuX_sPIyw','2026-05-30 23:28:15'),(472,'歐里人文咖啡','店內招牌味就是知名的深坑豆腐冰淇淋，由顏老師的兒子所開設的知名兜福工廠製作，每天人潮不斷進出買冰淇淋，還有小朋友吃得津津有味的表情，就知道這美味多吸引人，除了豆腐冰淇淋外，顏香鮮奶豆腐腦這一道料理，也很受歡迎，豆腐腦是豆腐加入鹽滷後的模樣，就是豆腐布丁，口感軟軟嫩嫩十分好吃，是新推出的熱門商品。為提供真實、無毒的天然好食物，再將店內手作甜點及餐食的原料升級成P.D.O冷壓初榨橄欖油，品牌名稱由「顏藝德興」正式更名為「歐里姐姐」，門市亦更名為歐里人文咖啡。','深坑街48號','222',25.0017200,121.6149100,NULL,0.00,0,'ChIJsVAoDsWqQjQR1PgfjvtDPt0','2026-05-30 23:28:16'),(473,'食匠溫州大餛飩','三峽區小吃雲集，想吃什麼都找得到，想來碗料多味美的溫州大餛飩也不是問題！位於三峽文化路上的溫州大餛飩真的是價格公道，用料實在，半個拳頭大的餛飩，咬下去全是一大片肉塊。餛飩皮軟綿綿，內餡肉又紮實香甜，再喝一口湯，滋味十分清香，整體口感超級對味！天氣若還有點涼，非常推薦來三峽吃一碗溫州大餛飩，令人口水直流的好滋味，保證讓人魂牽夢縈，想一吃再吃！','文化路140號1樓','237',24.9362700,121.3706500,1,0.00,0,'ChIJV65KyvMbaDQR-wEGS9zFEtc','2026-05-30 23:28:18'),(474,'蔡家現打果汁','濃郁的現打果汁，完全沒有人工調味，無香料無色素，你看的到老闆就在你面前，現剖新鮮水果切塊或丁，放入果汁機裡，加入少許冰塊，轉動果汁機攪拌均勻，在加入純甘蔗砂糖，就是一杯含有豐富維他命及纖維質，香甜又可口的純手工現打香濃果汁，你一定要來試試。','中央北路68號','241',25.0661500,121.5003300,NULL,0.00,0,'ChIJox1sb-KpQjQRYUp8etCvzTM','2026-05-30 23:28:19'),(475,'曾記花枝羹','在文化北路上的這間魷魚羹，沒有多餘的菜單，只有簡單的米粉炒、花枝羹、滷肉飯，就成功吸引了許多在地以及外來的遊客，花枝肥美有嚼勁，沒有過多魚漿包裹，每一口都吃的到新鮮吃的到老闆的用心，湯頭香甜而不膩，許多媽媽都會帶著小朋友來到這，看著小朋友口口滿足的表情，當家長的就心滿意足了。','文化北路150號','241',25.0671700,121.4981900,NULL,0.00,0,'ChIJwaiHvOypQjQREGkLfEO_7wg','2026-05-30 23:28:20'),(476,'海園活海鮮','「涼拌海菜」是「海園活海鮮」的招牌菜，也是最受歡迎的一道菜，裡面有珊瑚菜，川燙過後，加進葱、薑、蒜拌勻，幾個小時入味後就很好吃了，老闆都會建議客人點這一道菜，因為膠質多、新鮮，咬起來脆脆的很好吃。「生魚片」有軟絲、紅魽、鮪魚，肉質甜美，新鮮，真的好吃。「軟絲」用小黃瓜和海苔捲起來，第一口咬下去黏黏的，繼續咬下去甜度出來，就沒有黏黏的感覺了，鮮度、甜度夠，很好吃；「紅魽」肉質甜美，很容易吃，「紅魽肚」油脂比較豐富。','鼻頭里鼻頭路245號','224',25.1240100,121.9137500,3,0.00,0,'ChIJu5bB_Y9DXTQRe-XsyLuTc-o','2026-05-30 23:28:21'),(477,'嘉義紅心粉圓','嘉義紅心粉圓位於蘆洲區美食重鎮長安街上，開業已三十餘年。店裡的豆漿、豆花、粉圓、黑糖粉粿都是純手工製造，老闆也特別強調自己做的產品完全天然。手工打造的粉圓為鎮店美食，以地瓜粉做成，不摻加任何的防腐劑，煮好的Q彈粉圓不像市售的顏色這麼深，而是帶著琥珀色的光澤，搭配著豆香十足的豆漿與新鮮軟嫩的豆花一起入口，輕嚼粉圓後佐著豆漿入喉，豆子的香味與粉圓清爽的甜味還在嘴裡流連忘返。','長安街63之1號','247',25.0797700,121.4628900,1,0.00,0,'ChIJb7olh7moQjQR1lp0LTRO62M','2026-05-30 23:28:22'),(478,'金瓜石藝棧景觀度假別墅','景觀餐廳典雅、舒適提供中西式料理與咖啡、飲品、茶飲、點心、美酒、音樂。中西式精緻餐飲，海鮮料理台菜及台式合菜，團體Buffet和下午茶及DIY BBQ且不定期舉辦人文藝術活動。餐飲、咖啡、茶點、住宿、賞景、人文、藝術是聚餐、宴會、開會、洽談業務、婚紗外景、休閒旅遊，享美食、賞美景、悠閒住宿，有幸福感的休閒勝地！好吃、好睡、好廚\"藝\"，好山、好水、好客\"棧\"！好地方、好風景、好休閒、好親切！享美食、賞美景、悠閑住宿到\"仙境藝棧\"第1讚！一泊二食，一日遊，二天一夜及各種套裝旅遊行程安排或依個別需求安排計時旅遊行程，讓您的旅遊行程更加豐盛與滿意！本店榮獲多項獎項及政府的認證，品質保證，除了讓您安心享受美食也讓您住得安全、安心、愜意、舒適、衛生、有保障又可靠。歡迎您來享受唯美、詩情的身心靈之旅及台灣唯美的獨特景色！','金瓜石山尖路2號','224',25.1156700,121.8543500,NULL,0.00,0,'ChIJbZK_Ox1FXTQRQdMcUaeIvTM','2026-05-30 23:28:24'),(479,'三重今大魯肉飯','如果火雞肉飯是嘉義的代表作，那麼推崇三重為滷肉飯之都也不為過。不論大街小巷，美食節目報導的、隱藏版的、網友推薦的真是多得不可勝數。除了五燈獎、吉祥號、蓮霧、唯豐等知名的滷肉飯外，位在三重區大仁街上的「今大魯肉飯」也是超人氣的庶民美食。每天清晨6點一開門，運將、上班族、做小生意的老闆們紛紛上門，就知道今大美食的魅力。已經營數十年傳承至第二代的今大魯肉飯，以肥而不膩、香郁夠味的滷肉飯而聞名。有別於一般滷肉飯肥瘦比例適中，或者全為瘦肉燥的滷肉飯，今大的滷肉飯用的全是肥肉。但由於老闆黃源泉曾在青葉餐廳擔任主廚，不僅手藝一流，他還特別使用老母雞和豬大骨熬的湯頭做肉燥湯底，用獨家的滷製手法，將Q軟的白飯上淋上滿滿的肥肉燥，不但不油膩，還十分順口好吃。','大仁街40號','241',25.0643700,121.4915200,1,0.00,0,'ChIJyxws_B-pQjQR-OlL3aVgbIo','2026-05-30 23:28:25'),(480,'野宴食堂','野宴食堂的老闆阿德在都市裡是學習日本料理出生，後來隱身山林，打破山林只賣山產的印象；喜愛釣魚的他還賣起了新鮮的深海料理。來這裡可以同時享受山珍海味的感動。連喜愛輕食的李四川副市長，因公務關係也吃遍臺北大街小巷，由於石碇山上的野宴食堂老闆的手藝要得，重點是口味清淡適度，特別是魚鮮多嚐原味，少用烹調技巧加味，深得他的喜愛。他說，吃完野宴食堂的魚鮮，才知道這家店有難得一見的真功夫。','彭山里崩山12號','223',24.9726200,121.6745700,3,0.00,0,'ChIJ3cNOnHhVXTQRfUZLFb09FFA','2026-05-30 23:28:26'),(481,'金包里陳記天婦羅炸魚條','這家在菜市場裡已經賣了70年的炸物老攤，迄今已由第三代陳金杉夫婦接手，堅持使用最好的食油，炸出來的食材顏色特別純白，健康、乾淨的品質深獲消費者的信賴。每天陳老闆親自挑選鮮魚備料，高人氣的炸魚條是整塊用鯊魚肉製作，先切、後醃、再炸，以糖、鹽、胡椒、八角入味，真是美味極了。賣得最好的天婦羅則用鯊魚漿混合鮮魚漿捏製而成，魚漿含量高，口感完完全全不同於一般市面上的天婦羅，軟Q、香濃的鮮味隨著每一口咀嚼溢流而出，感動的美食料理就在這兒。還有賣得超好的三色燒賣和雞捲，也是金山的知名招牌美食。','中山路190巷2號','208',25.2216900,121.6378200,NULL,0.00,0,'ChIJXzsMDxRLXTQRKhWcOM4w5-s','2026-05-30 23:28:27'),(482,'金山李家粿行(富品家傳統美食)','在金山區場經營超過30年的知名粿店，是當地人口中的點心名攤，小小的攤子只賣米苔目、涼糕、粉條、草仔粿等幾種簡單的美食，每天卻有一群粉絲遠從其他地方騎車、開車來買，主要的原因是老闆娘許玉娥對在來米蒸煮成米苔目、粉條的古法，30年如一日，讓人吃出媽媽溫暖的味道。特別是俗稱「鹼仔粿」的粉粿，完全不使用硼砂，純在來米製成，先洗米、磨米、脫乾後再糰揉，道道手工毫不含糊。加上麥芽和黑糖共同煉製的糖漿，一口接一口的快感真的停不下來。','中山路188號市場50號','208',25.2216400,121.6380800,NULL,0.00,0,'ChIJo2Asw1dLXTQR2kPXRknq6ms','2026-05-30 23:28:29'),(483,'阿郎甜不辣魚丸店','在地悠久的市場老店-阿郎魚丸，以魚丸、貢丸、甜不辣等火鍋料特色美食，在市場佔有一席之地。老闆娘阿秋和負責經營的第二代兒子每天現做現賣，用新鮮和美味兩個金字招牌，吸引客人不斷上門。這裡的魚丸、虱目魚丸、鱈魚丸都是用上等魚肉融合鯊魚肉一起打漿捏塑而成。混合兩種魚漿的丸子不但彈牙有勁，且好吃、耐煮，讓味蕾獲得前所未有的滿足。而炸物、魚包蛋、蛋腸和夏季限定的燒賣，也是到此必嚐的美味。資料參考:新北市美食吃透透8月號','金包里街61號之1(第一零售市場49號攤','208',25.2217200,121.6383700,NULL,0.00,0,'ChIJAUo06FdLXTQRcuSPpyVsTQY','2026-05-30 23:28:30'),(484,'阿玉麻粩','金山老街上第一家專賣「麻粩」的阿玉麻粩，已在金山屹立逾20年，從小孩子做麻粩做到現在的阿玉媽媽郭李玉雲，原本是跟隨母親貼補家用，後來習得一身好手藝後，試著將原本是拜拜用給神吃的敬品，變成是不分年節的點心，後來又加入各式各樣的口味，跳脫了原本只用花生、芝麻的的基本款，成為金山地區知名的伴手禮，連前任新北市長周錫瑋及新北市大家長朱立倫都是常客，也成為市府的迎賓伴手禮之一。早期麻粩型態較大，現在已改良成小巧的造型，一口吃的點心非常受到年輕人喜愛，也能吃出那滿滿的幸福味兒。','中山路110號','208',25.2196000,121.6397300,1,0.00,0,'ChIJx4b86FdLXTQRBu6gfwX7Jxc','2026-05-30 23:28:31'),(485,'康喜軒牛角麵包三峽老街一店','三峽老街知名的金牛角冰淇淋創始老店，以創意的冰淇淋加金牛角麵包，和各式口味的牛角麵包聞名，在老街上幾乎人手一支邊走邊吃，不難想像金牛角冰淇淋的魅力。康喜軒的金牛角內軟Q、外酥脆，多層次的入口質感，令許多行家讚賞推薦，特別是原味金牛角麵包剛出爐後香氣四溢，遊客更是不絕於途、聞香下馬。康喜軒的金牛角冰淇淋有多種口味選擇，除了傳統的香草、巧克力、葡萄、抹茶，還有藍莓優格等11種。如果鍾情於金牛角麵包，又想來點不一樣的味道，香蕉、土鳳梨金牛角麵包，不妨買來嚐試，除了酥香之外，還有淡淡的果香，更是另一種美食境界層次囉。','民權街44號','237',24.9336700,121.3697000,NULL,0.00,0,NULL,'2026-05-30 20:04:04'),(486,'媽媽咪呀義大利餐廳','在樹林當地已經有逾20年歷史的媽媽咪呀義大利餐廳，可說是大同山下的美食奇葩，真正道地的各式義大利經典料理，別說是樹林區絕無僅有，就算在大臺北也難得嚐到這麼美味的義大利菜。這些菜色的靈魂，都是來自主廚兼老闆，也就是義大利籍臺灣女婿的手藝，如果有時間想真正一嚐絕品義大利麵、披薩，來媽媽咪呀，行家力薦絕對不虛此行。這家溫馨的家庭式餐廳位置並不起眼，離樹林火車站後站也要走路約10分鐘以上路程，義大利籍老闆和在地樹林人的老闆娘又超低調，很少媒體發現她們的存在，更不是美食刊物報導熱門店家。','復興路293號','238',24.9889800,121.4186900,2,0.00,0,'ChIJdUfBHxcdaDQR644YaawklYw','2026-05-30 23:28:33'),(487,'小戴雞排','樹林火車站後站緊鄰熱鬧的中山路，路衝的樹德街裡隱藏了一家知名的平價雞排名店「小戴」，很受當地學生歡迎。這裡的雞排都是新鮮現炸，大排長龍的景象隨時上演，招牌的黑胡椒雞排肉嫩又大塊，要吃得趁早；雞柳條、雞翅也是熱門商品，還有平價飲料供應。','樹德街61號','238',24.9920200,121.4207400,1,0.00,0,'ChIJuQG3bz4daDQRIdJ2xvJ3erU','2026-05-30 23:28:34'),(488,'永安包子店','在鹽水雞對面的永安包子店在永安市場裡也有26年以上的歷史，現在大多由年輕的第二代老闆經營。永安包子店的包子、饅頭，都是用老麵發麵，口感、綿密度都特別美味、紮實，變化出來的各式豆沙包、花捲、菜包、鮮奶饅頭等，香美濃郁的麵香讓客人讚不絕口。第一代呂老闆的手藝，是來自臺北市南門市場裡的外省老伯伯的真傳，除了店內招牌的山東饅頭、鮮奶饅頭，絕技菜包更是來此必嚐美味。菜包皮老麵發，內餡加入清江菜、筍子、香菇一起蒸熟，完全上海式的口味，不少老客人直誇家鄉味真令人懷念。','安樂路431號','234',25.0042900,121.5141400,NULL,0.00,0,'ChIJoV-8h-epQjQRNsD3-Nibg3Q','2026-05-30 23:28:35'),(489,'名豐豆腐','提起永安市場的豆腐，那就非「名豐」莫屬。名豐是國內知名的豆製品名店，總公司在新莊復興路，現在還有觀光工廠讓消費者、學校、廠商參觀、導覽解說。黃孝誠老闆早年因想再吃到媽媽做的天然純酵母發酵、不添加防腐劑臭豆腐，因緣際會下走入食品業。名豐豆腐最早發跡就在永安市場，雖然總公司和中央廚房都搬到新莊，但黃老闆還是在永安市場留下一處攤位，專門服務以前的老客人。重視健康、自然的名豐，豆腐製程從黃豆選料就十分嚴謹，各式產品令消費者稱讚。包括豆類週邊製品，如豆漿、木棉豆腐、豆包、豆餅、豆皮、油豆腐、豆干等新鮮供應，攤子前還有超低溫流水保持豆腐產品的鮮度與美味。','安樂路431號','234',25.0042900,121.5141400,NULL,0.00,0,'ChIJhanmQuqpQjQRaYug8u1oRvo','2026-05-30 23:28:36'),(490,'璞石麗緻','烏來一年365天，一天24小時都展現不同的意境，「山、風、雨、露」氣氛變化萬千，位於烏來堰堤之上的璞石麗緻溫泉會館，座擁烏來絕佳自然美景，飽覽雲霧繚繞之美，會館以極簡、自然與意境為設計風格，不做過多的華麗綴飾，優雅的禪風空間感，融合環境原始風貌的自然景觀，猶如藝術品般的外觀，令人讚嘆連連。與山光水色連成一片的飯店大廳延續極簡禪風，日式地炕、整面自然斧劈峭壁美景送入眼簾，及簡潔的大廳高柱等。在大廳地炕小坐片刻，舒適的驚艷讓等待變成一種享受。為提供泡湯的遊客全新藝文食尚美感，烏來璞石麗緻溫泉會館「璞食軒」餐廳以簡約素雅的中國禪韻風貌呈現，呈現的是目前引領世界餐飲潮流的「無國界創作料理」。結合了日式懷石料理、西式及中式等精髓，掌握菜餚口感外，還融入了烏來當地特色食材，依四季呈現不同美食風貌，除品嚐美食的幸福感受外，完全的享受驚艷視覺饗宴。','忠治里新烏路5段88號','233',24.8717500,121.5475700,NULL,0.00,0,'ChIJ-Yhnv7MGaDQRDrl39xQnW6U','2026-05-30 23:28:38'),(491,'全興大腸蚵仔麵線','臺灣知名小吃「蚵仔麵線」幾乎無所不在，泰山區明志路上也有一家不起眼的麵線店，門口卻是經常大排長龍，這家「全興」大腸蚵仔麵線不僅是美食雜誌採訪的常客，也是許多司機運將吃巧、吃飽的美食勝地。全興的大腸蚵仔麵線深獲饕客們歡迎的原因，就在於料多實在。第一次來的客人可能還不太習慣老闆將蚵仔、大腸放在碗底的方式，用湯匙撈一下，就可發現老闆是很大方的。全興的大腸蚵仔麵線共有三種配料，入味的滷大腸、鮮蚵和肉羹塊，口感與中和宜安路的蚵仔麵線很接近，卻又各有巧妙。店內、攤子前有辣椒、蒜泥和烏醋讓客人依不同習慣加料，尤其加辣椒融合的口感最受行家歡迎。','明志路一段300號','243',25.0596700,121.4317500,1,0.00,0,'ChIJs9Zz-zKmQjQRszPe-AVN8Bw','2026-05-30 23:28:39'),(492,'陳記彌月油飯','位在瑞芳第一市場內最角落的瑞芳陳記彌月油飯，在當地是已有近卅年歷史的老字號油飯名家，開車走瑞芳橋往瑞濱方向，一上橋頭還能看見小小的彌月油飯招牌。小攤子的超夯美食，就是那軟Q不膩，就算放冷入口依然越嚼越香的油飯。老闆陳銘能選用中部的長糯米，依古法用炊斗慢慢將糯米蒸熟後，加入紅蔥頭、萬家香醬油和佐料拌炒，每一口都令人驚奇。一般油飯冷了就變硬，陳記的油飯很特別，只會越吃越順口，在食材上多花點成本，就是要客人吃得滿意呢。油飯上淋上老闆用木炭熬煮的香菇滷汁，肉汁減油又能吃出炭香味，難怪每天人潮不斷。店內還有很美味的肉羹湯、魷魚羹湯，搭配麵、米粉、板條，好吃的美味就上桌囉。','明燈路3段2號','224',25.1076100,121.8091000,1,0.00,0,'ChIJqVzJv_dPXTQRn9enm4Njp5I','2026-05-30 23:28:40'),(493,'如記甘蔗鵝','如記的甘蔗雞、甘蔗鵝，每天市場一開市，就有美食行家和消費者不斷上門，光站在攤子前，就能聞到濃濃的甘蔗雞、鵝香噴噴的味道，而一天幾十隻的銷量，也是市場內的冠軍。如記小小的攤子只賣甘蔗雞、鵝和鹽水雞、鵝四種主力美食，還有一些雞下水、鵝腸和筍絲，讓消費者買回家搭配。楊老闆說，還是甘蔗雞、鵝賣得最好，因為客人遠遠地就能聞到這很特殊的香味。楊老闆料理甘蔗雞、鵝的手法，是嚴選現宰的家禽，然後馬上下鍋煮鹽水，先將肉裡面的鮮美肉汁鎖住，然後再放入烤爐中以二砂進行煙燻。憑著經驗和火候的控制，肉腿還不能爆皮，以免肉汁流失，等客人點用後服務切片裝盒，好吃的甘蔗雞、鵝上菜囉。','舊城路19號41號攤','249',25.1466900,121.3999100,NULL,0.00,0,'ChIJIW6ZMqulQjQRuj09PYksSSM','2026-05-30 23:28:41'),(494,'老圓環','老圓環是下庄市場所有攤位中，最整潔乾淨的名攤，第二代老闆張偉傑傳承自媽媽李秀緞的手藝，加上很有經營理念，將歐洲傳統市場與美食攤結合的概念引進八里，美食與整齊明亮的攤位一結合，果然是人氣標竿，各式的雞肉產品、雞捲、炸物賣得嚇嚇叫，其中雞捲更是八里老一輩子的行家難忘的美食。雞捲好吃除了料好實在，裡面的醃肉與菜料相融合，有一種厚實醇香的滋味，建議您一定要嚐嚐。另外甘蔗燻雞、招牌鹹酥雞都是上班族加菜的首選。&   取名老圓環並非這家店來自臺北圓環，而是一種很「澎派」的意象，表示攤子上美食很多。雖然八里的消費族群不像臺北市區那麼多，但張老闆還是很認真地將每道美食做出讓人稱讚的滋味。除了雞捲、甘蔗燻雞，炸物類也是明星美食，四季蔬果就是用新鮮的時蔬下鍋油炸，清爽不膩又帶有果菜香甜的爽脆，來吃看看就知道。','舊城路19號5號攤位','249',25.1466900,121.3999100,NULL,0.00,0,'ChIJHSI7LaulQjQR4Q-x5FcRMoA','2026-05-30 23:28:42'),(495,'阿嬷ㄟ豆花','鶯歌陶瓷老街上以陶藝店居多，但來到這裡也能吃到純天然手工製作的傳統豆花，除了傳統用黃豆做的豆花外，還能吃到香氣特別的黑豆花。一碗豆花可自選兩種配料，想要另外再加薑汁也沒問題，滿滿一碗豆花夏天解渴、冬天暖胃。純手工製作的豆花口感綿密，淡淡的豆香直撲鼻尖，傳統好滋味一吃就知道，來到鶯歌逛老街買陶器，走累了隨時就坐下來品嘗一碗手工豆花吧！','尖山埔路115號','239',24.9510800,121.3471600,1,0.00,0,'ChIJ0XC2v6weaDQRKLc1jZ2ogAg','2026-05-30 23:28:43'),(496,'老牌鶯歌蚵仔麵線','鶯歌是個極有庶民生活感的地方，處處都能找到合口味的在地小吃，例如一般常見的蚵仔麵線，在鶯歌當然也吃得到！一小碗蚵仔麵線裡的用料卻十分豐富，新鮮的蚵仔又大又鮮美，一吃就知道是新鮮好貨。口感Q彈的大腸，相較於蚵仔的軟潤感略帶一些嚼勁，再喝進一口滑順的熱麵線，當成正餐、午後小點或消夜都是絕佳選擇！','中正一路91號','239',24.9549600,121.3522000,NULL,0.00,0,'ChIJ1cNDEwAfaDQRLSNqi0FBDk8','2026-05-30 23:28:44'),(497,'破鑼麵店','經常來鶯歌陶瓷老街逛逛的美食行家，除了老街裡的美食之外，在老街旁建國路上的破鑼麵，總是吸引他們來光顧。麵店門口只有「破鑼」兩個字，歷史也夠悠久，從1945年台灣光復到現在，超過一甲子的歲月，古早味的內涵讓店內一到假日就出現排隊的人潮。店裡賣的是道地的台灣傳統小吃，擔仔麵、乾麵都是強項，而老闆娘吳小姐的招牌料理，還是那遠近馳名的紅燒肉，肉質嫩口感不乾澀，每個餐桌上幾乎人人一盤，不難發覺這美食的威力。另外排骨湯的湯底也是以大骨熬成，想嚐點不同的吃法，可以點滷肉飯加排骨湯，也是很夯的吃法。小菜裡的魯白菜和油豆腐加上豬頭肉，三種經典小菜，下回來鶯歌一定要吃吃看喔。','鎮國路246號','239',24.9535800,121.3475800,1,0.00,0,'ChIJu6IGbaweaDQRZEfXem-TZxE','2026-05-30 23:28:45'),(498,'咕嚕咕嚕牛肉麵','距離先嗇宮站不到100公尺的「咕嚕咕嚕牛肉麵」館，是當地知名的特色小吃之一。料理以麵Q、肉質鮮嫩聞名，不加化學添料是老闆多年來的堅持，不採冷凍牛肉，只用本地新鮮的牛肉熬製，雖然讓成本高了一倍，因此為老饕們的最愛。','光復路一段19號','241',25.0475100,121.4722100,2,0.00,0,'ChIJf2rEZV-oQjQR7y-X0w-8otw','2026-05-30 23:28:46'),(499,'相傳滷肉飯(冬粉王)','位於先嗇宮站新莊化成路有家「冬粉王」（又名相傳滷肉飯），店裡提供豬腸冬粉、滷肉飯等多種傳統台式小吃，主餐以飯類套餐為主，排骨飯、焢肉飯、豬腳飯、雞排飯價位均在40到50元，鱈魚飯也是45元(小)/55元(大)，在價位上非常的便宜，另外，還提供海陸雙拼、排控雙拼、雙色排骨，一種套餐吃到兩種主菜，最貴不過75元，因此為附近工業區消費者的最愛。','化成路364巷6號','242',25.0495500,121.4661800,NULL,0.00,0,'ChIJX-A8KGCoQjQRODNjFHUd6rg','2026-05-30 23:28:47'),(500,'尚青ㄟ羊肉爐','尚青ㄟ羊肉爐在三重地區相當有名，由於他採用現宰的溫體羊肉，當場料理，因此吸引各地饕客，生意相當的好。這家店羊料理不會讓人感到太重的腥味，三層肉是處理的不錯，建議還可以來幾盤熱炒或是肝璉，有興趣來吃的人客可以參考一下喔!','重陽路1段6號','241',25.0571500,121.4865200,3,0.00,0,'ChIJW202buOoQjQRpVCIB58wJ5Q','2026-05-30 23:28:48'),(501,'古伯手工米苔目','古伯米苔目是三峽民權老街上，深獲美食行家們推崇的小吃店，一般人還以為古伯老闆古國晃應該擁有幾十年的美食技藝，才能把米苔目做得如此爐火純青。其實古老闆十多年前還是三峽老街上知名的西裝店老師傅，只是不敵時代演進成衣市場的進逼，於是下定決心到新竹拜師學藝，加上客家人的硬頸精神，做出令人讚不絕口的傳統客家米苔目，十多年的時間也在老街打響名號，現在要到古伯店裡嚐碗湯美、米香的米苔目，有時還得在外頭站一陣子才有位置坐。','民權街9號','237',24.9345100,121.3704200,NULL,0.00,0,'ChIJHYgT7vEbaDQRvqRWSrEgWO8','2026-05-30 23:28:49'),(502,'鼎豐懷舊客家美食','鼎豐客家板條52年了，是擁有金字招牌的老字號。也是正統客家村莊的粄條，擁有濃厚的客庄濃情。特別是店內的豬油拌飯，更讓你體會先民時代的懷舊風味。店內的菜單經濟又實惠，假日更是高棚滿座，只要過老三峽拱橋就可抵達。主要商品、規格說明：客家梅干扣肉、客家三角丸、客家湯圓、酥炸肥腸、蹄膀、銀芽豆皮捲...等','愛國路38號','237',24.9329500,121.3744600,1,0.00,0,'ChIJFSeUgfIbaDQRxfgOQTlKA5A','2026-05-30 23:28:51'),(503,'茶鄉桂花農園','桂花農園位於石碇區隆盛村又稱桂花村北32鄉道，是臺灣古老茶區之一，地處海拔300多公尺，因土壤中含砂礫，全年雨量適中，早在50-60年代，茶葉興盛時期，當地茶農便以桂花作為烘焙茶葉之香料，提升茶的附加價值，每100公斤茶必須配上25公斤的桂花，因此茶園旁種植大量桂花樹，每年8月過後，全村老少穿梭桂花林間，採集新鮮桂花，形成當地特有景觀，是當地居民重要的生活記憶。','隆盛里新興坑4號','223',25.0167100,121.6536100,2,0.00,0,'ChIJ_8T7l-5UXTQR5Fib1M56b1o','2026-05-30 23:28:52'),(504,'龍蝦大王','光是龍蝦就有清蒸、味噌、沙西米等十多種作法，其他如九孔碩大肥美，可配合客人喜好現場烹調。餐廳有專屬的免費停車場，停車方面的問題不用擔心，食材新鮮有各種從附近漁港來的新鮮魚貨。','仁和路186號','228',25.0523900,121.9234900,2,0.00,0,'ChIJl7i6TL9cXTQRsFlX8PAqa28','2026-05-30 23:28:53'),(505,'盧記藥燉排骨','來到蘆洲廟口除了好吃的切仔麵，廟口前許多知名小吃攤也是饕客們嚐美味的熱區。其中，已經傳承兩代的盧記藥燉排骨，香濃的湯頭、熟透軟嫩的排骨，是當地超人氣的古早味。盧老闆說，漢方是媽媽每天準來到蘆洲廟口除了好吃的切仔麵，盧記只賣藥燉排骨和當歸土虱兩種美食，越晚人越多，都是為了那迷人的藥燉湯頭而來，尤其晚上藥燉湯頭越煮越濃，內行的行家都喜歡晚點來品嚐鍋底的精華。','得勝街135號對面','247',25.0833400,121.4719000,1,0.00,0,'ChIJVwAREMmoQjQRZDBoFzdHQG0','2026-05-30 23:28:54'),(506,'運鈍根湯','傳說中數十年來只賣一鍋湯的神奇高級食補料理店，「運鈍根」這個店名想必引起許多人的好奇。「運」是指運轉，「鈍」是指身體裡的不健康，「根」則是厚植本身根基以及再生能力，將這三個字以台語發音，也有同樣的意思。來這裡用餐很特別，空腹先喝三碗湯，喝湯後，由吸收藥效後產生的反應就能判斷出身體狀況，健康的人會產生饑餓感，肝火旺的人則會想吐，每個人會有不同的反應，店家也因此很貼心的設計了優雅舒適的空間供客人休息。想喝到這碗湯必須先預約，每鍋湯都是50種珍貴藥材和米酒燉煮8小時後，再放入烏骨雞燉半小時提煉出的精華，能吃到就是福。','祥和路1號','231',24.9594500,121.5040300,4,0.00,0,'ChIJTQ09F4fVDRQRMF_27nHGb3c','2026-05-30 23:28:55'),(507,'滴水坊餐廳','別以為冬季進補就一定是大魚大肉、山珍海味，喜歡清淡飲食或是食素的朋友們，永和區就有一家既能養身又美味的素食進補好所在。佛光山的星雲大師取「滴水之恩，湧泉以報」之意，在各地設立滴水坊以茶會友，以優雅的裝潢和美味健康的餐點，提供一個在喧鬧城市中忙裡偷閒的靜謐空間，中西口味的眾多料理選擇，讓人吃得歡喜也吃得養身，而其中最令人難忘的就是，以十多種藥材和水果熬煮成的藥膳火鍋，湯頭清甜、料多實在，一口一口都是天然食物精煉出的原味。用餐後不妨逛逛一樓的滴水書坊，在滿足口腹之慾的同時，也能讓心靈能大快朵頤知識的養分。','中正路446號1樓','234',25.0027800,121.5176100,2,0.00,0,'ChIJ2RoT-OapQjQR3Jka1xM47EM','2026-05-30 23:28:57'),(508,'飛月小館','飛月小館是永和區深受老饕推薦的客家創意美食店，整體很具古早味氛圍，生意極佳、座位有限，一定要事先預約。小館沒有大招牌，也不醒目，料理以家常菜為主。「食材最重要！」老闆最重視就是食材的好壞、新鮮和營養，因此，有相當大的精力與時間是投注在食材採購上的，雞肉要放山雞，豬肉是本地黑豬肉，牛肉是臺灣黃牛肉，鯛魚不用放養的，蔬菜堅持有機，選用來自南投、三峽等各種在地食材...「現在文明病太多了，自己不吃的，絕不給客人吃」，就是這樣堅持最好、最新鮮的觀念，深獲行家推崇。','秀朗路二段179號','234',25.0014700,121.5259200,2,0.00,0,'ChIJuaQW0vqpQjQRiXFyGQ-rkRI','2026-05-30 23:28:58'),(509,'慕拉諾義式餐廳','慕拉諾(Murano)義式餐廳 ，聘請星級義式料理主廚 ，搭配精心調製的配料與醬汁 ，堅持使用最新鮮的食材 ，更設計充滿美味與創意的義式餐點 ，在舒適高雅的空間理 ，享受豐富義式美食 ！預約專線：02-2277-6070 友善服務□.外語友善(能提供與他國顧客溝通之語言或媒介)。   □.行動裝置充電 (提供電源插座、USB等供行動裝置、手提電腦等設備充電)。  □.信用卡/悠遊卡/第三方支付服務(提供現金以外的交易方式)。□.素食友善(提供全素食/蛋奶素餐點) (不含蔥、蒜、韭菜、薤(蕎)、興渠(洋蔥)、肉類)。 □.友善廁所(提供借用廁所服務)。  □.Free WiFi(提供顧客無線網路之服務)。','中港路291號','242',25.0442100,121.4527800,2,0.00,0,'ChIJOxj4OHqoQjQRHV7LR32h6nI','2026-05-30 23:28:59'),(510,'北斗肉圓','永和保平路與永貞路口的「北斗肉圓」給我機會讓我帶著它，在上海一炮而紅。有道是：「機會是留給已經預備好的人。」北斗肉圓楊先生兄弟兩人從故鄉移居新北市20逾年，低調又內斂，甚少接受媒體採訪，但他的肉圓店卻總是出現人龍排隊。楊老闆把林書豪最喜歡的肉圓，用傳統的方式像照顧幼稚園小朋友一樣的態度，耐心的翻來覆去，不慍不火，泡炸到酥透，一大口直徑油鍋裡的肉圓都激烈的高呼「快來吃我！快來吃我！」兩位溫良謙恭的阿姨把肉圓遞到您的面前，這才是我覺得小吃可以把服務作到位的態度。','永貞路309號','234',25.0064100,121.5102000,1,0.00,0,'ChIJ3TK_xtypQjQR-5G1zzQupyo','2026-05-30 23:29:00'),(511,'216莊園咖啡','新北市的五月雪桐花開，除了土城桐花公園迷人，三峽的鳶山及熊空山上，也是綠色山巒點點白頭，尤其熊空山桐花秘徑知道遊客較少，如果喜歡人少的悠閒感，不妨假日相約親友或同學，到山上的216莊園咖啡享受花與咖啡的五感體驗，熱情的老闆和貼心的服務，真讓人有回到「山上的家」之感覺。216莊園咖啡有豐富的生態環境，室外用餐區在溪邊的大樹下，還有露天陽台可以賞景喝飲品。這裡的美食，主要以美式早午餐為主，老闆娘張太太的手藝很厲害，早午餐盤子裡滿滿的美食，包括烤土司、培根、德式香腸、美式炒蛋、薯泥，還有美式咖啡一杯，坐在景觀迷人、與自然親近的感覺，令人身心舒暢食慾大增。216莊園咖啡主要以美式早午餐及咖啡為主，中午附設簡餐，吃完主餐、賞完桐花，不妨再來份冰淇淋焦糖巧克力鬆餅的下午茶，配上洛神蘋果茶或蜂蜜香柚茶，還是老闆拿手的美式咖啡，都令這趟賞花行幸福無比。','竹崙路216巷5號','237',24.8825900,121.4486600,2,0.00,0,'ChIJRc61wfgbaDQRgB8hwFrZCXk','2026-05-30 23:29:01'),(512,'竹圍陳家刈包','在淡水有幾家刈包店，都是學生們喜愛的美食攤，也是電視美食節目報導的常客，其中位於捷運竹圍站附近民族路上的陳家刈包，更是箇中翹楚，刈包皮Q細緻，從蒸籠裡拿出來，夾上老闆特製的焢肉，整個一大塊給得十分大方，老闆強調這焢肉是家傳製法，半肥半瘦經長時間的滷製，每塊豬肉外型不但完整而色同琥珀，而且肥肉部位入口即消，瘦肉部位軟嫩適口，肥而不膩且鹹中帶甘，多層次的美食風味，再加上花生粉的香濃醇郁，呈現一種小吃美食的藝術，連遠從臺北市前來的知味客也聞香下馬。陳家刈包還有一道排骨酥麵也料理得極好，順口滑溜，以大骨湯底為主加上酥炸過後的排骨酥，和刈包共組美味食韻。','民族路72號','251',25.1357200,121.4621700,1,0.00,0,'ChIJ48s5-p2vQjQRiP_c47nLAmI','2026-05-30 23:29:03'),(513,'六必居 潮州一品沙鍋粥','一碗粥品作法有許多種，廣東粥、台式鹹粥是一般消費者經常吃到的美食，近幾年在板橋流行一種潮州沙鍋粥，由於粥品強調以台東關山皇帝米為主材料，而且是在客人點選後，才將生米放到砂鍋中慢慢熬煮，加入昆布高湯以及用腰果、松子、花生等磨成泥後的堅果醬，讓湯頭表現出一種極為濃郁的鮮甘珍味，因此非常受到熱愛粥品的老饕們熱情推薦。','民權路3號','220',25.0098700,121.4629400,2,0.00,0,'ChIJNZKIdx6oQjQRdPECsfSu_Rs','2026-05-30 23:29:04'),(514,'阿英傳統越南麵','這間在八里國小對面開了十幾年的小吃店，老闆娘是嫁來台灣的越南新娘，一開始只是想開個小店，為家裡貼補家計，沒想到因為道地口味，與認真料理方式，讓忠實顧客越來越多，變成來到八里不能錯過的好味道。每天各種不同的湯底，有牛肉、豬肉、蕃茄、海鮮，還有粥，都是老闆娘半夜熬好，湯頭清爽好喝沒話說。而生牛肉河粉更是必點招牌之一，直接用熱湯燙熟的牛肉片特別軟嫩，加上九層塔的香味，並擠入一旁附的檸檬與辣椒，酸酸辣辣的感覺，讓人大呼過癮！而涼拌木瓜絲更是開胃必點，爽脆的口感與酸辣的滋味，吃完了絕對會懷念。老闆娘給的料毫不手軟，也吸引許多媒體的報導。','中山路二段229號','249',25.1491800,121.4034500,1,0.00,0,'ChIJv_XweKqlQjQRl13HgGCylrE','2026-05-30 23:29:05'),(515,'楊媽媽小食堂','在蘆洲巷子內經營20年以上的這間小店，靠的是阿給與甜不辣美味的口碑相傳，老主顧越來越多。在豆皮內裝滿Q彈的滷冬粉，用新鮮的魚漿包裹，放在熱騰騰的甜不辣湯裡，可以一口阿給一口湯，更可以將冬粉混入湯裡一起享用，也有不同滋味。特調醬汁淋在阿給與甜不辣上，更是讓人忘不掉的原因。附近居民與學生一吃就是好幾年，更有搬家到中南部的客人特地再回來吃。這家溫馨小店的阿給和淡水的阿給有些不同，可做成湯、乾兩種吃法，美味阿給的好搭檔「醬汁」是老闆多年的經驗結晶，以味噌、黃豆、辣椒做成基底醬料後，再爆香、加糖，特殊的比例讓醬料甘而不濃，和阿給一搭美味極了。楊媽媽小食堂已傳到第二代，為了發揚光大傳統小吃，將老店重新裝潢整理，門口加上餐點模型，店內裝上冷氣，儼然是餐廳的舒適享受。更利用網路推出宅急便的服務，老滋味一點都不少，讓不住在蘆洲的民眾也能品嚐老闆娘的好手藝。推薦菜色:阿給','信義路259巷25號1樓','247',25.0843500,121.4777200,1,0.00,0,'ChIJGy5j2s2oQjQRfeeIzYktooA','2026-05-30 23:29:07'),(516,'蔡東興號','位於永和區環河西路上的蔡東興號，和周家年糕同樣為新北市的年糕超人氣名店。而蔡東興號更特別只專注於年糕的製作，製作的是傳承自浙江的「寧波年糕」，以蓬萊米作為原料，洗淨後加水慢慢磨成米漿，吃起來富彈性、口感細緻，並有一番獨特的綿密感。','環河西路二段13號','234',25.0160700,121.5080300,NULL,0.00,0,'ChIJ-5xGRwCpQjQR8YG1Sppzvws','2026-05-30 23:29:08'),(517,'阿寶燒雞','提到新莊公有市場的熟食，已經在市場一樓賣燒雞超過50年的阿寶燒雞，是絕對不能錯過的地方美味。這家老攤子的女主人李寶貴，正是自日治時期在新莊老街上就非常著名的「東寶食堂」第二代。李寶貴的臺式燒雞，在小小的攤子上每到假日都能賣上百隻燒雞，尤其最近春節過年，一天更上看五百隻的實力，由此不難發覺新莊人對阿寶燒雞的喜愛。阿寶的燒雞作法十分獨到，選用現宰溫體雞，先洗淨後就用獨家的醬汁開始醃漬，等雞肉完全入味後，再掛到傳統的烤爐中，新鮮的全雞在烤爐的高溫烘烤下，外皮呈現一種誘人的金黃油亮，雞肉則鮮嫩多汁，入口有一種難以言語的甘香濃郁，完完全全的古早味，吸引許多上了年紀的老饕不遠千里而來，多買幾隻回家回味一番。','新莊路315號','242',25.0340200,121.4534400,NULL,0.00,0,'ChIJGSjSp3OoQjQR2fjhaJCVo1E','2026-05-30 23:29:09'),(518,'牛哥肉鋪','深邃輪廓、率性馬尾，鄭老闆看起來像個藝術家，他的攤舖是自己親手設計組裝，肉品陳列條理分明，十分整潔。老闆外表酷帥，說話卻非常熱情，經常與客人分享專業的料理知識，而對品質的要求與童叟無欺的經營方針，贏得了客人深厚的信任感。','全興路212號','243',25.0561600,121.4336400,NULL,0.00,0,'ChIJc8xzXc2nQjQRC8kHgnMG5vQ','2026-05-30 23:29:09'),(519,'家錚雜貨鋪','空間不大的傳統柑仔店，之所以屹立逾40年，能在現今便利商店環伺的市場上生存，除了老闆娘將賣場弄得乾淨整潔，服務親切外，更重要的是商品有特色且多元化，品質新鮮、貨品齊全，因此抓得住客人的心！曾獲101年度樂活名攤1星認證，商品皆由台灣與日本產地直送，品質純正，在數百種來自各個產地的南北雜貨中，又以包裝精美的醬油最具人氣。','全興路212號2樓','243',25.0562500,121.4337600,NULL,0.00,0,NULL,'2026-05-30 20:04:04'),(520,'吳媽媽手工水餃','泰山的庶民小吃，儘管常見，做法上卻盡其可能用心製作。泰山公有市場二樓內有大家口耳相傳的道地現包水餃，只要吃過的人都覺得好吃，有時一買就是好幾盒。這樣用心現包的水餃，內餡是特別選用豬前腿胛心肉，搭配高麗菜及韭菜一起攪拌，包入水餃皮中再下熱水煮熟。吃下去發現內餡豬肉極為鮮甜，加上高麗菜的甜，韭菜的香氣，直接吃不用沾醬油就十分美味！','全興路212號2樓','243',25.0561600,121.4336400,1,0.00,0,'ChIJe2dMWs2nQjQRUGImi7gz9FA','2026-05-30 23:29:11'),(521,'好朋友的店水果攤','「來來來！西瓜甜喔！」老闆娘阿鳳熱情的招呼每個客人，客人手裡挑選著光澤飽滿的新鮮水果，順口聊起自家小孩，幾個媽媽就這樣開了話匣子，好不愉快。好朋友的店不只水果新鮮便宜，阿鳳更希望每個客人都成為好朋友，讓水果攤成為一個讓經過客人都想停下來聊聊天，放鬆心情的溫馨小站。','全興路212號','243',25.0561600,121.4336400,NULL,0.00,0,'ChIJ3VIbPgCnQjQR1c45YN3jzPM','2026-05-30 23:29:12'),(522,'皇后鎮森林','位於三峽區竹崙路山區的皇后鎮森林，離市區不遠，加上環境十分幽靜、漂亮，佔地高達6甲又緊臨溪畔，除了吸引許多熱愛休閒美食的客人上門，體驗在藍天綠地中暢快呼吸的快感，老闆林憲君熱愛大自然休閒露營，因此這裡也開闢了露營區，成為露營愛好者口中最接近臺北的露營天堂。24小時的露營服務，大面積的綠地森林，還有露天的咖啡廳，吸引了《放羊的星星》、《敲敲愛上你》在此取景，除了用餐之外，現場還有音樂演奏，十分地浪漫。來到這裡，最著名的歐式香草風味美食料理一定要來嚐嚐，獨特風味套餐道道都是經典。最受遊客們歡迎的德國豬腳，選用臺產新鮮豬腳先醃漬後，等客人點用時，先下油鍋酥炸讓外皮呈現脆感，再進烤箱烤至熟透。出菜用刀輕輕一切，入口後外酥內軟嫩的口感，真是魅力無窮。','竹崙路95巷1號','237',24.9177800,121.4336000,NULL,0.00,0,'ChIJGajFXEUbaDQR_Gcb2D3nxh0','2026-05-30 23:29:14'),(523,'三峽李溪口現烤香腸','在成福路上幾家香腸店中，三峽李溪口黑豬肉香腸是饕家們口中，口感十分特別的香腸老店，每到假日店門前總是門庭若市，大家站著吃、等著買回家，讓李溪口的美食名聲響叮噹。李老闆30幾年前就開始用三峽的黑毛豬灌香腸，在路旁烤香腸賣給路過的遊客，後來還推出全臺唯一的無筋黑豬肉香腸，原味、麻辣、黑胡椒、蒜味、紅麴、五香和高粱酒一共7種口味，以獨特的肥瘦比例，讓每一條香腸油量都相當，烤出來的香腸真是好吃。','成福路280號','237',24.9234200,121.4283700,NULL,0.00,0,'ChIJlyx5OVwbaDQRCdOINzWrZkQ','2026-05-30 23:29:15'),(524,'古早厝豆腐美食','店內貼滿了許多臺灣早年的電影海報以及影劇歌星等報章新聞剪貼，濃濃的懷舊風格，乾淨明亮。招牌菜有牛腩的肥牛臭豆腐、料多味濃的麻辣鴨血臭豆腐羹，以及用雞湯、豬肉調製的滷桂竹筍等。','深坑街140號','222',25.0011800,121.6128900,2,0.00,0,'ChIJCdcFXcSqQjQRqDhO2weNaFg','2026-05-30 23:29:16'),(525,'浙寧嘉園餐廳','老闆對道地浙寧佳餚有30餘年料理經驗，手藝扎實，做出來的料理是色香味俱全，令人回味。','中正路一段70號','252',25.2578400,121.5039700,NULL,0.00,0,'ChIJQTw03s22QjQRh_4YdXQ5g8M','2026-05-30 23:29:17'),(526,'豹豹咖啡館','有中式快炒，也有西式餐點。自製甜點以芋頭點心非常受客人青睞。夏季時，店門口有供應冰淇淋，讓遊客備感貼心又清涼。','德茂里下員坑33-6號','253',25.2832000,121.5195000,NULL,0.00,0,'ChIJv92A3YG3QjQR03ncfIEvpBg','2026-05-30 23:29:18'),(527,'八里寶奶奶花枝燒','炸得金黃又大又酥脆的深海大花枝，加上店家特製美乃滋與芥茉醬兩種醬料，上頭再舖上增加香味的柴魚片，吃起來清爽不油膩。','渡船頭街26號','249',25.1585700,121.4350100,NULL,0.00,0,'ChIJ85nIEGalQjQRnaapYEDYCsI','2026-05-30 23:29:20'),(528,'林口電廠冰棒','在林口電廠裡販售的傳統的枝仔冰，最愛歡迎的是花生口味，其他口味有米糕、紅豆、芋頭、薏仁、牛奶等，口味選擇眾多，非常的透心涼，很多人都是專程來此團購的，但還是自備冰桶比較環保。','台電新村3號','244',25.0859900,121.3879700,NULL,0.00,0,'ChIJ-4ETlaSmQjQR9D2tNd1IG94','2026-05-30 23:29:21'),(529,'五股老顧客肉圓蚵仔麵線','店家只賣麵線跟肉圓，老闆卻對品質非常要求，肉圓每天限量製作，腸子也是當天早上現買現做；食材新鮮、原味，完全不添加任何的化學及染色，不會對身體造成傷害，是五股在地人才知道的美味。','民義路一段120號','248',25.0858900,121.4348700,1,0.00,0,'ChIJ0QUjXRqmQjQRX2mfWs9wsRk','2026-05-30 23:29:22'),(530,'茶花莊-清雅鮮香野薑花粽、花草冰淇淋','雙溪區的茶花莊向來以園內的多達800種茶花而聞名，在茶花園裡聞花香，同時品嚐主人將雙溪特產「野薑花」入菜的手藝，更是許多名人雅士最熱衷的假日休閒活動。廣達2.5公頃的茶花園裡，將美食、茶花與生態結合，來這裡吃頓飯，清新脫俗、心靈超脫的感覺油然而生。茶花園的主人莊豪雄說，園區的各式品種茶花都是來自世界各國的珍品。滿園花色、小園曲徑，走在其中茶花香氣清淡優雅，淺近飄來令人著迷。','平林里3鄰梅竹蹊67號','227',25.0314200,121.8464100,NULL,0.00,0,'ChIJke_no09aXTQR_DqkfKbq10k','2026-05-30 23:29:24'),(531,'米工坊-月桃肉粽','華人包粽子巧思不斷，除了竹葉包粽，為了增加粽子的特別口感和香氣，還有使用「月桃葉」包粽，位於新莊的「米工坊」正是箇中翹楚，多年來老闆特選來自水質無污染且高優質的「台東池上糯米」做為粽子的原料，粽子的餡料與糯米拌炒至半熟後，外面再包覆月桃葉，經過蒸煮後米粒香Q柔軟，形成一種美食色、香、味的綜合藝術，香氣獨具值得嚐嚐。月桃葉本身也是一種藥用植物，端午節前後正是月桃盛開時，因此用來包粽深具傳統風味。月桃肉粽內餡有豬肉、蛋黃、香菇、蝦仁、花生，加上月桃的滋味，真誘人食慾。米工坊另一款招牌肉粽餡料則有豬肉、香菇絲、蝦仁、蘿蔔乾，和池上糯米搭配，給人一種非吃不可的魅力。端午節米工坊月桃肉粽限量供應，記得電話先訂。','中信街44號','242',25.0508800,121.4496700,1,0.00,0,'ChIJQd_YXX6oQjQRcv8D8xex0w8','2026-05-30 23:29:25'),(532,'金蕎蛋糕-點心蛋糕伴手禮專家','在中和地區享有極高評價的金蕎蛋糕，不僅紅遍中和點心界，得獎無數，更成為許多公司行號舉辦點心茶會的最佳夥伴，像鴻禧旅行社、威剛、優派、遊戲橘子、大宇資訊、圓剛等企業，都指定金蕎來幫忙。還有很多客人都是在茶會上嚐到美味的點心，尋味找上門來，不僅深獲老饕的推崇，也讓辦活動的主人面子十足。來到金蕎的店面，很少不被琳瑯滿目的美食所震撼，每一樣點心都讓人看得口水直流，而且這些點心可都是名氣響亮、大有來頭。','連城路265號','235',24.9963100,121.4911800,2,0.00,0,'ChIJvUcyqIACaDQRECdZwMSC2Es','2026-05-30 23:29:26'),(533,'芎經園咖啡盆景餐廳','一個充滿人文藝術的複合空間，2011年坐落於淡水紅樹林，眺望整個淡水河景緻，天空的藍 夕陽的紅，在松柏的氛圍中被感動，歡迎喜愛松柏，喜愛美食的朋友們一起來跟我們共享這一片美景在淡水紅樹林捷運站附近最新發現的咖啡莊園【芎經園】，在這裡遠眺淡水出海口的夕陽，渾然天成美景加上咖啡香，一洗都市喧囂，享受自然身心靈SPA。莊園主人回憶十多年前即著手構思莊園，近期以氣派透天結合淡水美景，莊園內擺飾所呈現的風貌與氣度，在這裡我們可以暫 時忘卻都市帶來的節奏，用自己的步調刻畫出不同的人生，打拼之餘也可以這麼悠哉的享受 天地日月之氣，在不協調的年代走出自我的天堂世界。','中正東路二段5巷25號','251',25.1585800,121.4598600,2,0.00,0,'ChIJhZ8tHu2vQjQRXu75g_seymA','2026-05-30 23:29:27'),(534,'桃樂絲森林餐廳','桃樂絲森林餐廳位在觀音山風景區內的一座小山上，種滿了八里文旦、水蜜桃與甜桃等水果，還坐擁淡水河口的美景，並有豐富的生態資源，更曾榮獲2008年新北市最具代表特色的優質餐廳，鄰近大臺北地區，來這裡走一趟，能讓你感受到一種最自然的寧靜享受。八里文旦柚‧中秋獻禮-中秋節是臺灣重要節慶之一，越接近中秋節，視為餽贈親友好伴手的應景水果－文旦柚也陸續上市！其中，素有「北八里‧南麻豆」美稱的新北市八里區文旦柚可說是市場寵兒，其柔軟多汁的口感深受老饕喜愛。黃金文旦柚‧柚子產品-為了提升家鄉的文旦柚品質，桃樂絲森林特別推出改良品種－黃金文旦柚，其外觀較一般文旦柚金黃光滑的特色十分討喜，當作中秋禮品，面子十足！桃樂絲森林也供應柚子醋、柚子茶、柚子酥、柚子餅乾、柚子醬油等產品，一網打盡八里文旦柚的美妙滋味！e-mail：cathy.3011@yahoo.com.tw','荖阡里荖阡坑路6鄰34之5號','249',25.1246100,121.4071600,2,0.00,0,'ChIJ_w_owEmkQjQReb_iC-2hyqI','2026-05-30 23:29:28'),(535,'馬家堡餐飲小吃店','營業項目為餐飲、小吃，並附設有卡拉ＯＫ，建議於造訪前先去電詢問一下是否有營業喔～','福山里大羅蘭47號','233',24.7751800,121.5002000,2,0.00,0,'ChIJQUwuYvAOaDQRPR9pjTawiVw','2026-05-30 23:29:30'),(536,'馬岸休閒美食','營業項目有：山產、野菜、清涼茶座、並附設卡拉ＯＫ（自助式）。','福山里大羅蘭5鄰25號','233',24.7750000,121.5003800,NULL,0.00,0,'ChIJGwBwZvAOaDQR-bPrUjI8n7Y','2026-05-30 23:29:31'),(537,'明緣小棧','位於北宜路上的中間休憩點，有家明緣小棧，可遠眺山巒雲海享受微風輕拂的美麗景致，曾經上過「美鳳有約」與「台灣尚青」兩大美食節目，是北宜路的最高點的餐廳。由於一年四季皆可觀賞雲海，並結合地方特產包種茶、研發特色茶餐及有機家常菜，加上平價的收費，成為當地相當有名的餐廳，特色菜有茶香山豚、河粉茶壽司、茶卜肉等。','格頭里北宜路五段80號','223',24.9518200,121.6462800,NULL,0.00,0,'ChIJlSVY0O3_ZzQReZt-tIdqWvk','2026-05-30 23:29:32'),(538,'翰品酒店','歐式風格　品味獨具　翰品酒店新莊以Art Nouveau為設計主軸，採優雅時尚的法式風格，融合低調奢華的東方美學，展現出充滿活力的傳統之美。戶外歐風廣場為概念，四周牆面包覆著歐式藝術銅雕，飯店內了融合浪漫歐洲街頭的氛圍。走進大廳，仿佛進入歐洲小鎮溫暖靜謐而舒適的環境，讓旅人在住宿時充分的讓身心靈自在放鬆。','中正路82號','242',25.0376300,121.4581000,NULL,0.00,0,'ChIJbV3QL26oQjQRxkIefq2PpI0','2026-05-30 23:29:33'),(539,'友信魚樂世界','有「青」才敢大聲！友信魚樂世界早年是深澳一帶服務釣友抓小卷的知名船家，後來自家漁船出海捕魚，漁獲就在自家開設的餐廳分享饕客，每道海鮮料理新鮮得令人激賞不已，難怪晚上還有剛下班的臺北客直接走高速公路轉62快速道路，就是要驅車來此嚐鮮。友信的招牌菜，就是用透抽、小卷做成的各式料理，以及各種魚產變化出創意美食。','深澳路189-7號','224',25.1342900,121.8205500,2,0.00,0,'ChIJf56FbHhFXTQROeROVwm-DyU','2026-05-30 23:29:34'),(540,'老船長平價海鮮','這家位於深澳漁港旁的知名老牌海鮮餐廳，之所以稱為老船長，是因為老闆廖正明從十幾歲就跑船到六十幾歲，船上的員工都尊稱他一聲「老」船長。下船開海鮮餐廳，他的獨特手藝一樣令人尊敬，深澳港特產的小卷、透抽，都料理得十分出色，臺北客們還慕名而來，就是要吃到老船長最鮮的漁獲。老船長平價海鮮的招牌菜，當然是深澳大宗魚產的透抽、小卷所變化的各式料理，最鮮、也是最基本的吃法就是清蒸，簡單又天然，美味得令人咋舌，各家作法雖然差不多，但老船長還是有變化多端的豐富口感與風貌，來深澳吃老船長的透抽、小卷，好像成了一種朝聖，蒸、燙、炒、炸都濃鮮至美、新穎別緻的。','深澳里深澳路189-5號','224',25.1340200,121.8217300,2,0.00,0,'ChIJteqBHHhFXTQRgkyb0qfmXXU','2026-05-30 23:29:35'),(541,'黃記港式燒臘','這家已在土城區場有十幾年歷史的熟食老攤，黃老闆夫妻倆都是澳門人，廿幾年前移民來臺灣，在土城落地生根，就將一身粵菜、燒臘的好功夫也帶到臺灣來。原本黃記只在市場外擺小攤做生意，後來客人越來越多，就搬進市場裡服務老饕們。黃記最有名的美食，就是烤鴨，一早擺攤10點半不到就賣個精光，還有脆皮燒肉也一樣受歡迎，懂狀況的婆婆媽媽們就會起個大早先來買，一到節日還得先預訂才不會空手而回。','四維路143號','242',25.0222700,121.4228300,1,0.00,0,'ChIJ_4IXEu6nQjQRJ_HRTc1Tet4','2026-05-30 23:29:36'),(542,'土城市場熟食攤','這家在中正路市場入口的熟食攤，沒有店名和招牌，廿幾年來在土城區場小有名氣。老舊傳統的攤位，攤子上的一道道熟食，卻是美味得令人誇讚。王老闆的攤子上每天都會準備十幾樣熟食，包括豬耳朵、豬頭皮、粉肝、火腿、香腸和燒雞，其中燒雞、火腿和豬頭皮，都是店裡最受歡迎的美味。燒雞是老闆特別用中藥滷湯，將洗淨的當日現宰鮮雞滷熟後，再放入烤爐用砂糖燻烤，透過中藥滷湯和煙燻砂糖兩種味道的融合，將燒雞的美味完美呈現。王老闆的豬腳火腿也是來此必買美食，作法是先將整隻的豬腳將內部的骨、肉刮除乾淨，只留下中空的豬腳皮，最後再填入美味的豬腿肉、封口，再放入滷湯中熬煮至熟透，等客人點用再切盤。豬腳火腿將豬腳皮的軟Q咬勁和嫩滑豬腿肉相結合，氣味濃郁、鮮美燻香，令人入口生春。','中正路18號1樓','236',24.9749400,121.4430100,NULL,0.00,0,'ChIJkWPJfisdaDQRjYfH67SG300','2026-05-30 23:29:38'),(543,'新港生炒鴨肉羹','許多美食行家對鴨肉羹的美味念念不忘，尤其來自嘉義道地新港口味的板橋「新港現炒鴨肉羹」更是推崇備至。這家位於中正路不起眼的小店，老闆娘和前板橋區長江惠貞同名，多年來堅持在地口感，使用樹林最著名的高家五印醋為提味媒介，讓這碗台灣小吃成了老饕們口中的極品。鴨肉羹的作法是先用油將蒜、洋蔥和辣椒爆香後，再拌炒新鮮的鴨肉絲，等炒香之後再加入來自老闆娘家鄉又脆又爽甜的梅山筍絲，最後淋上一點五印醋，淺嚐一口就令人激賞不已。摒除一般用太白粉勾芡調羹的作法，江惠貞嚴選臺灣本產的蕃薯粉，讓身體更健康無負擔。鴨肉羹吃法可加麵、冬粉和米粉，南部人吃「鴨肉羹飯」的吃法值得試試，飯粒在吸飽了香甜夠味的鴨肉羹湯後，搭配得十分巧妙。而江惠貞的小菜「滷杏鮑菇」、「滷五香豆干」也不可錯過。','中正路281號','220',25.0190000,121.4555000,1,0.00,0,'ChIJ8f0vYASoQjQRJ-xdBJB0mlg','2026-05-30 23:29:39'),(544,'許家莊魯肉飯','這家不論何時經過，總是門庭若市的美食名店，不僅許多美食行家撰文極力推薦，便宜的價格也吸引無數的運將朋友來嚐美味。許家莊最有名的滷肉飯來此必嚐，純手工切肉丁，有稜有角的肉塊上，用獨家秘方滷製出來的甘醇口感，吃得到老闆對滷肉飯品質的堅持與用心，而另一道人氣雞肉飯則有道地的南部味，用整隻大火雞肉撕成雞絲舖排在香噴噴的米飯上，最後再淋上雞汁熬成的鹹汁，雞肉飯的美味完全昇華。許家莊配菜CP值超高，和滷肉飯、雞肉飯主配角搭配得很完美，鹹水黑鯽魚是內行人必點的菜色，用黑鯽魚先洗淨後，再用醬筍、鹹冬瓜一起入味熬煮，醬筍和鹹冬瓜的鹹味透入魚肉，嫩滑美味的層次口感很受老饕的喜愛。','莒光路117號','235',25.0022700,121.4725600,1,0.00,0,'ChIJNytf8p4CaDQRH1Wy3HQAlPM','2026-05-30 23:29:40'),(545,'海爺四號乾麵','海爺紅油皮蛋是網路上知名的團購美食，原來在三峽就能找到實體店面可以品嚐，就位於三峽中華路與愛國路交叉口附近。這裡的紅油皮蛋可以當作配菜單點，或是直接點一份紅油皮蛋麵。口感微辣的紅油皮蛋，從紅黑色的賣相就能猜出一二，店家大廚紮實的火候控制，才能快炒出這盤辣度鹹度適中的紅油皮蛋。由於口味偏重，所以十分下飯，搭配其他炒青菜或炒飯一起吃，是品嚐紅油皮蛋的最佳吃法。','光明路5號','237',24.9318400,121.3727300,1,0.00,0,'ChIJXUmeqLl_DhQR3ycqELFAz7M','2026-05-30 23:29:41'),(546,'八煙溫泉會館','八煙會館最受美食行家們推薦的美食，正是有口皆碑的精緻日式料理，其中以多樣道地日本風味菜組合而成的「八煙日式合菜」，共有十幾道菜色，包括生魚片、火鍋、壽司、水果盤、烤物、炸物，以及用金山當地漁港現撈海鮮料理而成的創意美食，每道菜色都由自日本學成歸國的大廚，將日、臺兩地的美食精華融合，料理出一道道膾炙人口的美味佳餚。八煙的生魚片除了進口的鮭魚等各式高級魚種，也有金山當地的新鮮魚貨，一邊泡湯，一邊享受金山海味，讓休閒的時光洋溢無限幸福感。','重和里林口35號','208',25.2049600,121.5936100,NULL,0.00,0,'ChIJN4uFSQ6zQjQRwxQZcRDmnhU','2026-05-30 23:29:42'),(547,'樹林乃冰鎮滷味','位於樹林後火車站左前方一、兩百公尺遠的樹林冰鎮滷味，揚名樹林區、博得美食行家們的肯定之外，來有許多台北課還特別專程開車或搭火車來買。這家冰鎮滷味攤子並不起眼，而且還開在寢具店門口，其實兩家都是同一個老闆，原本廿幾年前在台北市賣寢具，後來搬到樹林還是重拾老本行，只是晚上又多賣一項家傳得好滷味，沒想到一、二十年下來，死忠客人不少，加上口耳相傳，這傍晚才推出攤子出來的美食一開賣就人潮不斷，','中山路一段156號','238',24.9896200,121.4222500,2,0.00,0,'ChIJr4z3GxYdaDQR8-l6yv8kaG4','2026-05-30 23:29:44'),(548,'新八樂牛肉麵','「新八樂」的牛肉燉得軟爛卻形不散、湯頭醇厚還帶著牛油香氣、而且麵條又非常彈牙，除此之外，新八樂的牛肉麵價格也很平易近人。它的湯頭是以含有豐沛牛髓的牛大骨、洋蔥、番茄、白蘿蔔(獨特的辛味可去牛腥)、黃豆(讓湯頭更濃稠)等熬煮二十幾個小時而成，不僅把牛髓的溫潤甘甜給熬了出來，也將洋蔥的輕甜、番茄的美妙酸香及茄紅素(可讓湯頭成漂亮的深紅色)充分釋出，對上炒過薑的豆辦醬後，就成了記有深度又富層次的湯頭。至於牛肉，店裡使用的是澳洲牛腱，吃來飽含肉之而步柴、軟爛不糜而有口感。除了牛肉麵，將牛腸牛肚處理得很乾淨、切得很厚很大塊、嚼來軟Q過癮的牛雜麵，洋溢蒜泥、豹蔥、胡椒、牛油香氣的牛肉或牛雜乾拌麵，淡淡清鮮、料多扎實的榨菜肉絲麵等，也很精彩；各式小菜之中，則以煙燻豬頭皮最具特色。','三民路35巷2-2號','231',24.9705800,121.5373600,1,0.00,0,'ChIJXYgQYfUBaDQRmmf4UQ6pJBY','2026-05-30 23:29:45'),(549,'石板小吃店','位於烏來老街上的小吃店餐廳，主要以泰雅風味料理為主，其中包含石板烤肉、山產、野菜等，過去以石板烤肉外帶為主，去年轉型為可內用的快炒餐廳，每到假日即高朋滿座，但老闆依舊展現原住民族的熱情與活力，為每位上門的饕客提供讓人窩心的服務。','烏來街48號','233',24.8629800,121.5514700,NULL,0.00,0,'ChIJX6gtHYkGaDQRmxL6HTqukuw','2026-05-30 23:29:46'),(550,'金山藷童瑤','金山藷童謠位於金山老街，是金山著名的地方特色伴手禮專賣店，共有20幾種商品，有冰烤黃金地瓜、手工烘焙梅甘地瓜片、炭烤拔絲地瓜片、黃金蜜地瓜、黃金地瓜球、黃金地瓜酥、跳石芋頭片、原味紅金地瓜片、地瓜太陽餅、金磚地瓜土鳳梨酥…等各種金山地方特色商品。','金包里街62號','208',25.2213500,121.6391600,NULL,0.00,0,'ChIJiXwhwldLXTQRhtYXa22HcYI','2026-05-30 23:29:47'),(551,'洪記溫泉蛋','位於烏來老街上的洪記溫泉蛋是先煮再泡，有著比茶葉蛋更溫潤的香氣，軟嫩的蛋白，含著淡淡的鹹味，宛如糖心般的半熟蛋黃，冰冰涼涼的非常順口！喜歡喝酒的人也可以嚐試一下店內另一個招牌－紹興酒蛋，一樣滑嫩的蛋白，卻帶著紹興酒香~這兩種蛋，就算不敢吃生蛋的人也可以嚐試一下~此外店內除了溫泉蛋之外，亦提供當季水果，醃漬水果供遊客選擇。','烏來街117號','233',24.8632900,121.5514700,2,0.00,0,'ChIJud_iHokGaDQRh8JWGsNuYc0','2026-05-30 23:29:48'),(552,'阿基尼亞甕梅','阿基尼亞-甕梅桂花烏梅汁集結新店碧潭地靈人傑之旺，依山傍水之美，旺美\"甕梅\"之精隨，特選天然材料，七種中藥材提煉而成，生津止渴，平衡體內酸鹼值，調整腸胃機能，另外純手工製的甕象徵\"望你牽成\"，希望人與人相處能夠圓融，相互包容，是最佳伴手禮的選擇。','銀河路86號','231',24.9595000,121.5808800,NULL,0.00,0,'ChIJbYznnMoBaDQRVrOnYK4dMAo','2026-05-30 23:29:50'),(553,'八里一支釣小吃店','位於八里左岸不遠的八里一支釣小吃店，雖然沒有精彩的裝潢，卻是許多愛品嚐海味的行家們，每次來到八里絕不會錯過的超級名店。已經14年以上歷史的海鮮店，老闆兼大廚鄭坤記，原本就是海釣同好們組成的「一支釣」協會會員，本來只是幾位海釣好友每回釣上海魚後，自己烹調著吃，沒想到越來越受大家歡迎，後來乾脆就開了家小吃店，把會員的海魚料理成令人驚艷的美味，就這樣「八里一支釣」盛名遠傳千里，連桃園的客人也趨之若鶩，專程開車來嚐嚐鄭老闆手藝。','龍米路三段49之1號','249',25.1587900,121.4239400,2,0.00,0,'ChIJT6BHlWylQjQRx-Ap5O4W0hA','2026-05-30 23:29:51'),(554,'玉知高華知高飯','三重區的小吃美食名店林立，尤其知高飯、豬腳飯、滷肉飯等庶民美食更是享譽全臺。其中位於溪尾的「溪尾知高飯」，更是箇中翹楚，用溫體黑豬腿庫及老滷汁慢火細燉製成的知高飯，不僅不油膩、十分Q彈，還帶有黑豬肉質的鮮甜美味，一到用餐時刻門口停滿運將司機的「小黃」，就不難得知這人間美味的魅力。','溪尾街206號','241',25.0811900,121.4881300,1,0.00,0,'ChIJneZTgdaoQjQRZGnXGnN8gug','2026-05-30 23:29:52'),(555,'花岩山林花園餐廳','這家位於三峽區滿月圓附近的花園餐廳，不僅是許多登山踏青的遊客們，中途嚐美食、賞美景的勝地，還有各式風格的民宿，包括卡布里貝殼屋、綠野小舍、椰林小屋、小樽河畔日式屋…等，讓遊客能停泊腳步，體驗身處群山中，與幽谷、樓台、親水、冥想、浪漫相處的心靈舒暢。尤其與市區車程不遠的距離，一時刻間坐擁山林美景，或坐在地中海風的陽傘亭台區，品啜典藏香醇咖啡或英式下午茶、在燭光搖曳中品嚐豐盛佳餚，都讓人有沉浸幸福鄉的感覺。','有木里有木路104之1號','237',24.8646400,121.4395200,2,0.00,0,'ChIJ5bQWU9saaDQR423duuvDdZw','2026-05-30 23:29:53'),(556,'大海邊美食小吃店','每當用餐時間到時，位於漁港旁的大海邊美食小吃總是高朋滿座，主因為老闆提供了新鮮海鮮食材，店裡的招牌菜包含：活魚清蒸、綜合壽司以及涼拌鯛魚皮，除此之外，顧客在用餐時向窗外的大海一望，無不讓人心曠神怡，使得在品嘗美味時亦有愉悅的心情伴隨著。','龜吼里漁澳路2號','207',25.1937000,121.6858100,2,0.00,0,'ChIJozZ_IXJMXTQR-f8xfaV_944','2026-05-30 23:29:55'),(557,'好初早餐','這間連外地人都知道的早午餐店，可以說是掀起板橋早午餐風潮的始祖之一，夯到一店人潮排爆、好初早餐還在板橋車站附近開了二店呢。因為價格超平實、選擇又豐富，不管是漢堡、吐司、飲料幾乎全都在百元以下，像是鴨胸堡、鹹豬肉堡、瓜仔肉三明治等，在好初有許多外面吃不到的特色口味，就連飲料也有一般難見的冷泡茶、氣泡飲，還不斷研發新菜色難怪會讓人想一吃再吃，即使開了二店，一店依舊是人潮不斷，不想等到天荒地老還是一開店就殺過去吧。','文化路二段125巷70號','220',25.0278000,121.4700000,2,0.00,0,'ChIJL-vCckCoQjQRXK1f5AaQ6gs','2026-05-30 23:29:56'),(558,'慶祥樓北方館','北京烤鴨是鎮店之寶，非嚐不可。老闆陳彥庭選用宜蘭生產，四斤重熟成鴨子，整理乾淨之後，塞進獨門中藥配方醃製一天，要烤之前取出藥包，塗上一層薄薄的麥芽，陳老闆強調：「這樣可以使得鴨子烤出來之後，表皮酥脆，色澤漂亮。」烤鴨子必須用桃木溫火烤45分鐘，表皮變成褐色才可出爐上桌。其他還有烤鴨三吃、京都子排、蒼蠅頭、客家小炒…等，都是店裡人氣名菜。','中正路169號','220',25.0161700,121.4566800,2,0.00,0,'ChIJGaa6tQSoQjQR3riDsIublWc','2026-05-30 23:29:57'),(559,'福慧根湯','數十年的老店福慧根湯背後有著一段神奇的故事，其命名是以「不忘根要感恩、信念堅定開智慧、知足健康便是福」為經營宗旨，福慧根創辦人張老先生三十幾年前從一位吳老醫師那兒習得漢方食養的秘方及燉煮火候精髓，期間全心全力地練湯閉關，也免費請人喝湯結緣，最後推出福慧根養生藥膳後便一炮而紅。','車子路122&123號','231',24.9517600,121.5062100,3,0.00,0,'ChIJI2NHsLMDaDQRB6KKT8396_I','2026-05-30 23:29:58'),(560,'南機場豆腐殿','亮白色的招牌上襯著豆府殿三個紅色大字，以及老闆帥氣的肖像，頗具設計感的招牌非常好認，菜單以白字木頭底掛在攤前及牆上，為店內增添不少古色古香的氛圍，不算太大的店面要因應絡繹不絕的客人，老闆也在店內掛上寫著「座位有限要聊天請至咖啡店」的有趣招牌，看著店家前滿滿的人潮，生意之好也難怪老闆得這麼做了。','中安街74號','235',25.0021300,121.5123200,1,0.00,0,'ChIJEWMy292pQjQRayVBZ7ApWyQ','2026-05-30 23:29:59'),(561,'咖啡意識烘焙館','已經開業6逾年的咖啡意識烘焙館專賣各式咖啡以及咖啡豆，堅持不賣食物品項就是為了要專注於咖啡的高品質。從挑豆、選豆、烘豆、烹煮到品嚐全部都是由老闆張文蔚Jerry一手包辦，擔任國內各大咖啡豆比賽的專任評審以及各類咖啡的比賽評審，同時也身兼台北精品咖啡協會的理事。','永利路109號','234',25.0027000,121.5234300,NULL,0.00,0,'ChIJ45djuiuqQjQRGC53pHedQCc','2026-05-30 23:30:00'),(562,'朱銘美術館-綠方塊茶屋','位於朱銘美術館坐落在太極廣場與慈母碑旁的綠方塊茶屋適時地提供觀眾一個休憩的好空間。累了嗎？綠方塊茶屋提供您香醇的咖啡、沁涼冰沙及可口點心，在藝術氛圍中，點點綠意，享片刻清閑！','西勢湖2號','208',25.2430700,121.6109200,NULL,0.00,0,'ChIJHyynXru0QjQR-8NTCYcja3c','2026-05-30 23:30:02'),(563,'泰雅巴萊部落村','超有 sense 的原住民 DIY 活動體驗~原住民生活體驗, 泰雅化文體驗套裝行程, 會議交誼, 大專院校迎新宿營, 機關團體幹部訓練, 校外教學, 員工旅遊, 童軍露營, 野炊, 客製化休閒活動規劃, 夏令營, 石板烤肉, 迎新, 露營, 住宿','烏來里西羅岸路132號','233',24.8599900,121.5394100,NULL,0.00,0,'ChIJ16x0qX8GaDQReTgeomy-KSE','2026-05-30 23:30:03'),(564,'芭達桑原住民主題餐廳','芭達桑位於八里左岸(觀海大道)面向淡水河畔的優勢，讓這裡的氣氛浪漫優美，正是欣賞落日餘暉最佳的觀景處，店內主打原住民特色料理，提供各式山產、野菜 美食、特調飲品、創意甜點，重情禮聘最頂尖的料理達人團隊。以創新的手法，融合原住民食材及香料，揉和平地常見的料理方式。以健康有機為出發點交織出與一 般不同的美味佳餚，挑動每一個顧客的味蕾．本餐廳有三個樓層(樓中樓設計)大器漂流木的裝潢氣氛，加上每天固定原住民歌手的現場演唱，絕對是您約會宴客， 聚餐會議，品嚐原住民料理，體驗原住民文化的最佳去處。','觀海大道111號','249',25.1619700,121.4257000,2,0.00,0,'ChIJLZblBWulQjQRuoALU--RoUk','2026-05-30 23:30:04'),(565,'汪汪地瓜園(薄暮田原)','多年前的一個無心插柳之舉，為了幫助家中的地瓜銷售，上網拍賣農田裡未採收的地瓜，讓想要親手挖地瓜的朋友可以親訪這片農田，之後種種的演變，促成了今日的汪汪地瓜園。旺旺一隻乖巧的小黃狗，跟前跟後的隨著主人在農田裡辛勤的耕耘著，此一景色正是薄暮田原LOGO所要表達的意境，而汪汪地瓜園因而以此命名。多年來汪汪地瓜園在賴爸爸與賴媽媽的耕耘下慢慢的得到了許多朋友的認同，每年到了採收的季節總是有著許多熟悉的面孔一再的到訪，農田裡總是擠滿了一雙雙生澀雙手，用心的挖掘著那值得期待的地瓜農獲，看著農田裡的朋友們眼中閃耀的喜悅及農田裡歡樂的笑聲，對賴爸爸及賴媽媽就是最好的肯定。','重和里六股林口74號','208',25.2168800,121.6011200,NULL,0.00,0,'ChIJ6wCK-WezQjQRRkno4fCXcoQ','2026-05-30 23:30:05'),(566,'兩支北方麵食館 (板橋店)','兩支北方麵食館成立於土城海山捷運商圈，經營團隊的組合來自於一群志工同好，誠懇、樸實、熱心、充滿人情味是我們創立經營服務理念。     兩支對北方麵食有種堅持道地美味的執著，從醒麵、桿皮、包餡到成品，每一個環節都是對客戶的尊重與責任，期待您的肯定與支持~    專營北方麵食點心:牛肉麵、酸辣麵、豬肉炸醬麵、榨菜肉絲麵、各式炒麵、豬肉捲餅、牛肉捲餅、餡餅、抓餅、宜蘭蔥餅、蔥油餅、韭菜盒、招牌湯包、蟹黃湯包、各式蒸餃、小米粥、各式炒飯、燴飯、酸菜白肉火鍋、泡菜小火鍋、各式風味熱炒。','民族路261號','220',25.0069400,121.4704700,2,0.00,0,'ChIJY7wvbyCoQjQR7WMYdV6osFU','2026-05-30 23:30:06'),(567,'尚鼎精品茗茶','尚鼎茶葉緣起　　尚鼎茶葉自產自製、批發給茶行，從1991開始獲得很多高山茶比賽及全國高山茶競賽，頭等、貳等、參等獎。我們認為比賽茶是對自己專業的鑑定，且做好茶是我們的本份，進而更鑽研來自合歡山系高海拔台灣茶，一定要不斷的精進成長。直到1993年創立自有品牌並深根於板橋，要求茶葉本質必須安全優質，才能做尚鼎之茶，因此國、內外都有不少愛喝尚鼎之茶的忠實客戶，至今已走過二十多年的歲月。被笑憨人，我們也甘願做~　　自2009年開始將茶葉逐批送國際認證單位SGS農藥殘留檢驗，以最嚴格的標準把關，將茶葉食品安全盡力做到最好!一開始大家都覺得是不可能的事情，這個選擇經常使我們面臨沒有茶可賣的瓶頸，甚至讓茶友買不到茶而被罵…但尚鼎仍堅持不變的初衷。','四川路二段110號','220',24.9940300,121.4506700,NULL,0.00,0,'ChIJ23EWDrQCaDQRekkX1HlOhl0','2026-05-30 23:30:08'),(568,'福圓號真功夫養生饅頭','創始店位於台北市文山區興隆路上，傳承超過四十年山東老師傅手藝採用天然酵母菌(老麵)，堅持手工製作，揉出麵團筋性，當天現做現蒸，保證絕無添加化學香精、人工色素及防腐劑，這是我們對產品品質及顧客口碑的堅持！產品食材使用台灣在地生產食材，例如:台南東山煙燻桂圓肉、大甲芋頭、龍井南瓜、萬丹紅豆、屏東芒果、雲林地瓜......等，並且還有新鮮非基因改造無糖豆漿，提供顧客搭配饅頭包子顛覆傳統饅頭的印象，福圓號養生饅頭除了招牌桂圓饅頭跟雜糧饅頭以外還有20幾種創意饅頭口味，相當受各年齡層的喜歡！','永和路二段153號','234',25.0130500,121.5151900,1,0.00,0,'ChIJUx43E-qpQjQRYw9GlcOtdj0','2026-05-30 23:30:09'),(569,'上水樸石日式鍋物','『上水樸石』日式鍋物，座落於三峽台北大學旁，離三鶯交流道約5分鐘車程，擁有兩棟獨棟挑高建築，兩棟建築之間，以綠葉佐以白色石子打造的戶外庭院，石板的設計貫穿兩棟建築，創造寫意的散步步道以及開闊迎接陽光入眼的餐廳氣質。','國際一街22號','237',24.9429700,121.3740300,2,0.00,0,'ChIJMx7lvvUbaDQRhKoVGyJg6A4','2026-05-30 23:30:10'),(570,'斯陋cafe','斯陋.cafe 手沖精選單品珈啡店喫pao.2手工窯烤天然酵母麵包/特製輕食/自家釀造飲品/精選好茶斯陋.弍階 賣 .生活美學雜貨 預約 咖啡席/茶席/生活上意想不到課程','中正路13號','227',25.0365100,121.8651900,2,0.00,0,'ChIJU2F0_KhbXTQRQ5iZ0hVTs8Q','2026-05-30 23:30:11'),(571,'白金花園酒店花園咖啡廳食光藝廊','花園咖啡廳食光藝廊營業項目含：咖啡飲品、鉑金商務早餐、典藏私廚午晚套餐以及花園下午茶；天然健康食材、醬料、肉品、均由現場廚房製作，非一般使用中央廚房調理包，所有餐點均為現點現做，咖啡、飲品、茶使用現煮現泡，杯杯鮮泡，原味回甘，採用自家烘培咖啡豆，現磨現萃香醇濃郁，讓您品嚐最天然、鮮美的原味。','安興路77號','231',24.9749300,121.5153000,NULL,0.00,0,'ChIJrfYWQxUCaDQRKuvZDMH5itA','2026-05-30 23:30:13'),(572,'伴山農莊','獨家白窯燒烤技術，搭配天然果乾、核果、澳洲湖鹽等天然食材，堅持手作的天然美味歐式麵包，用柴燒窯烤等繁雜的工法，用手做的溫度，做出天然美味的歐式麵包。','炮子崙24號','222',24.9884000,121.6051800,NULL,0.00,0,'ChIJvd8pI5aqQjQRp4ah33VrkqI','2026-05-30 23:30:14'),(573,'瑞芳美食廣場','瑞芳美食廣場位於瑞芳火車站正對面，為交通樞紐，鄰近於歷史悠久的瑞芳老街，是遊客們觀光的重要景點。該市場成立已50餘年，從傳統市場轉型為著名的美食街，想吃到最正港的瑞芳小吃，來這裡準沒錯！市場內各類特色美食應有盡有，香氣十足口感酥脆的福州胡椒餅、堅持用黑毛溫體豬製成又大又美味的肉羹麵、特選大塊半肉半筋燉煮鮮濃的牛肉麵、用鮮肥飽滿的蚵仔搭配新鮮蔬菜做的蚵仔煎…等，都令消費者流連忘返。','民生街35巷2號','224',25.1069900,121.8057200,1,0.00,0,'ChIJqeTM4vlPXTQRTMyCMLtAPAc','2026-05-30 23:30:15'),(574,'虎記涼麵','友善服務：□.信用卡/悠遊卡/第三方支付服務(提供現金以外的交易方式)。','中正路307號1樓','242',25.0351500,121.4482400,1,0.00,0,'ChIJOxv3AHWoQjQRA_AOGsazOW4','2026-05-30 23:30:17'),(575,'九份黃金豆干','(1)豆干：沙茶(原味、辣味)長條(原味、辣味)(每包150元，3包特價400元)   手工碳烤素蹄筋(原味、辣味) (每包150元，3包特價400元)(2)肉干：黑胡椒牛肉干、原味豬肉干、蜜汁豬肉干(每包150元，3包特價400元)(3)現烤的起士牛奶棒(每支40元)，3支(特價)100元','基山街4號之5','224',25.1094700,121.8452700,NULL,0.00,0,'ChIJJVP0IRhFXTQRJxF2nkV5uaE','2026-05-30 23:30:18'),(576,'高麗照茗茶','「九份高麗照茗茶」位於九份最熱鬧的基山老街上，主要販售來自台灣各地的高山茶，本店的服務人員以熱情的服務態度為您介紹茶的的各種相關知識、種類和各異的香氣，並以精美的包裝為產品增添精緻度，是您選購伴手禮的最佳選擇。熱情好客的老闆更將於現場以專業的泡茶手法，為您沏上一壺溫熱的高山好茶，帶您品茗純淨無汙染的台灣高山茶，用舌尖感受真正的芳香甘醇；歡迎您一同來品茗好茶，感受台灣的道地人情味。本店專售：凍頂烏龍茶、阿里山高山茶、台灣高山茶…..等等的優質台灣茶葉。','基山街19號','224',25.1094800,121.8454100,NULL,0.00,0,'ChIJiVb1IhhFXTQRDnjuFsU-iYw','2026-05-30 23:30:19'),(577,'玄明田食堂','本餐廳菜單上有中、英、日、韓四國語言的介紹，是外國遊客的友善餐廳。室內雖然沒有過於複雜的裝潢，首先看到的是牆上各種菜單的照片，體現我們對食材的要求與對每一道菜所追求完美的品質。店內的招牌菜是九份獨有的「礦山雞」，類似用茶燻入味的作法，雞皮微黃吃起來帶有煙燻的香氣、略帶鹹味，肉質鮮嫩偏軟，幾乎入口即化的礦山雞超好吃。我們還有炸到外酥內嫩的「金磚豆腐」，及香味四溢的「爌肉飯」，爌肉燉到軟硬適中恰到好處，澆上微甜的滷汁，配上又脆又夠味的醃蘿蔔，令人不禁食指大動。如果您到九份來，不可錯過到玄明田食堂來品嚐我們的手藝，及我們當地的礦山雞。','基山街82號','224',25.1086600,121.8445400,NULL,0.00,0,'ChIJe47V_hdFXTQRK8ilaOvag0k','2026-05-30 23:30:20'),(578,'九份勝紘野生葡萄籽','【九份勝紘野生葡萄籽】來到這裡多年，為了讓更多地方的人知道勝紘漿果產品的好處，在這裡讓遊客試喝，喜歡再買。「野生葡萄籽」採用台灣彰化二林鎮葡萄，連皮帶籽帶果肉以古法釀造而成。經由我們為您將葡萄(籽)研磨細狀，讓您輕鬆的吸取到整顆葡萄(籽)的營養，確保營養不流失。「蔓越莓」採用北美洲進口優質整顆蔓越莓果實；「藍莓」則採用紐西蘭進口優質藍莓，均以台灣古法釀造而成，酸帶澀甜的滋味讓您愛不釋口，享用方便，容易保存，營養美味完全吸收。我們追求安全消費、健康樂活，選擇安全的原料與製作過程帶動起健康的生活方式。','昌隆街18號1樓','224',25.0525200,121.4922100,NULL,0.00,0,'ChIJl8pMlgKpQjQRmo9xx3E2MEA','2026-05-30 23:30:22'),(579,'九份金滿堂黑糖茶鋪','一個來自台灣北部小漁村的女孩，因為感念母親常常為她熬煮黑糖薑母茶緩解生理期或感冒的不適，因而創立了「金滿堂黑糖茶鋪」，也藉此傳承了母親滿滿的愛。「金滿堂黑糖茶鋪」對於食材的嚴格挑選與人工仔細清洗，絕不參雜次品製作，依傳統古法熬煮、慢火細燉，三、四個小時不停的攪拌，待冷卻成形完全乾燥後，到衛生獨立包裝，就是為了給顧客喝到最好的，吃到最健康的與最安全的食品。我們製作了各種風味俱佳的養生系列產品，方便更多顧客最快享用各式養生健康茶，不需耗費6-8小時去熬煮，從散裝到獨立包裝，更推出迷你包裝，讓大家外出攜帶方便。都能喝到媽媽用心為你熬煮的手工薑母茶。本店專賣各式黑糖、老薑系列產品，可供客戶選擇，人氣產品為黑糖桂圓薑母茶，養生黑糖桂圓海燕窩及冬蟲夏草牛蒡茶，冰糖蜂蜜菊花茶，黑糖冬瓜茶，黑糖養生四物飲，真實材料純手工古法釀製，是最佳伴手禮、送禮、自用兩相宜，並有貨到付款宅配服務，歡...','基山街59號','224',25.1087400,121.8453800,NULL,0.00,0,'ChIJHxh1AxhFXTQRkyHaHUOd8Rg','2026-05-30 23:30:22'),(580,'精釀吧 BestBrews','來到BestBrews酒吧，暢飲醇飲優選的當地啤酒，可以盡情放肆對自己支持的球隊大喊，也可以靜靜的小酌沈澱心情。約48個座位數，以沙發為主，讓您可以舒適的在酒吧渡過休閒的下班時光。','文化三路一段一號1樓','244',25.0660800,121.3608800,NULL,0.00,0,'ChIJFb0LlO-nQjQRGWh28ywbsqo','2026-05-30 23:30:23'),(581,'宜客樂The Eatery','日本美食文化追求精細以及精美的傳統美學，並吸納了西式料理的精髓，讓西餐的設計更精緻，因而創造出“和風洋食”的新派系。主廚以日式的烹調與食材為出發點，並搭配西式元素，喜愛西餐的食客，不妨嘗試一下和風洋食食藝風格的體驗。','文化三路一段一號1樓','244',25.0660900,121.3608800,NULL,0.00,0,'ChIJ9Sd-pCenQjQRPUXphvCt4is','2026-05-30 23:30:25'),(582,'AP蓽蘿藝術活動中心','我們以藝術空間為主，將兩棟老宅打通改造成融合展區，個人工作室以及早午餐的複合式場地，為了改善環境，更於頂樓設置魚菜共生系統，供應餐廳食材所需，提倡「將土地還給大自然」。走進店裡，一樓是早午餐，隨處可見畫作與雕塑作品藝術氣息濃厚；沿著天井樓梯上樓，二、三、四樓皆作為藝術空間提供出租，展示收藏作品。未來還希望推廣「一里一店」計畫，盼能為社會帶來正面益處。','英專路139號','251',25.1728200,121.4465700,NULL,0.00,0,'ChIJPfNAZvivQjQR-6OBhLa1Hqs','2026-05-30 23:30:26'),(583,'長青穀典堅果餐廳','於98年創立榖典國際”長青榖典”，秉持著以自然、養生、健康為產品本質，保留食物原有營養，不添加防腐劑及化學成分，不僅通過SGS認證，並朝天然食品有機食品發展，並通過慈心有機驗證，於106年6月創立”長青榖典堅果餐廳”，符合新時代飲食觀念，用心做出健康、美味的產品，與客戶一同分享。','民族街2-1號','237',24.9313600,121.3690000,NULL,0.00,0,'ChIJ1bYcZQAbaDQRNXOOC1trFWI','2026-05-31 00:29:33'),(584,'伊莎貝拉海灘咖啡館','位於在石門區白沙灣這塊美地中，漫步在北海岸風稜石園區內步道上，醒目藍、黃、白建築標竿正是伊莎貝拉，內有附設兒童遊樂區、歐式公主床座、夜景獨家露天式用餐、盤座區能舒適躺著、盤腿、赤腳伴隨歌手駐唱享受無敵海景。提供窯烤披薩、調酒、咖啡，異國料理、適合情侶親子、各式聚會包場活動、婚紗攝影及求婚場景，還有DIY小神廚教學提倡親子互動，合作農夫市集有機蔬果、漁夫之家，春一枝冰品…開始啟程夏日消暑休閒勝地。','德茂里下員坑15-17號','253',25.2861600,121.5118500,2,0.00,0,'ChIJNeaxmKSuQjQRHzEz_jKuYS8','2026-05-30 23:30:28'),(585,'魚藏婚宴廣場/海鮮食堂','魚藏海鮮宴會廣場，位於新北市淡水區漁人碼頭情人橋畔，海景視野遼闊，百坪宴會空間桌數可容納50桌，空間使用十分靈活，非宴會時段也能隔成4個獨立包廂，同時提供麥克風、投影布幕等設備，軟硬體兼具，是朋友聚會、家庭聚餐、生日宴會及結婚喜宴的最佳宴客會所，海鮮食材採用本港漁船直送，多樣的新鮮海產，精緻的料理方式，讓賓客能享用最在地的美食鮮味，歡迎您的蒞臨。','觀海路201號','251',25.1845200,121.4112300,2,0.00,0,'ChIJV2yI_i2lQjQRhUc3ScQrCOU','2026-05-30 23:30:29'),(586,'私藏不藏私','距離捷運景安站超近的咖啡店「私藏不藏私」，店門口有著濃濃鄉村風，推開木門，店內的裝潢給人很放鬆的感覺，牆上掛著明信片、皮件等各式小物，沒錯，這裡也有販售日式雜貨，每半年會調整擺設和菜單，每個位置都很有特色，不同角落能感受到老闆的用心。店內提供咖啡、鬆餅、自製優格、輕食、便當等餐點，你沒有看錯，這裡還有像日劇裡會出現的日式便當，光是擺盤就讓人想多拍幾張照，菜色豐富，吃起來更是美味！在這裡吃個午餐、喝喝下午茶，就像在家一樣溫暖又舒適。照片提供：私藏不藏私','景安路167巷6號','235',24.9945000,121.5057600,2,0.00,0,'ChIJo2wc_XYCaDQRCbEOE_gFH_U','2026-05-30 23:30:30'),(587,'永哥港式點心坊','菜色選擇豐富、店家服務良好是網路上大推的餐廳，位於捷運大坪林旁的永哥港式點心坊是聚餐的好選擇，主廚曾待過神旺飯店、京星港式飲茶等知名餐廳，廚藝經歷二十餘年，料理絕對屬於水準之上。叉燒蒸腸粉—Q軟滑嫩的外皮裹腹著叉燒肉，與醬油搭配起來清爽美味；鹹魚雞粒豆腐煲—煎過滑嫩的蛋豆腐，在與醬料一同拌炒，超級下飯；港點—蝦餃、燒賣、鳳爪也都是店內招牌；假日來記得點限定的黑糖麻糬蛋塔，層層酥脆的塔皮極香，加了黑糖麻糬使得口感多了個層次，非常好吃！','寶安街36號','231',24.9825800,121.5420900,2,0.00,0,'ChIJkfaLXfkBaDQRTVeU9-hqWIg','2026-05-30 23:30:31'),(588,'MATTER CAFÉ','MATTER CAFÉ位在捷運新埔站附近，主打早午餐和舒芙蕾，工業風簡約裝潢，佐以乾燥花和小雲朵裝飾，讓整個空間亮起來，浪漫又可愛，一定要拍幾張網美照。板橋的早午餐遠近馳名，MATTER CAFÉ表現也不庸俗，新鮮的食材現點現做，鹹食還有燉飯、義大利麵供選擇。來到這必點舒芙蕾鬆餅，網路上好評不斷，圓潤可愛的外型，一送上來就香氣逼人，蓬鬆綿密的入口即化，與糖霜的搭配極佳，或是與其他醬料一同食用，真是太幸福啦！價格佛心還不收服務費，難怪擁有超高人氣！（照片：MATTER CAFÉ提供）','文化路一段316號1樓','220',25.0220400,121.4677700,2,0.00,0,'ChIJ8SFgBRaoQjQR9KhFvIXIPL4','2026-05-30 23:30:33'),(589,'小樂堂','抹茶控的絕對不能錯過！食尚玩家、網路上都大力推薦，飲料部分選擇豐富，如：抹茶、玄米茶、焙茶、冰淇淋拿鐵等，香濃好喝。甜點則是以當季食材製作，添加日本進口宇治丸久小山園抹茶粉，入口微苦但隨即回甘，淡雅的抹茶香氣令人激賞，店家另外家了日本金賞綠藻粉，更兼顧營養。其他甜點像是—檸檬塔，酸V阿酸V的檸檬內餡搭配酥脆塔皮，整體吃起來清新美味、焦糖可可蛋糕也都是不錯的選擇，店家堅持每天現做，建議提早預定以免撲空。（照片：小樂堂提供）','二十張路1巷1弄3號','231',24.9825300,121.5405200,2,0.00,0,'ChIJVVVVVT6oQjQRx2eL_J_6nBY','2026-05-30 23:30:34'),(590,'蒜味雞排','特殊的蒜味正是他的招牌，來此不妨試試最台式的雞排！','新莊福壽街124巷2-5號1樓','242',25.0513800,121.4576800,1,0.00,0,'ChIJ0QJdAFocaDQRKg30Zb7oOX8','2026-05-30 23:30:35'),(591,'氧森谷主題餐廳','氧森谷王老闆用私人山谷、舒適用餐空間、綠意盎然休閒庭園、主廚美味餐點形塑一座讓遊客流連忘返的奇蹟山谷。隨著不同季節的變化，氧森谷也會用不同的面貌迎接每位來訪的旅人，更融合當地特色與創意，希望透過親自體驗的方式感受不一樣的坪林新旅遊體驗。','粗窟村仁里坂15-2號','232',24.9236700,121.6909400,2,0.00,0,'ChIJi0AmRHb_ZzQR4qrLUnOgrpQ','2026-05-30 23:30:36'),(592,'幸福三號冰淇淋','位於金山大橋附近的幸福三號冰淇淋，是專賣明治冰淇淋的店唷! 幸福三號冰淇淋口味眾多，並提供露天咖啡座讓你品嚐綿密濃郁的明治冰淇淋之外，還可以遠眺金山大橋海景唷!','豐漁里民生路3號','208',25.2237100,121.6479600,NULL,0.00,0,'ChIJaw9ngV5LXTQR9dKCMEGOzAI','2026-05-30 23:30:38'),(593,'明軒肉鬆食品','三十年手藝的傳承，造就美味不朽傳奇！肉香濃郁撲鼻，紮實咬勁越嚼越香甜， 越吃越涮嘴，絕對經得起考驗，小時候的記憶值得延續，讓更多人知道傳統美食的好滋味，「美食、傳統、品質」。  友善服務 □外語友善(能提供與他國顧客溝通之語言或媒介)。    □信用卡/悠遊卡/第三方支付服務(提供現金以外的交易方式)。','中正路140號','244',25.0773400,121.3929500,NULL,0.00,0,'ChIJkYvHp_CmQjQRgk1m7fu4VVM','2026-05-30 23:30:39'),(594,'聯瑜烘焙麵包','店內以無添加糖、無添加油、無添加奶、無添加蛋、高纖、健康素材、口感好的麵包為主。用心研發不同優質菌種，只為給您更多更好的選擇，天然酵母烘焙出來的產品，製程中會產生多種豐富的礦物質.胺基酸及消化酵素，具極高的營養價值,食用不易產生胃酸。聯瑜烘焙麵包好吃的秘密，是使用天然酵母老麵，天然A最好天然菌種-鳳梨、奇異果、檸檬、蘋果、葡萄、小麥、黑裸麥酵母菌...等等。引進日本最新型三幸機械烤箱採用花崗岩大理石爐底，製法採用遠紅外線定溫烘焙技術,以特殊瞬間高溫烘焙工法，100%完整鎖住麵包香氣與口感，保留天然的琥珀色澤散發獨特芳香，口口滿足。','明志街21號','241',25.0642000,121.4923000,NULL,0.00,0,'ChIJA10t8R-pQjQR74dmi-bDyy8','2026-05-30 23:30:40'),(595,'十八味高級草本茶',NULL,'中正路192號','251',25.1700900,121.4401500,NULL,0.00,0,'ChIJsSbZplmlQjQR2GLGaJPLJSc','2026-05-30 23:30:41'),(596,'紅龜麵店','已經傳承至第二代、有近一甲子年紀的紅龜麵店，可說是平溪老街最具歷史與美味的代表麵攤，遊客們來到平溪，每逢午、晚餐時間，很多人總會找上這兒來解饞，因此座無虛席是假日常見的景象。最早紅龜麵店就開在平溪線鐵軌旁，搭個簡易的棚子開店做生意，後來講求衛生、也要給客人更好的用餐環境，一年多前就搬到對面的現址重新營業。在紅龜麵店用餐，不時有平溪線火車從頭頂上呼嘯而過，應該是麵攤用餐的另一種迷人的情趣。','平溪街31號','226',25.0256600,121.7387100,NULL,0.00,0,'ChIJAbGz9bRWXTQRmluff2ONsFE','2026-05-30 23:30:42'),(597,'老徐的店','因為在9號省道上，這間店是上烏來泡湯時必經的店,在網路上受到廣大網友好評。只看得到店的招牌,看不到店面，必須從路旁的小路走下去才可以進到店內，由老闆推薦自豪的私房料理給客人，像是招牌的砂鍋魚頭、涼拌菜、炸豬手、石頭蝦等，口碑當相當好，不過因為份量比較大，建議找多一點人來比較好點菜，也可以一次品嚐到較多料理。','新烏路三段寶島巷9號','231',24.8988700,121.5520700,2,0.00,0,'ChIJNWmNmaGADhQRKqS4YWEOcDs','2026-05-30 23:30:44'),(598,'姑媽早點豆漿店','濃郁的豆漿米漿，搭配著手工精緻的酥餅，現烤的香味讓人食指大動，真材實料的韭菜盒還有水煎包，煎的外皮香酥鬆軟，內餡有著韭菜豆干絲，口口飽滿，吃起來非常過癮，發麵餅加蔥蛋，咬下一口，嘴裡帶點淡淡的甜味，越咬越有勁，中間還有蔥油香，好吃的東西走的是平價親民的路線，點了一桌美食，讓人開始愛上吃早餐，一起迎接活力的一天。  推薦產品:豆漿米漿、鹹豆漿、甜鹹酥餅、發麵餅 、韭菜盒 、水煎包','三民路79號1樓','231',24.9714300,121.5358000,1,0.00,0,'ChIJP5acyB8CaDQRYz97iAI7CAo','2026-05-30 23:30:45'),(600,'青年小吃店','逛完阿榮片場，不遠的林口舊街上，可是美食小吃攤林立，其中深獲林口區親和運將推薦的青年小吃店，是來到林口不可錯過的美食店。這家專賣香噴噴又Q軟的汕頭麵、乾板條聞名，是當地鄉親簡單解決一餐的美味好選擇，更特別的是老闆還有一項特別的美食技藝，就是有口皆碑的紅豆湯圓和鮮肉鹹湯圓，是當地學生們放學後解饞的首選。這裡的紅豆湯煮得不糊爛，完整的紅豆顆粒，和圓柱型Q軟有勁的湯圓形成絕配，甜度合宜的甜湯，濃稠中帶有淡淡的迷人豆香。','中正路76號','244',25.0773900,121.3946100,1,0.00,0,'ChIJlY2vUfemQjQRwXVV4UGvmG0','2026-05-30 23:30:47'),(602,'Asia 49 亞洲料理 酒廊','位在高50層、新北最高的「百揚大樓」內，位於49樓的Asia 49亞洲料理及酒廊號稱是新北第一景觀餐廳！除了有360度的落地窗可全面觀賞市區景致，餐廳提供的料理則是亞洲菜系，從韓式、泰式、星馬料理到中式菜豐富多而多樣化，無論是情人約會或聚餐都合宜，，最重要的是餐後走到戶外區散散步看看夜景可說是極致享受啦。不過難道不用餐就不能上來嗎？當然不是，店家低消為一客餐或一杯飲料，用完餐後來此點杯調酒小酌一番、配上絕美夜景就很有FU了呢。','新站路16號','220',25.0130800,121.4669100,3,0.00,0,'ChIJuaevwBioQjQReh0h1TCH0BQ','2026-05-30 23:30:48'),(603,'白師傅食品有限公司','甜而不膩的牛軋糖，杏仁果等配料的天然風味與濃郁的牛奶香，在入口的瞬間連同適當的甜味一同滿佈於口中。除此之外的各種糕點亦均各具特色風味，綜合五種果類的五仁酥亦是推薦的人氣商品！  推薦產品：綜合牛軋糖、五仁酥','淡金路三段405-2號','251',25.2084400,121.4489800,NULL,0.00,0,'ChIJm6NgbgCwQjQRdojCWXooaGE','2026-05-30 23:30:49'),(604,'老柴咖啡館','老柴咖啡館除了提供香醇好喝的咖啡外，還有提供許多美味的三明治、鬆餅及甜點，另外，店內的空間運用也非常不錯，這邊還另有沙發及獨立空間，是個非常有氣氛的咖啡館。','大觀路113號','237',24.9453600,121.3745800,2,0.00,0,'ChIJAyay8QocaDQRWD1c6djVv_U','2026-05-30 23:30:50'),(605,'當樂咖啡','走一個復古風的當樂咖啡，店內處處可以看出店家用心的裝潢，好像小時候走進爺爺奶奶的家，偉士牌機車停在磨石子地板上，大同電扇呼嚕嚕的吹著用餐席，餐具與開水放在古老碗櫥裡，架子上則擺放老電視、黑膠唱片和收音機，讓人好懷念～不要以為早午餐份量很少，錯！澎湃的「有蝦有魚奶油燉菜」是店裡招牌，光用看的就很吸睛，大大的碗上鋪著一層酥皮，裡面的魚蝦和高麗菜給的很有誠意，吸滿湯汁的燉菜香甜濃郁，不愧是人氣必點！除此之外還有圓盤早午餐、小鐵鍋、三明治等豐富料理供顧客選擇。','光正街40號','220',25.0173500,121.4618800,2,0.00,0,'ChIJLbAQIcE1aDQRhR_JO2UmEuM','2026-05-30 23:30:51'),(606,'金湧泉SPA溫泉會館-水彎彎餐廳','配合萬里螃蟹季推出萬里蟹鮑魚粥 + 露天風呂門票的套裝優惠，由粵菜師傅使出煲粥絕活，煲出萬里蟹最精純的鹹鮮原味，餐前還可享受南洋風情造景的露天溫泉、海底硫磺低鹽泉及SPA水療設施','萬里加投213-3號','207',25.2160200,121.6431900,NULL,0.00,0,'ChIJC9arlaZMXTQR1Cm4VmCWX58','2026-05-30 23:30:52'),(607,'胡叻南洋火鍋','胡叻提供道地馬來西亞風味湯頭，讓顧客不用到馬來西亞就能品嚐到道地獨特的異國風情。對於湯頭的執著，堅持每個步驟的用心，絕不添加化學香料，以真材實料的南洋香料紅咖哩、椰漿奶水、香茅等數十種材料加上大骨熬煮湯頭，提供顧客健康香醇濃郁的南洋風味。  友善服務  □行動裝置充電 (提供電源插座、USB等供行動裝置、手提電腦等設備充電)。   □素食友善(提供全素食/蛋奶素餐點) (不含蔥、蒜、韭菜、薤(蕎)、興渠(洋蔥)、肉類)。  □友善廁所(提供借用廁所服務)。   □Free WiFi(提供顧客無線網路之服務)。','泰安街41號','242',25.0424400,121.4466700,2,0.00,0,'ChIJ0aCC8denQjQRfJmvpzPXZ8s','2026-05-30 23:30:54'),(608,'雲林赤肉羹','手工赤肉搭配南部口味羹湯，以及那浸泡滷汁裡的滷味，還有香味撲鼻的滷肉飯，10來年堅持的口味值得一試！','佳園路一段22之7號','238',24.9713500,121.3926900,1,0.00,0,'ChIJ2bdDn1AcaDQRxAC6Yofq_fI','2026-05-30 23:30:55'),(609,'馨宣手作咖啡',NULL,'啦卡路20號','233',24.8619900,121.5546900,NULL,0.00,0,'ChIJp2E9XwAHaDQRZM4Y78vrRRQ','2026-05-30 23:30:56'),(611,'芳三里紅茶老店','所多消費者到美食街看到「芳三里」這店名，還以為是瑞芳區的哪個里？其實這是第一代老闆周淡煙老先生對自家紅茶品質的自豪，現在老攤由第二代接手經營，讓50年老店繼續散發茶香味。鑽研茶湯的內行人說，要煮出好茶，水質是關鍵；深諳此道的老闆特地避開每天自來水公司為管線消毒的時間，接引來自員山半山的天然礦泉，並選用特選日月潭阿薩姆種茶葉，茶一煮開，熱氣蒸騰，香氣遠飄三里外，印證了老字號店名，果然名符其實。','民生街35巷2號','224',25.1069500,121.8035400,NULL,0.00,0,'ChIJkamx_flPXTQRb7scoN_uFDQ','2026-05-30 23:30:58'),(612,'桃樂絲柚香農場',NULL,'荖阡里六鄰 34-5號','249',25.1248900,121.4071600,NULL,0.00,0,NULL,'2026-05-30 20:04:04'),(613,'樂釜極上鍋物(板橋店)',NULL,'中山路一段8號','220',25.0078800,121.4599300,NULL,0.00,0,'ChIJ4UL9D6mpQjQRJ6h8FJO4dac','2026-05-30 23:30:59'),(614,'光權 Kuang\'s Bistro','什麼是北歐開面三明治？這是來自北歐的三明治吃法，在麵包上放上各種配料，最上面不蓋麵包就是所謂的開面三明治。座落在板橋車站附近的光正街這間光權 Kuang\'s Bistro，主打的就是這種開面三明治，蔬菜、雞腿肉疊得高高，第一眼看到大概會想「這該怎麼吃啊？」不過食材新鮮、料理得宜吃起來美味無負擔，除了開面三明治外，店內還提供早午餐店少見的精緻義式小點、咖啡等，週末午後來份爽口三明治配上香濃咖啡，在漸冷的天氣中格外舒服。','光正街32號','220',25.0173400,121.4621900,2,0.00,0,'ChIJi4VaGBqoQjQRC35zaJ3Giy8','2026-05-30 23:31:01'),(615,'50樓Café','坐落於新北最高百揚大樓的頂樓(50F)，由遠東集團和香格里拉酒店集團聯手打造，是全國最高的自助餐廳，以無敵景觀及海陸百匯聞名，主廚秉持「從產地到餐桌、安心上菜」的理念，運用寶島豐饒物產，搭配高檔進口食材，提供絕佳餐飲體驗，佳餚美點，琳瑯豐富，讓人大快朵頤！(菜色以現場供應為準)','新站路16號','220',25.0130300,121.4669500,NULL,0.00,0,'ChIJuaevwBioQjQRYxPlADKSd5U','2026-05-30 23:31:02'),(616,'淡水中正觀光市場','中正觀光市場座落於文化古城的淡水老街中，走出市場外便是河岸美景及各式小吃和童玩店。中正觀光市場有別於一般傳統市場販售蔬果生鮮肉品，而是具有當地特色的阿給、鐵蛋及魚丸湯，其味道與淡水老街上的老店不相上下，市場內亦設有共食區，提供遊客小歇片刻，伴著街頭藝人的悠揚樂章，感受淡水金色水岸的悠閒。','中正路115號','251',25.1701300,121.4397500,NULL,0.00,0,'ChIJlRYhhlqlQjQRNbn28SBy4iQ','2026-05-30 23:31:03'),(617,'島灰(一品豆花)','這兒豆花的豆味兒香醇濃郁，相當綿密而紮實的口感有點像嫩豆腐，口感滑順，糖水甜度也剛剛好。而「新鮮水果豆花」，豆花上鋪滿了各式色彩的水果，賣相一流，相當特別，值得一試。','得和路373巷2號','234',24.9994900,121.5248300,1,0.00,0,'ChIJO1NruuSpQjQRK2dTsM7G_w8','2026-05-30 23:31:04'),(618,'亞美淇日式烘焙坊','亞美淇自2007年創店以來，秉持著新鮮、自然、創新、品質第一的精神~~用熱情製作出讓顧客期待與驚喜的產品，嚴選上等食材，嚴格把關原料及產地來源，檢驗合格證明才予以製作。用心的烘焙、貼心的服務，使顧客吃的健康、安心，是亞美淇的責任與方針。  友善服務 □1.外語友善(能提供與他國顧客溝通之語言或媒介)。    □4.素食友善(提供全素食/蛋奶素餐點) (不含蔥、蒜、韭菜、薤(蕎)、興渠(洋蔥)、肉類)。','中正路83號','244',25.0772200,121.3947000,NULL,0.00,0,'ChIJZTKTQvemQjQRu7ZEaM47pxo','2026-05-30 23:31:06'),(619,'樂釜極上鍋物(徐匯店)',NULL,'永安北路二段8巷10號','247',25.0808600,121.4807700,2,0.00,0,'ChIJi6G_spmpQjQRRmEmZBh7cf0','2026-05-30 23:31:07'),(620,'新勝發餅舖(板橋總店)','新勝發創始人杜發，13歲就開始工作，15歲就到餅舖當學徒，約在1960年代，老婆杜楊月圓賣了結婚時的首飾、標會，才湊足本錢，終於有了自己的店，而杜發構思出的「豆蓉肉塊酥」，更成為新勝發長銷至今的招牌產品。由蛋黃酥演化而來的豆蓉肉塊酥，最初是考慮到中秋節前蛋黃價格波動大，現代人也開始重視健康，經過不斷嘗試，終於成功以獨家配方滷製的豬肉塊取代蛋黃，搭配白豆沙和綠豆沙混合的豆蓉，成為新勝發熱銷的產品，因為堅持不含防腐劑，保鮮期只有六天。在第二代接手後，新勝發經營的腳步更快也更積極，開始進駐日系百貨公司、在淡水開設分店，更轉向廈門投石問路。精緻豆蓉肉塊酥，由蛋黃酥衍生而來，當時考慮到中秋前鹹蛋黃價格波動太大，現代人也漸注重健康等因素，以溫體黑豬肉塊取代了鹹蛋黃，加上獨家配方滷汁，再加上白鳳豆沙和綠豆沙搭配的豆蓉，特殊的口感，更堅持不含防腐劑，雖只有六天的保存期限，仍舊是吸引饕客趨之若鶩。','中山路2段388之1號','220',25.0203300,121.4823700,2,0.00,0,'ChIJf9MlIjeoQjQReG6tBlGmqx4','2026-05-30 23:31:08'),(621,'油庫口蚵仔麵線','身為板橋人怎麼可能沒吃過油庫口？從民國75年開店至今的油庫口蚵仔麵線，除了招牌的麵線外最特別的就是店內還兼賣烤香腸，一碗麵線加一支香腸可是許多人的定番組合，麵線爽口滑順、蚵仔嫩滑、大腸Q軟，再叫上一支炭香四溢的香腸，一口咬下肉汁滿滿，超過三十年的老店、獨特的組合，承載的不僅是美味更是板橋人的回憶啊。','文化路一段188巷44號','220',25.0167700,121.4658700,1,0.00,0,'ChIJTx1TvheoQjQRqAqXqmNy55o','2026-05-30 23:31:09'),(622,'樂釜極上鍋物(長榮店)',NULL,'長榮路41號1樓','247',25.0832100,121.4636000,2,0.00,0,'ChIJQd9OmEGpQjQRCZsMR4nkSaI','2026-05-30 23:31:11'),(623,'白河阿婆碗粿、米苔目【總店】','從前在台南縣白河鎮，有一個85歲的阿婆，阿婆推著車子在市場賣米苔目、碗粿已經50多年了。沒有華麗的包裝，也沒有電視的報導，‧但只要吃上一口，就會被她的味道深深吸引住，彷彿回到古早年代，孩提嘻笑怒罵時的懷舊記憶一一浮現腦海。阿婆十分講求食物的品質，絕不偷工減料或添加任何化學物品，「遵循古法、堅持手工」是阿婆的理念，在阿婆身上，讓人看到了老一輩台灣人對吃的尊嚴與執著。雖然隨著年齡漸長，阿婆不得不放棄這項傳統的手藝，幸好，阿婆將這傳統又美味的做法傳授下來，讓實在的好味道繼續流傳。','大同北路4號','241',25.0619300,121.4954100,1,0.00,0,'ChIJAz-35M2pQjQRTDCZE7DinEg','2026-05-30 23:31:12'),(624,'金翡翠餐飲店','金翡翠餐飲店，證書編號：03-00150，聯絡電話：02-2492-1291','龜吼里漁澳路16號之3','207',25.1951100,121.6870400,2,0.00,0,'ChIJ20SDFG9MXTQRDhmxcIbvpb0','2026-05-30 23:31:13'),(625,'海邊灶咖','歡迎各位灶友們帶著親朋好友們一起來灶咖坐坐 提供餐食、早午餐、咖啡、飲品、調酒、甜點 歡迎灶友們能熱情給我們建議 我們會盡力改善 希望能將灶咖打造成溫暖又愜意的好地方','北勢子19之1號','252',25.2543700,121.4737700,2,0.00,0,'ChIJawie5qqxQjQRmJBg0ShMBOc','2026-05-30 23:31:14'),(627,'阿虎嬸菜頭粿','一般菜頭粿只有逢年過節才販賣，而主打絶不添加化學藥品的阿虎嬸菜頭粿則是一年四季都有，用了50年的時間，經過無數次的調整才找到與別人不一樣的地方，將傳統風味新鮮呈給消費者。  推薦菜色:芋肉包、蘿蔔糕、草仔粿','豐年街豐二巷39號','242',25.0308300,121.4473100,NULL,0.00,0,'ChIJ-xZK7AqoQjQRqmtrxCKbMGE','2026-05-30 23:31:16'),(628,'花漾朋派','位在四號公園旁的花漾朋派，最開始從澳洲回來的老闆希望讓大家吃到正統鹹派，而開了花漾朋派的前身朋派Pompie，後來加入了鮮花果昔、千層蛋糕等以花漾朋派的身份重出江湖。主打的花漾果昔加入食用花及燕麥，以新鮮水果打製而成，不但健康拍起來也超級上鏡。當然來份鹹派早午餐是一定要的，在招牌鹹派上疊上半熟太陽蛋、炒野菇、沙拉等，果真是超「朋派」啊！除了這兩樣之外現在花漾朋派還有包括千層蛋糕、生乳霜淇淋、布丁等也是夏天搶手的人氣甜點呢。','安樂路164號','234',25.0007200,121.5145900,2,0.00,0,'ChIJgW4GS-upQjQR38utU53EDtQ','2026-05-30 23:31:17'),(629,'十分切仔麵','切仔麵就像你我的老鄰居，下班下課後，市場巷弄裡，有許多的時光都是在切仔麵攤度過的，親切樸實的老闆目前已是第二代接手，有著年輕人的毅力，保留著最傳統的味道，也發揮經歷大飯店廚師的創意，提供多樣飯店招牌菜，讓來到平溪的旅客，體驗到新舊年代不一樣的好味道。','十分街67號','226',25.0427300,121.7773700,NULL,0.00,0,'ChIJk_k40edQXTQR-RDgsborSV4','2026-05-30 23:31:19'),(630,'好日子餐飲有限公司','完美婚禮，終生幸福。「好日子餐廳」為您訂製精緻料理與完善的場地規畫。讓這一天，成為新人們難忘的好日子！ 在好日子 幸福也可以很簡單，接受預約、歡迎散客和適合團體聚會。  友善服務 □.外語友善(能提供與他國顧客溝通之語言或媒介)。    □.行動裝置充電 (提供電源插座、USB等供行動裝置、手提電腦等設備充電)。   □.信用卡/悠遊卡/第三方支付服務(提供現金以外的交易方式)。 □.素食友善(提供全素食/蛋奶素餐點) (不含蔥、蒜、韭菜、薤(蕎)、興渠(洋蔥)、肉類)。  □.友善廁所(提供借用廁所服務)。   □.Free WiFi(提供顧客無線網路之服務)。','文化一路二段131號','244',25.0797200,121.3818300,2,0.00,0,'ChIJHR2vHeamQjQRyVpvYMwoo5o','2026-05-30 23:31:20'),(631,'仁和鮑魚','販售各式通過產銷履歷驗證之國產海鮮及各地青農優質農產品','香蘭街31-1號旁','228',25.0230000,121.9825700,NULL,0.00,0,'ChIJuwV_N2VdXTQRez630TnpnHg','2026-05-30 23:31:21'),(632,'富鼎砂鍋粥','友善服務 □.外語友善(能提供與他國顧客溝通之語言或媒介)。    □.信用卡/悠遊卡/第三方支付服務(提供現金以外的交易方式)。 □.素食友善(提供全素食/蛋奶素餐點) (不含蔥、蒜、韭菜、薤(蕎)、興渠(洋蔥)、肉類)。  □.友善廁所(提供借用廁所服務)。   □.Free WiFi(提供顧客無線網路之服務)。','新泰路195號','242',25.0379100,121.4471300,2,0.00,0,'ChIJg6rq33WoQjQRBEHFvEGv-d0','2026-05-30 23:31:22'),(634,'AirMagic 種苗育種農場',NULL,'興華里楓子林51-7號','252',25.2108100,121.4953600,NULL,0.00,0,'ChIJe3nj5TGwQjQR52s2VZcwfUI','2026-05-30 23:31:24'),(635,'滿築極品鍋物',NULL,'重陽路一段49號','241',25.0615200,121.4850300,2,0.00,0,'ChIJHX7EOfepQjQRq9aH-ul97gs','2026-05-30 23:31:25'),(636,'新勝發餅舖(淡水旗艦店)','淡水「新勝發餅舖」是由迄今已有五十年的板橋埔墘老店，「新勝發餅舖」五十年來的第一家分店。以四千萬買下四層樓店舖並重新裝潢，以純手工的「臺灣人文餅鋪」為訴求，讓到淡水一遊的觀光客，都能吃到記憶中的傳統滋味。第一代創始人杜發從十三歲做學徒起，便投入製餅行業，剛開始是賣一些拜拜用的麵龜，以及傳統的中式糕餅，因為用料實、口感佳，逐漸在當地闖出一點名號。除了繼承傳統的口味，也不斷嘗試開發新產品，「豆蓉肉塊酥」就是約十六年前杜發的構想，成為「新勝發」獨家的招牌產品，杜蘇志及么女兩兄妹，均前往日本進修，學習日本烘焙技術，提供了讓豆蓉與肉塊酸甜中和，以及不添加任何防腐劑可以保存六天新鮮度的技術，推出之後大受歡迎，也打響了新勝發的名號。 推薦產品:豆蓉肉塊酥/精緻豆蓉肉塊酥','中正路52號','251',25.1695600,121.4433500,2,0.00,0,'ChIJm4ESAlClQjQRz7ChLVcztdA','2026-05-30 23:31:26'),(637,'Merci Cafe','來到板橋怎麼可以不吃早午餐呢？板橋早午餐文化的始祖之一就是這間「Merci Café」，從最開始的一間到現在一連開了四間店Merci cafe . Merci petit . Merci creme . Merci Vielle，四間都有各自的特色，可以營業這麼多年靠的當然不只是名氣，復古工業風的裝潢讓走進Merci Café的客人都能享受到悠閒的氛圍，豐富而平價的早午餐菜單可以說是CP值極高，難怪Merci Café早午餐名店的盛名多年不衰啊。','新民街7巷17號','220',25.0103400,121.4634200,2,0.00,0,'ChIJhTXJjh6oQjQRSKCh4Nlo93o','2026-05-30 23:31:28'),(638,'提立歐義式餐廳','深根於八里的義式美食，有著不一樣的理念。  挑高的空間，增加用餐的舒適環境  TILLIO 堅持使用自然食材取代人工添加，無調理包、無味精、完全廚師的料理  例如用新鮮的南瓜取代南瓜調味料、開放式廚房讓食材公開透明化，  我們主張呈現食物最自然的原樣，讓每位顧客們都重新獲得能量，  擺脫對外食的不安與恐慌。   TILLIO 堅持讓人您吃的安心、吃的健康，  簡單卻又不失美味的料理，是我們的初心。  我們有各式美食包括:  原塊炭烤牛排、義大利麵、燉飯、手工比薩、經典沙拉、  義式開胃菜、各式飲品、蛋糕~  歡迎您前來品嘗美食唷!!','商港路2號','249',25.1446500,121.3977600,2,0.00,0,'ChIJvwoDcFOkQjQR_NlfqfAtiio','2026-05-30 23:31:29'),(639,'海邊走走-淡水生活概念總店','品牌理念： 『海邊走走手工蛋捲』是台灣第一蛋捲伴手禮品牌，名稱的由來顧名思義是希望傳達出，輕鬆自在來台灣淡水踏青，買好吃的美食，度過美好的一天。 並搭配品牌手工蛋捲，讓手工蛋捲有了新的生命，首創爆漿的花生餡口味蛋捲，深受台灣及亞洲各國消費者喜歡，目前是來台旅遊必買伴手禮。','公明街37巷6號','251',121.4434300,25.1691200,NULL,0.00,0,NULL,'2026-05-30 20:04:04'),(640,'臺北牛肉麵‧大陸麵店','民國六十一年創業的大陸麵店，從復興高中、文化大學、陽明醫學院，到民國八十一年在淡水淡江大學開店，原味湯頭、平實價格和堅持乾淨衛生的理念，擄獲許多學子的心，尤其是招牌「魯士麵」，現煎的黑豬肉里肌片麵，更是淡江人畢業後最懷念的滋味，很多學生當了爸爸媽媽，還會帶孩子來吃一碗記憶中的麵，感受和老闆娘話家常的溫馨。湯頭講求原味不加醬油，使用不帶肉的小肋骨精燉湯頭，僅用中藥材提味，健康又鮮甜，麵條則是訂做手工麵條，有Ｑ度不易爛，和清醇香噴噴的湯頭相得益彰，不只在淡水，臺北車站也有分店，愛吃麵的朋友不妨一試。','北新路182巷5弄25號1F','251',25.1774800,121.4494300,NULL,0.00,0,'ChIJIdlu7P6vQjQRdkEliasMgCY','2026-05-30 23:31:30'),(641,'熊米屋社會企業有限公司','建構庇護性場域，協助身心障礙朋友及中高齡失業婦女。 提供技能培訓、職業重建及就業、創業的新社區網絡。','瑞濱路83號','224',25.1207500,121.8213200,NULL,0.00,0,'ChIJn2ykW4BFXTQR1WTePQSph6Q','2026-05-30 23:31:31'),(642,'小馬貝菈',NULL,'大坑2號','252',25.2652300,121.5155200,2,0.00,0,'ChIJ5_vsuLi2QjQRx78ITbW_G3g','2026-05-30 23:31:33'),(643,'鮮物本舖',NULL,'灔山街65-3號','228',25.0724100,121.9196400,NULL,0.00,0,'ChIJp_j5A4hdXTQRyd6T_q2kH3Y','2026-05-30 23:31:34'),(644,'新勝發漁業',NULL,'美灩山街2-2號','228',25.0595400,121.9274200,NULL,0.00,0,'ChIJV4_AqslcXTQRuwX_YJIlXbI','2026-05-30 23:31:35'),(645,'藻堂',NULL,'大同路二段240號16樓之一','221',25.0654700,121.6540800,NULL,0.00,0,'ChIJO7NIT2pTXTQRx4CdukGcNRA','2026-05-30 23:31:36'),(646,'海邊走走–淡水生活概念二店','品牌理念： 『海邊走走手工蛋捲』是台灣第一蛋捲伴手禮品牌，名稱的由來顧名思義是希望傳達出，輕鬆自在來台灣淡水踏青，買好吃的美食，度過美好的一天。 並搭配品牌手工蛋捲，讓手工蛋捲有了新的生命，首創爆漿的花生餡口味蛋捲，深受台灣及亞洲各國消費者喜歡，目前是來台旅遊必買伴手禮。','中正路165號','251',25.1710900,121.4388000,NULL,0.00,0,'ChIJU7vbH0OlQjQRR7fvpalAcUE','2026-05-30 23:31:37'),(647,'深坑小林肉粽','位在新北市深坑區的小林肉粽，就位在主要道路旁，交通方便，讓路過的客人選購容易，已經有30幾年的歷史在深坑頗具知名度，店內販售的粽子種類包羅萬象，有粿粽、素菜粽、湖州焢肉粽、湖州紅豆粽、紅棗蓮子粽、五穀養生粽等多種選擇，如今是由第2代接手，而店面與包粽子的廠房就在隔壁，有興趣的民眾可以看到包粽子的過程，內餡的真材實料，一點都不馬虎，全呈透明公開，讓你吃的安心也吃的放心。','北深路二段155-9號','222',25.0020600,121.6129600,1,0.00,0,'ChIJOXrv98SqQjQRzd3Ru4Hf3nU','2026-05-30 23:31:38'),(648,'糊塗羊肉爐','在板橋越晚越熱鬧的湳雅夜市裡，一入冬，香氣四溢的糊塗羊肉爐成為許多人的暖胃首選。這家店已經有三十多年的歷史，不僅每天營業到凌晨，連過年期間都有開伙，爽朗的童寶俊老闆陪伴許多人度過寒冷的冬天，也培養出客戶的好口碑。湯頭有中藥和清燉兩種選擇，米酒、麻油、薑各種暖身必備配方全都入，結合羊骨長時間熬成的完美滋味，另外，由於使用中華民國養羊協會出產的溪湖國產羊肉，不僅肉質鮮美有彈性，吃起來絕無腥臊味，還可以一次吃到帶皮、帶骨、薄片多種口感的羊肉。難得糊塗的鄭板橋若有口福享用板橋如此佳味，想必是天天都來「糊塗」一下了！','南雅西路2段2-7號','220',25.0091900,121.4533100,2,0.00,0,'ChIJu0MBxakCaDQR25MgnWck4_0','2026-05-30 23:31:39'),(649,'泰山公有零售市場',NULL,'全興路212號','243',25.0561600,121.4336300,NULL,0.00,0,NULL,'2026-05-30 20:04:04'),(650,'三峽公有零售市場','三峽公有市場為一棟符合節能與環保的公有市場，鄰近三峽老街，內通風及採光充足、走道相當寬敞，提供舒適的購物環境。位於市場3樓還有日韓式精品、美容保養、文創手作及咖啡廳等特色攤位，如商店街之概念，販賣種類豐富，配合三峽老街的舒適環境及周圍店家的童玩、飲食文化，是個多元且現代化的菜市場。另地下室也設置有汽機車停車位，進出交通十分方便，顛覆傳統的公有零售市場印象。','民生街186號','237',24.9349500,121.3710500,NULL,0.00,0,'ChIJuf_J9PEbaDQRluEQ1_Z2c_I','2026-05-30 23:31:41'),(651,'板橋黃石公有零售市場','黃石市場靠近府中捷運站1號出口，鄰近府中商圈週邊，餐廳及商場林立，生活機能便利，是個遊逛、採購及聚餐的首選。市場2樓於每周日上午9點至下午4點舉辦2手市集，現場近60個攤位，販賣商品琳瑯滿目，且不定期舉辦主題活動及消費滿額抽獎活動，讓民眾撿便宜又享好康。','宮口街37號','220',25.0107000,121.4570000,NULL,0.00,0,'ChIJreUzywKoQjQRfq-fM7xrchE','2026-05-30 23:31:42'),(652,'金山第一公有零售市場','台灣早期的居民都是伴隨著廟會聚集地點與交通要道，而發展出各自獨特的傳統市集。位於早期舊名「金包里」的金山第一公有零售市場建置於日據時代，是台灣少數超過50年以上歷史的傳統市場。在金山第一公有零售市場裡可依不同時令買到當地所特有的山菜、山藥、芋頭、箭竹筍、甘藷、芋頭、茭白筍、紅心地瓜等蔬菜。老街上古老建築及金山鴨肉名聲遠播，假日人聲鼎沸，金山區場是當地居民的購物天堂，更是假日觀光客採買享受美食的好去處。','中山路188號','208',25.2215200,121.6379600,NULL,0.00,0,'ChIJZ6oO3FdLXTQR8aPJ2OxHsAc','2026-05-30 23:31:43'),(653,'蔡記冰店','夏日必備，超大份量傳統冰店！這間位在雙溪區立公有市場的蔡冰(蔡記冰店)，是遊客到雙溪推薦必吃的在地名店之一。點一碗綜合豆花，不僅品項超豐富，還內含約10種料，連豆花都被埋在料理面。同樣的價格，但份量卻是一般市面上的2至3倍之多，建議可以跟好朋友一起分享食用唷！','太平路50號','227',25.0354500,121.8647800,NULL,0.00,0,'ChIJP7F-mfVbXTQR6pzNPWV6kPA','2026-05-30 23:31:44'),(654,'生泉全有機茶園(王有里有機茶)','在坪林已有百年傳承，並榮獲行政院農委會92年神農獎的有機茶農王有里，堅持有機栽種茶葉已有十幾年，並獲得有機認證多年。他的「生泉有機茶園」除了有百年蓊鬱老樹，還不時飄散著茶香，由於有機種茶就是得面臨著草除不盡、蟲抓不完的窘境，早年甚至還只能採收到一點點茶葉，連買肥料、茶苗的錢都不夠。不過，因堅持要將祖先乾淨的土地留給下一代，王有里十幾年苦撐下來，已深得老客人的信賴，加上電視媒體不斷採訪，並且有許多單位前來觀摩、進行生態環境教學，讓這裡的茶葉品質遠近馳名，自用送禮皆上選。','漁光里乾溪1號','232',24.9767400,121.7425000,NULL,0.00,0,'ChIJfdWxh11WXTQRCd6kf9aHL94','2026-05-30 23:31:46'),(655,'李儀餅店','傳承自基隆百年餅家「李鵠餅店」，老闆是李鵠餅店的第四代，自行出來創業也以本家的手藝面世。「李鵠餅店」最富盛名的綠豆沙餅、鳳梨酥和咖哩酥，在「李儀餅店」自然不會缺席，店裡並增加芋頭酥、奶油太陽餅等新的口味，其中芋頭酥還得過2001年基隆市名產特優金牌獎，廣受消費者歡迎，由於注重品質，目前李儀餅店除九份總店之外，各地亦開發多家分店。推薦產品：鳳梨酥、太陽餅。','汽車路18號','224',25.1099600,121.8441500,NULL,0.00,0,'ChIJUVDRARhFXTQRmBnvMswsfZA','2026-05-30 23:31:47'),(656,'鶯歌甕仔麵','早先位於尖山埔路上的甕仔麵，現在遷移至重慶路上老街陶館內的2樓美食廣場，是道地鶯歌美食中最讓人津津樂道的一家店。尤其在逛完琳瑯滿目的1樓商場之後，信步至位於美食廣場內的甕仔麵，可以看見以老倉庫的古樸風格設計餐廳裡，每個人都享用著店家特別以鶯歌當地生產的甕所盛裝的甕仔麵，懷舊的氣氛搭配古早的美味，真是別有一番好滋味！地址：新北市鶯歌區重慶街95號（老街陶館2樓）營業時間：10：00;17：00（假日延長至20：00）早先位於尖山埔路上的甕仔麵，現在遷移至重慶路上老街陶館內的2樓美食廣場，是道地鶯歌美食中最讓人津津樂道的一家店。尤其在逛完琳瑯滿目的1樓商場之後，信步至位於美食廣場內的甕仔麵，可以看見以老倉庫的古樸風格設計餐廳裡，每個人都享用著店家特別以鶯歌當地生產的甕所盛裝的甕仔麵，懷舊的氣氛搭配古早的美味，真是別有一番好滋味！','重慶街95號','239',24.9522300,121.3481100,NULL,0.00,0,'ChIJI9smeKseaDQRKH-DVjz9gpY','2026-05-30 23:31:48'),(657,'青島藥燉牛肉麵','老闆特製藥燉湯頭，搭配富嚼勁的麵條及軟嫩牛肉，以及燉煮入味的豬腳，清爽的湯頭讓人吮指回味。 另老闆特製的「椰奶豆」，也是值得一嚐的甜點呦！','中山路三段120號','238',24.9722400,121.3924300,NULL,0.00,0,'ChIJiTFjyFAcaDQRaam9u_jBkIs','2026-05-30 23:31:49'),(658,'Mr.雪腐','位在四號公園旁的這家Mr.雪腐招牌的雪果冰用得是新鮮水果製成的冰磚，一口口的水果鮮甜讓人放心大口吃。新出的惡魔果實系列則在水果上刨上滿滿雪綿冰，再鋪上大塊西瓜或哈密瓜感覺怎麼吃也不怕胖，可別以為賣冰只有一個夏季，在Mr.雪腐每到冬天還會推出豆腐煲讓你暖胃又暖心呦。','得和路2號','234',25.0007000,121.5147300,NULL,0.00,0,'ChIJE9KxreCpQjQRwQenDH3x_4g','2026-05-30 23:31:51'),(659,'笠林懷古料理(笠林茶棧)','擁有15年以上歷史的笠林懷古料理，原本是製茶泡茶的地方，因為顧客越來越多，在顧客建議之下，決定轉型成為餐廳，店內還保留早期石碇的農村風情，建築古色古香，內部紅瓦地板、木飾裝潢，呈現出傳統古樸的味道，菜餚以台菜和客家菜為主，充滿懷古風情，定位為特色小吃。用專注與堅持的心對待來訪的客人，保持原味與創新是這邊的一大特色。  推薦菜色:桂花子排、笠林咕咕雞','永定里靜安路一段292巷6號','223',25.0067000,121.6972400,2,0.00,0,'ChIJg-6Ol5fWDRQRWD-v4nPMjzc','2026-05-30 23:31:52'),(660,'黑殿飯店(創始店)','淡水區超人氣的排骨店「黑店」並不是這家店會坑人而叫黑店，而是因原本的店面小小黑黑的，而被附近的學生們戲稱流傳至今。黑店排骨飯的風格是眷村的懷舊排骨飯，老闆憑著一身炸排骨手藝，不僅在淡水屹立廿幾年，而且排骨飯上面那塊很夠份量的大排骨，炸得又香、又酥，美妙的古早風味遠近馳名，連《近在咫尺》電影劇組人員三不五時就來這裡叫便當。 「黑店」的排骨飯除了美味大排骨，米飯也煮得特別Q軟好吃有彈性，搭配著酸菜和肉醬豆干，把五、六十年代的排骨飯味道都保留了下來。來到黑店平實的價格也令人激賞，排骨飯才90元，不喜歡吃排骨飯還有麵點可供選擇，加點一些滷味小菜拼盤，更可嚐到老闆的深厚的滷功實力。傳說中的淡水古早味排骨飯，排骨大塊又美味，每逢假日長長的人潮都是為了它而來。1碗／90元   資料來源:新北市美食吃透透九月號','中正路一段62巷8號','251',25.1773000,121.4258800,2,0.00,0,'ChIJp8_h80ilQjQRPPqVtqEu46w','2026-05-30 23:31:53'),(661,'林益和堂中藥店','位在雙溪老街的林益和堂中藥店，建於清同治年間，是由林燦廷中醫師在雙溪區所成立的中藥店，西式洋樓設計的建築中，還帶有古典的色彩，整體外觀美輪美奐，目前後代還是繼續在此營業。 若要拍照，請先徵求屋主同意。','長安街3號','227',25.0346500,121.8645900,NULL,0.00,0,'ChIJlZ_u1K5bXTQRAer827fHNZc','2026-05-30 23:31:54'),(662,'板橋後埔公有零售市場','後埔市場設立於民國51年，位處於繁華熱鬧的府中商圈。歷經多年，仍舊保持其清爽整潔、乾淨明亮的環境，是一個麻雀雖小五臟俱全的市集。市場現攤位配置分為傳統市場及委外經營管理2個區域。自106年導入無毒生產、安全食用、友善環境理念，集結常態性農民市集，藉由友善土地的方式經營傳統市場，期待老市場結合新農業及社區回饋等概念，為本市場注入新生命。市場一樓，可看見製作有機豆漿、豆腐，所有豆漿、豆腐均不使用基改黃豆；再去看看市場2樓，以友善土地概念經營運用部份空間飼養蜜蜂，建立安全無毒環境，才能讓蜜蜂永續生存。','大華街5號','220',25.0066500,121.4588000,NULL,0.00,0,'ChIJtbUt6aYCaDQR33CqdgsaRP8','2026-05-30 23:31:56'),(663,'馬崗街27號咖啡小館','位在馬崗潮間帶附近的漁港內有一家小小的咖啡廳，這間馬崗街27號咖啡小館是由一對隊伍軍人夫妻攜手打造，不說可能不知道這間咖啡廳還是全台最東邊的咖啡廳呢。因為騎著單車路過愛上了馬崗這個小村落，夫妻倆胼手胝足地在2016年落腳此處，店內提供各種手沖咖啡還有限量供應的滷肉飯等，雖然咖啡廳座位不多，卻容納了老闆的滿滿熱誠，還熱情地分享各種在地人的經驗，騎車或遊玩時累了來這裡簡單小憩一下跟老闆聊聊吧。也提醒你咖啡廳內沒有提供廁所喔!','馬崗街27號','228',25.0129000,122.0033200,1,0.00,0,'ChIJU9xRjoNnXTQRcLTuBtTGmKM','2026-05-30 23:31:57'),(664,'朝日夫婦','去年新開的這家朝日夫婦冰店，短短一年多已經成了外國人也知道的淡水剉冰名店。店主是一對從沖繩回鄉的夫妻，命名為朝日是因為曾是潛水教練的丈夫在太陽還沒升起的每個朝日出門工作，希望回到故鄉後，能一起看著淡水夕日，想念著沖繩的朝日。季節限定冰款的「淡水夕日」是加入台灣道地的火龍果及芒果製成的水果醬，象徵淡水的黃昏美景，招牌的宇治金時則是加入白玉、紅豆，再淋上濃郁的抹茶醬！好吃又好拍讓朝日夫婦平假日天天排隊人潮滿滿，據說時常得排上一小時才吃得到呢！','中正路233-3號','251',25.1734500,121.4351600,NULL,0.00,0,'ChIJh0s1mVqlQjQRUrppA9KE5Lg','2026-05-30 23:31:58'),(665,'樂釜極上鍋物(重新店)',NULL,'重新路二段15-3號1樓','241',25.0655200,121.5028700,2,0.00,0,'ChIJKTs8dsepQjQRqKXHjIiv6L4','2026-05-30 23:31:59'),(666,'九份紅樓有限公司 九份紅樓餐廳',NULL,'輕便路131號','224',25.1086600,121.8435600,NULL,0.00,0,'ChIJY2D6sNVFXTQRXXOLTYQOrbA','2026-05-30 23:32:01'),(667,'二號倉庫藝文咖啡館',NULL,'中山路一段 4 號','252',25.2588800,121.5009100,2,0.00,0,'ChIJ1xVOiNG2QjQRCB10GAQtKt4','2026-05-30 23:32:02'),(668,'深坑大樹下','就在老街的入口處，也是老街上最早的豆腐料理店之一，價位公道，滿滿一桌各式口味的豆腐料理，吃起來有一種幸福的感覺，推薦品嚐的有腸旺鴨血臭豆腐，以十多種中藥熬煮二小時以上而成，口感絕佳。','深坑街163號','222',25.0011200,121.6127300,2,0.00,0,'ChIJT30aAcWqQjQRwkgjq18Gw3I','2026-05-30 23:32:03'),(669,'卡滋爆米花觀光工廠樂園',NULL,'觀海大道171號','249',25.1618900,121.4226700,NULL,0.00,0,'ChIJX_uo67ilQjQRG_AfmSnkGVw','2026-05-30 23:32:04'),(670,'新北市貢寮區漁會',NULL,'真理里新港街91號','228',25.0568600,121.9265400,NULL,0.00,0,'ChIJgXvWw8dcXTQRX4fEUDECy4E','2026-05-30 23:32:06'),(671,'蕃婆林休閒農場',NULL,'錫板里17鄰番婆林44號','252',25.2380300,121.4944400,NULL,0.00,0,'ChIJQ5IOBiGxQjQRVNSEP-IOWbc','2026-05-30 23:32:07'),(672,'啨躍咖啡',NULL,'福德街14號','208',25.2217600,121.6392200,NULL,0.00,0,'ChIJ5XkzXklLXTQRivcXsrnRfrI','2026-05-30 23:32:08'),(673,'阿瑞官粿店','新莊地區的百年老店，如今透過網路的力量，也成了團購的熱門店家，招牌商品芋粿巧用料實在，大塊的芋頭和肉角，加入少許蝦米、油蔥，古早美味讓人難忘。 推薦產品:芋粿巧、草仔粿與油飯、碗粿 推薦名人:黃林玲玲議員推薦','新莊路49號','242',25.0372900,121.4587500,1,0.00,0,'ChIJYxLiRW6oQjQRKIbRNXVlLQQ','2026-05-30 23:32:09'),(674,'茶茶cafe','茶茶提供咖啡、手搖飲、簡餐、義大利麵、小火鍋等，低消為一杯飲品，無限制用餐時間，是消磨時間的好地方！','中山路一段41號','252',25.2583200,121.5009100,NULL,0.00,0,'ChIJpwNx65m3QjQRa1Va5SqYdvg','2026-05-30 23:32:10'),(675,'紅樓中餐廳','西元一八五八年，英法聯軍戰役締結天津條約，把淡水港訂為通商口岸，洋樓式建築，始進入淡水。紅樓，又名達觀樓。起建於清光緒二十一年﹝西元一八九五年﹞，歷時四年半，於清光緒二十五年﹝西元一八九九年﹞竣工。從紅樓入口的巷子走到紅樓，總共一百零六階石階，因為紅樓位處淡水「五虎崗」中的第三崗，視野遼闊，一目千里，所以名為「達觀樓」。由老街渡船頭的人潮中遁入對面小巷，沿石階而上，短短一段上坡路之後驀然回首─淡水海口、市街人潮，已因丘陵地形的高度驟升而一覽無遺，老畫家筆下的「紅樓美景」終於不是傳說。百年來，見證淡水港埠盛衰變遷的紅樓，幾經烽火，外牆磚面毀損；西元一九九九年三月，經過專家考證，在一磚一瓦的精心修護後，於西元兩千年元月完工，重現紅樓百年前原貌。','三民街2巷6號','251',25.1712400,121.4394100,2,0.00,0,'ChIJ0aIdGFqlQjQRKMswTtT-i_8','2026-05-30 23:32:12'),(676,'讚讚原汁牛肉麵','半筋半肉的牛肉麵是一般人的最愛，讚讚最知道顧客的喜好，遵循古法用特調獨家秘方爆香後，加入新鮮牛大骨熬煮的湯頭，不添加醬油的煮法滑嫩爽口，是最優質的原汁牛肉麵。  推薦菜色:原汁牛肉麵、排骨麵','沙崙路12號','251',25.1809500,121.4211500,2,0.00,0,'ChIJW0a_azalQjQRJoYJmnLJK4Q','2026-05-30 23:32:13'),(677,'汐止金龍公有零售市場','金龍公有零售市場位於汐止中興路與康寧路交叉口，裡外環境皆有專人負責整理清潔，並且定期消毒，讓逛市場的民眾感到衛生又安心。市場內如同走星光大道般鋪上了紅地毯作為防滑墊。市集裡尤其以一攤專賣道地古早味鹹湯圓讓客人願意排隊等待。還有用特選豬大骨熬煮多時配上Q軟口感彈性米粉的米粉湯，也有用心燻滷巧手製作的素食，還有鮮美大塊遵循古法的肉羹與醬汁香氣逼人、口口入味的涼麵…等等。每攤都是各路行家所推薦的好味道。','中興路250號','221',25.0683800,121.6295200,NULL,0.00,0,'ChIJVWo3vExTXTQRpL5VV5qKlo0','2026-05-30 23:32:14'),(678,'隨意鳥窩西班牙私房工作室','西班牙（歐陸）私房料理工作室位於北海岸的西班牙私廚，結合了“家”與工作室的溫馨氛圍，不僅提供正宗的西班牙料理，還可租借場地，是聚餐、包場或單純享受大自然的理想選擇。這裡有美麗的山水與清新的空氣，讓您在好空間裡放鬆身心。餐廳提供停車位、酒精飲料、廁所設施，以及免費充電服務，是一個充滿溫度與舒適感的好去處。','新庄子126-1號','252',25.2686700,121.5106700,2,0.00,0,'ChIJKUbRlECoQjQRywFp7-kvU_o','2026-05-30 23:32:15'),(679,'Pizza Olmo','柴燒披薩好吃的秘訣是老闆親手堆砌的窯，再用龍眼木為燃料，所散發的果香增添披薩美味與酥脆。','崁子腳58之12號','253',25.2865400,121.5305400,2,0.00,0,'ChIJQZUkKcq2QjQRi8jKvdUhMVo','2026-05-30 23:32:16'),(680,'煙燻雞腳','沒有華麗的店面，樸實如柑仔店，水桶裝的各式煙燻滷味，其中雞腳更是來到山仔腳必吃的好味道喔！','佳園路一段1號','238',24.9718000,121.3927500,1,0.00,0,'ChIJG6BfvVAcaDQRoNVKKV92LCI','2026-05-30 23:32:18'),(681,'老牌阿給(楊記阿給)','淡水的小吃林立，其中就以「阿給」最具代表性，最早的創始店是位在真理街的楊記阿給，是正港的原創好滋味。阿給是先將油豆腐切開一面，放入炒過的冬粉，再用新鮮的魚漿，將切開的部分封起來，放入蒸籠蒸熟，淋上楊記獨家調配的醬汁，吃起來教人難忘。','真理街6-1號','251',25.1740900,121.4375800,NULL,0.00,0,NULL,'2026-05-30 20:04:04'),(682,'普園北平館','以中式料理麵食聞名中和，道地的中國北方、北平菜，不論餡餅、捲餅、韭菜盒、小米粥、蒸餃，還是山西刀削麵等麵食、湯類，都有老師傅手藝的好滋味。其中牛肉餡餅必嚐！恰到好處的餅皮，將肉汁完全鎖住，輕咬一口漫流而出的鮮燙口感，令人久久無法忘懷。  推薦菜色:小籠湯包、花素蒸餃、牛肉捲餅、牛肉餡餅、韭菜盒、合菜戴帽','中山路一段291號','234',25.0068100,121.5069500,NULL,0.00,0,'ChIJh-byxt6pQjQR5ErXWvLuPEs','2026-05-30 23:32:19'),(683,'永和永安公有零售市場','永安市場位於中和與永和之間的交接位置，在永和當地佔有舉足輕重的重要性，且距離四號公園不遠。其中一間永安包子頗負盛名，店內最經典暢銷的商品為獨家口味的青江菜包，以竹筍切絲、青江菜、香菇為料，手工製作，不加任何化學物質、防腐劑，適逢民俗節慶推出特定商品讓顧客購買。另一間媲美阿基師口味的阿見師鹹水雞,招牌熱賣的無骨醉雞，是精選土雞腿、烹煮後冰鎮去骨，以雞湯浸泡，保有雞肉原味，再淋上蔥油，香味四溢，是許多政商名流的首選。永安市場不僅交通便利、購物選擇多樣化又方便。','安樂路431號','234',25.0043100,121.5141200,NULL,0.00,0,'ChIJEwLfNNypQjQRihHLfwmGhSQ','2026-05-30 23:32:21'),(684,'海大牧場','「海大牧場」位於龍洞岬與澳底間，是東北角新興的旅遊景點，最大特色是「無敵海景」及「新鮮的九孔與鮑魚」。遊客可在此一邊聽濤觀景放空，一邊品嚐該地養殖場現出最新鮮甜美的九孔與鮑魚料理，有許多老饕驅車前來，只為一嚐烤鮑魚的鮮美滋味。海大牧場由於地處龍洞南口海洋公園的延伸，坐擁大片海灣美景，不論早上、中午、黃昏、夜晚，皆有意想不到的景致變化。加上海浪衝到海岸激起的沖天浪花及海風帶來的水霧，都能讓都市人忘卻煩惱，十分療癒。  將活的九孔與鮑魚直接燒烤，不加其他調味料，可直接體驗新鮮九孔與鮑魚的「鮮」、「美」。口感上九孔的肉質Q彈，而鮑魚則屬軟嫩，若想更深入了解九孔與鮑魚，服務人員也會熱情詳細解說。','美灩山街61之3號','228',25.0713000,121.9224200,2,0.00,0,'ChIJnW6HV0pDXTQRvZ18Id97czU','2026-05-30 23:32:22'),(685,'聖馬汀咖啡工坊','從兩人的堅持到現在的創意團隊，聖馬汀會不斷的學習、持續的努力，與大家分享精品咖啡的味道。  友善服務 □.外語友善(能提供與他國顧客溝通之語言或媒介)。    □.行動裝置充電 (提供電源插座、USB等供行動裝置、手提電腦等設備充電)。   □.素食友善(提供全素食/蛋奶素餐點) (不含蔥、蒜、韭菜、薤(蕎)、興渠(洋蔥)、肉類)。  □.友善廁所(提供借用廁所服務)。   □.Free WiFi(提供顧客無線網路之服務)。','文化一路二段2號','244',25.0764700,121.3801900,2,0.00,0,'ChIJgc7_3O6mQjQRdEvoXt6GZHI','2026-05-30 23:32:23'),(686,'普蕾納烘焙坊','BREADNA麵包好吃的秘訣除了烘焙的技巧，原料的挑選更是口感優劣的指標。我們使用的麵包原料皆是業界最高規，高品質的食材結合高技術的烘焙，讓BREADNA麵包擁有口感鬆軟卻不失嚼勁、保濕度極高的絶佳表現，品嚐酥脆的口感和香軟的麵包體在口中融合的幸福感。  友善服務 □.外語友善(能提供與他國顧客溝通之語言或媒介)。    □.信用卡/悠遊卡/第三方支付服務(提供現金以外的交易方式)。 □.素食友善(提供全素食/蛋奶素餐點) (不含蔥、蒜、韭菜、薤(蕎)、興渠(洋蔥)、肉類)。','四維路56號','244',25.0792400,121.3753800,2,0.00,0,'ChIJgXme6SanQjQRCZ85_uycDic','2026-05-30 23:32:24'),(687,'透早日頭','使命 1-重視身體健康所需的完整營養早餐 2-推廣健康、美味、創意蔬食餐點 3-鮮活身心靈  主力商品 紫米燒海苔飯糰、帝堡(法式麵包)、彈堡(軟法麵包)、香椿抓餅捲、三明治(全麥吐司)、烏龍麵、作調鮮飲  友善服務 □外語友善(能提供與他國顧客溝通之語言或媒介)。    □行動裝置充電 (提供電源插座、USB等供行動裝置、手提電腦等設備充電)。   □素食友善(提供全素食/蛋奶素餐點) (不含蔥、蒜、韭菜、薤(蕎)、興渠(洋蔥)、肉類)。  □友善廁所(提供借用廁所服務)。   □Free WiFi(提供顧客無線網路之服務)。','和興街7號1樓','242',25.0390100,121.4474100,2,0.00,0,'ChIJyznqa3aoQjQRA0ig_lgYb30','2026-05-30 23:32:26'),(688,'阿松檳榔.烘焙坊',NULL,'仁和路136號','228',25.0514600,121.9231700,NULL,0.00,0,'ChIJ21p3BwBdXTQRJ8VX1w5HftU','2026-05-30 23:32:27'),(689,'一良茶屋',NULL,'草里里11鄰草埔尾14號','253',25.2643300,121.6027800,NULL,0.00,0,'ChIJ_7txVYK1QjQRdqLO28gOBMk','2026-05-30 23:32:28'),(690,'金山紅(金山紅紅地瓜乳酪蛋糕專賣店)',NULL,'金包里街40號','208',25.2214000,121.6414200,2,0.00,0,'ChIJywdKda9LXTQRf6RrB0AAbkY','2026-05-30 23:32:29'),(691,'麵飽飽食魂堂',NULL,'和平路101巷7號1樓','220',24.9950600,121.4620900,NULL,0.00,0,'ChIJZ2VJStwDaDQRiiAxLIE6ccY','2026-05-30 23:32:31'),(692,'曼特寧庭園咖啡','曼特寧庭園咖啡佔地寬廣，店裡富有早期古早農村生活的氣息，庭園內滾動水車，大型的遊艇的設計讓現代都會區人們享受到的休閒空間。店內濃濃香醇的咖啡香，品嚐咖啡之後口感由醇轉潤、厚而不豐。','環京路247號','208',25.2205700,121.6320000,2,0.00,0,'ChIJKUrVEKpMXTQRxfrUKzOZfRI','2026-05-30 23:32:32'),(693,'阿婆鐵蛋有限公司','阿婆鐵蛋創立於1980年，已有四十餘年歷史，創始人為盧楊碧雲女士，因為過於忙碌無意間將蛋滷得太久，沒想到硬硬的滷蛋讓許多客人吃了之後都讚不絕口… 這就是鐵蛋誕生的故事！    阿婆鐵蛋出產的鐵蛋講求不添加任何防腐劑，堅持使用國產蛋、上等中藥材及龜甲萬醬油滷製而成，這樣的堅持是希望消費大眾能吃的健康、安心。 今年阿婆鐵蛋有限公司更上一層榮獲ISO22000及HACCP國際雙認證， 用心把關消費者的健康，讓大家真正感受道地的淡水名產『阿婆鐵蛋』 鐵蛋產品有真空殺菌包及當日現吃手拿盒兩種，自用送禮兩相宜喔！！','中正路135-1號','251',25.1704400,121.4391900,NULL,0.00,0,'ChIJFeAxLlqlQjQRccugbSbZELA','2026-05-30 23:32:33');
